    private boolean shouldSuppressTournamentFlashChat(Player player) {
        if (player == null) {
            return false;
        }
        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        return room != null
                && room.getGameMode().isFlashTournament()
                && room.getState() == RoomState.PLAYING;
    }

    private void sendFlashMessage(Player player, String message) {
        if (player == null || message == null || shouldSuppressTournamentFlashChat(player)) {
            return;
        }
        player.sendMessage(message);
    }

    public void installBundledFlashNoteSongs() {
        ConfigurationSection root = plugin.getConfigManager().getConfig()
                .getConfigurationSection("hunter_game.flash_mode.note_block_melodies");
        if (root != null && !root.getBoolean("install_bundled_songs", true)) {
            return;
        }
        String sourceFolder = root == null ? "flash-note-songs" : root.getString("source_folder", "flash-note-songs");
        File targetRoot = new File(plugin.getDataFolder(), sourceFolder == null || sourceFolder.isBlank() ? "flash-note-songs" : sourceFolder);
        if (!targetRoot.exists() && !targetRoot.mkdirs()) {
            plugin.getLogger().warning("无法创建内置音符盒曲库目录: " + targetRoot.getAbsolutePath());
            return;
        }

        List<String> entries;
        try (InputStream manifest = plugin.getResource("flash-note-songs/manifest.txt")) {
            if (manifest == null) {
                return;
            }
            entries = new String(manifest.readAllBytes(), StandardCharsets.UTF_8).lines()
                    .map(String::trim)
                    .filter(line -> !line.isEmpty() && !line.startsWith("#"))
                    .toList();
        } catch (IOException ex) {
            plugin.getLogger().warning("读取内置音符盒曲库清单失败: " + ex.getMessage());
            return;
        }

        int installed = 0;
        int skipped = 0;
        try {
            File canonicalRoot = targetRoot.getCanonicalFile();
            for (String entry : entries) {
                String normalized = entry.replace('\\', '/');
                if (normalized.startsWith("/") || normalized.contains("../") || normalized.contains("..\\")) {
                    skipped++;
                    continue;
                }
                File target = new File(targetRoot, normalized);
                File canonicalTarget = target.getCanonicalFile();
                if (!canonicalTarget.toPath().startsWith(canonicalRoot.toPath())) {
                    skipped++;
                    continue;
                }
                if (canonicalTarget.isFile() && canonicalTarget.length() > 0L) {
                    skipped++;
                    continue;
                }
                File parent = canonicalTarget.getParentFile();
                if (parent != null && !parent.exists() && !parent.mkdirs()) {
                    skipped++;
                    continue;
                }
                try (InputStream input = plugin.getResource("flash-note-songs/" + normalized)) {
                    if (input == null) {
                        skipped++;
                        continue;
                    }
                    Files.copy(input, canonicalTarget.toPath(), StandardCopyOption.REPLACE_EXISTING);
                    installed++;
                }
            }
        } catch (IOException ex) {
            plugin.getLogger().warning("释放内置音符盒曲库失败: " + ex.getMessage());
            return;
        }
        if (installed > 0) {
            plugin.getLogger().info("§x§B§B§8§8§F§F♫ 已释放 " + installed + " 首内置音符盒谱源，跳过 " + skipped + " 首已有谱源。");
        }
    }

