    /**
     * 同步玩家身上的闪光物品显示数据。
     * 旧版本物品通常 PDC 还在，只是 lore / item_model / max_stack_size 等显示组件落后；
     * 这里会保留功能标记与玩家自定义显示名，只刷新插件当前版本负责维护的内容。
     */
    public boolean syncFlashItemLore(Player player) {
        if (player == null) {
            return false;
        }
        boolean changed = false;
        PlayerInventory inventory = player.getInventory();

        ItemStack[] storage = inventory.getStorageContents();
        if (syncFlashItemLore(storage)) {
            inventory.setStorageContents(storage);
            changed = true;
        }

        ItemStack[] armor = inventory.getArmorContents();
        if (syncFlashItemLore(armor)) {
            inventory.setArmorContents(armor);
            changed = true;
        }

        ItemStack offhand = inventory.getItemInOffHand();
        ItemStack syncedOffhand = syncFlashItemLore(offhand);
        if (!isSameStack(offhand, syncedOffhand)) {
            inventory.setItemInOffHand(syncedOffhand);
            changed = true;
        }

        if (syncInventoryFlashItemLore(player.getEnderChest())) {
            changed = true;
        }

        ItemStack cursor = player.getItemOnCursor();
        ItemStack syncedCursor = syncFlashItemLore(cursor);
        if (!isSameStack(cursor, syncedCursor)) {
            player.setItemOnCursor(syncedCursor);
            changed = true;
        }

        if (changed) {
            Bukkit.getScheduler().runTask(plugin, player::updateInventory);
        }
        return changed;
    }

    public boolean syncInventoryFlashItemLore(Inventory inventory) {
        if (inventory == null) {
            return false;
        }
        ItemStack[] contents = inventory.getContents();
        if (!syncFlashItemLore(contents)) {
            return false;
        }
        inventory.setContents(contents);
        return true;
    }

    public boolean syncFlashItemLore(ItemStack[] items) {
        if (items == null || items.length == 0) {
            return false;
        }
        boolean changed = false;
        for (int i = 0; i < items.length; i++) {
            ItemStack original = items[i];
            ItemStack synced = syncFlashItemLore(original);
            if (!isSameStack(original, synced)) {
                items[i] = synced;
                changed = true;
            }
        }
        return changed;
    }

    public ItemStack syncFlashItemLore(ItemStack item) {
        if (isEmpty(item)) {
            return item;
        }

        ItemStack freshSpecial = createFreshFlashSpecialItem(item);
        if (freshSpecial != null) {
            return carryStackStateToFreshItem(item, freshSpecial);
        }

        ItemStack result = item.clone();
        ItemStack before = result.clone();
        refreshFlashEquipmentLore(result);
        return result.equals(before) ? item : result;
    }

    private ItemStack createFreshFlashSpecialItem(ItemStack item) {
        if (isMagicBrushItem(item)) {
            ItemStack result = item.clone();
            result.setAmount(1);
            applyMagicBrushMark(result);
            return result;
        }
        if (isFeatherQuill(item)) {
            return createFeatherQuill();
        }
        if (isBrushItem(item)) {
            return createBrush();
        }
        if (isCondensedSlimeBlock(item)) {
            return createCondensedSlimeBlock();
        }
        if (isCondensedEnderPearl(item)) {
            return createCondensedEnderPearl();
        }
        if (isPseudoPoisonPotato(item)) {
            return createPseudoPoisonPotato();
        }
        if (isTmt(item)) {
            return createTmt();
        }
        if (isFlashFishingBait(item)) {
            return createFlashFishingBait();
        }
        if (isEnhancedWindCharge(item)) {
            return createEnhancedWindCharge();
        }
        if (isEnhancedWindChargeStage(item)) {
            return createStagedEnhancedWindCharge();
        }
        int specialFoodId = getFlashSpecialFoodId(item);
        if (specialFoodId > 0) {
            return createFlashSpecialFood(specialFoodId);
        }
        if (isFlashFishingCatch(item)) {
            return createFlashFishingCatch(getFlashFishingCatchType(item));
        }
        if (isInvisibleItemFrame(item)) {
            return createInvisibleItemFrame(item);
        }
        return null;
    }

    private ItemStack carryStackStateToFreshItem(ItemStack oldItem, ItemStack freshItem) {
        if (freshItem == null) {
            return oldItem;
        }
        int amount = oldItem == null ? freshItem.getAmount() : oldItem.getAmount();
        freshItem.setAmount(Math.max(1, amount));
        if (oldItem == null || !oldItem.hasItemMeta()) {
            return freshItem;
        }
        ItemMeta oldMeta = oldItem.getItemMeta();
        ItemMeta freshMeta = freshItem.getItemMeta();
        if (oldMeta == null || freshMeta == null) {
            return freshItem;
        }
        if (oldMeta.hasDisplayName()) {
            freshMeta.setDisplayName(oldMeta.getDisplayName());
        }
        if (oldMeta instanceof Damageable oldDamageable && freshMeta instanceof Damageable freshDamageable) {
            freshDamageable.setDamage(oldDamageable.getDamage());
        }
        freshItem.setItemMeta(freshMeta);
        return freshItem;
    }

    private boolean refreshFlashEquipmentLore(ItemStack item) {
        if (isEmpty(item) || !item.hasItemMeta()) {
            return false;
        }
        ItemMeta meta = item.getItemMeta();
        if (meta == null) {
            return false;
        }

        if (hasPersistentByte(item, tmtHoeKey)) {
            refreshTmtHoeLore(meta);
        }
        if (hasPersistentByte(item, tntMinecartHoeKey)) {
            refreshTntMinecartHoeLore(meta);
        }

        Integer unstableMaceLevel = meta.getPersistentDataContainer().get(unstableMaceLevelKey, PersistentDataType.INTEGER);
        if (unstableMaceLevel != null && unstableMaceLevel > 0 && item.getType() == Material.MACE) {
            meta.setItemName("§x§F§F§5§5§A§A不§x§F§2§6§4§B§7稳§x§E§5§7§3§C§4定§x§D§8§8§2§D§1重§x§C§B§9§1§D§E锤");
            refreshUnstableMaceLore(meta, unstableMaceLevel);
        }

        if (hasUnstableCoreShield(item)) {
            meta.setItemName(UNSTABLE_CORE_SHIELD_NAME);
            meta.getPersistentDataContainer().set(unstableCoreShieldKey, PersistentDataType.BYTE, (byte) 1);
            meta.addItemFlags(org.bukkit.inventory.ItemFlag.HIDE_ATTRIBUTES);
            meta.setLore(null);
        }

        if (hasPersistentByte(item, totemArmorKey)) {
            refreshTotemArmorLore(meta);
        }

        String goldenAppleType = meta.getPersistentDataContainer().get(goldenAppleArmorTypeKey, PersistentDataType.STRING);
        Integer goldenAppleLevel = meta.getPersistentDataContainer().get(goldenAppleArmorLevelKey, PersistentDataType.INTEGER);
        if (goldenAppleType != null && goldenAppleLevel != null && goldenAppleLevel > 0 && isArmor(item)) {
            int maxLevel = "enchanted".equals(goldenAppleType) ? 2 : 3;
            int safeLevel = Math.max(1, Math.min(maxLevel, goldenAppleLevel));
            double healthBonus = getGoldenAppleArmorHealthBonus(goldenAppleType, safeLevel);
            meta.getPersistentDataContainer().set(goldenAppleArmorLevelKey, PersistentDataType.INTEGER, safeLevel);
            applyGoldenAppleArmorHealthModifier(meta, item.getType(), healthBonus);
            refreshGoldenAppleArmorLore(meta, goldenAppleType, safeLevel, healthBonus);
        }

        Integer harnessLevel = meta.getPersistentDataContainer().get(happyGhastHarnessSwiftLevelKey, PersistentDataType.INTEGER);
        if (harnessLevel != null && harnessLevel > 0) {
            refreshHappyGhastHarnessLore(meta, Math.max(1, Math.min(3, harnessLevel)));
        }

        if (hasPersistentByte(item, doubledPotionKey)) {
            refreshDoubledPotionLore(meta);
        }

        refreshSwordPotionLoreFromStoredData(item, meta, 1);
        refreshSwordPotionLoreFromStoredData(item, meta, 2);
        refreshSwordReturnLoreFromStoredData(meta);

        if (hasPersistentDouble(item, materialSwordSpeedBonusKey) || hasPersistentDouble(item, materialSwordDamagePenaltyKey)) {
            refreshMaterialSwordLoreAndAttributes(item, meta);
        }
        if (hasPersistentDouble(item, materialAxeDamageBonusKey) || hasPersistentDouble(item, materialAxeCooldownIncreaseKey)) {
            refreshMaterialAxeLoreAndAttributes(item, meta);
        }
        if (hasPersistentByte(item, redstoneStabilizerKey) && (isSword(item) || isAxe(item))) {
            applyRedstoneStabilizerAttackSpeedModifier(meta, item.getType());
            refreshRedstoneStabilizerLore(meta);
        }
        if (hasPersistentByte(item, materialArmorLayerKey) && isArmor(item)) {
            refreshMaterialArmorLore(item, meta);
        }

        Integer tntArmorLayers = meta.getPersistentDataContainer().get(tntArmorExplosionImmunityLayersKey, PersistentDataType.INTEGER);
        if (tntArmorLayers != null && tntArmorLayers > 0 && isArmor(item)) {
            refreshTntArmorLore(meta, Math.max(1, Math.min(TNT_ARMOR_MAX_LAYERS, tntArmorLayers)));
        }

        if (hasPersistentByte(item, bootWoolLayerKey) || hasPersistentByte(item, bootFeatherLayerKey)) {
            refreshBootSilentLore(item, meta);
        }

        Double condensedSlimeBonus = meta.getPersistentDataContainer().get(condensedSlimeBootCrawlBonusKey, PersistentDataType.DOUBLE);
        if (condensedSlimeBonus != null && isBoots(item)) {
            refreshCondensedSlimeBootLore(meta, condensedSlimeBonus);
        }
        if (hasPersistentByte(item, condensedEnderPearlArmorKey) && isArmor(item)) {
            refreshCondensedEnderPearlArmorLore(meta);
        }

        if (isPrismarineTrident(item)) {
            refreshSingleLoreLine(meta, TRIDENT_PRISMARINE_LINE);
        }
        if (isAmethystCrossbow(item)) {
            refreshSingleLoreLine(meta, CROSSBOW_AMETHYST_LINE);
        }
        if (isWindRodTrident(item)) {
            refreshSingleLoreLine(meta, WIND_ROD_TRIDENT_LINE);
        }
        if (isWindRodCrossbow(item)) {
            refreshSingleLoreLine(meta, WIND_ROD_CROSSBOW_LINE);
        }
        if (isDragonBreathWeapon(item)) {
            refreshSingleLoreLine(meta, DRAGON_BREATH_WEAPON_LINE);
        }
        if (isStormChestplate(item)) {
            refreshSingleLoreLine(meta, STORM_CHESTPLATE_LINE);
        }
        refreshStormSwordLore(meta, getStormSwordLevelFromMeta(meta), hasPersistentByte(item, stormSwordKineticKey));
        if (isArmor(item)) {
            ensureVanillaArmorAttributes(meta, item.getType());
        }
        if (isSword(item) || isAxe(item)) {
            ensureVanillaWeaponAttackDamageAttribute(meta, item.getType());
        }

        item.setItemMeta(meta);
        if (hasUnstableCoreShield(item)) {
            applyUnstableCoreShieldDurability(item);
        }
        return true;
    }

    private void refreshTotemArmorLore(ItemMeta meta) {
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line != null && (line.startsWith(TOTEM_ARMOR_LINE_PREFIX)
                || line.startsWith("§8- §x§F§F§D§D§88不死图腾护层：")
                || line.replaceAll("§.", "").contains("濒死复活并碎掉这一件")));
        lore.add(TOTEM_ARMOR_LINE_PREFIX + "§f自己近战伤害 -10%§8 / §f自己远程伤害 +15%");
        lore.add("§8- §7耐久高于 §f50% §7时，可触发濒死复活并碎掉这一件");
        meta.addEnchant(Enchantment.UNBREAKING, 1, true);
        meta.setLore(lore);
    }

    private void refreshDoubledPotionLore(ItemMeta meta) {
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(DOUBLED_POTION_LINE::equals);
        lore.add(DOUBLED_POTION_LINE);
        meta.setLore(lore);
    }

    private void refreshSwordPotionLoreFromStoredData(ItemStack sword, ItemMeta meta, int slot) {
        int uses = getSwordPotionUses(sword, slot);
        ItemStack potion = uses > 0 ? getStoredSwordPotion(sword, slot) : null;
        if (uses > 0 || meta.getPersistentDataContainer().has(getSwordPotionDataKey(slot), PersistentDataType.BYTE_ARRAY)) {
            refreshSwordPotionLore(meta, sword, slot, potion, uses);
        }
    }

    private void refreshSwordReturnLoreFromStoredData(ItemMeta meta) {
        if (meta == null || !meta.getPersistentDataContainer().has(swordReturnWorldKey, PersistentDataType.STRING)) {
            return;
        }
        String worldName = meta.getPersistentDataContainer().get(swordReturnWorldKey, PersistentDataType.STRING);
        if (worldName == null || worldName.equals("__pending_anvil__")) {
            List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
            lore.removeIf(line -> line != null && line.startsWith(SWORD_RETURN_POINT_LINE_PREFIX));
            lore.add(SWORD_RETURN_POINT_LINE_PREFIX + "§7等待铁砧坐标写入，§f仅触发一次");
            meta.setLore(lore);
            return;
        }
        World world = Bukkit.getWorld(worldName);
        Double x = meta.getPersistentDataContainer().get(swordReturnXKey, PersistentDataType.DOUBLE);
        Double y = meta.getPersistentDataContainer().get(swordReturnYKey, PersistentDataType.DOUBLE);
        Double z = meta.getPersistentDataContainer().get(swordReturnZKey, PersistentDataType.DOUBLE);
        if (world == null || x == null || y == null || z == null) {
            return;
        }
        Float yaw = meta.getPersistentDataContainer().get(swordReturnYawKey, PersistentDataType.FLOAT);
        Float pitch = meta.getPersistentDataContainer().get(swordReturnPitchKey, PersistentDataType.FLOAT);
        refreshSwordReturnLore(meta, new Location(world, x, y, z, yaw == null ? 0.0F : yaw, pitch == null ? 0.0F : pitch));
    }

    private void refreshMaterialSwordLoreAndAttributes(ItemStack item, ItemMeta meta) {
        double speedBonus = meta.getPersistentDataContainer().getOrDefault(materialSwordSpeedBonusKey, PersistentDataType.DOUBLE, 0.0D);
        double damagePenalty = meta.getPersistentDataContainer().getOrDefault(materialSwordDamagePenaltyKey, PersistentDataType.DOUBLE, 0.0D);
        applyMaterialSwordAttributeModifiers(meta, item.getType(), speedBonus, damagePenalty);
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line != null && (line.startsWith(SWORD_MATERIAL_PREFIX) || line.startsWith(SWORD_MATERIAL_DAMAGE_LINE_PREFIX)));
        lore.add(SWORD_MATERIAL_PREFIX + " §f攻击速度 +" + formatPercent(speedBonus) + "§8 / §f伤害 -" + formatPercent(damagePenalty));
        lore.add(SWORD_MATERIAL_DAMAGE_LINE_PREFIX + "§f" + formatPercent(damagePenalty));
        meta.setLore(lore);
    }

    private void refreshMaterialAxeLoreAndAttributes(ItemStack item, ItemMeta meta) {
        double damageBonus = meta.getPersistentDataContainer().getOrDefault(materialAxeDamageBonusKey, PersistentDataType.DOUBLE, 0.0D);
        double cooldownIncrease = meta.getPersistentDataContainer().getOrDefault(materialAxeCooldownIncreaseKey, PersistentDataType.DOUBLE, 0.0D);
        applyMaterialAxeAttackSpeedModifier(meta, item.getType(), damageBonus, cooldownIncrease);
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line != null && (line.startsWith(AXE_MATERIAL_PREFIX) || line.startsWith(MATERIAL_AXE_SPEED_LINE_PREFIX)));
        lore.add(AXE_MATERIAL_PREFIX + " §f伤害 +" + formatPercent(damageBonus) + "§8 / §f额外冷却 +" + formatPercent(cooldownIncrease));
        lore.add(MATERIAL_AXE_SPEED_LINE_PREFIX + "§f" + formatPercent(cooldownIncrease));
        meta.setLore(lore);
    }

    private void refreshRedstoneStabilizerLore(ItemMeta meta) {
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(REDSTONE_STABILIZER_LINE::equals);
        lore.add(REDSTONE_STABILIZER_LINE);
        meta.setLore(lore);
    }

    private void refreshMaterialArmorLore(ItemStack item, ItemMeta meta) {
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line != null && line.startsWith(ARMOR_MATERIAL_LINE_PREFIX));
        lore.add(ARMOR_MATERIAL_LINE_PREFIX + "§f斧增伤抵消 +" + formatPercent(getMaterialArmorAxeBonusReduction(item))
                + "§8 / §f通用免伤 +" + formatPercent(MATERIAL_ARMOR_GENERAL_DAMAGE_REDUCTION_PER_PIECE));
        meta.setLore(lore);
    }

    private void refreshBootSilentLore(ItemStack item, ItemMeta meta) {
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line != null && (line.contains("已打上羊毛缓冲层")
                || line.contains("已打上羽毛缓冲层")
                || line.contains("轻步完成：")));
        boolean wool = hasPersistentByte(item, bootWoolLayerKey);
        boolean feather = hasPersistentByte(item, bootFeatherLayerKey);
        if (wool && feather) {
            lore.add(BOOT_SILENT_READY_LINE);
        } else if (wool) {
            lore.add(BOOT_WOOL_LINE);
        } else if (feather) {
            lore.add(BOOT_FEATHER_LINE);
        }
        meta.setLore(lore);
    }

    private void refreshCondensedSlimeBootLore(ItemMeta meta, double bonus) {
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line != null && line.startsWith(CONDENSED_SLIME_BOOT_LINE_PREFIX));
        lore.add(CONDENSED_SLIME_BOOT_LINE_PREFIX + "§f爬行速度 +" + formatPercent(Math.max(0.0D, Math.min(1.0D, bonus))));
        meta.setLore(lore);
    }

    private void refreshCondensedEnderPearlArmorLore(ItemMeta meta) {
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line != null && line.startsWith(CONDENSED_ENDER_PEARL_ARMOR_LINE_PREFIX));
        lore.add(CONDENSED_ENDER_PEARL_ARMOR_LINE);
        meta.setLore(lore);
    }

    private void refreshSingleLoreLine(ItemMeta meta, String line) {
        if (meta == null || line == null) {
            return;
        }
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line::equals);
        lore.add(line);
        meta.setLore(lore);
    }

    private int getStormSwordLevelFromMeta(ItemMeta meta) {
        if (meta == null) {
            return 0;
        }
        Integer level = meta.getPersistentDataContainer().get(stormSwordLevelKey, PersistentDataType.INTEGER);
        return level == null ? 0 : Math.max(0, Math.min(3, level));
    }

    private void refreshStormSwordLore(ItemMeta meta, int level, boolean kinetic) {
        if (meta == null || level <= 0) {
            return;
        }
        applyStormSwordEnchantment(meta, level);
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line != null && (line.startsWith(STORM_SWORD_LINE_PREFIX) || line.equals(STORM_SWORD_KINETIC_LINE)));
        lore.add(STORM_SWORD_LINE_PREFIX + " " + toRoman(level) + "：§7风弹脉冲已接入剑身");
        if (kinetic) {
            lore.add(STORM_SWORD_KINETIC_LINE);
        }
        meta.setLore(lore);
    }

    private boolean isSameStack(ItemStack first, ItemStack second) {
        if (first == null || first.getType() == Material.AIR) {
            return second == null || second.getType() == Material.AIR;
        }
        return first.equals(second);
    }

    private void applyFlashSpecialFoodEffect(Player player, FlashSpecialFoodProfile profile) {
        if (player == null || profile == null) {
            return;
        }
        for (FoodPotionEffect effect : profile.effects()) {
            player.addPotionEffect(new PotionEffect(effect.type(), effect.durationTicks(), effect.amplifier(), false, true, true));
        }
        if (profile.cleanse()) {
            removeFlashFoodNegativeEffects(player);
        }
        if (profile.extinguish()) {
            player.setFireTicks(0);
        }
        if (profile.fireTicks() > 0) {
            player.setFireTicks(Math.max(player.getFireTicks(), profile.fireTicks()));
        }
        if (profile.heal() > 0.0D) {
            AttributeInstance maxHealth = player.getAttribute(Attribute.MAX_HEALTH);
            double max = maxHealth == null ? 20.0D : maxHealth.getValue();
            player.setHealth(Math.min(max, player.getHealth() + profile.heal()));
        }
        if (profile.currentDamageRate() > 0.0D) {
            player.setHealth(Math.max(1.0D, player.getHealth() * (1.0D - profile.currentDamageRate())));
        }
        if (profile.velocityY() > 0.0D) {
            Vector velocity = player.getVelocity();
            velocity.setY(Math.max(velocity.getY(), profile.velocityY()));
            player.setVelocity(velocity);
            player.setFallDistance(0.0F);
        }
        player.setFoodLevel(Math.min(20, player.getFoodLevel() + Math.max(1, profile.nutrition())));
        player.setSaturation(Math.min(20.0F, player.getSaturation() + Math.max(0.1F, profile.saturation())));
        Location center = player.getLocation().add(0.0D, 1.0D, 0.0D);
        player.getWorld().spawnParticle(profile.particle(), center, 28, 0.32D, 0.34D, 0.32D, 0.045D);
        if (profile.lightning()) {
            player.getWorld().strikeLightningEffect(player.getLocation());
        }
        player.playSound(player.getLocation(), profile.sound(), 0.72f, profile.pitch());
        player.playSound(player.getLocation(), Sound.BLOCK_AMETHYST_BLOCK_CHIME, 0.32f, Math.min(2.0f, profile.pitch() + 0.28f));
        player.sendActionBar("§x§B§B§8§8§F§F✦ §f吃下了 " + profile.name() + " §8| §7编号 §f" + profile.id() + "§7/§f" + FLASH_SPECIAL_FOOD_MAX_ID);
    }

    private void removeFlashFoodNegativeEffects(Player player) {
        player.removePotionEffect(PotionEffectType.POISON);
        player.removePotionEffect(PotionEffectType.WITHER);
        player.removePotionEffect(PotionEffectType.SLOWNESS);
        player.removePotionEffect(PotionEffectType.WEAKNESS);
        player.removePotionEffect(PotionEffectType.HUNGER);
        player.removePotionEffect(PotionEffectType.BLINDNESS);
        player.removePotionEffect(PotionEffectType.DARKNESS);
        player.removePotionEffect(PotionEffectType.MINING_FATIGUE);
        player.removePotionEffect(PotionEffectType.NAUSEA);
        player.removePotionEffect(PotionEffectType.UNLUCK);
    }

