    public boolean isUpgradeBook(ItemStack item) {
        if (item == null || item.getType() != Material.ENCHANTED_BOOK) {
            return false;
        }
        if (!(item.getItemMeta() instanceof EnchantmentStorageMeta meta)) {
            return false;
        }

        Byte legacyFlag = meta.getPersistentDataContainer().get(upgradeBookKey, PersistentDataType.BYTE);
        if (legacyFlag != null && legacyFlag == (byte) 1) {
            return true;
        }

        Enchantment upgradeEnchantment = getUpgradeEnchantment();
        return upgradeEnchantment != null && meta.hasStoredEnchant(upgradeEnchantment);
    }

    public boolean isUpgradeApplied(ItemStack item) {
        if (item == null || item.getType() == Material.AIR || !item.hasItemMeta()) {
            return false;
        }

        Enchantment upgradeEnchantment = getUpgradeEnchantment();
        if (upgradeEnchantment != null && item.getEnchantmentLevel(upgradeEnchantment) > 0) {
            return true;
        }

        Byte legacyFlag = item.getItemMeta().getPersistentDataContainer().get(upgradedItemKey, PersistentDataType.BYTE);
        return legacyFlag != null && legacyFlag == (byte) 1;
    }

    public boolean handleInvisibleItemFrameInfusion(InventoryClickEvent event) {
        if (event == null || !(event.getWhoClicked() instanceof Player player) || !event.isRightClick()) {
            return false;
        }
        ItemStack current = event.getCurrentItem();
        ItemStack cursor = event.getCursor();
        boolean cursorPotion = isEightMinuteInvisibilityPotion(cursor);
        boolean currentPotion = isEightMinuteInvisibilityPotion(current);
        boolean currentFrame = isPlainItemFrame(current);
        boolean cursorFrame = isPlainItemFrame(cursor);

        if (cursorPotion && currentFrame) {
            ItemStack result = createInvisibleItemFrame(current);
            if (result == null) {
                return false;
            }
            event.setCancelled(true);
            if (current.getAmount() <= 1) {
                event.setCurrentItem(result);
                consumeOneCursorPotion(event, cursor);
            } else {
                ItemStack rest = current.clone();
                rest.setAmount(current.getAmount() - 1);
                event.setCurrentItem(rest);
                event.setCursor(result);
            }
            playInvisibleItemFrameInfusionSound(player);
            return true;
        }

        if (currentPotion && cursorFrame) {
            ItemStack result = createInvisibleItemFrame(cursor);
            if (result == null) {
                return false;
            }
            event.setCancelled(true);
            event.setCurrentItem(result);
            if (cursor.getAmount() <= 1) {
                event.setCursor(null);
            } else {
                ItemStack rest = cursor.clone();
                rest.setAmount(cursor.getAmount() - 1);
                event.setCursor(rest);
            }
            playInvisibleItemFrameInfusionSound(player);
            return true;
        }
        return false;
    }

    private void consumeOneCursorPotion(InventoryClickEvent event, ItemStack cursor) {
        if (cursor == null || event == null) {
            return;
        }
        if (cursor.getAmount() <= 1) {
            event.setCursor(null);
            return;
        }
        ItemStack rest = cursor.clone();
        rest.setAmount(cursor.getAmount() - 1);
        event.setCursor(rest);
    }

    private boolean isPlainItemFrame(ItemStack item) {
        if (item == null || (item.getType() != Material.ITEM_FRAME && item.getType() != Material.GLOW_ITEM_FRAME)) {
            return false;
        }
        return !isInvisibleItemFrame(item);
    }

    private boolean isInvisibleItemFrame(ItemStack item) {
        if (item == null || (item.getType() != Material.ITEM_FRAME && item.getType() != Material.GLOW_ITEM_FRAME) || !item.hasItemMeta()) {
            return false;
        }
        ItemMeta meta = item.getItemMeta();
        return meta.getPersistentDataContainer().has(invisibleItemFrameKey, PersistentDataType.BYTE);
    }

    private ItemStack createInvisibleItemFrame(ItemStack base) {
        if (base == null || (base.getType() != Material.ITEM_FRAME && base.getType() != Material.GLOW_ITEM_FRAME)) {
            return null;
        }
        ItemStack result = base.clone();
        result.setAmount(1);
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return null;
        }
        meta.getPersistentDataContainer().set(invisibleItemFrameKey, PersistentDataType.BYTE, (byte) 1);
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line != null && line.replace("§f", "").replace("§7", "").replace("§8", "").contains("隐身"));
        lore.add("§8- §f隐身");
        meta.setLore(lore);
        meta.addEnchant(Enchantment.UNBREAKING, 1, true);
        meta.addItemFlags(org.bukkit.inventory.ItemFlag.HIDE_ENCHANTS);
        result.setItemMeta(meta);
        return result;
    }

    private boolean isEightMinuteInvisibilityPotion(ItemStack item) {
        if (item == null || item.getType() != Material.POTION || !(item.getItemMeta() instanceof PotionMeta meta)) {
            return false;
        }
        if (meta.getBasePotionType() == PotionType.LONG_INVISIBILITY) {
            return true;
        }
        for (PotionEffect effect : meta.getCustomEffects()) {
            if (effect.getType().equals(PotionEffectType.INVISIBILITY) && effect.getDuration() >= 20 * 60 * 8 - 20) {
                return true;
            }
        }
        return false;
    }

    private void playInvisibleItemFrameInfusionSound(Player player) {
        if (player == null) {
            return;
        }
        Location location = player.getLocation();
        player.playSound(location, Sound.BLOCK_ENCHANTMENT_TABLE_USE, 0.72f, 1.42f);
        player.playSound(location, Sound.BLOCK_AMETHYST_BLOCK_CHIME, 0.46f, 1.72f);
        player.playSound(location, Sound.ENTITY_ILLUSIONER_PREPARE_MIRROR, 0.28f, 1.36f);
    }

    public void handleInvisibleItemFramePlace(HangingPlaceEvent event) {
        if (event == null || !(event.getEntity() instanceof ItemFrame frame) || !isInvisibleItemFrame(event.getItemStack())) {
            return;
        }
        frame.getPersistentDataContainer().set(invisibleItemFrameKey, PersistentDataType.BYTE, (byte) 1);
        Bukkit.getScheduler().runTask(plugin, () -> {
            if (!frame.isValid()) {
                return;
            }
            frame.setVisible(false);
            frame.setFixed(false);
            frame.setItemDropChance(1.0F);
        });
    }

    public void prepareAnvilResult(PrepareAnvilEvent event) {
        ItemStack first = event.getInventory().getFirstItem();
        ItemStack second = event.getInventory().getSecondItem();
        ItemStack result = createFlashAnvilResult(first, second);

        if (result != null) {
            event.getInventory().setRepairCost(1);
            event.setResult(result);
        }
    }

    public void handleFlashCraftPrepare(PrepareItemCraftEvent event) {
        if (!(event.getView().getPlayer() instanceof Player player)) {
            return;
        }

        ItemStack[] matrix = event.getInventory().getMatrix();
        ItemStack matrixSpecialResult = createFlashSpecialCraftResult(matrix);
        if (isTmtRecipeMatrix(matrix) && getRemainingTmtCrafts(player) <= 0) {
            event.getInventory().setResult(null);
            player.sendActionBar("§x§F§F§5§5§3§3✦ §cTMT §7合成次数已用完 §8| §f" + getTmtCraftLimitText(player));
            return;
        }
        boolean flashSpecialMatrix = !isEmpty(matrixSpecialResult);
        boolean pluginRecipe = false;
        if (event.getRecipe() instanceof org.bukkit.Keyed keyed) {
            NamespacedKey key = keyed.getKey();
            pluginRecipe = featherQuillRecipeKey.equals(key) || magicBrushRecipeKey.equals(key)
                    || condensedSlimeRecipeKey.equals(key) || condensedEnderPearlRecipeKey.equals(key)
                    || pseudoPoisonPotatoRecipeKey.equals(key) || tmtRecipeKey.equals(key)
                    || flashFishingBaitRecipeKey.equals(key);
            if (pluginRecipe) {
                if (isEmpty(matrixSpecialResult)) {
                    event.getInventory().setResult(null);
                    return;
                }
                event.getInventory().setResult(matrixSpecialResult);
            }
        }
        if (!pluginRecipe && flashSpecialMatrix) {
            event.getInventory().setResult(matrixSpecialResult);
        }
        if (!pluginRecipe && !flashSpecialMatrix && containsFlashRecipeLockedItem(matrix)) {
            event.getInventory().setResult(null);
            return;
        }

        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        if (!isFlashCombatAvailable(player, room)) {
            return;
        }

        plugin.getRoomManager().ensurePlayerRecipesAvailable(player);

        if (pluginRecipe || flashSpecialMatrix) {
            if (isEmpty(matrixSpecialResult)) {
                event.getInventory().setResult(null);
                return;
            }
            event.getInventory().setResult(matrixSpecialResult);
            return;
        }

        ItemStack baseResult = createFlashSpecialCraftResult(matrix);
        if (isEmpty(baseResult)) {
            baseResult = event.getInventory().getResult();
        }
        if (isEmpty(baseResult) && event.getRecipe() != null) {
            baseResult = event.getRecipe().getResult();
        }
        if (isEmpty(baseResult)) {
            return;
        }

        if (shouldDoubleFlashCraft(player, baseResult, matrix, false)) {
            event.getInventory().setResult(createDoubledCraftResult(baseResult));
        } else {
            event.getInventory().setResult(baseResult.clone());
        }
    }

    private ItemStack createFlashSpecialCraftResult(ItemStack[] matrix) {
        if (isFeatherQuillRecipeMatrix(matrix)) {
            return createFeatherQuill();
        }
        if (isBrushRecipeMatrix(matrix)) {
            return createBrush();
        }
        if (isCondensedSlimeRecipeMatrix(matrix)) {
            return createCondensedSlimeBlock();
        }
        if (isCondensedEnderPearlRecipeMatrix(matrix)) {
            return createCondensedEnderPearl();
        }
        if (isPseudoPoisonPotatoRecipeMatrix(matrix)) {
            return createPseudoPoisonPotato();
        }
        if (isTmtRecipeMatrix(matrix)) {
            return createTmt();
        }
        if (isFlashFishingBaitRecipeMatrix(matrix)) {
            return createFlashFishingBait();
        }
        return null;
    }

    private boolean containsFlashRecipeLockedItem(ItemStack[] matrix) {
        if (matrix == null) {
            return false;
        }
        for (ItemStack item : matrix) {
            if (!isEmpty(item) && isFlashRecipeLockedItem(item)) {
                return true;
            }
        }
        return false;
    }

    private boolean isFlashRecipeLockedItem(ItemStack item) {
        return isFeatherQuill(item) || isBrushItem(item) || isCondensedSlimeBlock(item)
                || isCondensedEnderPearl(item) || isPseudoPoisonPotato(item) || isFlashSpecialFood(item)
                || isTmt(item) || isFlashFishingBait(item) || isFlashFishingCatch(item)
                || isEnhancedWindCharge(item);
    }

    private boolean isFeatherQuillRecipeMatrix(ItemStack[] matrix) {
        int paper = 0;
        int string = 0;
        int other = 0;
        for (ItemStack item : matrix) {
            if (isEmpty(item)) {
                continue;
            }
            if (item.getType() == Material.PAPER && !isFeatherQuill(item) && !isBrushItem(item)) {
                paper++;
            } else if (item.getType() == Material.STRING) {
                string++;
            } else {
                other++;
            }
        }
        return paper == 1 && string == 3 && other == 0;
    }

    private boolean isBrushRecipeMatrix(ItemStack[] matrix) {
        int quill = 0;
        int stick = 0;
        int other = 0;
        for (ItemStack item : matrix) {
            if (isEmpty(item)) {
                continue;
            }
            if (isFeatherQuill(item)) {
                quill++;
            } else if (item.getType() == Material.STICK) {
                stick++;
            } else {
                other++;
            }
        }
        return quill == 1 && stick == 1 && other == 0;
    }

    private boolean isCondensedSlimeRecipeMatrix(ItemStack[] matrix) {
        int slimeBlocks = 0;
        int other = 0;
        for (ItemStack item : matrix) {
            if (isEmpty(item)) {
                continue;
            }
            if (item.getType() == Material.SLIME_BLOCK && !isCondensedSlimeBlock(item)) {
                slimeBlocks++;
            } else {
                other++;
            }
        }
        return slimeBlocks == 4 && other == 0;
    }

    private boolean isCondensedEnderPearlRecipeMatrix(ItemStack[] matrix) {
        int pearls = 0;
        int other = 0;
        for (ItemStack item : matrix) {
            if (isEmpty(item)) {
                continue;
            }
            if (item.getType() == Material.ENDER_PEARL) {
                pearls++;
            } else {
                other++;
            }
        }
        return pearls == 9 && other == 0;
    }

    private boolean isPseudoPoisonPotatoRecipeMatrix(ItemStack[] matrix) {
        int potatoes = 0;
        int kelp = 0;
        int other = 0;
        for (ItemStack item : matrix) {
            if (isEmpty(item)) {
                continue;
            }
            if (item.getType() == Material.POTATO && !isPseudoPoisonPotato(item) && !isFlashSpecialFood(item)) {
                potatoes++;
            } else if (item.getType() == Material.KELP) {
                kelp++;
            } else {
                other++;
            }
        }
        return potatoes == 1 && kelp == 1 && other == 0;
    }

    private boolean isTmtRecipeMatrix(ItemStack[] matrix) {
        int tnt = 0;
        int other = 0;
        for (ItemStack item : matrix) {
            if (isEmpty(item)) {
                continue;
            }
            if (item.getType() == Material.TNT && !isTmt(item)) {
                tnt++;
            } else {
                other++;
            }
        }
        return tnt == 4 && other == 0;
    }

    private int getRemainingTmtCrafts(Player player) {
        if (player == null) {
            return 0;
        }
        long now = System.currentTimeMillis();
        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        if (room != null) {
            int used = getTmtCraftCountInRoom(player, room.getRoomId());
            return Math.max(0, TMT_DAILY_CRAFT_LIMIT - used);
        }
        int used = getTmtCraftCountInWindow(player, now);
        return Math.max(0, TMT_DAILY_CRAFT_LIMIT - used);
    }

    private int getTmtCraftCountInRoom(Player player, String roomId) {
        org.bukkit.persistence.PersistentDataContainer data = player.getPersistentDataContainer();
        String storedRoomId = data.get(tmtCraftRoomIdKey, PersistentDataType.STRING);
        Integer count = data.get(tmtCraftRoomCountKey, PersistentDataType.INTEGER);
        if (roomId == null || roomId.isBlank() || !roomId.equals(storedRoomId)) {
            data.set(tmtCraftRoomIdKey, PersistentDataType.STRING, roomId == null ? "" : roomId);
            data.set(tmtCraftRoomCountKey, PersistentDataType.INTEGER, 0);
            return 0;
        }
        return Math.max(0, count == null ? 0 : count);
    }

    private int getTmtCraftCountInWindow(Player player, long now) {
        org.bukkit.persistence.PersistentDataContainer data = player.getPersistentDataContainer();
        Long windowStart = data.get(tmtCraftWindowStartKey, PersistentDataType.LONG);
        Integer count = data.get(tmtCraftCountKey, PersistentDataType.INTEGER);
        if (windowStart == null || windowStart <= 0L || now < windowStart || now - windowStart >= TMT_CRAFT_WINDOW_MILLIS) {
            data.set(tmtCraftWindowStartKey, PersistentDataType.LONG, now);
            data.set(tmtCraftCountKey, PersistentDataType.INTEGER, 0);
            return 0;
        }
        return Math.max(0, count == null ? 0 : count);
    }

    private void rememberTmtCrafts(Player player, int amount) {
        if (player == null || amount <= 0) {
            return;
        }
        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        if (room != null) {
            int used = getTmtCraftCountInRoom(player, room.getRoomId());
            player.getPersistentDataContainer().set(tmtCraftRoomCountKey, PersistentDataType.INTEGER,
                    Math.min(TMT_DAILY_CRAFT_LIMIT, used + amount));
            return;
        }
        long now = System.currentTimeMillis();
        int used = getTmtCraftCountInWindow(player, now);
        player.getPersistentDataContainer().set(tmtCraftCountKey, PersistentDataType.INTEGER,
                Math.min(TMT_DAILY_CRAFT_LIMIT, used + amount));
    }

    private String getTmtCraftLimitText(Player player) {
        GameRoom room = player == null ? null : plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        return room == null ? "24小时最多" + TMT_DAILY_CRAFT_LIMIT + "个" : "本局最多" + TMT_DAILY_CRAFT_LIMIT + "个";
    }

    private boolean isFlashFishingBaitRecipeMatrix(ItemStack[] matrix) {
        int kelp = 0;
        int fish = 0;
        int other = 0;
        for (ItemStack item : matrix) {
            if (isEmpty(item)) {
                continue;
            }
            if (item.getType() == Material.KELP && !isFlashFishingBait(item)) {
                kelp++;
            } else if (isRawFishingBaitFish(item.getType())) {
                fish++;
            } else {
                other++;
            }
        }
        return kelp == 1 && fish == 1 && other == 0;
    }

    private boolean isRawFishingBaitFish(Material material) {
        return material == Material.COD
                || material == Material.SALMON
                || material == Material.TROPICAL_FISH
                || material == Material.PUFFERFISH;
    }

    public void handleFlashCraftTake(CraftItemEvent event) {
        if (!(event.getWhoClicked() instanceof Player player)) {
            return;
        }
        if (event.isCancelled()) {
            return;
        }

        ItemStack[] earlyMatrix = event.getInventory().getMatrix();
        if (isTmtRecipeMatrix(earlyMatrix)) {
            handleTmtCraftTake(event, player, earlyMatrix, createTmt());
            return;
        }

        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        if (!isFlashCombatAvailable(player, room)) {
            return;
        }

        ItemStack[] matrix = event.getInventory().getMatrix();
        ItemStack specialResult = createFlashSpecialCraftResult(matrix);
        ItemStack result = event.getCurrentItem();
        ItemStack recipeBaseResult = specialResult;
        if (isEmpty(recipeBaseResult) && event.getRecipe() != null) {
            recipeBaseResult = event.getRecipe().getResult();
        }
        if (isEmpty(result)) {
            result = recipeBaseResult;
        }
        if (isEmpty(recipeBaseResult)) {
            return;
        }
        if (isTmt(recipeBaseResult)) {
            handleTmtCraftTake(event, player, matrix, recipeBaseResult);
            return;
        }
        if (!isEmpty(result) && result.getMaxStackSize() > 1) {
            if (event.isShiftClick()) {
                handleShiftFlashCraftTake(event, player, recipeBaseResult, matrix);
                return;
            }
            if (shouldDoubleFlashCraft(player, recipeBaseResult, matrix, false)) {
                ItemStack expected = createDoubledCraftResult(recipeBaseResult);
                if (result.getAmount() < expected.getAmount()) {
                    ItemStack fixed = result.clone();
                    fixed.setAmount(Math.min(fixed.getMaxStackSize(), expected.getAmount()));
                    event.setCurrentItem(fixed);
                    event.getInventory().setResult(fixed.clone());
                }
                rememberLimitedDoubleCraftUse(player, recipeBaseResult, matrix, false);
            } else {
                ItemStack fixed = recipeBaseResult.clone();
                event.setCurrentItem(fixed);
                event.getInventory().setResult(fixed.clone());
            }
            return;
        }
        // 闪光模式的配方双倍只处理可堆叠物品。
        // 羽笔、画笔、魔法画笔这类 max_stack_size=1 的特殊物品不额外复制，避免重新变成可堆叠。
    }

    private void handleTmtCraftTake(CraftItemEvent event, Player player, ItemStack[] matrix, ItemStack recipeBaseResult) {
        int remaining = getRemainingTmtCrafts(player);
        if (remaining <= 0) {
            event.setCancelled(true);
            event.getInventory().setResult(null);
            player.playSound(player.getLocation(), Sound.ENTITY_VILLAGER_NO, 0.72f, 0.72f);
            player.sendActionBar("§x§F§F§5§5§3§3✦ §cTMT §7合成次数已用完 §8| §f" + getTmtCraftLimitText(player));
            return;
        }
        ItemStack oneCraft = recipeBaseResult.clone();
        oneCraft.setAmount(1);
        if (!event.isShiftClick()) {
            event.setCurrentItem(oneCraft);
            event.getInventory().setResult(oneCraft.clone());
            rememberTmtCrafts(player, 1);
            player.sendActionBar("§x§F§F§5§5§3§3✦ §cTMT §7已合成 §f1§7 个 §8| §7今日剩余 §f" + getRemainingTmtCrafts(player));
            return;
        }

        int craftableByMatrix = getCraftableTimesByMatrix(matrix);
        int craftCount = Math.min(craftableByMatrix, remaining);
        int availableSpace = getInventorySpaceFor(player.getInventory(), oneCraft);
        craftCount = Math.min(craftCount, availableSpace);
        if (craftCount <= 0) {
            event.setCancelled(true);
            player.playSound(player.getLocation(), Sound.ENTITY_VILLAGER_NO, 0.72f, 0.86f);
            player.sendActionBar("§x§F§F§5§5§3§3✦ §cTMT §7背包空间不足或次数不足");
            return;
        }
        event.setCancelled(true);
        ItemStack[] consumedMatrix = event.getInventory().getMatrix();
        consumeCraftMatrix(consumedMatrix, craftCount);
        event.getInventory().setMatrix(consumedMatrix);
        event.getInventory().setResult(getRemainingTmtCrafts(player) - craftCount > 0 ? oneCraft.clone() : null);
        giveStackedCraftResult(player, oneCraft, craftCount);
        rememberTmtCrafts(player, craftCount);
        player.sendActionBar("§x§F§F§5§5§3§3✦ §cTMT §7已合成 §f" + craftCount + "§7 个 §8| §7今日剩余 §f" + getRemainingTmtCrafts(player));
        Bukkit.getScheduler().runTask(plugin, player::updateInventory);
    }

    private ItemStack createDoubledCraftResult(ItemStack baseResult) {
        ItemStack doubled = baseResult.clone();
        int baseAmount = Math.max(1, doubled.getAmount());
        int doubledAmount = Math.min(doubled.getMaxStackSize(), baseAmount * 2);
        doubled.setAmount(Math.max(baseAmount, doubledAmount));
        return doubled;
    }

    private void handleShiftFlashCraftTake(CraftItemEvent event, Player player, ItemStack baseResult, ItemStack[] matrix) {
        if (isEmpty(baseResult) || baseResult.getMaxStackSize() <= 1 || matrix == null) {
            return;
        }
        if (isFlashDoubleCraftBlocked(player, baseResult, matrix)) {
            return;
        }

        int craftableByMatrix = getCraftableTimesByMatrix(matrix);
        if (craftableByMatrix <= 0) {
            return;
        }

        ItemStack oneCraft = baseResult.clone();
        oneCraft.setAmount(Math.max(1, oneCraft.getAmount()));
        ItemStack doubledCraft = createDoubledCraftResult(baseResult);
        int baseAmount = oneCraft.getAmount();
        int doubledAmount = Math.max(baseAmount, doubledCraft.getAmount());
        int extraAmount = Math.max(0, doubledAmount - baseAmount);
        String limitedKey = getFlashDoubleCraftLimitedKey(player, baseResult, matrix);
        int limit = getFlashDoubleCraftLimit(limitedKey);
        int remainingDoubleUses = limitedKey == null ? craftableByMatrix : Math.max(0, limit
                - recyclableDoubleCraftCounts.getOrDefault(player.getUniqueId(), Map.of()).getOrDefault(limitedKey, 0));

        int availableSpace = getInventorySpaceFor(player.getInventory(), oneCraft);
        if (availableSpace < baseAmount) {
            event.setCancelled(true);
            player.playSound(player.getLocation(), Sound.ENTITY_VILLAGER_NO, 0.72f, 0.86f);
            return;
        }

        int craftCount = 0;
        int doubleCraftCount = 0;
        int outputAmount = 0;
        for (int i = 0; i < craftableByMatrix; i++) {
            boolean doubled = doubleCraftCount < remainingDoubleUses;
            int nextAmount = baseAmount + (doubled ? extraAmount : 0);
            if (nextAmount <= 0 || outputAmount + nextAmount > availableSpace) {
                break;
            }
            outputAmount += nextAmount;
            craftCount++;
            if (doubled) {
                doubleCraftCount++;
            }
        }

        if (craftCount <= 0 || outputAmount <= 0) {
            event.setCancelled(true);
            player.playSound(player.getLocation(), Sound.ENTITY_VILLAGER_NO, 0.72f, 0.86f);
            return;
        }

        event.setCancelled(true);
        ItemStack[] consumedMatrix = event.getInventory().getMatrix();
        consumeCraftMatrix(consumedMatrix, craftCount);
        event.getInventory().setMatrix(consumedMatrix);
        event.getInventory().setResult(null);
        giveStackedCraftResult(player, oneCraft, outputAmount);
        rememberLimitedDoubleCraftUses(player, limitedKey, doubleCraftCount);
        Bukkit.getScheduler().runTask(plugin, player::updateInventory);
    }

    private int getCraftableTimesByMatrix(ItemStack[] matrix) {
        int craftableByMatrix = Integer.MAX_VALUE;
        for (ItemStack item : matrix) {
            if (isEmpty(item)) {
                continue;
            }
            craftableByMatrix = Math.min(craftableByMatrix, item.getAmount());
        }
        return craftableByMatrix == Integer.MAX_VALUE ? 0 : craftableByMatrix;
    }

    private int getInventorySpaceFor(PlayerInventory inventory, ItemStack result) {
        int space = 0;
        int max = Math.max(1, result.getMaxStackSize());
        for (ItemStack item : inventory.getStorageContents()) {
            if (isEmpty(item)) {
                space += max;
            } else if (item.isSimilar(result) && item.getAmount() < max) {
                space += max - item.getAmount();
            }
        }
        return space;
    }

    private void consumeCraftMatrix(ItemStack[] matrix, int craftCount) {
        for (int i = 0; i < matrix.length; i++) {
            ItemStack item = matrix[i];
            if (isEmpty(item)) {
                continue;
            }
            int nextAmount = item.getAmount() - craftCount;
            if (nextAmount <= 0) {
                matrix[i] = null;
            } else {
                item.setAmount(nextAmount);
                matrix[i] = item;
            }
        }
    }

    private void giveStackedCraftResult(Player player, ItemStack template, int totalAmount) {
        int max = Math.max(1, template.getMaxStackSize());
        int remaining = totalAmount;
        while (remaining > 0) {
            ItemStack stack = template.clone();
            int amount = Math.min(max, remaining);
            stack.setAmount(amount);
            Map<Integer, ItemStack> leftovers = player.getInventory().addItem(stack);
            for (ItemStack leftover : leftovers.values()) {
                if (!isEmpty(leftover)) {
                    player.getWorld().dropItemNaturally(player.getLocation(), leftover);
                }
            }
            remaining -= amount;
        }
        player.playSound(player.getLocation(), Sound.ENTITY_ITEM_PICKUP, 0.42f, 1.38f);
    }

    private boolean shouldDoubleFlashCraft(Player player, ItemStack baseResult, ItemStack[] matrix, boolean shiftClick) {
        if (player == null || isEmpty(baseResult) || baseResult.getMaxStackSize() <= 1) {
            return false;
        }
        if (shiftClick) {
            return false;
        }
        if (isFlashDoubleCraftBlocked(player, baseResult, matrix)) {
            return false;
        }
        String limitedKey = getFlashDoubleCraftLimitedKey(player, baseResult, matrix);
        if (limitedKey == null) {
            return true;
        }
        int used = recyclableDoubleCraftCounts
                .getOrDefault(player.getUniqueId(), Map.of())
                .getOrDefault(limitedKey, 0);
        return used < getFlashDoubleCraftLimit(limitedKey);
    }

    private void rememberLimitedDoubleCraftUse(Player player, ItemStack baseResult, ItemStack[] matrix, boolean forceLimit) {
        if (player == null || isEmpty(baseResult)) {
            return;
        }
        String limitedKey = getFlashDoubleCraftLimitedKey(player, baseResult, matrix);
        if (limitedKey == null) {
            return;
        }
        rememberLimitedDoubleCraftUses(player, limitedKey, forceLimit ? getFlashDoubleCraftLimit(limitedKey) : 1);
    }

    private void rememberLimitedDoubleCraftUses(Player player, String limitedKey, int amount) {
        if (player == null || limitedKey == null || amount <= 0) {
            return;
        }
        Map<String, Integer> counts = recyclableDoubleCraftCounts.computeIfAbsent(player.getUniqueId(), ignored -> new HashMap<>());
        counts.put(limitedKey, Math.min(getFlashDoubleCraftLimit(limitedKey), counts.getOrDefault(limitedKey, 0) + amount));
    }

    private boolean isFlashDoubleCraftBlocked(Player player, ItemStack baseResult, ItemStack[] matrix) {
        if (isEmpty(baseResult)) {
            return true;
        }
        Material type = baseResult.getType();
        if (type == Material.NETHERITE_UPGRADE_SMITHING_TEMPLATE) {
            return true;
        }
        if (type == Material.NETHERITE_BLOCK) {
            return true;
        }
        if (type == Material.NETHERITE_INGOT) {
            return !canPreyDoubleNetheriteIngot(player, matrix);
        }
        return false;
    }

    private String getFlashDoubleCraftLimitedKey(Player player, ItemStack baseResult, ItemStack[] matrix) {
        if (!isEmpty(baseResult) && baseResult.getType() == Material.NETHERITE_INGOT && canPreyDoubleNetheriteIngot(player, matrix)) {
            return "prey_netherite_ingot";
        }
        return getLimitedDoubleCraftKey(baseResult, matrix);
    }

    private int getFlashDoubleCraftLimit(String limitedKey) {
        if ("prey_netherite_ingot".equals(limitedKey)) {
            return FLASH_PREY_NETHERITE_DOUBLE_CRAFT_LIMIT;
        }
        return FLASH_RECYCLABLE_DOUBLE_CRAFT_LIMIT;
    }

    private boolean canPreyDoubleNetheriteIngot(Player player, ItemStack[] matrix) {
        if (player == null || matrix == null) {
            return false;
        }
        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        if (!isFlashMode(room) || !room.isPrey(player.getUniqueId())) {
            return false;
        }
        boolean hasScrap = false;
        for (ItemStack item : matrix) {
            if (isEmpty(item)) {
                continue;
            }
            if (item.getType() == Material.NETHERITE_SCRAP) {
                hasScrap = true;
            }
            if (item.getType() == Material.NETHERITE_INGOT || item.getType() == Material.NETHERITE_BLOCK) {
                return false;
            }
        }
        return hasScrap;
    }

    private String getLimitedDoubleCraftKey(ItemStack baseResult, ItemStack[] matrix) {
        if (isEmpty(baseResult) || matrix == null) {
            return null;
        }
        String resultGroup = getRecyclableCraftGroup(baseResult.getType());
        if (resultGroup == null) {
            return null;
        }
        List<String> ingredientTypes = new ArrayList<>();
        boolean sameGroupConversion = false;
        for (ItemStack item : matrix) {
            if (isEmpty(item)) {
                continue;
            }
            Material type = item.getType();
            ingredientTypes.add(type.name());
            String group = getRecyclableCraftGroup(type);
            if (resultGroup.equals(group) && type != baseResult.getType()) {
                sameGroupConversion = true;
            }
        }
        if (!sameGroupConversion) {
            return null;
        }
        ingredientTypes.sort(String::compareTo);
        return resultGroup + ">" + baseResult.getType().name() + ":" + String.join(",", ingredientTypes);
    }

    private String getRecyclableCraftGroup(Material material) {
        if (material == null) {
            return null;
        }
        return switch (material) {
            case IRON_NUGGET, IRON_INGOT, IRON_BLOCK, RAW_IRON, RAW_IRON_BLOCK -> "iron";
            case GOLD_NUGGET, GOLD_INGOT, GOLD_BLOCK, RAW_GOLD, RAW_GOLD_BLOCK -> "gold";
            case COPPER_INGOT, COPPER_BLOCK, RAW_COPPER, RAW_COPPER_BLOCK -> "copper";
            case NETHERITE_INGOT, NETHERITE_BLOCK -> "netherite";
            case DIAMOND, DIAMOND_BLOCK -> "diamond";
            case EMERALD, EMERALD_BLOCK -> "emerald";
            case COAL, COAL_BLOCK -> "coal";
            case REDSTONE, REDSTONE_BLOCK -> "redstone";
            case LAPIS_LAZULI, LAPIS_BLOCK -> "lapis";
            case QUARTZ, QUARTZ_BLOCK -> "quartz";
            case AMETHYST_SHARD, AMETHYST_BLOCK -> "amethyst";
            case BONE, BONE_MEAL, BONE_BLOCK -> "bone";
            case WHEAT, HAY_BLOCK -> "wheat";
            case DRIED_KELP, DRIED_KELP_BLOCK -> "dried_kelp";
            case SLIME_BALL, SLIME_BLOCK -> "slime";
            case HONEYCOMB, HONEYCOMB_BLOCK -> "honeycomb";
            case CLAY_BALL, CLAY -> "clay";
            case SNOWBALL, SNOW_BLOCK -> "snow";
            default -> null;
        };
    }

    private int estimateFlashUnstackableCraftCopies(CraftItemEvent event, ItemStack result) {
        if (!event.isShiftClick()) {
            return Math.max(1, result.getAmount());
        }

        int craftableByMatrix = Integer.MAX_VALUE;
        for (ItemStack item : event.getInventory().getMatrix()) {
            if (isEmpty(item)) {
                continue;
            }
            craftableByMatrix = Math.min(craftableByMatrix, item.getAmount());
        }
        if (craftableByMatrix == Integer.MAX_VALUE) {
            return 1;
        }

        int freeSlots = 0;
        for (ItemStack item : event.getWhoClicked().getInventory().getStorageContents()) {
            if (isEmpty(item)) {
                freeSlots++;
            }
        }
        if (freeSlots <= 0) {
            return 0;
        }
        return Math.max(0, Math.min(craftableByMatrix, freeSlots));
    }

    public void handleFlashAnvilTakeResult(InventoryClickEvent event) {
        if (!(event.getWhoClicked() instanceof Player player) || !(event.getView().getTopInventory() instanceof AnvilInventory anvil)) {
            return;
        }
        if (event.getRawSlot() != 2) {
            return;
        }

        ItemStack first = anvil.getFirstItem();
        ItemStack second = anvil.getSecondItem();
        ItemStack result = createFlashAnvilResult(first, second);
        if (isEmpty(result)) {
            return;
        }

        boolean unstableMaceForge = isUnstableMaceCoreRecipe(first, second);
        boolean unstableCoreShieldForge = isUnstableCoreShieldRecipe(first, second);
        event.setCancelled(true);
        if (unstableMaceForge && !rollUnstableMaceForgeSuccess(player, anvil, first, second)) {
            consumeAnvilInput(anvil, true);
            consumeAnvilInput(anvil, false);
            anvil.setRepairCost(1);
            anvil.setResult(null);
            explodeFlashAnvil(anvil.getLocation(), player, false);
            player.sendActionBar("§x§F§F§5§5§5§5✖ §c重锤核心失控，§7重锤被铁砧裂爆吞没了");
            Bukkit.getScheduler().runTask(plugin, player::updateInventory);
            return;
        }

        applyAnvilLocationDataIfNeeded(anvil, result);

        result.setAmount(1);
        if (!giveAnvilResult(player, event, result)) {
            player.playSound(player.getLocation(), Sound.BLOCK_NOTE_BLOCK_BASS, 0.65f, 0.78f);
            return;
        }

        consumeAnvilInput(anvil, true);
        consumeAnvilInput(anvil, false);
        anvil.setRepairCost(1);
        anvil.setResult(null);
        if (unstableMaceForge || unstableCoreShieldForge) {
            explodeFlashAnvil(anvil.getLocation(), player, true);
            if (unstableCoreShieldForge) {
                player.sendActionBar("§x§8§8§D§D§F§F✦ §b重锤核心已嵌入盾牌，§7铁砧被核心震碎");
            }
        } else {
            player.playSound(player.getLocation(), Sound.BLOCK_ANVIL_USE, 0.75f, 1.16f);
        }
        Bukkit.getScheduler().runTask(plugin, player::updateInventory);
    }

    public boolean handleFlashInventoryArmorUpgrade(InventoryClickEvent event) {
        if (!(event.getWhoClicked() instanceof Player player) || !event.isRightClick()) {
            return false;
        }
        if (event.getClickedInventory() == null || !event.getClickedInventory().equals(player.getInventory())) {
            return false;
        }
        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        if (!isFlashCombatAvailable(player, room)) {
            return false;
        }

        ItemStack cursor = event.getCursor();
        ItemStack current = event.getCurrentItem();
        if (isEmpty(cursor) || isEmpty(current)) {
            return false;
        }
        if (isCondensedSlimeBlock(cursor) && isBoots(current)) {
            return applyCondensedSlimeToBootsClick(event, player, cursor, current, true);
        }
        if (isCondensedSlimeBlock(current) && isBoots(cursor)) {
            return applyCondensedSlimeToBootsClick(event, player, current, cursor, false);
        }
        if (isCondensedEnderPearl(cursor) && isArmor(current)) {
            return applyCondensedEnderPearlToArmorClick(event, player, cursor, current, true);
        }
        if (isCondensedEnderPearl(current) && isArmor(cursor)) {
            return applyCondensedEnderPearlToArmorClick(event, player, current, cursor, false);
        }
        if (!isArmor(current)) {
            return false;
        }
        Material appleType = cursor.getType();
        if (appleType != Material.GOLDEN_APPLE && appleType != Material.ENCHANTED_GOLDEN_APPLE) {
            return false;
        }

        ItemStack result = tryApplyGoldenAppleToArmor(current, appleType);
        if (result == null) {
            ItemStack normalized = current.clone();
            if (normalizeGoldenAppleArmorHealthModifier(normalized)) {
                event.setCancelled(true);
                event.setCurrentItem(normalized);
                player.playSound(player.getLocation(), Sound.BLOCK_AMETHYST_BLOCK_CHIME, 0.52f, 1.62f);
                Bukkit.getScheduler().runTask(plugin, player::updateInventory);
                return true;
            }
            player.playSound(player.getLocation(), Sound.BLOCK_NOTE_BLOCK_BASS, 0.62f, 0.86f);
            return false;
        }

        event.setCancelled(true);
        event.setCurrentItem(result);
        ItemStack nextCursor = cursor.clone();
        nextCursor.setAmount(cursor.getAmount() - 1);
        player.setItemOnCursor(nextCursor.getAmount() <= 0 ? null : nextCursor);
        player.swingHand(EquipmentSlot.HAND);
        player.playSound(player.getLocation(), appleType == Material.ENCHANTED_GOLDEN_APPLE ? Sound.BLOCK_ENCHANTMENT_TABLE_USE : Sound.ENTITY_PLAYER_LEVELUP, 0.72f, appleType == Material.ENCHANTED_GOLDEN_APPLE ? 1.44f : 1.72f);
        player.playSound(player.getLocation(), Sound.ITEM_ARMOR_EQUIP_GOLD, 0.55f, 1.38f);
        player.getWorld().spawnParticle(appleType == Material.ENCHANTED_GOLDEN_APPLE ? Particle.ENCHANT : Particle.HAPPY_VILLAGER,
                player.getLocation().add(0.0D, 1.0D, 0.0D), 24, 0.26D, 0.32D, 0.26D, 0.04D);
        Bukkit.getScheduler().runTask(plugin, player::updateInventory);
        return true;
    }

    public boolean handleFlashBundleClick(InventoryClickEvent event) {
        if (!(event.getWhoClicked() instanceof Player player) || !event.isRightClick()) {
            return false;
        }
        if (event.getClickedInventory() == null || !event.getClickedInventory().equals(player.getInventory())) {
            return false;
        }
        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        if (!isFlashCombatAvailable(player, room)) {
            return false;
        }

        ItemStack cursor = event.getCursor();
        ItemStack current = event.getCurrentItem();
        if (isBundle(current) && isFlashBundleUnstackableCandidate(cursor)) {
            ItemStack nextBundle = tryAddUnstackableToBundle(current, cursor);
            if (nextBundle == null) {
                player.playSound(player.getLocation(), Sound.ITEM_BUNDLE_INSERT_FAIL, 0.58f, 0.82f);
                return false;
            }
            event.setCancelled(true);
            event.setCurrentItem(nextBundle);
            ItemStack nextCursor = cursor.clone();
            nextCursor.setAmount(cursor.getAmount() - 1);
            player.setItemOnCursor(nextCursor.getAmount() <= 0 ? null : nextCursor);
            playFlashBundleInsert(player);
            Bukkit.getScheduler().runTask(plugin, player::updateInventory);
            return true;
        }

        if (isBundle(cursor) && isFlashBundleUnstackableCandidate(current)) {
            ItemStack nextBundle = tryAddUnstackableToBundle(cursor, current);
            if (nextBundle == null) {
                player.playSound(player.getLocation(), Sound.ITEM_BUNDLE_INSERT_FAIL, 0.58f, 0.82f);
                return false;
            }
            event.setCancelled(true);
            player.setItemOnCursor(nextBundle);
            ItemStack nextCurrent = current.clone();
            nextCurrent.setAmount(current.getAmount() - 1);
            event.setCurrentItem(nextCurrent.getAmount() <= 0 ? null : nextCurrent);
            playFlashBundleInsert(player);
            Bukkit.getScheduler().runTask(plugin, player::updateInventory);
            return true;
        }

        if (isBundle(current) && isEmpty(cursor)) {
            BundleTakeResult result = takeLastItemFromBundle(current);
            if (result == null) {
                return false;
            }
            event.setCancelled(true);
            event.setCurrentItem(result.bundle());
            player.setItemOnCursor(result.item());
            playFlashBundleRemove(player);
            Bukkit.getScheduler().runTask(plugin, player::updateInventory);
            return true;
        }

        if (isBundle(cursor) && isEmpty(current)) {
            BundleTakeResult result = takeLastItemFromBundle(cursor);
            if (result == null) {
                return false;
            }
            event.setCancelled(true);
            player.setItemOnCursor(result.bundle());
            event.setCurrentItem(result.item());
            playFlashBundleRemove(player);
            Bukkit.getScheduler().runTask(plugin, player::updateInventory);
            return true;
        }

        return false;
    }

    private ItemStack tryAddUnstackableToBundle(ItemStack bundle, ItemStack item) {
        if (!isBundle(bundle) || !isFlashBundleUnstackableCandidate(item)) {
            return null;
        }
        ItemStack result = bundle.clone();
        if (!(result.getItemMeta() instanceof BundleMeta meta)) {
            return null;
        }
        List<ItemStack> items = new ArrayList<>(meta.getItems());
        if (countFlashBundleUnstackables(items) >= FLASH_BUNDLE_UNSTACKABLE_LIMIT) {
            return null;
        }
        ItemStack stored = item.clone();
        stored.setAmount(1);
        items.add(stored);
        meta.setItems(items);
        result.setItemMeta(meta);
        return result;
    }

    private BundleTakeResult takeLastItemFromBundle(ItemStack bundle) {
        if (!isBundle(bundle)) {
            return null;
        }
        ItemStack result = bundle.clone();
        if (!(result.getItemMeta() instanceof BundleMeta meta)) {
            return null;
        }
        List<ItemStack> items = new ArrayList<>(meta.getItems());
        if (items.isEmpty()) {
            return null;
        }
        ItemStack taken = items.remove(items.size() - 1);
        if (isEmpty(taken)) {
            return null;
        }
        ItemStack cursorItem = taken.clone();
        cursorItem.setAmount(Math.max(1, cursorItem.getAmount()));
        meta.setItems(items);
        result.setItemMeta(meta);
        return new BundleTakeResult(result, cursorItem);
    }

    private int countFlashBundleUnstackables(List<ItemStack> items) {
        int count = 0;
        if (items == null) {
            return 0;
        }
        for (ItemStack item : items) {
            if (isFlashBundleUnstackableCandidate(item)) {
                count += Math.max(1, item.getAmount());
            }
        }
        return count;
    }

    private boolean isBundle(ItemStack item) {
        return item != null && item.getType() != Material.AIR && item.getType().name().endsWith("BUNDLE");
    }

    private boolean isFlashBundleUnstackableCandidate(ItemStack item) {
        return !isEmpty(item) && !isBundle(item) && item.getMaxStackSize() <= 1;
    }

    private void playFlashBundleInsert(Player player) {
        player.swingHand(EquipmentSlot.HAND);
        player.playSound(player.getLocation(), Sound.ITEM_BUNDLE_INSERT, 0.74f, 1.18f);
        player.playSound(player.getLocation(), Sound.BLOCK_AMETHYST_BLOCK_CHIME, 0.28f, 1.62f);
    }

    private void playFlashBundleRemove(Player player) {
        player.swingHand(EquipmentSlot.HAND);
        player.playSound(player.getLocation(), Sound.ITEM_BUNDLE_REMOVE_ONE, 0.72f, 1.08f);
        player.playSound(player.getLocation(), Sound.BLOCK_AMETHYST_BLOCK_HIT, 0.26f, 1.48f);
    }

    private ItemStack createFlashAnvilResult(ItemStack first, ItemStack second) {
        if (isEmpty(first) || isEmpty(second)) {
            return null;
        }

        ItemStack result = null;
        if (isUnstableMaceCoreRecipe(first, second)) {
            result = tryApplyUnstableMaceCore(getUnstableMaceInput(first, second));
        } else if (isUnstableCoreShieldRecipe(first, second)) {
            result = tryApplyUnstableCoreShield(getUnstableCoreShieldInput(first, second));
        } else if (isEnhancedWindChargeAnvilRecipe(first, second)) {
            result = tryApplyEnhancedWindChargeStage(getEnhancedWindChargeInput(first, second));
        } else if (isTmtHoeRecipe(first, second)) {
            result = tryApplyTmtToHoe(getTmtHoeInput(first, second));
        } else if (isTntMinecartHoeRecipe(first, second)) {
            result = tryApplyTntMinecartToHoe(getTntMinecartHoeInput(first, second));
        } else if (isUpgradeBook(second)) {
            result = applyUpgradeMark(first);
        } else if (second.getType() == Material.ENCHANTED_BOOK) {
            if (isSword(first)) {
                result = tryApplySwordBook(first, second);
            } else if (first.getType() == Material.TRIDENT) {
                result = tryApplyTridentBook(first, second);
            } else if (first.getType() == Material.FISHING_ROD) {
                result = tryApplyFishingRodBook(first, second);
            } else if (first.getType() == Material.SHIELD) {
                result = tryApplyShieldBook(first, second);
            } else if (first.getType() == Material.CROSSBOW) {
                result = tryApplyCrossbowBook(first, second);
            } else if (first.getType() == Material.BUCKET || first.getType() == Material.WATER_BUCKET) {
                result = tryApplyBucketBook(first, second);
            } else if (first.getType() == Material.SPYGLASS) {
                result = tryApplySpyglassBook(first, second);
            } else if (isHarness(first)) {
                result = tryApplyHarnessBook(first, second);
            }
        } else if (first.getType() == Material.ENCHANTED_BOOK && isHarness(second)) {
            result = tryApplyHarnessBook(second, first);
        } else if (isArmor(first) && second.getType() == Material.TOTEM_OF_UNDYING) {
            result = tryApplyTotemToArmor(first);
        } else if (first.getType() == Material.TOTEM_OF_UNDYING && isArmor(second)) {
            result = tryApplyTotemToArmor(second);
        } else if (isSword(first) && isCondensedEnderPearl(second)) {
            result = tryApplyReturnPointToSword(first, second);
        } else if (isCondensedEnderPearl(first) && isSword(second)) {
            result = tryApplyReturnPointToSword(second, first);
        } else if (isPotionItem(first) && isPotionItem(second)) {
            result = tryDoublePotion(first, second);
        } else if (isSword(first) && isPotionItem(second)) {
            result = tryApplyPotionToSword(first, second);
        } else if (isPotionItem(first) && isSword(second)) {
            result = tryApplyPotionToSword(second, first);
        }
        return result;
    }

    private boolean giveAnvilResult(Player player, InventoryClickEvent event, ItemStack result) {
        if (event.isShiftClick()) {
            return player.getInventory().addItem(result.clone()).isEmpty();
        }
        ItemStack cursor = event.getCursor();
        if (isEmpty(cursor)) {
            event.setCursor(result.clone());
            return true;
        }
        if (cursor.isSimilar(result) && cursor.getAmount() + result.getAmount() <= cursor.getMaxStackSize()) {
            ItemStack merged = cursor.clone();
            merged.setAmount(merged.getAmount() + result.getAmount());
            event.setCursor(merged);
            return true;
        }
        return false;
    }

    private void consumeAnvilInput(AnvilInventory anvil, boolean firstSlot) {
        ItemStack item = firstSlot ? anvil.getFirstItem() : anvil.getSecondItem();
        if (isEmpty(item)) {
            return;
        }
        ItemStack rest = item.clone();
        rest.setAmount(rest.getAmount() - 1);
        if (firstSlot) {
            anvil.setFirstItem(rest.getAmount() <= 0 ? null : rest);
        } else {
            anvil.setSecondItem(rest.getAmount() <= 0 ? null : rest);
        }
    }

    private boolean isUnstableMaceCoreRecipe(ItemStack first, ItemStack second) {
        return false;
    }

    private boolean isUnstableCoreShieldRecipe(ItemStack first, ItemStack second) {
        return (isShield(first) && isHeavyCore(second) && !hasUnstableCoreShield(first))
                || (isHeavyCore(first) && isShield(second) && !hasUnstableCoreShield(second));
    }

    private boolean isTmtHoeRecipe(ItemStack first, ItemStack second) {
        return false;
    }

    private boolean isTntMinecartHoeRecipe(ItemStack first, ItemStack second) {
        return isHoe(first) && isTntMinecartItem(second) && !hasExplosiveHoeCharge(first);
    }

    private boolean isEnhancedWindChargeAnvilRecipe(ItemStack first, ItemStack second) {
        return (isWindChargeAnvilInput(first) && second != null && second.getType() == Material.BREEZE_ROD)
                || (first != null && first.getType() == Material.BREEZE_ROD && isWindChargeAnvilInput(second));
    }

    private boolean isWindChargeAnvilInput(ItemStack item) {
        return item != null && item.getType() == Material.WIND_CHARGE && !isEnhancedWindCharge(item);
    }

    private ItemStack getEnhancedWindChargeInput(ItemStack first, ItemStack second) {
        if (isWindChargeAnvilInput(first) && second != null && second.getType() == Material.BREEZE_ROD) {
            return first;
        }
        if (first != null && first.getType() == Material.BREEZE_ROD && isWindChargeAnvilInput(second)) {
            return second;
        }
        return null;
    }

    private ItemStack tryApplyEnhancedWindChargeStage(ItemStack windCharge) {
        if (!isWindChargeAnvilInput(windCharge)) {
            return null;
        }
        return isEnhancedWindChargeStage(windCharge) ? createEnhancedWindCharge() : createStagedEnhancedWindCharge();
    }

    private ItemStack getUnstableMaceInput(ItemStack first, ItemStack second) {
        if (isMace(first) && isHeavyCore(second)) {
            return first;
        }
        if (isHeavyCore(first) && isMace(second)) {
            return second;
        }
        return null;
    }

    private ItemStack getUnstableCoreShieldInput(ItemStack first, ItemStack second) {
        if (isShield(first) && isHeavyCore(second)) {
            return first;
        }
        if (isHeavyCore(first) && isShield(second)) {
            return second;
        }
        return null;
    }

    private ItemStack getTmtHoeInput(ItemStack first, ItemStack second) {
        if (isHoe(first) && isTmt(second)) {
            return first;
        }
        if (isTmt(first) && isHoe(second)) {
            return second;
        }
        return null;
    }

    private ItemStack getTntMinecartHoeInput(ItemStack first, ItemStack second) {
        if (isHoe(first) && isTntMinecartItem(second)) {
            return first;
        }
        return null;
    }

    private boolean isMace(ItemStack item) {
        return item != null && item.getType() == Material.MACE;
    }

    private boolean isShield(ItemStack item) {
        return item != null && item.getType() == Material.SHIELD;
    }

    private boolean isHeavyCore(ItemStack item) {
        return item != null && item.getType() == Material.HEAVY_CORE;
    }

    private ItemStack tryApplyTmtToHoe(ItemStack hoe) {
        if (!isHoe(hoe) || hasExplosiveHoeCharge(hoe)) {
            return null;
        }
        ItemStack result = hoe.clone();
        result.setAmount(1);
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return null;
        }
        meta.getPersistentDataContainer().set(tmtHoeKey, PersistentDataType.BYTE, (byte) 1);
        meta.addItemFlags(org.bukkit.inventory.ItemFlag.HIDE_ATTRIBUTES);
        refreshTmtHoeLore(meta);
        result.setItemMeta(meta);
        return result;
    }

    private void refreshTmtHoeLore(ItemMeta meta) {
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line != null && (line.startsWith("§8- §x§F§F§5§5§3§3TMT陷阱")
                || line.replaceAll("§.", "").contains("TMT陷阱锄")));
        lore.add(TMT_HOE_LINE);
        lore.add("§8- §x§F§F§9§9§5§5放置方式：§7按 §fQ §7丢出锄头，落点方块变成陷阱");
        meta.setLore(lore);
    }

    private ItemStack tryApplyTntMinecartToHoe(ItemStack hoe) {
        if (!isHoe(hoe) || hasExplosiveHoeCharge(hoe)) {
            return null;
        }
        ItemStack result = hoe.clone();
        result.setAmount(1);
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return null;
        }
        meta.getPersistentDataContainer().set(tntMinecartHoeKey, PersistentDataType.BYTE, (byte) 1);
        meta.addItemFlags(org.bukkit.inventory.ItemFlag.HIDE_ATTRIBUTES);
        refreshTntMinecartHoeLore(meta);
        result.setItemMeta(meta);
        return result;
    }

    private void refreshTntMinecartHoeLore(ItemMeta meta) {
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line != null && (line.startsWith("§8- §x§F§F§A§A§4§4TNT矿车雷")
                || line.replaceAll("§.", "").contains("TNT矿车雷锄")));
        lore.add(TNT_MINECART_HOE_LINE);
        lore.add("§8- §x§F§F§D§D§7§7放置方式：§7按 §fQ §7丢出锄头，落点方块变成矿车雷");
        meta.setLore(lore);
    }

    private ItemStack tryApplyUnstableMaceCore(ItemStack mace) {
        if (!isMace(mace)) {
            return null;
        }
        int currentLevel = getUnstableMaceLevel(mace);
        if (currentLevel >= UNSTABLE_MACE_MAX_LEVEL) {
            return null;
        }

        int nextLevel = currentLevel + 1;
        ItemStack result = mace.clone();
        result.setAmount(1);
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return null;
        }

        meta.getPersistentDataContainer().set(unstableMaceHiddenKey, PersistentDataType.BYTE, (byte) 1);
        meta.getPersistentDataContainer().set(unstableMaceLevelKey, PersistentDataType.INTEGER, nextLevel);
        meta.addItemFlags(org.bukkit.inventory.ItemFlag.HIDE_ATTRIBUTES);
        refreshUnstableMaceLore(meta, nextLevel);
        result.setItemMeta(meta);
        return result;
    }

    private ItemStack tryApplyUnstableCoreShield(ItemStack shield) {
        if (!isShield(shield) || hasUnstableCoreShield(shield)) {
            return null;
        }
        ItemStack result = shield.clone();
        result.setAmount(1);
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return null;
        }
        meta.setItemName(UNSTABLE_CORE_SHIELD_NAME);
        meta.getPersistentDataContainer().set(unstableCoreShieldKey, PersistentDataType.BYTE, (byte) 1);
        meta.addItemFlags(org.bukkit.inventory.ItemFlag.HIDE_ATTRIBUTES);
        meta.setLore(null);
        result.setItemMeta(meta);
        applyUnstableCoreShieldDurability(result);
        return result;
    }

    public ItemStack createUnstableCoreShield() {
        ItemStack result = new ItemStack(Material.SHIELD);
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return result;
        }
        meta.setItemName(UNSTABLE_CORE_SHIELD_NAME);
        meta.getPersistentDataContainer().set(unstableCoreShieldKey, PersistentDataType.BYTE, (byte) 1);
        meta.addItemFlags(org.bukkit.inventory.ItemFlag.HIDE_ATTRIBUTES);
        meta.setLore(null);
        result.setItemMeta(meta);
        applyUnstableCoreShieldDurability(result);
        return result;
    }

    private void applyUnstableCoreShieldDurability(ItemStack shield) {
        if (shield == null || shield.getType() != Material.SHIELD) {
            return;
        }
        shield.setData(DataComponentTypes.MAX_DAMAGE, UNSTABLE_CORE_SHIELD_MAX_DAMAGE);
    }

    public ItemStack createUnstableMace(int level) {
        int safeLevel = Math.max(1, Math.min(UNSTABLE_MACE_MAX_LEVEL, level));
        ItemStack result = new ItemStack(Material.MACE);
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return result;
        }
        meta.setItemName("§x§F§F§5§5§A§A不§x§F§2§6§4§B§7稳§x§E§5§7§3§C§4定§x§D§8§8§2§D§1重§x§C§B§9§1§D§E锤");
        meta.getPersistentDataContainer().set(unstableMaceHiddenKey, PersistentDataType.BYTE, (byte) 1);
        meta.getPersistentDataContainer().set(unstableMaceLevelKey, PersistentDataType.INTEGER, safeLevel);
        meta.addItemFlags(org.bukkit.inventory.ItemFlag.HIDE_ATTRIBUTES);
        refreshUnstableMaceLore(meta, safeLevel);
        result.setItemMeta(meta);
        return result;
    }

    private void refreshUnstableMaceLore(ItemMeta meta, int level) {
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> {
            if (line == null) {
                return false;
            }
            String plain = line.replaceAll("§.", "");
            return line.startsWith(UNSTABLE_MACE_LINE_PREFIX)
                    || line.startsWith(UNSTABLE_MACE_UNLOCK_LINE_PREFIX + "1/10")
                    || line.startsWith(UNSTABLE_MACE_UNLOCK_LINE_PREFIX + "2/10")
                    || line.startsWith(UNSTABLE_MACE_UNLOCK_LINE_PREFIX + "3/10")
                    || line.startsWith(UNSTABLE_MACE_UNLOCK_LINE_PREFIX + "4/10")
                    || line.startsWith(UNSTABLE_MACE_UNLOCK_LINE_PREFIX + "5/10")
                    || line.startsWith(UNSTABLE_MACE_UNLOCK_LINE_PREFIX + "6/10")
                    || line.startsWith(UNSTABLE_MACE_UNLOCK_LINE_PREFIX + "7/10")
                    || line.startsWith(UNSTABLE_MACE_UNLOCK_LINE_PREFIX + "8/10")
                    || line.startsWith(UNSTABLE_MACE_UNLOCK_LINE_PREFIX + "9/10")
                    || line.startsWith(UNSTABLE_MACE_UNLOCK_LINE_PREFIX + "10/10")
                    || plain.startsWith("不稳定 ")
                    || plain.contains("不稳定重锤")
                    || plain.contains("重锤核心共振")
                    || plain.contains("反弹窗口")
                    || plain.contains("下一枚重锤核心成功率")
                    || plain.contains("不稳定已满载");
        });
        int clamped = Math.max(1, Math.min(UNSTABLE_MACE_MAX_LEVEL, level));
        lore.add(UNSTABLE_MACE_SIMPLE_COLOR + "不" + UNSTABLE_MACE_SIMPLE_COLOR + "稳"
                + UNSTABLE_MACE_SIMPLE_COLOR + "定 " + UNSTABLE_MACE_SIMPLE_COLOR + clamped
                + UNSTABLE_MACE_SIMPLE_COLOR + "/" + UNSTABLE_MACE_SIMPLE_COLOR + "?");
        meta.setLore(lore);
    }

    private String getUnstableMaceUnlockName(int level) {
        return switch (level) {
            case 1 -> "核心猛击：不再增加伤害，三击可能反噬弹飞";
            case 2 -> "裂锤回音：命中后短延迟触发回音扰动";
            case 3 -> "护盾裂痕：猛击盾牌会震出额外盾冷却";
            case 4 -> "相位残影：命中后残影追击并扰动目标";
            case 5 -> "坠星蓄势：坠落越深，落点星裂范围越强";
            case 6 -> "错位锁定：命中玩家后短暂封住水平位移";
            case 7 -> "失控校准：反噬概率会按上一次成败自动升降";
            case 8 -> "重力坍缩：折跃猛击时牵引附近目标";
            case 9 -> "核心暴鸣：小概率爆鸣并反噬自身";
            case 10 -> "终末共振：高阶折跃猛击爆发范围共振";
            default -> "未知核心回路";
        };
    }

    private boolean rollUnstableMaceForgeSuccess(Player player, AnvilInventory anvil, ItemStack first, ItemStack second) {
        ItemStack mace = getUnstableMaceInput(first, second);
        int currentLevel = getUnstableMaceLevel(mace);
        double chance = getUnstableMaceForgeChance(currentLevel);
        if (chance >= 1.0D || ThreadLocalRandom.current().nextDouble() < chance) {
            player.sendActionBar("§x§F§F§8§8§D§D✦ §f重锤核心嵌入成功，§7铁砧开始失稳");
            return true;
        }
        return false;
    }

    private double getUnstableMaceForgeChance(int currentLevel) {
        if (currentLevel <= 0) {
            return 1.0D;
        }
        return Math.max(0.0D, Math.min(1.0D, Math.pow(0.5D, currentLevel)));
    }

    private void explodeFlashAnvil(Location location, Player player, boolean success) {
        Location center = location == null ? player.getLocation().clone() : location.clone().add(0.5D, 0.55D, 0.5D);
        World world = center.getWorld();
        if (world == null) {
            return;
        }
        if (location != null) {
            Block block = location.getBlock();
            Material type = block.getType();
            if (type == Material.ANVIL || type == Material.CHIPPED_ANVIL || type == Material.DAMAGED_ANVIL) {
                block.setType(Material.AIR, false);
            }
        }

        world.spawnParticle(Particle.EXPLOSION, center, success ? 5 : 8, 0.20D, 0.16D, 0.20D, 0.02D);
        world.spawnParticle(Particle.ELECTRIC_SPARK, center, success ? 34 : 52, 0.42D, 0.32D, 0.42D, 0.12D);
        world.spawnParticle(Particle.CRIT, center, success ? 20 : 32, 0.34D, 0.24D, 0.34D, 0.10D);
        world.createExplosion(center.getX(), center.getY(), center.getZ(), success ? 2.15F : 2.85F, false, false);
        world.playSound(center, Sound.BLOCK_ANVIL_DESTROY, 1.0f, success ? 1.06f : 0.72f);
        world.playSound(center, Sound.ENTITY_GENERIC_EXPLODE, success ? 0.72f : 0.96f, success ? 1.34f : 0.86f);
        if (player != null && player.isOnline()) {
            player.playSound(player.getLocation(), Sound.BLOCK_RESPAWN_ANCHOR_DEPLETE, 0.42f, success ? 1.42f : 0.72f);
        }
    }

    private ItemStack applyUpgradeMark(ItemStack base) {
        ItemStack result = base.clone();
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return null;
        }

        meta.getPersistentDataContainer().set(upgradedItemKey, PersistentDataType.BYTE, (byte) 1);
        if (meta.hasLore() && meta.getLore() != null) {
            List<String> lore = new ArrayList<>(meta.getLore());
            if (lore.removeIf(LEGACY_UPGRADE_LINE::equals)) {
                meta.setLore(lore.isEmpty() ? null : lore);
            }
        }
        result.setItemMeta(meta);

        Enchantment upgradeEnchantment = getUpgradeEnchantment();
        if (upgradeEnchantment == null) {
            return result;
        }

        if (result.getItemMeta() instanceof EnchantmentStorageMeta storageMeta) {
            if (!storageMeta.hasStoredEnchant(upgradeEnchantment)) {
                storageMeta.addStoredEnchant(upgradeEnchantment, 1, true);
            }
            result.setItemMeta(storageMeta);
        } else if (result.getEnchantmentLevel(upgradeEnchantment) <= 0) {
            result.addUnsafeEnchantment(upgradeEnchantment, 1);
        }
        if (isBrushItem(result)) {
            applyMagicBrushMark(result);
        }
        return result;
    }

    private void applyMagicBrushMark(ItemStack brush) {
        if (brush == null || brush.getType() != Material.PAPER) {
            return;
        }
        ItemMeta meta = brush.getItemMeta();
        if (meta == null) {
            return;
        }
        meta.setItemName(MAGIC_BRUSH_NAME);
        meta.getPersistentDataContainer().set(magicBrushBaseKey, PersistentDataType.BYTE, (byte) 1);
        meta.getPersistentDataContainer().set(magicBrushActiveKey, PersistentDataType.BYTE, (byte) 1);
        meta.setLore(List.of(
                "§8- §x§B§B§8§8§F§F长按右键绘制，支持空气和地面",
                "§8- §7丢出画笔确认图案并进入施法",
                "§8- §7离开绘制平面 §f8格 §7会自动散掉",
                "§8- §7直线、月弧、雷纹、螺旋、星阵都能远程攻击",
                "§8- §7双环、棱形、沙漏会触发不同的增益和控制"
        ));
        brush.setItemMeta(meta);
        brush.setData(DataComponentTypes.ITEM_MODEL, NamespacedKey.minecraft("brush"));
        brush.setData(DataComponentTypes.MAX_STACK_SIZE, 1);
        applyMagicBrushUseComponent(brush);
    }

    private void applyMagicBrushUseComponent(ItemStack brush) {
        if (brush == null || brush.getType() != Material.PAPER) {
            return;
        }
        brush.setData(DataComponentTypes.CONSUMABLE, Consumable.consumable()
                .consumeSeconds(72000.0F)
                .animation(ItemUseAnimation.BRUSH)
                .sound(Key.key("minecraft:item.brush.brushing.generic"))
                .hasConsumeParticles(false));
    }

    private ItemStack tryApplySwordBook(ItemStack sword, ItemStack book) {
        if (!(book.getItemMeta() instanceof EnchantmentStorageMeta meta)) {
            return null;
        }
        boolean hasSupported = false;
        ItemStack result = sword.clone();
        for (Enchantment enchantment : meta.getStoredEnchants().keySet()) {
            if (enchantment == Enchantment.BLAST_PROTECTION || enchantment == Enchantment.PIERCING || enchantment == Enchantment.LOYALTY) {
                int level = meta.getStoredEnchantLevel(enchantment);
                result.addUnsafeEnchantment(enchantment, Math.max(level, result.getEnchantmentLevel(enchantment)));
                hasSupported = true;
            }
        }
        return hasSupported ? result : null;
    }

    private ItemStack tryApplyTridentBook(ItemStack trident, ItemStack book) {
        if (!(book.getItemMeta() instanceof EnchantmentStorageMeta meta)) {
            return null;
        }
        boolean hasSupported = false;
        ItemStack result = trident.clone();
        for (Enchantment enchantment : meta.getStoredEnchants().keySet()) {
            if (enchantment == Enchantment.SHARPNESS || enchantment == Enchantment.LOYALTY || enchantment == Enchantment.RIPTIDE) {
                if (enchantment == Enchantment.RIPTIDE && isPrismarineTrident(result)) {
                    continue;
                }
                int level = meta.getStoredEnchantLevel(enchantment);
                result.addUnsafeEnchantment(enchantment, Math.max(level, result.getEnchantmentLevel(enchantment)));
                hasSupported = true;
            }
        }
        return hasSupported ? result : null;
    }

    private ItemStack tryApplyFishingRodBook(ItemStack rod, ItemStack book) {
        return tryApplySingleBookEnchant(rod, book, Enchantment.RIPTIDE);
    }

    private ItemStack tryApplyShieldBook(ItemStack shield, ItemStack book) {
        return tryApplySingleBookEnchant(shield, book, Enchantment.THORNS);
    }

    private ItemStack tryApplyCrossbowBook(ItemStack crossbow, ItemStack book) {
        if (!(book.getItemMeta() instanceof EnchantmentStorageMeta meta)) {
            return null;
        }
        boolean supported = false;
        ItemStack result = crossbow.clone();
        for (Map.Entry<Enchantment, Integer> entry : meta.getStoredEnchants().entrySet()) {
            Enchantment enchantment = entry.getKey();
            if (enchantment != Enchantment.PIERCING && enchantment != Enchantment.MULTISHOT) {
                continue;
            }
            int level = Math.max(entry.getValue(), result.getEnchantmentLevel(enchantment));
            result.addUnsafeEnchantment(enchantment, level);
            supported = true;
        }
        return supported ? result : null;
    }

    private ItemStack tryApplyTotemToArmor(ItemStack armor) {
        if (!isArmor(armor) || hasPersistentByte(armor, totemArmorKey)) {
            return null;
        }
        ItemStack result = armor.clone();
        result.setAmount(1);
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return null;
        }
        meta.getPersistentDataContainer().set(totemArmorKey, PersistentDataType.BYTE, (byte) 1);
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line.startsWith(TOTEM_ARMOR_LINE_PREFIX)
                || line.startsWith("§8- §x§F§F§D§D§88不死图腾护层："));
        lore.add(TOTEM_ARMOR_LINE_PREFIX + "§f自己近战伤害 -10%§8 / §f自己远程伤害 +15%");
        lore.add("§8- §7耐久高于 §f50% §7时，可触发濒死复活并碎掉这一件");
        meta.setLore(lore);
        result.setItemMeta(meta);
        result.addUnsafeEnchantment(Enchantment.UNBREAKING, Math.max(1, result.getEnchantmentLevel(Enchantment.UNBREAKING)));
        return result;
    }

    private ItemStack tryApplyGoldenAppleToArmor(ItemStack armor, Material appleType) {
        if (!isArmor(armor) || (appleType != Material.GOLDEN_APPLE && appleType != Material.ENCHANTED_GOLDEN_APPLE)) {
            return null;
        }
        ItemStack result = armor.clone();
        result.setAmount(1);
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return null;
        }
        String newType = appleType == Material.ENCHANTED_GOLDEN_APPLE ? "enchanted" : "normal";
        String oldType = meta.getPersistentDataContainer().get(goldenAppleArmorTypeKey, PersistentDataType.STRING);
        int maxLevel = "enchanted".equals(newType) ? 2 : 3;
        int oldLevel = meta.getPersistentDataContainer().getOrDefault(goldenAppleArmorLevelKey, PersistentDataType.INTEGER, 0);
        if (oldType != null && !oldType.equals(newType)) {
            return null;
        }
        if (oldLevel >= maxLevel) {
            return null;
        }
        int nextLevel = oldLevel + 1;
        double healthBonus = getGoldenAppleArmorHealthBonus(newType, nextLevel);
        meta.getPersistentDataContainer().set(goldenAppleArmorTypeKey, PersistentDataType.STRING, newType);
        meta.getPersistentDataContainer().set(goldenAppleArmorLevelKey, PersistentDataType.INTEGER, nextLevel);
        applyGoldenAppleArmorHealthModifier(meta, result.getType(), healthBonus);
        refreshGoldenAppleArmorLore(meta, newType, nextLevel, healthBonus);
        result.setItemMeta(meta);
        return result;
    }

    private void applyGoldenAppleArmorHealthModifier(ItemMeta meta, Material armorType, double healthBonus) {
        removeAttributeModifierByKey(meta, Attribute.MAX_HEALTH, goldenAppleArmorHealthModifierKey);
        removeAttributeModifierByKey(meta, Attribute.MAX_HEALTH, goldenAppleArmorHealthHeadModifierKey);
        removeAttributeModifierByKey(meta, Attribute.MAX_HEALTH, goldenAppleArmorHealthChestModifierKey);
        removeAttributeModifierByKey(meta, Attribute.MAX_HEALTH, goldenAppleArmorHealthLegsModifierKey);
        removeAttributeModifierByKey(meta, Attribute.MAX_HEALTH, goldenAppleArmorHealthFeetModifierKey);
        ensureVanillaArmorAttributes(meta, armorType);
        EquipmentSlotGroup group = getArmorEquipmentSlotGroup(armorType);
        if (group == null || healthBonus <= 0.0D) {
            return;
        }
        NamespacedKey modifierKey = getGoldenAppleArmorHealthModifierKey(armorType);
        meta.addAttributeModifier(Attribute.MAX_HEALTH, new AttributeModifier(
                modifierKey,
                healthBonus,
                AttributeModifier.Operation.ADD_NUMBER,
                group
        ));
    }

    private void ensureVanillaArmorAttributes(ItemMeta meta, Material armorType) {
        EquipmentSlotGroup group = getArmorEquipmentSlotGroup(armorType);
        EquipmentSlot slot = getArmorEquipmentSlot(armorType);
        if (meta == null || group == null || slot == null) {
            return;
        }
        ensureVanillaEquipmentAttribute(meta, armorType, slot, Attribute.ARMOR,
                getBaseArmorAttributeModifierKey(armorType, Attribute.ARMOR), group, baseArmorArmorModifierKey);
        ensureVanillaEquipmentAttribute(meta, armorType, slot, Attribute.ARMOR_TOUGHNESS,
                getBaseArmorAttributeModifierKey(armorType, Attribute.ARMOR_TOUGHNESS), group, baseArmorToughnessModifierKey);
        ensureVanillaEquipmentAttribute(meta, armorType, slot, Attribute.KNOCKBACK_RESISTANCE,
                getBaseArmorAttributeModifierKey(armorType, Attribute.KNOCKBACK_RESISTANCE), group, baseArmorKnockbackResistanceModifierKey);
    }

    private void ensureVanillaWeaponAttackDamageAttribute(ItemMeta meta, Material weaponType) {
        if (meta == null || weaponType == null || weaponType == Material.AIR) {
            return;
        }
        // 剑/斧有自定义攻速或伤害组件后，Paper 会把整套默认属性视为被覆盖。
        // 原本只写攻速会让客户端不再显示原版攻击伤害，所以这里把原版攻击伤害显式补回去。
        if (!hasPersistentDoubleMeta(meta, materialSwordSpeedBonusKey)
                && !hasPersistentDoubleMeta(meta, materialSwordDamagePenaltyKey)
                && !hasPersistentDoubleMeta(meta, materialAxeDamageBonusKey)
                && !hasPersistentDoubleMeta(meta, materialAxeCooldownIncreaseKey)
                && !hasPersistentByteMeta(meta, redstoneStabilizerKey)) {
            return;
        }
        if (hasPersistentDoubleMeta(meta, materialSwordDamagePenaltyKey) || hasPersistentDoubleMeta(meta, materialAxeDamageBonusKey)) {
            return;
        }
        ensureVanillaEquipmentAttribute(meta, weaponType, EquipmentSlot.HAND, Attribute.ATTACK_DAMAGE, baseWeaponAttackDamageModifierKey, EquipmentSlotGroup.MAINHAND);
    }

    private void ensureVanillaEquipmentAttribute(ItemMeta meta, Material material, EquipmentSlot slot,
                                                 Attribute attribute, NamespacedKey key, EquipmentSlotGroup group,
                                                 NamespacedKey... legacyKeys) {
        if (meta == null || material == null || slot == null || attribute == null || key == null || group == null) {
            return;
        }
        removeLegacyAttributeModifierKeys(meta, attribute, key, legacyKeys);
        double amount = getDefaultEquipmentAttributeAmount(material, slot, attribute, 0.0D);
        if (amount <= 0.0D) {
            removeAttributeModifierByKey(meta, attribute, key);
            return;
        }
        Collection<AttributeModifier> modifiers = meta.getAttributeModifiers(attribute);
        if (modifiers != null) {
            for (AttributeModifier modifier : modifiers) {
                if (!modifier.getKey().equals(key)
                        && modifier.getOperation() == AttributeModifier.Operation.ADD_NUMBER
                        && Math.abs(modifier.getAmount() - amount) < 0.0001D) {
                    removeAttributeModifierByKey(meta, attribute, key);
                    return;
                }
            }
        }
        removeAttributeModifierByKey(meta, attribute, key);
        meta.addAttributeModifier(attribute, new AttributeModifier(
                key,
                amount,
                AttributeModifier.Operation.ADD_NUMBER,
                group
        ));
    }

    private void removeLegacyAttributeModifierKeys(ItemMeta meta, Attribute attribute, NamespacedKey activeKey, NamespacedKey... legacyKeys) {
        if (legacyKeys == null || legacyKeys.length == 0) {
            return;
        }
        for (NamespacedKey legacyKey : legacyKeys) {
            if (legacyKey != null && !legacyKey.equals(activeKey)) {
                removeAttributeModifierByKey(meta, attribute, legacyKey);
            }
        }
    }

    private NamespacedKey getBaseArmorAttributeModifierKey(Material armorType, Attribute attribute) {
        String attributePart;
        if (attribute == Attribute.ARMOR) {
            attributePart = "armor";
        } else if (attribute == Attribute.ARMOR_TOUGHNESS) {
            attributePart = "toughness";
        } else if (attribute == Attribute.KNOCKBACK_RESISTANCE) {
            attributePart = "knockback_resistance";
        } else {
            attributePart = "generic";
        }
        return new NamespacedKey(plugin, "flash_base_armor_" + attributePart + "_" + getArmorSlotKeySuffix(armorType));
    }

    private String getArmorSlotKeySuffix(Material armorType) {
        if (armorType == null) {
            return "unknown";
        }
        String name = armorType.name();
        if (name.endsWith("_HELMET")) {
            return "head";
        }
        if (name.endsWith("_CHESTPLATE") || armorType == Material.ELYTRA) {
            return "chest";
        }
        if (name.endsWith("_LEGGINGS")) {
            return "legs";
        }
        if (name.endsWith("_BOOTS")) {
            return "feet";
        }
        return "unknown";
    }

    private double getDefaultEquipmentAttributeAmount(Material material, EquipmentSlot slot, Attribute attribute, double fallback) {
        if (material == null || slot == null || attribute == null) {
            return fallback;
        }
        var modifiers = material.getDefaultAttributeModifiers(slot).get(attribute);
        if (modifiers == null || modifiers.isEmpty()) {
            return fallback;
        }
        double value = attribute == Attribute.ATTACK_DAMAGE ? 1.0D : attribute == Attribute.ATTACK_SPEED ? 4.0D : fallback;
        double addScalar = 0.0D;
        double multiplyScalar = 1.0D;
        for (AttributeModifier modifier : modifiers) {
            if (modifier.getOperation() == AttributeModifier.Operation.ADD_NUMBER) {
                value += modifier.getAmount();
            } else if (modifier.getOperation() == AttributeModifier.Operation.ADD_SCALAR) {
                addScalar += modifier.getAmount();
            } else if (modifier.getOperation() == AttributeModifier.Operation.MULTIPLY_SCALAR_1) {
                multiplyScalar *= 1.0D + modifier.getAmount();
            }
        }
        if (addScalar != 0.0D) {
            value += value * addScalar;
        }
        value *= multiplyScalar;
        return Math.max(0.0D, value);
    }

    private boolean hasPersistentDoubleMeta(ItemMeta meta, NamespacedKey key) {
        return meta != null && key != null && meta.getPersistentDataContainer().has(key, PersistentDataType.DOUBLE);
    }

    private boolean hasPersistentByteMeta(ItemMeta meta, NamespacedKey key) {
        return meta != null && key != null && meta.getPersistentDataContainer().has(key, PersistentDataType.BYTE);
    }

    private NamespacedKey getGoldenAppleArmorHealthModifierKey(Material armorType) {
        if (armorType == null) {
            return goldenAppleArmorHealthModifierKey;
        }
        String name = armorType.name();
        if (name.endsWith("_HELMET")) {
            return goldenAppleArmorHealthHeadModifierKey;
        }
        if (name.endsWith("_CHESTPLATE") || armorType == Material.ELYTRA) {
            return goldenAppleArmorHealthChestModifierKey;
        }
        if (name.endsWith("_LEGGINGS")) {
            return goldenAppleArmorHealthLegsModifierKey;
        }
        if (name.endsWith("_BOOTS")) {
            return goldenAppleArmorHealthFeetModifierKey;
        }
        return goldenAppleArmorHealthModifierKey;
    }

    private EquipmentSlotGroup getArmorEquipmentSlotGroup(Material armorType) {
        if (armorType == null) {
            return null;
        }
        String name = armorType.name();
        if (name.endsWith("_HELMET")) {
            return EquipmentSlotGroup.HEAD;
        }
        if (name.endsWith("_CHESTPLATE") || armorType == Material.ELYTRA) {
            return EquipmentSlotGroup.CHEST;
        }
        if (name.endsWith("_LEGGINGS")) {
            return EquipmentSlotGroup.LEGS;
        }
        if (name.endsWith("_BOOTS")) {
            return EquipmentSlotGroup.FEET;
        }
        return null;
    }

    private double getGoldenAppleArmorHealthBonus(String type, int level) {
        if ("enchanted".equals(type)) {
            return level >= 2 ? 14.0D : 5.0D;
        }
        return switch (Math.max(1, Math.min(3, level))) {
            case 1 -> 3.0D;
            case 2 -> 8.0D;
            default -> 12.0D;
        };
    }

    private void refreshGoldenAppleArmorLore(ItemMeta meta, String type, int level, double healthBonus) {
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> {
            if (line == null) {
                return false;
            }
            String plain = line.replaceAll("§.", "");
            return line.startsWith(GOLDEN_APPLE_ARMOR_LINE_PREFIX)
                    || line.startsWith(ENCHANTED_GOLDEN_APPLE_ARMOR_LINE_PREFIX)
                    || plain.contains("普通金苹果护甲")
                    || plain.contains("附魔金苹果护甲")
                    || plain.contains("同路线金苹果护甲")
                    || plain.contains("低血量获得抗性")
                    || plain.contains("低血量提高自己近战");
        });
        if ("enchanted".equals(type)) {
            lore.add(ENCHANTED_GOLDEN_APPLE_ARMOR_LINE_PREFIX + "§f" + level + "§7/§f2 §8| §7最大生命 §a+" + formatOneDecimal(healthBonus));
            if (level >= 2) {
                lore.add("§8- §7满级：低血量获得抗性 I，自己远程伤害 §b+25%");
            }
        } else {
            lore.add(GOLDEN_APPLE_ARMOR_LINE_PREFIX + "§f" + level + "§7/§f3 §8| §7最大生命 §a+" + formatOneDecimal(healthBonus));
            if (level >= 3) {
                lore.add("§8- §7满级：低血量提高自己近战，自己远程伤害 §b+12%");
            }
        }
        lore.add("§8- §7攻击目标有同路线金苹果护甲时，增伤削弱 §f25%");
        meta.setLore(lore);
    }

    private String formatOneDecimal(double value) {
        return String.format(Locale.ROOT, "%.1f", value);
    }

    private ItemStack tryApplyBucketBook(ItemStack bucket, ItemStack book) {
        return tryApplySingleBookEnchant(bucket, book, Enchantment.LUCK_OF_THE_SEA);
    }

    private ItemStack tryApplySpyglassBook(ItemStack spyglass, ItemStack book) {
        return tryApplySingleBookEnchant(spyglass, book, Enchantment.FIRE_ASPECT);
    }

    private ItemStack tryApplyHarnessBook(ItemStack harness, ItemStack book) {
        if (!(book.getItemMeta() instanceof EnchantmentStorageMeta meta) || !meta.hasStoredEnchant(Enchantment.SWIFT_SNEAK)) {
            return null;
        }
        ItemStack result = harness.clone();
        int level = Math.max(meta.getStoredEnchantLevel(Enchantment.SWIFT_SNEAK), result.getEnchantmentLevel(Enchantment.SWIFT_SNEAK));
        level = Math.max(1, Math.min(3, level));
        result.addUnsafeEnchantment(Enchantment.SWIFT_SNEAK, level);
        ItemMeta resultMeta = result.getItemMeta();
        if (resultMeta != null) {
            resultMeta.getPersistentDataContainer().set(happyGhastHarnessSwiftLevelKey, PersistentDataType.INTEGER, level);
            refreshHappyGhastHarnessLore(resultMeta, level);
            result.setItemMeta(resultMeta);
        }
        return result;
    }

    private void refreshHappyGhastHarnessLore(ItemMeta meta, int level) {
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line != null && (line.startsWith(HAPPY_GHAST_SWIFT_HARNESS_LINE_PREFIX)
                || line.replaceAll("§.", "").contains("迅捷乐魂")
                || line.replaceAll("§.", "").contains("骑上乐魂后会持续校准速度")));
        lore.add(HAPPY_GHAST_SWIFT_HARNESS_LINE_PREFIX + "§7飞行速度 §a×" + formatOneDecimal(getHappyGhastHarnessSpeedMultiplier(level))
                + " §8| §f" + level + "§7/§f3");
        lore.add("§8- §7骑上乐魂后会持续校准速度，空中也会生效");
        meta.setLore(lore);
    }

    private ItemStack tryApplySingleBookEnchant(ItemStack base, ItemStack book, Enchantment enchantment) {
        if (!(book.getItemMeta() instanceof EnchantmentStorageMeta meta) || !meta.hasStoredEnchant(enchantment)) {
            return null;
        }
        ItemStack result = base.clone();
        int level = meta.getStoredEnchantLevel(enchantment);
        result.addUnsafeEnchantment(enchantment, Math.max(level, result.getEnchantmentLevel(enchantment)));
        return result;
    }

    private ItemStack tryApplyPotionToSword(ItemStack sword, ItemStack potion) {
        if (!isSword(sword) || !isPotionItem(potion) || getPotionEffects(potion).isEmpty()) {
            return null;
        }
        if (getSwordPotionUses(sword, 1) > 0 && getSwordPotionUses(sword, 2) > 0) {
            return null;
        }
        ItemStack result = sword.clone();
        result.setAmount(1);
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return null;
        }
        int slot = getSwordPotionUses(result, 1) <= 0 ? 1 : 2;
        meta.getPersistentDataContainer().set(getSwordPotionDataKey(slot), PersistentDataType.BYTE_ARRAY, potion.clone().serializeAsBytes());
        meta.getPersistentDataContainer().set(getSwordPotionUsesKey(slot), PersistentDataType.INTEGER, SWORD_POTION_MAX_USES);
        refreshSwordPotionLore(meta, result, slot, potion, SWORD_POTION_MAX_USES);
        result.setItemMeta(meta);
        return result;
    }

    private ItemStack tryApplyReturnPointToSword(ItemStack sword, ItemStack pearl) {
        if (!isSword(sword) || !isCondensedEnderPearl(pearl)) {
            return null;
        }
        ItemStack result = sword.clone();
        result.setAmount(1);
        ItemMeta meta = result.getItemMeta();
        if (meta == null || meta.getPersistentDataContainer().has(swordReturnWorldKey, PersistentDataType.STRING)) {
            return null;
        }
        meta.getPersistentDataContainer().set(swordReturnWorldKey, PersistentDataType.STRING, "__pending_anvil__");
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line != null && line.startsWith(SWORD_RETURN_POINT_LINE_PREFIX));
        lore.add(SWORD_RETURN_POINT_LINE_PREFIX + "§7等待铁砧坐标写入，§f仅触发一次");
        meta.setLore(lore);
        result.setItemMeta(meta);
        return result;
    }

    private ItemStack tryDoublePotion(ItemStack first, ItemStack second) {
        if (first.getType() != second.getType()
                || !(first.getItemMeta() instanceof PotionMeta firstMeta)
                || !(second.getItemMeta() instanceof PotionMeta secondMeta)
                || isDoubledPotion(first)
                || isDoubledPotion(second)
                || !isSamePotionForDoubling(firstMeta, secondMeta)) {
            return null;
        }

        List<PotionEffect> effects = firstMeta.getAllEffects();
        if (effects.isEmpty()) {
            return null;
        }

        ItemStack result = first.clone();
        result.setAmount(1);
        if (!(result.getItemMeta() instanceof PotionMeta resultMeta)) {
            return null;
        }

        try {
            resultMeta.setBasePotionType(PotionType.WATER);
        } catch (RuntimeException ignored) {
            // 某些服务端对特殊药水类型限制比较严，保留原基础类型也能正常显示翻倍后的自定义效果。
        }
        resultMeta.clearCustomEffects();
        boolean hasTimedEffect = false;
        for (PotionEffect effect : effects) {
            int duration = effect.getDuration();
            if (duration > 1 && !effect.getType().isInstant()) {
                duration = Math.min(Integer.MAX_VALUE / 2, duration * 2);
                hasTimedEffect = true;
            }
            resultMeta.addCustomEffect(new PotionEffect(
                    effect.getType(),
                    duration,
                    effect.getAmplifier(),
                    effect.isAmbient(),
                    effect.hasParticles(),
                    effect.hasIcon()
            ), true);
        }
        if (!hasTimedEffect) {
            return null;
        }

        resultMeta.getPersistentDataContainer().set(doubledPotionKey, PersistentDataType.BYTE, (byte) 1);
        List<String> lore = resultMeta.hasLore() && resultMeta.getLore() != null ? new ArrayList<>(resultMeta.getLore()) : new ArrayList<>();
        lore.removeIf(DOUBLED_POTION_LINE::equals);
        lore.add(DOUBLED_POTION_LINE);
        resultMeta.setLore(lore);
        result.setItemMeta(resultMeta);
        return result;
    }

    private boolean isPotionItem(ItemStack item) {
        return item != null && (item.getType() == Material.POTION || item.getType() == Material.SPLASH_POTION || item.getType() == Material.LINGERING_POTION);
    }

    private boolean isDoubledPotion(ItemStack item) {
        if (!isPotionItem(item) || !item.hasItemMeta()) {
            return false;
        }
        Byte flag = item.getItemMeta().getPersistentDataContainer().get(doubledPotionKey, PersistentDataType.BYTE);
        return flag != null && flag == (byte) 1;
    }

    private boolean isSamePotionForDoubling(PotionMeta first, PotionMeta second) {
        if (first.hasBasePotionType() != second.hasBasePotionType()) {
            return false;
        }
        if (first.hasBasePotionType() && first.getBasePotionType() != second.getBasePotionType()) {
            return false;
        }
        List<PotionEffect> firstEffects = first.getAllEffects();
        List<PotionEffect> secondEffects = second.getAllEffects();
        if (firstEffects.size() != secondEffects.size()) {
            return false;
        }
        for (int i = 0; i < firstEffects.size(); i++) {
            PotionEffect a = firstEffects.get(i);
            PotionEffect b = secondEffects.get(i);
            if (!a.getType().equals(b.getType())
                    || a.getAmplifier() != b.getAmplifier()
                    || a.getDuration() != b.getDuration()
                    || a.isAmbient() != b.isAmbient()
                    || a.hasParticles() != b.hasParticles()
                    || a.hasIcon() != b.hasIcon()) {
                return false;
            }
        }
        return true;
    }

    private List<PotionEffect> getPotionEffects(ItemStack potion) {
        if (!(potion != null && potion.getItemMeta() instanceof PotionMeta meta)) {
            return List.of();
        }
        return meta.getAllEffects();
    }

    private NamespacedKey getSwordPotionDataKey(int slot) {
        return slot == 2 ? swordPotionData2Key : swordPotionDataKey;
    }

    private NamespacedKey getSwordPotionUsesKey(int slot) {
        return slot == 2 ? swordPotionUses2Key : swordPotionUsesKey;
    }

    private ItemStack getStoredSwordPotion(ItemStack sword) {
        return getStoredSwordPotion(sword, 1);
    }

    private ItemStack getStoredSwordPotion(ItemStack sword, int slot) {
        if (!isSword(sword) || !sword.hasItemMeta()) {
            return null;
        }
        byte[] raw = sword.getItemMeta().getPersistentDataContainer().get(getSwordPotionDataKey(slot), PersistentDataType.BYTE_ARRAY);
        if (raw == null || raw.length == 0) {
            return null;
        }
        try {
            ItemStack potion = ItemStack.deserializeBytes(raw);
            return isPotionItem(potion) ? potion : null;
        } catch (RuntimeException ignored) {
            return null;
        }
    }

    private int getSwordPotionUses(ItemStack sword) {
        return getSwordPotionUses(sword, 1);
    }

    private int getSwordPotionUses(ItemStack sword, int slot) {
        if (!isSword(sword) || !sword.hasItemMeta()) {
            return 0;
        }
        Integer uses = sword.getItemMeta().getPersistentDataContainer().get(getSwordPotionUsesKey(slot), PersistentDataType.INTEGER);
        return uses == null ? 0 : Math.max(0, uses);
    }

    private void setSwordPotionUses(ItemStack sword, int uses) {
        setSwordPotionUses(sword, 1, uses);
    }

    private void setSwordPotionUses(ItemStack sword, int slot, int uses) {
        if (!isSword(sword)) {
            return;
        }
        ItemMeta meta = sword.getItemMeta();
        if (meta == null) {
            return;
        }
        if (uses <= 0) {
            meta.getPersistentDataContainer().remove(getSwordPotionDataKey(slot));
            meta.getPersistentDataContainer().remove(getSwordPotionUsesKey(slot));
        } else {
            meta.getPersistentDataContainer().set(getSwordPotionUsesKey(slot), PersistentDataType.INTEGER, uses);
        }
        refreshSwordPotionLore(meta, sword, slot, uses > 0 ? getStoredSwordPotion(sword, slot) : null, uses);
        sword.setItemMeta(meta);
    }

    private void refreshSwordPotionLore(ItemMeta meta, ItemStack sword, int slot, ItemStack potion, int uses) {
        if (meta == null) {
            return;
        }
        String slotPrefix = SWORD_POTION_SLOT_PREFIX + slot + "：";
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line != null && (line.startsWith(slotPrefix) || line.startsWith(SWORD_POTION_LINE_PREFIX)));
        if (uses > 0 && potion != null) {
            lore.add(slotPrefix + getPotionEffectsText(potion) + " §8/ §7剩余 §f" + uses + " §7次");
        }
        meta.setLore(lore.isEmpty() ? null : lore);
    }

    private String getPotionEffectsText(ItemStack potion) {
        List<PotionEffect> effects = getPotionEffects(potion);
        if (effects.isEmpty()) {
            return "§7未知效果";
        }
        List<String> names = new ArrayList<>();
        for (PotionEffect effect : effects) {
            names.add("§f" + translatePotionEffect(effect.getType()) + toRomanLevel(effect.getAmplifier() + 1));
        }
        return String.join("§8、", names);
    }

    private String translatePotionEffect(PotionEffectType type) {
        if (type == PotionEffectType.SPEED) return "速度";
        if (type == PotionEffectType.SLOWNESS) return "缓慢";
        if (type == PotionEffectType.HASTE) return "急迫";
        if (type == PotionEffectType.MINING_FATIGUE) return "挖掘疲劳";
        if (type == PotionEffectType.STRENGTH) return "力量";
        if (type == PotionEffectType.INSTANT_HEALTH) return "治疗";
        if (type == PotionEffectType.INSTANT_DAMAGE) return "伤害";
        if (type == PotionEffectType.JUMP_BOOST) return "跳跃提升";
        if (type == PotionEffectType.NAUSEA) return "反胃";
        if (type == PotionEffectType.REGENERATION) return "生命恢复";
        if (type == PotionEffectType.RESISTANCE) return "抗性提升";
        if (type == PotionEffectType.FIRE_RESISTANCE) return "防火";
        if (type == PotionEffectType.WATER_BREATHING) return "水下呼吸";
        if (type == PotionEffectType.INVISIBILITY) return "隐身";
        if (type == PotionEffectType.BLINDNESS) return "失明";
        if (type == PotionEffectType.NIGHT_VISION) return "夜视";
        if (type == PotionEffectType.HUNGER) return "饥饿";
        if (type == PotionEffectType.WEAKNESS) return "虚弱";
        if (type == PotionEffectType.POISON) return "中毒";
        if (type == PotionEffectType.WITHER) return "凋零";
        if (type == PotionEffectType.HEALTH_BOOST) return "生命提升";
        if (type == PotionEffectType.ABSORPTION) return "伤害吸收";
        if (type == PotionEffectType.SATURATION) return "饱和";
        if (type == PotionEffectType.GLOWING) return "发光";
        if (type == PotionEffectType.LEVITATION) return "漂浮";
        if (type == PotionEffectType.LUCK) return "幸运";
        if (type == PotionEffectType.UNLUCK) return "霉运";
        if (type == PotionEffectType.SLOW_FALLING) return "缓降";
        if (type == PotionEffectType.CONDUIT_POWER) return "潮涌能量";
        if (type == PotionEffectType.DOLPHINS_GRACE) return "海豚的恩惠";
        if (type == PotionEffectType.BAD_OMEN) return "不祥之兆";
        if (type == PotionEffectType.HERO_OF_THE_VILLAGE) return "村庄英雄";
        if (type == PotionEffectType.DARKNESS) return "黑暗";
        return type.getKey().getKey();
    }

    private String toRomanLevel(int level) {
        return switch (Math.max(1, level)) {
            case 1 -> " I";
            case 2 -> " II";
            case 3 -> " III";
            case 4 -> " IV";
            case 5 -> " V";
            default -> " " + level;
        };
    }

    public boolean handleSwordWaveDrop(PlayerDropItemEvent event, Player player, GameRoom room) {
        if (!isFlashCombatAvailable(player, room)) {
            return false;
        }

        ItemStack dropped = event.getItemDrop().getItemStack();
        if (handleMagicBrushConfirmDrop(event, player, room, dropped)) {
            return true;
        }
        if (handleHoeTrapDrop(event, player, room, dropped)) {
            return true;
        }
        if (!isSword(dropped)) {
            return false;
        }

        event.setCancelled(false);
        event.getItemDrop().remove();
        player.playSound(player.getLocation(), Sound.ITEM_TRIDENT_THROW, 0.9f, 1.2f);
        player.playSound(player.getLocation(), Sound.ENTITY_BREEZE_SHOOT, 0.8f, 1.35f);
        player.playSound(player.getLocation(), Sound.BLOCK_AMETHYST_CLUSTER_BREAK, 0.55f, 1.7f);
        player.getWorld().spawnParticle(Particle.ITEM, player.getLocation().add(0, 1.0, 0), 24, 0.25, 0.15, 0.25, dropped);
        player.getWorld().spawnParticle(Particle.ENCHANT, player.getEyeLocation(), 16, 0.18, 0.12, 0.18, 0.02);
        launchSwordWave(player, room, dropped.clone());
        return true;
    }

    private boolean handleHoeTrapDrop(PlayerDropItemEvent event, Player player, GameRoom room, ItemStack dropped) {
        if (!isHoe(dropped)) {
            return false;
        }
        event.setCancelled(false);
        Item item = event.getItemDrop();
        ItemStack trapHoe = dropped.clone();
        trapHoe.setAmount(1);
        item.setItemStack(trapHoe);
        item.setPickupDelay(32767);
        item.setUnlimitedLifetime(true);

        player.swingMainHand();
        player.playSound(player.getLocation(), Sound.ITEM_HOE_TILL, 0.52f, 1.48f);
        player.playSound(player.getLocation(), Sound.BLOCK_SCULK_SENSOR_CLICKING, 0.32f, 1.88f);
        player.sendActionBar("§x§8§A§F§F§D§2⌑ §f锄头已投出，落到的方块会变成 §x§B§B§8§8§F§F陷阱");
        startHoeTrapDropMonitor(player.getUniqueId(), room == null ? "standalone:" + player.getUniqueId() : room.getRoomId(), item, trapHoe);
        return true;
    }

    private void startHoeTrapDropMonitor(UUID ownerUuid, String roomId, Item item, ItemStack trapHoe) {
        new BukkitRunnable() {
            private int ticks;
            private Location lastLocation = item.getLocation().clone();

            @Override
            public void run() {
                if (!item.isValid() || item.isDead() || item.getWorld() == null) {
                    cancel();
                    return;
                }
                ticks++;
                Location current = item.getLocation().clone();
                Block trapBlock = findHoeTrapLandingBlock(lastLocation, current, item, ticks);
                if (trapBlock != null && trapBlock.getWorld() != null) {
                    item.remove();
                    createHoeTrap(ownerUuid, roomId, trapBlock, trapHoe);
                    cancel();
                    return;
                }
                if (ticks >= 100) {
                    Block fallback = findSolidBlockBelow(current, 5);
                    item.remove();
                    if (fallback != null) {
                        createHoeTrap(ownerUuid, roomId, fallback, trapHoe);
                    } else {
                        Player owner = Bukkit.getPlayer(ownerUuid);
                        if (owner != null && owner.isOnline()) {
                            owner.getWorld().dropItemNaturally(owner.getLocation(), trapHoe);
                        }
                    }
                    cancel();
                    return;
                }
                lastLocation = current;
            }
        }.runTaskTimer(plugin, 1L, 1L);
    }

    private Block findHoeTrapLandingBlock(Location from, Location current, Item item, int ticks) {
        if (from == null || current == null || current.getWorld() == null || item == null) {
            return null;
        }
        World world = current.getWorld();
        if (from.getWorld() != null && from.getWorld().equals(world)) {
            Vector travel = current.toVector().subtract(from.toVector());
            double distance = travel.length();
            if (distance > 0.035D) {
                RayTraceResult result = world.rayTraceBlocks(from, travel.normalize(), distance + 0.18D, FluidCollisionMode.NEVER, true);
                if (result != null && isValidHoeTrapBlock(result.getHitBlock())) {
                    return result.getHitBlock();
                }
            }
        }

        Block currentBlock = current.getBlock();
        if (isValidHoeTrapBlock(currentBlock)) {
            return currentBlock;
        }

        if (item.isOnGround() || (ticks > 6 && item.getVelocity().lengthSquared() < 0.006D)) {
            Block below = findSolidBlockBelow(current, 5);
            if (below != null) {
                return below;
            }
        }
        return null;
    }

    private Block findSolidBlockBelow(Location location, int maxBlocks) {
        if (location == null || location.getWorld() == null) {
            return null;
        }
        World world = location.getWorld();
        int x = location.getBlockX();
        int z = location.getBlockZ();
        int startY = Math.min(world.getMaxHeight() - 1, location.getBlockY());
        int minY = Math.max(world.getMinHeight(), startY - Math.max(1, maxBlocks));
        for (int y = startY; y >= minY; y--) {
            Block block = world.getBlockAt(x, y, z);
            if (isValidHoeTrapBlock(block)) {
                return block;
            }
        }
        return null;
    }

    private boolean isValidHoeTrapBlock(Block block) {
        if (block == null || block.getWorld() == null || block.isEmpty() || block.isLiquid() || block.isPassable()) {
            return false;
        }
        Material type = block.getType();
        if (type == Material.FARMLAND) {
            return true;
        }
        if (type.isAir() || !type.isBlock() || !type.isSolid() || isIncompleteHoeTrapMaterial(type)) {
            return false;
        }
        BoundingBox box = block.getBoundingBox();
        if (box == null) {
            return false;
        }
        double widthX = box.getMaxX() - box.getMinX();
        double widthZ = box.getMaxZ() - box.getMinZ();
        double height = box.getMaxY() - box.getMinY();
        double relativeTop = box.getMaxY() - block.getY();
        double relativeBottom = box.getMinY() - block.getY();
        return widthX >= 0.95D && widthZ >= 0.95D && height >= 0.95D
                && relativeTop >= 0.95D && relativeBottom <= 0.05D;
    }

    private boolean isIncompleteHoeTrapMaterial(Material type) {
        if (type == null) {
            return true;
        }
        String name = type.name();
        return name.endsWith("_CARPET")
                || name.endsWith("_SLAB")
                || name.endsWith("_STAIRS")
                || name.endsWith("_BUTTON")
                || name.endsWith("_PRESSURE_PLATE")
                || name.endsWith("_TRAPDOOR")
                || name.endsWith("_FENCE")
                || name.endsWith("_FENCE_GATE")
                || name.endsWith("_WALL")
                || name.endsWith("_PANE")
                || name.endsWith("_DOOR")
                || name.endsWith("_SIGN")
                || name.endsWith("_HANGING_SIGN")
                || name.endsWith("_HEAD")
                || name.endsWith("_SKULL")
                || name.equals("SNOW")
                || name.equals("POINTED_DRIPSTONE")
                || name.equals("LADDER")
                || name.equals("CHAIN")
                || name.equals("IRON_BARS")
                || name.equals("END_ROD")
                || name.equals("LIGHTNING_ROD")
                || name.equals("FLOWER_POT")
                || name.equals("DECORATED_POT")
                || name.equals("CANDLE")
                || name.endsWith("_CANDLE")
                || name.equals("SEA_PICKLE")
                || name.equals("CAKE")
                || name.endsWith("_RAIL");
    }

    private Location getHoeTrapSurfaceCenter(Block trapBlock) {
        BoundingBox box = trapBlock.getBoundingBox();
        double y = box == null ? trapBlock.getY() + 1.06D : box.getMaxY() + 0.06D;
        return new Location(trapBlock.getWorld(), trapBlock.getX() + 0.5D, y, trapBlock.getZ() + 0.5D);
    }

    private boolean isHoeTrapSurfaceStillValid(HoeTrap trap) {
        return trap != null && trap.blockLocation() != null && isValidHoeTrapBlock(trap.blockLocation().getBlock());
    }

    private void createHoeTrap(UUID ownerUuid, String roomId, Block trapBlock, ItemStack trapHoe) {
        if (ownerUuid == null || trapBlock == null || trapBlock.getWorld() == null || !isHoe(trapHoe) || !isValidHoeTrapBlock(trapBlock)) {
            return;
        }
        String finalRoomId = roomId == null || roomId.isBlank() ? "standalone:" + ownerUuid : roomId;
        if (trapBlock.getType() == Material.FARMLAND) {
            createFarmlandHoeTrapField(ownerUuid, finalRoomId, trapBlock, trapHoe);
            return;
        }
        createSingleHoeTrap(ownerUuid, finalRoomId, trapBlock, trapHoe, false);
    }

    private void createFarmlandHoeTrapField(UUID ownerUuid, String roomId, Block centerBlock, ItemStack trapHoe) {
        int created = 0;
        for (int dx = -1; dx <= 1; dx++) {
            for (int dz = -1; dz <= 1; dz++) {
                Block block = centerBlock.getRelative(dx, 0, dz);
                if (block.getType() == Material.FARMLAND && isValidHoeTrapBlock(block)) {
                    createSingleHoeTrap(ownerUuid, roomId, block, trapHoe, false);
                    created++;
                }
            }
        }
        Player owner = Bukkit.getPlayer(ownerUuid);
        if (owner != null && owner.isOnline()) {
            owner.sendActionBar("§x§8§A§F§F§D§2⌑ §f锄头落入耕地，§a" + created + " §f格耕地陷阱已铺开 §8| §e每格单次触发");
            owner.playSound(owner.getLocation(), Sound.BLOCK_SCULK_CATALYST_BLOOM, 0.42f, 1.54f);
        }
    }

    private void createSingleHoeTrap(UUID ownerUuid, String finalRoomId, Block trapBlock, ItemStack trapHoe, boolean reusable) {
        Location blockLocation = trapBlock.getLocation();
        Location center = getHoeTrapSurfaceCenter(trapBlock);
        Material hoeType = trapHoe.getType();
        boolean tmtTrap = hasTmtHoeCharge(trapHoe);
        boolean minecartTrap = hasTntMinecartHoeCharge(trapHoe);
        flashHoeTraps.put(blockKey(blockLocation), new HoeTrap(ownerUuid, finalRoomId, blockLocation.clone(), center,
                hoeType, System.currentTimeMillis(), reusable, tmtTrap, minecartTrap, 0L));

        World world = center.getWorld();
        if (world != null) {
            Particle.DustOptions dust = new Particle.DustOptions(tmtTrap ? Color.fromRGB(255, 76, 45)
                    : minecartTrap ? Color.fromRGB(255, 176, 58) : getHoeTrapColor(hoeType), 1.05F);
            world.spawnParticle(tmtTrap || minecartTrap ? Particle.FLAME : Particle.SCULK_SOUL,
                    center.clone().add(0.0D, 0.18D, 0.0D), 18, 0.30D, 0.05D, 0.30D, 0.018D);
            world.spawnParticle(Particle.DUST, center.clone().add(0.0D, 0.10D, 0.0D), 18, 0.32D, 0.03D, 0.32D, 0.0D, dust);
            world.spawnParticle(Particle.ITEM, center.clone().add(0.0D, 0.32D, 0.0D), 12, 0.20D, 0.08D, 0.20D, 0.018D, trapHoe);
            if (minecartTrap) {
                world.spawnParticle(Particle.ITEM, center.clone().add(0.0D, 0.46D, 0.0D), 7, 0.16D, 0.05D, 0.16D, 0.012D,
                        new ItemStack(Material.TNT_MINECART));
            }
            world.playSound(center, tmtTrap || minecartTrap ? Sound.ENTITY_TNT_PRIMED : Sound.BLOCK_SCULK_SENSOR_CLICKING,
                    0.52f, tmtTrap ? 1.42f : minecartTrap ? 1.18f : 1.72f);
            world.playSound(center, tmtTrap ? Sound.BLOCK_COPPER_BULB_TURN_ON
                            : minecartTrap ? Sound.BLOCK_CHAIN_PLACE : Sound.BLOCK_AMETHYST_CLUSTER_PLACE,
                    0.40f, tmtTrap ? 0.82f : minecartTrap ? 1.26f : 1.58f);
            world.playSound(center, Sound.ITEM_HOE_TILL, 0.48f, 1.42f);
        }

        Player owner = Bukkit.getPlayer(ownerUuid);
        if (!reusable && owner != null && owner.isOnline()) {
            owner.sendActionBar(tmtTrap
                    ? "§x§F§F§5§5§3§3⌑ §cTMT" + getHoeDisplayName(hoeType) + "陷阱 §f已绑定落点方块 §8| §73秒延迟爆炸"
                    : minecartTrap
                    ? "§x§F§F§A§A§4§4⌑ §eTNT矿车雷" + getHoeDisplayName(hoeType) + " §f已绑定落点方块 §8| §71.5秒延迟爆炸"
                    : "§x§8§A§F§F§D§2⌑ §x§B§B§8§8§F§F" + getHoeDisplayName(hoeType)
                    + "陷阱 §f已绑定落点方块 §8| §a永久存在");
        }
    }

    private boolean handleMagicBrushConfirmDrop(PlayerDropItemEvent event, Player player, GameRoom room, ItemStack dropped) {
        if (!isMagicBrushItem(dropped)) {
            return false;
        }

        UUID uuid = player.getUniqueId();
        BrushDrawingSession session = magicBrushDrawings.get(uuid);
        ItemStack brush = dropped.clone();
        brush.setAmount(1);
        event.setCancelled(false);
        event.getItemDrop().remove();
        player.swingMainHand();
        player.getWorld().spawnParticle(Particle.ITEM, player.getEyeLocation().add(player.getEyeLocation().getDirection().multiply(0.55D)),
                18, 0.18D, 0.12D, 0.18D, 0.02D, brush);
        player.playSound(player.getLocation(), Sound.ITEM_BRUSH_BRUSHING_GRAVEL_COMPLETE, 0.72f, 1.22f);

        if (session == null || !session.isSameWorld(player) || session.points().size() < 5) {
            sendFlashMessage(player, plugin.getConfigManager().getHunterGamePrefix() + "§x§F§F§8§8§8§8✘ §c没有检测到完整法阵，魔法画笔正在回到背包。");
            returnMagicBrushLater(player.getUniqueId(), brush, 24L);
            if (session != null) {
                clearMagicBrushDrawing(uuid, session, true);
            }
            return true;
        }

        BrushSkill skill = detectBrushSkill(session);
        if (skill == BrushSkill.NONE) {
            sendFlashMessage(player, plugin.getConfigManager().getHunterGamePrefix() + "§x§F§F§C§C§7§7✦ §e法阵图案不稳定，线条散开了。");
            clearMagicBrushDrawing(uuid, session, true);
            returnMagicBrushLater(player.getUniqueId(), brush, 30L);
            return true;
        }

        session.casting(true);
        refreshMagicBrushParticles(session, true);
        sendFlashMessage(player, plugin.getConfigManager().getHunterGamePrefix() + "§x§B§B§8§8§F§F✧ §d施法中... §7已识别 §f"
                + getMagicBrushSkillName(skill) + "§7：§x§D§2§A§6§F§4" + getMagicBrushSkillDescription(skill));
        player.sendActionBar("§x§B§B§8§8§F§F✧ §d施法中... §f" + getMagicBrushSkillName(skill));
        player.getWorld().playSound(session.origin(), Sound.BLOCK_ENCHANTMENT_TABLE_USE, 0.68f, 1.25f);
        player.getWorld().playSound(session.origin(), Sound.BLOCK_AMETHYST_BLOCK_CHIME, 0.62f, 1.85f);

        new BukkitRunnable() {
            @Override
            public void run() {
                Player online = Bukkit.getPlayer(uuid);
                BrushDrawingSession current = magicBrushDrawings.get(uuid);
                if (online == null || !online.isOnline() || current != session) {
                    return;
                }
                GameRoom activeRoom = plugin.getRoomManager().getPlayerRoom(uuid);
                if (!isFlashCombatAvailable(online, activeRoom) || !current.isSameWorld(online)) {
                    clearMagicBrushDrawing(uuid, current, true);
                    return;
                }
                executeMagicBrushSkill(online, activeRoom, current, skill);
                clearMagicBrushDrawing(uuid, current, true);
            }
        }.runTaskLater(plugin, MAGIC_BRUSH_CAST_DELAY_TICKS);

        returnMagicBrushLater(uuid, brush, MAGIC_BRUSH_RETURN_DELAY_TICKS);
        return true;
    }

    private void returnMagicBrushLater(UUID playerId, ItemStack brush, long delayTicks) {
        if (playerId == null || brush == null || brush.getType() == Material.AIR) {
            return;
        }
        new BukkitRunnable() {
            @Override
            public void run() {
                Player player = Bukkit.getPlayer(playerId);
                if (player == null || !player.isOnline()) {
                    return;
                }
                applyMagicBrushUseComponent(brush);
                Map<Integer, ItemStack> leftover = player.getInventory().addItem(brush.clone());
                if (!leftover.isEmpty()) {
                    for (ItemStack item : leftover.values()) {
                        player.getWorld().dropItemNaturally(player.getLocation(), item);
                    }
                }
                player.playSound(player.getLocation(), Sound.ITEM_TRIDENT_RETURN, 0.62f, 1.62f);
                player.sendActionBar("§x§D§2§A§6§F§4✎ §f魔法画笔已回到背包");
            }
        }.runTaskLater(plugin, Math.max(1L, delayTicks));
    }

    public void applyMeleeUpgradeBonus(EntityDamageByEntityEvent event, Player attacker, LivingEntity victim, GameRoom room) {
        if (!isFlashCombatAvailable(attacker, room)) {
            return;
        }
        normalizeHeldRedstoneStabilizers(attacker);
        normalizeUnstableCoreShieldBlockingDelay(attacker);
        if (victim instanceof Player victimPlayer) {
            normalizeUnstableCoreShieldBlockingDelay(victimPlayer);
        }
        if (event.getDamager() instanceof Trident trident) {
            applyUpgradedTridentSharpness(event, trident, attacker);
        }
        if (event.getDamager() instanceof Player) {
            suppressQuickSwapAttributeInheritance(event, attacker);
            boolean maceShieldBreak = applyFlashMaceSmash(event, attacker, victim, room);
            applyFlashHoeMaterialDamage(event, attacker);
            applyMaterialAxeBonus(event, attacker, victim);
            applySwordPotionHit(event, attacker, victim, room);
            applyStormSwordKineticDamage(event, attacker, victim);
            applySwordReturnPointHit(attacker, victim, room);
            if (!maceShieldBreak) {
                applyFlashShieldBreak(event, attacker, victim, room);
            }
        }
        applyJukeboxAuraCombat(event, attacker, victim);
        applyOutgoingPlayerDamageRules(event, attacker, victim);
        applyMaterialArmorReduction(event, victim, room);
        // 最新规则：附魔改装 + 爆炸保护不再在近战命中生物时触发爆炸。
    }

    public void handleFlashTamedMountControl(PlayerMoveEvent event, Player player, GameRoom room) {
        if (!isFlashCombatAvailable(player, room) || !(player.getVehicle() instanceof LivingEntity pet) || !isFlashTamedBy(pet, player)) {
            return;
        }
        if (!(pet instanceof Skeleton || pet instanceof Enderman || pet instanceof Zombie)) {
            return;
        }

        org.bukkit.Input input = player.getCurrentInput();
        Vector direction = player.getLocation().getDirection();
        direction.setY(0.0D);
        if (direction.lengthSquared() < 0.0001D) {
            direction = pet.getLocation().getDirection();
            direction.setY(0.0D);
        }
        if (direction.lengthSquared() < 0.0001D) {
            direction = new Vector(0.0D, 0.0D, 1.0D);
        }
        direction.normalize();
        Vector right = new Vector(-direction.getZ(), 0.0D, direction.getX()).normalize();

        Vector move = new Vector();
        if (input.isForward()) {
            move.add(direction);
        }
        if (input.isBackward()) {
            move.subtract(direction.clone().multiply(0.65D));
        }
        if (input.isLeft()) {
            move.subtract(right.clone().multiply(0.72D));
        }
        if (input.isRight()) {
            move.add(right.clone().multiply(0.72D));
        }

        double speed = pet instanceof Enderman ? 0.36D : pet instanceof Zombie ? 0.29D : 0.31D;
        if (input.isSprint()) {
            speed *= 1.35D;
        }
        Vector velocity = pet.getVelocity();
        if (move.lengthSquared() > 0.0001D) {
            move.normalize().multiply(speed);
            velocity.setX(move.getX());
            velocity.setZ(move.getZ());
            pet.setRotation(player.getLocation().getYaw(), pet.getLocation().getPitch());
            if (pet instanceof Mob mob) {
                mob.setTarget(null);
                mob.getPathfinder().stopPathfinding();
            }
        } else {
            velocity.setX(velocity.getX() * 0.55D);
            velocity.setZ(velocity.getZ() * 0.55D);
        }
        if (input.isJump() && pet.isOnGround()) {
            velocity.setY(0.42D);
        }
        pet.setVelocity(velocity);
    }

    public void prepareSpearKineticThreshold(Player player, GameRoom room) {
        if (!isFlashCombatAvailable(player, room)) {
            return;
        }
        PlayerInventory inventory = player.getInventory();
        rememberAttackWeapon(player, inventory.getItemInMainHand());
        boostSpearKineticWeapon(inventory.getItemInMainHand());
        boostSpearKineticWeapon(inventory.getItemInOffHand());
    }

    public void markQuickSwapAttributeCorrection(Player player, ItemStack attackWeapon) {
        if (player == null || attackWeapon == null || attackWeapon.getType() == Material.AIR) {
            return;
        }
        ItemStack copy = attackWeapon.clone();
        copy.setAmount(1);
        pendingQuickSwapAttributeCorrections.put(player.getUniqueId(), new AttackWeaponSnapshot(copy, System.currentTimeMillis()));
    }

    public boolean handleDragonBreathWeaponInfusion(InventoryClickEvent event, Player player, GameRoom room) {
        if (!isFlashCombatAvailable(player, room) || !event.getClick().isRightClick()) {
            return false;
        }
        if (event.getClickedInventory() == null || event.getClickedInventory().getHolder() != player) {
            return false;
        }

        ItemStack cursor = event.getCursor();
        ItemStack current = event.getCurrentItem();
        if (isDragonBreathItem(cursor) && isBowOrCrossbow(current)) {
            event.setCancelled(true);
            ItemStack upgraded = applyDragonBreathWeaponMark(current);
            if (upgraded == null) {
                sendFlashMessage(player, plugin.getConfigManager().getHunterGamePrefix() + "§x§F§F§B§B§6§6✦ §e这把武器已经注入过龙息了。");
                player.playSound(player.getLocation(), Sound.BLOCK_NOTE_BLOCK_BASS, 0.75f, 0.9f);
                return true;
            }
            event.setCurrentItem(upgraded);
            consumeDragonBreathCursor(event, player, cursor);
            playDragonBreathInfusionFeedback(player, upgraded.getType());
            return true;
        }

        if (isDragonBreathItem(current) && isBowOrCrossbow(cursor)) {
            event.setCancelled(true);
            ItemStack upgraded = applyDragonBreathWeaponMark(cursor);
            if (upgraded == null) {
                sendFlashMessage(player, plugin.getConfigManager().getHunterGamePrefix() + "§x§F§F§B§B§6§6✦ §e这把武器已经注入过龙息了。");
                player.playSound(player.getLocation(), Sound.BLOCK_NOTE_BLOCK_BASS, 0.75f, 0.9f);
                return true;
            }
            event.setCursor(upgraded);
            consumeDragonBreathCurrent(event, player, current);
            playDragonBreathInfusionFeedback(player, upgraded.getType());
            return true;
        }
        return false;
    }

    public boolean handleMaterialUpgradeInfusion(InventoryClickEvent event, Player player, GameRoom room) {
        if (!isFlashCombatAvailable(player, room) || !event.getClick().isRightClick()) {
            return false;
        }
        if (event.getClickedInventory() == null || event.getClickedInventory().getHolder() != player) {
            return false;
        }

        ItemStack cursor = event.getCursor();
        ItemStack current = event.getCurrentItem();
        if (isEmpty(cursor) || isEmpty(current)) {
            return false;
        }
        if (normalizeRedstoneStabilizerItem(current)) {
            event.setCurrentItem(current);
        }
        if (normalizeRedstoneStabilizerItem(cursor)) {
            event.setCursor(cursor);
        }

        StormEquipmentUpgradeMatch cursorStormMatch = createStormEquipmentUpgrade(current, cursor);
        if (cursorStormMatch != null) {
            event.setCancelled(true);
            event.setCurrentItem(cursorStormMatch.result());
            consumeCursorItem(event, cursor);
            playStormEquipmentFeedback(player, cursorStormMatch);
            return true;
        }

        StormEquipmentUpgradeMatch currentStormMatch = createStormEquipmentUpgrade(cursor, current);
        if (currentStormMatch != null) {
            event.setCancelled(true);
            event.setCursor(currentStormMatch.result());
            consumeCurrentItem(event, current);
            playStormEquipmentFeedback(player, currentStormMatch);
            return true;
        }

        WindRodUpgradeMatch cursorWindRodMatch = createWindRodUpgrade(current, cursor.getType());
        if (cursorWindRodMatch != null) {
            event.setCancelled(true);
            event.setCurrentItem(cursorWindRodMatch.result());
            consumeCursorItem(event, cursor);
            playWindRodUpgradeFeedback(player, cursorWindRodMatch);
            return true;
        }

        WindRodUpgradeMatch currentWindRodMatch = createWindRodUpgrade(cursor, current.getType());
        if (currentWindRodMatch != null) {
            event.setCancelled(true);
            event.setCursor(currentWindRodMatch.result());
            consumeCurrentItem(event, current);
            playWindRodUpgradeFeedback(player, currentWindRodMatch);
            return true;
        }

        RedstoneStabilizerMatch cursorStabilizerMatch = createRedstoneStabilizerUpgrade(current, cursor.getType());
        if (cursorStabilizerMatch != null) {
            event.setCancelled(true);
            event.setCurrentItem(cursorStabilizerMatch.result());
            consumeCursorItem(event, cursor);
            playRedstoneStabilizerFeedback(player, cursorStabilizerMatch);
            return true;
        }

        RedstoneStabilizerMatch currentStabilizerMatch = createRedstoneStabilizerUpgrade(cursor, current.getType());
        if (currentStabilizerMatch != null) {
            event.setCancelled(true);
            event.setCursor(currentStabilizerMatch.result());
            consumeCurrentItem(event, current);
            playRedstoneStabilizerFeedback(player, currentStabilizerMatch);
            return true;
        }

        MaterialUpgradeMatch cursorMaterialMatch = createMaterialUpgrade(current, cursor.getType());
        if (cursorMaterialMatch != null) {
            event.setCancelled(true);
            event.setCurrentItem(cursorMaterialMatch.result());
            consumeCursorItem(event, cursor);
            playMaterialUpgradeFeedback(player, cursorMaterialMatch);
            return true;
        }

        MaterialUpgradeMatch currentMaterialMatch = createMaterialUpgrade(cursor, current.getType());
        if (currentMaterialMatch != null) {
            event.setCancelled(true);
            event.setCursor(currentMaterialMatch.result());
            consumeCurrentItem(event, current);
            playMaterialUpgradeFeedback(player, currentMaterialMatch);
            return true;
        }
        if ((isArmor(current) && cursor.getType() == Material.TNT && getTntArmorLayers(current) >= TNT_ARMOR_MAX_LAYERS)
                || (isArmor(cursor) && current.getType() == Material.TNT && getTntArmorLayers(cursor) >= TNT_ARMOR_MAX_LAYERS)) {
            event.setCancelled(true);
            sendFlashMessage(player, plugin.getConfigManager().getHunterGamePrefix()
                    + "§x§F§F§B§B§6§6✦ §e这件盔甲的 TNT 材料强化已经满了§7（§f"
                    + TNT_ARMOR_MAX_LAYERS + "§7/§f" + TNT_ARMOR_MAX_LAYERS + "§7）。");
            player.playSound(player.getLocation(), Sound.BLOCK_NOTE_BLOCK_BASS, 0.68f, 0.82f);
            return true;
        }
        return false;
    }

    private StormEquipmentUpgradeMatch createStormEquipmentUpgrade(ItemStack equipment, ItemStack catalyst) {
        if (isEmpty(equipment) || !isEnhancedWindCharge(catalyst)) {
            return null;
        }
        if (isSword(equipment)) {
            ItemStack result = tryApplyStormToSword(equipment);
            if (result == null) {
                return null;
            }
            return new StormEquipmentUpgradeMatch(result, hasStormSwordKinetic(result) ? "风暴矛势" : "风暴剑", getStormSwordLevel(result));
        }
        if (isChestplate(equipment) && !isStormChestplate(equipment)) {
            ItemStack result = equipment.clone();
            ItemMeta meta = result.getItemMeta();
            if (meta == null) {
                return null;
            }
            meta.getPersistentDataContainer().set(stormChestplateResistKey, PersistentDataType.BYTE, (byte) 1);
            List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
            lore.removeIf(STORM_CHESTPLATE_LINE::equals);
            lore.add(STORM_CHESTPLATE_LINE);
            meta.setLore(lore);
            result.setItemMeta(meta);
            return new StormEquipmentUpgradeMatch(result, "风暴胸甲", 0);
        }
        return null;
    }

    private EquipmentSlot getArmorEquipmentSlot(Material armorType) {
        if (armorType == null) {
            return null;
        }
        String name = armorType.name();
        if (name.endsWith("_HELMET")) {
            return EquipmentSlot.HEAD;
        }
        if (name.endsWith("_CHESTPLATE") || armorType == Material.ELYTRA) {
            return EquipmentSlot.CHEST;
        }
        if (name.endsWith("_LEGGINGS")) {
            return EquipmentSlot.LEGS;
        }
        if (name.endsWith("_BOOTS")) {
            return EquipmentSlot.FEET;
        }
        return null;
    }

    private ItemStack tryApplyStormToSword(ItemStack sword) {
        if (!isSword(sword)) {
            return null;
        }
        int currentLevel = getStormSwordLevel(sword);
        boolean kinetic = hasStormSwordKinetic(sword);
        if (currentLevel > 0 && kinetic) {
            return null;
        }
        ItemStack result = sword.clone();
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return null;
        }
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line != null && (line.startsWith(STORM_SWORD_LINE_PREFIX) || line.equals(STORM_SWORD_KINETIC_LINE)));
        if (currentLevel <= 0) {
            int rolledLevel = rollStormSwordLevel();
            meta.getPersistentDataContainer().set(stormSwordLevelKey, PersistentDataType.INTEGER, rolledLevel);
            applyStormSwordEnchantment(meta, rolledLevel);
            lore.add(STORM_SWORD_LINE_PREFIX + " " + toRoman(rolledLevel) + "：§7风弹脉冲已接入剑身");
        } else {
            meta.getPersistentDataContainer().set(stormSwordLevelKey, PersistentDataType.INTEGER, currentLevel);
            meta.getPersistentDataContainer().set(stormSwordKineticKey, PersistentDataType.BYTE, (byte) 1);
            applyStormSwordEnchantment(meta, currentLevel);
            lore.add(STORM_SWORD_LINE_PREFIX + " " + toRoman(currentLevel) + "：§7风弹脉冲已接入剑身");
            lore.add(STORM_SWORD_KINETIC_LINE);
        }
        meta.setLore(lore);
        result.setItemMeta(meta);
        return result;
    }

    private void applyStormSwordEnchantment(ItemMeta meta, int level) {
        if (meta == null) {
            return;
        }
        int safeLevel = Math.max(1, Math.min(3, level));
        meta.addEnchant(Enchantment.WIND_BURST, safeLevel, true);
    }

    private int rollStormSwordLevel() {
        double roll = ThreadLocalRandom.current().nextDouble();
        if (roll < 0.06D) {
            return 3;
        }
        if (roll < 0.30D) {
            return 2;
        }
        return 1;
    }

    private String toRoman(int level) {
        return switch (Math.max(1, Math.min(3, level))) {
            case 3 -> "III";
            case 2 -> "II";
            default -> "I";
        };
    }

    private void playStormEquipmentFeedback(Player player, StormEquipmentUpgradeMatch match) {
        if (player == null || match == null) {
            return;
        }
        String suffix = match.level() > 0 ? " §7等级 §b" + toRoman(match.level()) : "";
        sendFlashMessage(player, plugin.getConfigManager().getHunterGamePrefix()
                + "§x§B§B§F§F§F§F✦ §b强化风弹已接入 §f" + match.kind() + suffix + "§b。");
        player.playSound(player.getLocation(), Sound.ENTITY_BREEZE_WIND_BURST, 0.72f, 1.55f);
        player.playSound(player.getLocation(), Sound.BLOCK_AMETHYST_BLOCK_CHIME, 0.48f, 1.86f);
        player.getWorld().spawnParticle(Particle.GUST, player.getLocation().add(0.0D, 1.05D, 0.0D),
                28, 0.32D, 0.20D, 0.32D, 0.06D);
        player.getWorld().spawnParticle(Particle.ELECTRIC_SPARK, player.getLocation().add(0.0D, 1.05D, 0.0D),
                16, 0.25D, 0.16D, 0.25D, 0.035D);
    }

    private RedstoneStabilizerMatch createRedstoneStabilizerUpgrade(ItemStack weapon, Material material) {
        if (isEmpty(weapon) || material != Material.REDSTONE || (!isSword(weapon) && !isAxe(weapon)) || hasPersistentByte(weapon, redstoneStabilizerKey)) {
            return null;
        }
        ItemStack result = weapon.clone();
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return null;
        }
        meta.getPersistentDataContainer().set(redstoneStabilizerKey, PersistentDataType.BYTE, (byte) 1);
        applyRedstoneStabilizerAttackSpeedModifier(meta, weapon.getType());
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(REDSTONE_STABILIZER_LINE::equals);
        lore.add(REDSTONE_STABILIZER_LINE);
        meta.setLore(lore);
        result.setItemMeta(meta);
        return new RedstoneStabilizerMatch(isSword(weapon) ? "剑稳定器" : "斧稳定器", result);
    }

    private void applyRedstoneStabilizerAttackSpeedModifier(ItemMeta meta, Material weaponType) {
        removeAttributeModifierByKey(meta, Attribute.ATTACK_SPEED, redstoneStabilizerAttackSpeedModifierKey);
        double modifierAmount = calculateRedstoneStabilizerAttackSpeedModifier(meta, weaponType);
        meta.addAttributeModifier(Attribute.ATTACK_SPEED, new AttributeModifier(
                redstoneStabilizerAttackSpeedModifierKey,
                modifierAmount,
                AttributeModifier.Operation.ADD_NUMBER,
                EquipmentSlotGroup.MAINHAND
        ));
    }

    private double calculateRedstoneStabilizerAttackSpeedModifier(ItemMeta meta, Material weaponType) {
        double vanillaAttackSpeed = getDefaultMainHandAttributeAmount(
                weaponType,
                Attribute.ATTACK_SPEED,
                getFallbackMainHandAttackSpeed(weaponType)
        );
        boolean hasExplicitSpeed = hasAttackSpeedModifierExceptRedstone(meta);
        double currentAttackSpeed = hasExplicitSpeed
                ? getAttackSpeedAfterExistingModifiers(meta, vanillaAttackSpeed)
                : vanillaAttackSpeed;
        double targetAttackSpeed = Math.max(0.1D, currentAttackSpeed * (1.0D + REDSTONE_STABILIZER_ATTACK_SPEED_BONUS));

        // 1.21 的物品属性组件会以显式属性覆盖默认武器属性。
        // 如果红石稳定器是这把武器的第一个攻速属性，必须写入「目标攻速 - 玩家基础4.0」，
        // 不能只写 +0.16/+0.1，否则会把剑/斧的原版负攻速覆盖掉，导致攻速接近 4.0+。
        return hasExplicitSpeed ? targetAttackSpeed - currentAttackSpeed : targetAttackSpeed - 4.0D;
    }

    public void normalizeHeldRedstoneStabilizers(Player player) {
        if (player == null) {
            return;
        }
        PlayerInventory inventory = player.getInventory();
        boolean changed = false;
        ItemStack mainHand = inventory.getItemInMainHand();
        if (normalizeRedstoneStabilizerItem(mainHand)) {
            inventory.setItemInMainHand(mainHand);
            changed = true;
        }
        ItemStack offHand = inventory.getItemInOffHand();
        if (normalizeRedstoneStabilizerItem(offHand)) {
            inventory.setItemInOffHand(offHand);
            changed = true;
        }
        if (changed) {
            player.updateInventory();
        }
    }

    private boolean normalizeRedstoneStabilizerItem(ItemStack item) {
        if (isEmpty(item) || (!isSword(item) && !isAxe(item)) || !hasPersistentByte(item, redstoneStabilizerKey)) {
            return false;
        }
        ItemMeta meta = item.getItemMeta();
        if (meta == null) {
            return false;
        }

        double expectedAmount = calculateRedstoneStabilizerAttackSpeedModifier(meta, item.getType());
        Collection<AttributeModifier> modifiers = meta.getAttributeModifiers(Attribute.ATTACK_SPEED);
        boolean alreadyCorrect = false;
        int redstoneModifierCount = 0;
        if (modifiers != null) {
            for (AttributeModifier modifier : modifiers) {
                if (modifier.getKey().equals(redstoneStabilizerAttackSpeedModifierKey)) {
                    redstoneModifierCount++;
                    if (modifier.getOperation() == AttributeModifier.Operation.ADD_NUMBER
                            && Math.abs(modifier.getAmount() - expectedAmount) < 0.000001D) {
                        alreadyCorrect = true;
                    }
                }
            }
        }
        if (alreadyCorrect && redstoneModifierCount == 1) {
            return false;
        }

        applyRedstoneStabilizerAttackSpeedModifier(meta, item.getType());
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(REDSTONE_STABILIZER_LINE::equals);
        lore.add(REDSTONE_STABILIZER_LINE);
        meta.setLore(lore);
        item.setItemMeta(meta);
        return true;
    }

    private void removeAttributeModifierByKey(ItemMeta meta, Attribute attribute, NamespacedKey key) {
        if (meta == null || attribute == null || key == null || !meta.hasAttributeModifiers()) {
            return;
        }
        Collection<AttributeModifier> modifiers = meta.getAttributeModifiers(attribute);
        if (modifiers == null || modifiers.isEmpty()) {
            return;
        }
        for (AttributeModifier modifier : new ArrayList<>(modifiers)) {
            if (modifier.getKey().equals(key)) {
                meta.removeAttributeModifier(attribute, modifier);
            }
        }
    }

    private double getAttackSpeedAfterExistingModifiers(ItemMeta meta, double baseAttackSpeed) {
        if (meta == null || !meta.hasAttributeModifiers()) {
            return baseAttackSpeed;
        }
        Collection<AttributeModifier> modifiers = meta.getAttributeModifiers(Attribute.ATTACK_SPEED);
        if (modifiers == null || modifiers.isEmpty()) {
            return baseAttackSpeed;
        }
        double value = 4.0D;
        double addScalar = 0.0D;
        double multiplyScalar = 1.0D;
        boolean hasExplicitSpeed = false;
        for (AttributeModifier modifier : modifiers) {
            if (modifier.getKey().equals(redstoneStabilizerAttackSpeedModifierKey)) {
                continue;
            }
            hasExplicitSpeed = true;
            if (modifier.getOperation() == AttributeModifier.Operation.ADD_NUMBER) {
                value += modifier.getAmount();
            } else if (modifier.getOperation() == AttributeModifier.Operation.ADD_SCALAR) {
                addScalar += modifier.getAmount();
            } else if (modifier.getOperation() == AttributeModifier.Operation.MULTIPLY_SCALAR_1) {
                multiplyScalar *= 1.0D + modifier.getAmount();
            }
        }
        if (addScalar != 0.0D) {
            value += value * addScalar;
        }
        value *= multiplyScalar;
        return hasExplicitSpeed ? Math.max(0.1D, value) : baseAttackSpeed;
    }

    private boolean hasAttackSpeedModifierExceptRedstone(ItemMeta meta) {
        if (meta == null || !meta.hasAttributeModifiers()) {
            return false;
        }
        Collection<AttributeModifier> modifiers = meta.getAttributeModifiers(Attribute.ATTACK_SPEED);
        if (modifiers == null || modifiers.isEmpty()) {
            return false;
        }
        for (AttributeModifier modifier : modifiers) {
            if (!modifier.getKey().equals(redstoneStabilizerAttackSpeedModifierKey)) {
                return true;
            }
        }
        return false;
    }

