    private MaterialUpgradeMatch createMaterialUpgrade(ItemStack equipment, Material material) {
        if (isEmpty(equipment) || material == null || material == Material.AIR) {
            return null;
        }
        ItemStack swordResult = tryApplyMaterialSwordUpgrade(equipment, material);
        if (swordResult != null) {
            SwordMaterialUpgrade upgrade = getSwordMaterialUpgrade(equipment.getType(), material);
            return new MaterialUpgradeMatch(swordResult, "剑", upgrade == null ? 0.0D : upgrade.speedBonus(), upgrade == null ? 0.0D : upgrade.damagePenalty());
        }
        ItemStack axeResult = tryApplyMaterialAxeUpgrade(equipment, material);
        if (axeResult != null) {
            AxeMaterialUpgrade upgrade = getAxeMaterialUpgrade(equipment.getType(), material);
            return new MaterialUpgradeMatch(axeResult, "斧头", upgrade == null ? 0.0D : upgrade.damageBonus(), upgrade == null ? 0.0D : upgrade.cooldownIncrease());
        }
        ItemStack armorResult = tryApplyMaterialArmorUpgrade(equipment, material);
        if (armorResult != null) {
            return new MaterialUpgradeMatch(armorResult, "护甲", getMaterialArmorAxeBonusReduction(equipment), 0.0D);
        }
        ItemStack tntArmorResult = tryApplyTntArmorUpgrade(equipment, material);
        if (tntArmorResult != null) {
            return new MaterialUpgradeMatch(tntArmorResult, "TNT护甲", TNT_ARMOR_EXPLOSION_IMMUNITY_PER_LAYER, 0.0D);
        }
        ItemStack bootSilentResult = tryApplyBootSilentLayer(equipment, material);
        if (bootSilentResult != null) {
            double ready = isBootSilentReady(bootSilentResult) ? 0.40D : 0.0D;
            return new MaterialUpgradeMatch(bootSilentResult, "轻步鞋", ready, 0.0D);
        }
        ItemStack tridentResult = tryApplyPrismarineTridentUpgrade(equipment, material);
        if (tridentResult != null) {
            return new MaterialUpgradeMatch(tridentResult, "三叉戟", 0.25D, 0.0D);
        }
        ItemStack crossbowResult = tryApplyAmethystCrossbowUpgrade(equipment, material);
        if (crossbowResult != null) {
            return new MaterialUpgradeMatch(crossbowResult, "弩", 0.125D, 0.0D);
        }
        return null;
    }

    private ItemStack tryApplyMaterialSwordUpgrade(ItemStack sword, Material material) {
        SwordMaterialUpgrade upgrade = getSwordMaterialUpgrade(sword.getType(), material);
        if (upgrade == null || hasPersistentDouble(sword, materialSwordSpeedBonusKey)) {
            return null;
        }
        ItemStack result = sword.clone();
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return null;
        }
        meta.getPersistentDataContainer().set(materialSwordSpeedBonusKey, PersistentDataType.DOUBLE, upgrade.speedBonus());
        meta.getPersistentDataContainer().set(materialSwordDamagePenaltyKey, PersistentDataType.DOUBLE, upgrade.damagePenalty());
        applyMaterialSwordAttributeModifiers(meta, sword.getType(), upgrade.speedBonus(), upgrade.damagePenalty());
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line.startsWith(SWORD_MATERIAL_PREFIX));
        lore.removeIf(line -> line.startsWith(SWORD_MATERIAL_DAMAGE_LINE_PREFIX));
        lore.add(SWORD_MATERIAL_PREFIX + " §f攻击速度 +" + formatPercent(upgrade.speedBonus()) + "§8 / §f伤害 -" + formatPercent(upgrade.damagePenalty()));
        lore.add(SWORD_MATERIAL_DAMAGE_LINE_PREFIX + "§f" + formatPercent(upgrade.damagePenalty()));
        meta.setLore(lore);
        result.setItemMeta(meta);
        return result;
    }

    private void applyMaterialSwordAttributeModifiers(ItemMeta meta, Material swordType, double speedBonus, double damagePenalty) {
        removeAttributeModifierByKey(meta, Attribute.ATTACK_DAMAGE, materialSwordDamageModifierKey);
        removeAttributeModifierByKey(meta, Attribute.ATTACK_SPEED, materialSwordAttackSpeedModifierKey);

        double baseAttackDamage = getDefaultMainHandAttributeAmount(swordType, Attribute.ATTACK_DAMAGE, 1.0D);
        double targetAttackDamage = Math.max(1.0D, baseAttackDamage * (1.0D - Math.max(0.0D, Math.min(0.85D, damagePenalty))));
        meta.addAttributeModifier(Attribute.ATTACK_DAMAGE, new AttributeModifier(
                materialSwordDamageModifierKey,
                Math.max(0.0D, targetAttackDamage - 1.0D),
                AttributeModifier.Operation.ADD_NUMBER,
                EquipmentSlotGroup.MAINHAND
        ));

        double baseAttackSpeed = getDefaultMainHandAttributeAmount(swordType, Attribute.ATTACK_SPEED, 1.6D);
        double targetAttackSpeed = Math.max(0.1D, baseAttackSpeed * (1.0D + Math.max(0.0D, speedBonus)));
        meta.addAttributeModifier(Attribute.ATTACK_SPEED, new AttributeModifier(
                materialSwordAttackSpeedModifierKey,
                targetAttackSpeed - 4.0D,
                AttributeModifier.Operation.ADD_NUMBER,
                EquipmentSlotGroup.MAINHAND
        ));
    }

    private ItemStack tryApplyMaterialAxeUpgrade(ItemStack axe, Material material) {
        AxeMaterialUpgrade upgrade = getAxeMaterialUpgrade(axe.getType(), material);
        if (upgrade == null || hasPersistentDouble(axe, materialAxeDamageBonusKey)) {
            return null;
        }
        ItemStack result = axe.clone();
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return null;
        }
        meta.getPersistentDataContainer().set(materialAxeDamageBonusKey, PersistentDataType.DOUBLE, upgrade.damageBonus());
        meta.getPersistentDataContainer().set(materialAxeCooldownIncreaseKey, PersistentDataType.DOUBLE, upgrade.cooldownIncrease());
        applyMaterialAxeAttackSpeedModifier(meta, axe.getType(), upgrade.damageBonus(), upgrade.cooldownIncrease());
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line.startsWith(AXE_MATERIAL_PREFIX));
        lore.removeIf(line -> line.startsWith(MATERIAL_AXE_SPEED_LINE_PREFIX));
        lore.add(AXE_MATERIAL_PREFIX + " §f伤害 +" + formatPercent(upgrade.damageBonus()) + "§8 / §f额外冷却 +" + formatPercent(upgrade.cooldownIncrease()));
        lore.add(MATERIAL_AXE_SPEED_LINE_PREFIX + "§f" + formatPercent(upgrade.cooldownIncrease()));
        meta.setLore(lore);
        result.setItemMeta(meta);
        return result;
    }

    private void applyMaterialAxeAttackSpeedModifier(ItemMeta meta, Material axeType, double damageBonus, double cooldownIncrease) {
        removeAttributeModifierByKey(meta, Attribute.ATTACK_DAMAGE, materialAxeDamageBonusKey);
        removeAttributeModifierByKey(meta, Attribute.ATTACK_SPEED, materialAxeAttackSpeedModifierKey);
        double baseAttackDamage = getDefaultMainHandAttributeAmount(axeType, Attribute.ATTACK_DAMAGE, 1.0D);
        double targetAttackDamage = baseAttackDamage * (1.0D + Math.max(0.0D, damageBonus));
        meta.addAttributeModifier(Attribute.ATTACK_DAMAGE, new AttributeModifier(
                materialAxeDamageBonusKey,
                Math.max(0.0D, targetAttackDamage - 1.0D),
                AttributeModifier.Operation.ADD_NUMBER,
                EquipmentSlotGroup.MAINHAND
        ));
        double baseAttackSpeed = getDefaultMainHandAttributeAmount(axeType, Attribute.ATTACK_SPEED, getFallbackMainHandAttackSpeed(axeType));
        double targetAttackSpeed = baseAttackSpeed / (1.0D + Math.max(0.0D, cooldownIncrease));
        double modifierAmount = targetAttackSpeed - 4.0D;
        meta.addAttributeModifier(Attribute.ATTACK_SPEED, new AttributeModifier(
                materialAxeAttackSpeedModifierKey,
                modifierAmount,
                AttributeModifier.Operation.ADD_NUMBER,
                EquipmentSlotGroup.MAINHAND
        ));
    }

    private double getDefaultMainHandAttributeAmount(Material material, Attribute attribute, double fallback) {
        var modifiers = material.getDefaultAttributeModifiers(EquipmentSlot.HAND).get(attribute);
        if (modifiers == null || modifiers.isEmpty()) {
            return fallback;
        }
        double value = attribute == Attribute.ATTACK_DAMAGE ? 1.0D : attribute == Attribute.ATTACK_SPEED ? 4.0D : fallback;
        double addScalar = 0.0D;
        double multiplyScalar = 1.0D;
        for (AttributeModifier modifier : modifiers) {
            if (modifier.getOperation() == AttributeModifier.Operation.ADD_NUMBER) {
                value += modifier.getAmount();
            } else if (modifier.getOperation() == AttributeModifier.Operation.ADD_SCALAR) {
                addScalar += modifier.getAmount();
            } else if (modifier.getOperation() == AttributeModifier.Operation.MULTIPLY_SCALAR_1) {
                multiplyScalar *= 1.0D + modifier.getAmount();
            }
        }
        if (addScalar != 0.0D) {
            value += value * addScalar;
        }
        value *= multiplyScalar;
        return Math.max(0.1D, value);
    }

    private double getFallbackMainHandAttackSpeed(Material material) {
        if (material == null) {
            return 1.6D;
        }
        String name = material.name();
        if (name.endsWith("_SWORD")) {
            return 1.6D;
        }
        return switch (material) {
            case WOODEN_AXE, STONE_AXE -> 0.8D;
            case IRON_AXE, COPPER_AXE -> 0.9D;
            case GOLDEN_AXE, DIAMOND_AXE, NETHERITE_AXE -> 1.0D;
            default -> 1.6D;
        };
    }

    private ItemStack tryApplyMaterialArmorUpgrade(ItemStack armor, Material material) {
        if (!isArmor(armor) || !isArmorUpgradeMaterial(armor.getType(), material) || hasPersistentByte(armor, materialArmorLayerKey)) {
            return null;
        }
        ItemStack result = armor.clone();
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return null;
        }
        meta.getPersistentDataContainer().set(materialArmorLayerKey, PersistentDataType.BYTE, (byte) 1);
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        double axeBonusReduction = getMaterialArmorAxeBonusReduction(armor);
        lore.removeIf(line -> line != null && line.startsWith(ARMOR_MATERIAL_LINE_PREFIX));
        lore.add(ARMOR_MATERIAL_LINE_PREFIX + "§f斧增伤抵消 +" + formatPercent(axeBonusReduction) + "§8 / §f通用免伤 +" + formatPercent(MATERIAL_ARMOR_GENERAL_DAMAGE_REDUCTION_PER_PIECE));
        meta.setLore(lore);
        result.setItemMeta(meta);
        return result;
    }

    private ItemStack tryApplyTntArmorUpgrade(ItemStack armor, Material material) {
        if (!isArmor(armor) || material != Material.TNT) {
            return null;
        }
        int currentLayers = getTntArmorLayers(armor);
        if (currentLayers >= TNT_ARMOR_MAX_LAYERS) {
            return null;
        }
        int nextLayers = currentLayers + 1;
        ItemStack result = armor.clone();
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return null;
        }
        meta.getPersistentDataContainer().set(tntArmorExplosionImmunityLayersKey, PersistentDataType.INTEGER, nextLayers);
        refreshTntArmorLore(meta, nextLayers);
        result.setItemMeta(meta);
        return result;
    }

    private void refreshTntArmorLore(ItemMeta meta, int layers) {
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line != null && (line.startsWith(TNT_ARMOR_LINE_PREFIX) || line.contains("TNT材料强化")));
        double immunity = Math.min(TNT_ARMOR_MAX_LAYERS, Math.max(0, layers)) * TNT_ARMOR_EXPLOSION_IMMUNITY_PER_LAYER;
        lore.add(TNT_ARMOR_LINE_PREFIX + "§f" + layers + "§7/§f" + TNT_ARMOR_MAX_LAYERS
                + " §8| §7爆炸免疫 §a+" + formatPercent(immunity));
        meta.setLore(lore);
    }

    private void applyAnvilLocationDataIfNeeded(AnvilInventory anvil, ItemStack result) {
        if (!isSword(result) || anvil == null) {
            return;
        }
        ItemMeta meta = result.getItemMeta();
        if (meta == null || !meta.getPersistentDataContainer().has(swordReturnWorldKey, PersistentDataType.STRING)) {
            return;
        }
        Location location = anvil.getLocation();
        if (location == null || location.getWorld() == null) {
            return;
        }
        Location returnLocation = location.clone().add(0.5D, 1.0D, 0.5D);
        writeSwordReturnLocation(meta, returnLocation);
        refreshSwordReturnLore(meta, returnLocation);
        result.setItemMeta(meta);
    }

    private ItemStack tryApplyBootSilentLayer(ItemStack boots, Material material) {
        if (!isBoots(boots) || (!isWoolMaterial(material) && material != Material.FEATHER)) {
            return null;
        }
        boolean wool = isWoolMaterial(material);
        NamespacedKey layerKey = wool ? bootWoolLayerKey : bootFeatherLayerKey;
        if (hasPersistentByte(boots, layerKey)) {
            return null;
        }
        ItemStack result = boots.clone();
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return null;
        }
        meta.getPersistentDataContainer().set(layerKey, PersistentDataType.BYTE, (byte) 1);
        List<String> lore = meta.hasLore() && meta.getLore() != null ? new ArrayList<>(meta.getLore()) : new ArrayList<>();
        lore.removeIf(line -> line != null && (line.contains("已打上羊毛缓冲层")
                || line.contains("已打上羽毛缓冲层")
                || line.contains("轻步完成：")));
        boolean hasWoolLayer = hasPersistentByte(result, bootWoolLayerKey) || wool;
        boolean hasFeatherLayer = hasPersistentByte(result, bootFeatherLayerKey) || !wool;
        if (hasWoolLayer && hasFeatherLayer) {
            lore.add(BOOT_SILENT_READY_LINE);
        } else if (hasWoolLayer) {
            lore.add(BOOT_WOOL_LINE);
        } else if (hasFeatherLayer) {
            lore.add(BOOT_FEATHER_LINE);
        }
        meta.setLore(lore);
        result.setItemMeta(meta);
        return result;
    }

    private boolean applyCondensedSlimeToBootsClick(InventoryClickEvent event, Player player, ItemStack slime, ItemStack boots, boolean slimeOnCursor) {
        if (isEmpty(slime) || !isCondensedSlimeBlock(slime) || !isBoots(boots)) {
            return false;
        }
        event.setCancelled(true);
        ItemStack result = tryApplyCondensedSlimeToBoots(boots);
        if (result == null) {
            sendFlashMessage(player, plugin.getConfigManager().getHunterGamePrefix()
                    + "§x§F§F§D§7§7§7✦ §e这双鞋子已经接入浓缩粘液鞋底了。");
            player.playSound(player.getLocation(), Sound.BLOCK_SLIME_BLOCK_HIT, 0.62f, 0.72f);
            return true;
        }

        if (slimeOnCursor) {
            event.setCurrentItem(result);
            ItemStack nextCursor = slime.clone();
            nextCursor.setAmount(slime.getAmount() - 1);
            player.setItemOnCursor(nextCursor.getAmount() <= 0 ? null : nextCursor);
        } else {
            player.setItemOnCursor(result);
            ItemStack nextCurrent = slime.clone();
            nextCurrent.setAmount(slime.getAmount() - 1);
            event.setCurrentItem(nextCurrent.getAmount() <= 0 ? null : nextCurrent);
        }

        double bonus = getCondensedSlimeBootBonus(result);
        player.swingHand(EquipmentSlot.HAND);
        player.playSound(player.getLocation(), Sound.BLOCK_SLIME_BLOCK_PLACE, 0.72f, 1.18f);
        player.playSound(player.getLocation(), Sound.ENTITY_SLIME_SQUISH_SMALL, 0.58f, 1.42f);
        player.playSound(player.getLocation(), Sound.BLOCK_AMETHYST_BLOCK_CHIME, 0.30f, 1.82f);
        player.getWorld().spawnParticle(Particle.ITEM, player.getLocation().add(0.0D, 0.16D, 0.0D), 18,
                0.28D, 0.10D, 0.28D, 0.035D, new ItemStack(Material.SLIME_BLOCK));
        sendFlashMessage(player, plugin.getConfigManager().getHunterGamePrefix()
                + "§x§7§7§F§F§8§8✦ §a已接入浓缩粘液鞋底，爬行速度 §f+" + formatPercent(bonus) + "§a。");
        Bukkit.getScheduler().runTask(plugin, player::updateInventory);
        return true;
    }

