    private double getCondensedSlimeBootBaseBonus(Material bootType) {
        return bootType == Material.DIAMOND_BOOTS || bootType == Material.NETHERITE_BOOTS ? 0.40D : 0.20D;
    }

    private double getCondensedSlimeBootBonus(ItemStack boots) {
        if (!isBoots(boots) || !boots.hasItemMeta()) {
            return 0.0D;
        }
        Double bonus = boots.getItemMeta().getPersistentDataContainer().get(condensedSlimeBootCrawlBonusKey, PersistentDataType.DOUBLE);
        if (bonus == null) {
            return 0.0D;
        }
        return Math.max(0.0D, Math.min(1.0D, bonus));
    }

