    private void boostSpearKineticWeapon(ItemStack item) {
        if (!isSpear(item)) {
            return;
        }

        ItemMeta meta = item.getItemMeta();
        if (meta != null) {
            Byte boosted = meta.getPersistentDataContainer().get(spearKineticBoostedKey, PersistentDataType.BYTE);
            if (boosted != null && boosted == (byte) 1) {
                return;
            }
        }

        KineticWeapon kineticWeapon = item.getData(DataComponentTypes.KINETIC_WEAPON);
        if (kineticWeapon == null) {
            return;
        }

        KineticWeapon.Condition damageCondition = kineticWeapon.damageConditions();
        KineticWeapon.Condition boostedDamageCondition = KineticWeapon.condition(
                damageCondition.maxDurationTicks(),
                damageCondition.minSpeed() * 1.30F,
                damageCondition.minRelativeSpeed() * 1.30F
        );

        item.setData(DataComponentTypes.KINETIC_WEAPON, KineticWeapon.kineticWeapon()
                .contactCooldownTicks(kineticWeapon.contactCooldownTicks())
                .delayTicks(kineticWeapon.delayTicks())
                .dismountConditions(kineticWeapon.dismountConditions())
                .knockbackConditions(kineticWeapon.knockbackConditions())
                .damageConditions(boostedDamageCondition)
                .forwardMovement(kineticWeapon.forwardMovement())
                .damageMultiplier(kineticWeapon.damageMultiplier())
                .sound(kineticWeapon.sound())
                .hitSound(kineticWeapon.hitSound()));

        meta = item.getItemMeta();
        if (meta != null) {
            meta.getPersistentDataContainer().set(spearKineticBoostedKey, PersistentDataType.BYTE, (byte) 1);
            item.setItemMeta(meta);
        }
    }

    private void launchSwordWave(Player owner, GameRoom room, ItemStack sword) {
        Vector direction = owner.getEyeLocation().getDirection().normalize();
        Location start = owner.getEyeLocation().clone().add(direction.clone().multiply(0.85D));
        launchSwordWave(owner, room, sword, start, direction);
    }

    private void launchSwordWave(Player owner, GameRoom room, ItemStack sword, Location start, Vector direction) {
        World world = start.getWorld();
        if (world == null) {
            return;
        }
        Vector waveDirection = direction.clone().normalize();
        Vector collisionForward = createCollisionForward(waveDirection);
        WaveFrame visualFrame = createVisualFrame(waveDirection);
        WaveMotion motion = createWaveMotion(sword);
        double maxDistance = motion.maxDistance();
        double stepDistance = motion.stepDistance() * getJukeboxSwordFlightSpeedMultiplier(owner);
        double damage = getWaveDamage(sword) * getJukeboxSwordDamageMultiplier(owner);
        int basePierce = 1 + Math.max(0, sword.getEnchantmentLevel(Enchantment.PIERCING));
        boolean explosive = isUpgradeApplied(sword) && sword.getEnchantmentLevel(Enchantment.BLAST_PROTECTION) > 0;
        int blastLevel = sword.getEnchantmentLevel(Enchantment.BLAST_PROTECTION);
        Set<UUID> hitEntities = new HashSet<>();

        new BukkitRunnable() {
            double travelled = 0.0D;
            int remainingPierce = basePierce;
            final Location current = start.clone();

            @Override
            public void run() {
                if (!isFlashEffectStillActive(owner, room)) {
                    cancel();
                    return;
                }

                for (int i = 0; i < motion.stepsPerTick(); i++) {
                    if (travelled >= maxDistance) {
                        cancel();
                        return;
                    }

                    current.add(waveDirection.clone().multiply(stepDistance));
                    travelled += stepDistance;
                    if (shouldRenderWaveParticleFrame(travelled)) {
                        spawnWaveParticle(world, current, visualFrame, sword, travelled);
                    }

                    Location blockCollision = findWaveBlockCollision(current, collisionForward, travelled);
                    if (blockCollision != null) {
                        if (explosive) {
                            triggerExplosionBurst(owner, room, blockCollision.clone().add(0, 0.2, 0), blastLevel, 2.4D + blastLevel * 1.8D, null, collisionForward);
                        }
                        cancel();
                        return;
                    }

                    List<LivingEntity> targets = findWaveTargets(world, current, collisionForward, travelled, owner, room, hitEntities);
                    if (targets.isEmpty()) {
                        continue;
                    }

                    for (LivingEntity living : targets) {
                        hitEntities.add(living.getUniqueId());
                        damageFromWave(living, damage, owner);
                        if (explosive) {
                            triggerExplosionBurst(owner, room, living.getLocation().clone().add(0, 0.55, 0), blastLevel, 1.9D + blastLevel * 1.5D, living, collisionForward);
                        }
                        if (remainingPierce <= 0) {
                            cancel();
                            return;
                        }
                        remainingPierce--;
                    }
                }
            }
        }.runTaskTimer(plugin, 0L, 1L);
    }

    private List<LivingEntity> findWaveTargets(World world, Location current, Vector visualForward, double travelled, Player owner, GameRoom room, Set<UUID> hitEntities) {
        List<LivingEntity> targets = new ArrayList<>();
        WaveFrame frame = createWaveFrame(visualForward, travelled);

        for (Entity entity : world.getNearbyEntities(current, BOOMERANG_HALF_WIDTH + 0.8D, WAVE_MAX_VERTICAL + 0.25D, BOOMERANG_HALF_WIDTH + 0.8D)) {
            if (!(entity instanceof LivingEntity living) || (owner != null && living.getUniqueId().equals(owner.getUniqueId())) || hitEntities.contains(living.getUniqueId())) {
                continue;
            }
            if (living instanceof Player targetPlayer && !canWaveDamagePlayer(room, owner, targetPlayer)) {
                continue;
            }

            double minY = living.getBoundingBox().getMinY();
            double maxY = living.getBoundingBox().getMaxY();
            double verticalGap = current.getY() < minY ? minY - current.getY() : Math.max(0.0D, current.getY() - maxY);
            if (verticalGap > WAVE_MAX_VERTICAL) {
                continue;
            }

            Vector relative = living.getBoundingBox().getCenter().setY(current.getY()).subtract(current.toVector());
            double lateral = Math.abs(relative.dot(frame.right()));
            double forwardOffset = Math.abs(relative.dot(frame.forward()));
            double lateralLimit = BOOMERANG_HALF_WIDTH - Math.max(0.0D, verticalGap * 0.35D);

            if (lateral <= lateralLimit && forwardOffset <= WAVE_MAX_FORWARD) {
                targets.add(living);
            }
        }

        return targets;
    }

    private Location findWaveBlockCollision(Location current, Vector visualForward, double travelled) {
        for (Location sample : buildBoomerangSamplePoints(current, visualForward, travelled)) {
            Block block = sample.getBlock();
            if (!block.isPassable()) {
                return sample;
            }
        }
        return null;
    }

    private void triggerExplosionBurst(Player owner, GameRoom room, Location center, int blastLevel, double rawDamage, LivingEntity directTarget, Vector forward) {
        World world = center.getWorld();
        if (world == null) {
            return;
        }

        double radius = 2.35D + blastLevel * 0.68D;
        spawnRoundExplosionParticles(world, center, radius);
        world.playSound(center, Sound.ENTITY_LIGHTNING_BOLT_THUNDER, 1.0f, 1.0f);
        world.playSound(center, Sound.ENTITY_GENERIC_EXPLODE, 1.05f, 0.92f);

        if (canFlashExplosionBreakBlocks(owner, room)) {
            destroyBlocksAround(center, blastLevel, radius);
        }

        for (Entity nearby : world.getNearbyEntities(center, radius + 0.6D, radius + 0.6D, radius + 0.6D)) {
            if (!(nearby instanceof LivingEntity living) || (owner != null && living.getUniqueId().equals(owner.getUniqueId()))) {
                continue;
            }
            if (nearby instanceof Player targetPlayer && !canWaveDamagePlayer(room, owner, targetPlayer)) {
                continue;
            }

            Location hit = nearby.getLocation().clone().add(0, Math.min(1.0D, living.getHeight() * 0.5D), 0);
            double distance = center.distance(hit);
            if (distance > radius + 0.45D) {
                continue;
            }
            double falloff = Math.max(0.32D, 1.0D - distance / Math.max(0.01D, radius + 0.45D));
            double appliedDamage = directTarget != null && directTarget.getUniqueId().equals(living.getUniqueId())
                    ? rawDamage
                    : rawDamage * 0.72D * falloff;
            applyRawDamage(owner, living, appliedDamage);
        }
    }

    private void spawnRoundExplosionParticles(World world, Location center, double radius) {
        Particle.DustTransition color = new Particle.DustTransition(Color.fromRGB(255, 232, 128), Color.fromRGB(126, 180, 255), 1.45F);
        ThreadLocalRandom random = ThreadLocalRandom.current();

        world.spawnParticle(Particle.EXPLOSION, center, 4, radius * 0.22D, radius * 0.12D, radius * 0.22D, 0.015D);
        world.spawnParticle(Particle.LARGE_SMOKE, center, 18, radius * 0.46D, radius * 0.24D, radius * 0.46D, 0.032D);

        int shardCount = Math.max(28, (int) Math.ceil(radius * 13.0D));
        for (int i = 0; i < shardCount; i++) {
            double power = random.nextDouble(0.18D, 1.0D);
            double x = (random.nextDouble() - random.nextDouble()) * radius * 1.45D * power;
            double y = (random.nextDouble() - random.nextDouble()) * radius * 0.52D * power + random.nextDouble(-0.08D, 0.26D);
            double z = (random.nextDouble() - random.nextDouble()) * radius * 1.45D * power;
            Location point = center.clone().add(x, y, z);

            if (i % 5 == 0) {
                world.spawnParticle(Particle.EXPLOSION, point, 1, 0.04D, 0.04D, 0.04D, 0.0D);
            }
            world.spawnParticle(Particle.ELECTRIC_SPARK, point, 1, 0.24D, 0.10D, 0.24D, 0.075D);
            world.spawnParticle(Particle.DUST_COLOR_TRANSITION, point, 1, 0.10D, 0.08D, 0.10D, 0.0D, color);
            if (i % 3 == 0) {
                world.spawnParticle(Particle.ENCHANTED_HIT, point, 1, 0.12D, 0.08D, 0.12D, 0.025D);
            }
        }

        int streakCount = Math.max(9, (int) Math.ceil(radius * 3.2D));
        for (int i = 0; i < streakCount; i++) {
            Vector direction = new Vector(
                    random.nextDouble(-1.0D, 1.0D),
                    random.nextDouble(-0.28D, 0.46D),
                    random.nextDouble(-1.0D, 1.0D)
            );
            if (direction.lengthSquared() < 0.0001D) {
                direction = new Vector(1.0D, 0.0D, 0.0D);
            }
            direction.normalize();
            double length = random.nextDouble(radius * 0.34D, radius * 1.55D);
            int samples = random.nextInt(2, 5);
            for (int sample = 1; sample <= samples; sample++) {
                double distance = length * sample / samples;
                Location point = center.clone().add(direction.clone().multiply(distance));
                point.add(random.nextDouble(-0.18D, 0.18D), random.nextDouble(-0.10D, 0.10D), random.nextDouble(-0.18D, 0.18D));
                world.spawnParticle(Particle.ELECTRIC_SPARK, point, 1, 0.08D, 0.05D, 0.08D, 0.045D);
                world.spawnParticle(Particle.DUST_COLOR_TRANSITION, point, 1, 0.05D, 0.04D, 0.05D, 0.0D, color);
            }
        }

        world.spawnParticle(Particle.SMOKE, center, 22, radius * 0.62D, radius * 0.30D, radius * 0.62D, 0.035D);
        world.spawnParticle(Particle.ENCHANTED_HIT, center, 14, radius * 0.52D, radius * 0.24D, radius * 0.52D, 0.03D);
    }

    private void destroyBlocksAround(Location center, int blastLevel, double radius) {
        World world = center.getWorld();
        if (world == null || blastLevel <= 0) {
            return;
        }

        float hardnessCap = 1.15F + blastLevel * 0.95F;
        float resistanceCap = 10.0F + blastLevel * 8.0F;
        int cubeRadius = (int) Math.ceil(radius);

        for (int x = -cubeRadius; x <= cubeRadius; x++) {
            for (int y = -cubeRadius; y <= cubeRadius; y++) {
                for (int z = -cubeRadius; z <= cubeRadius; z++) {
                    Block block = center.clone().add(x, y, z).getBlock();
                    Location blockCenter = block.getLocation().add(0.5, 0.5, 0.5);
                    if (center.distanceSquared(blockCenter) > radius * radius) {
                        continue;
                    }
                    if (!shouldBreakBlock(block, hardnessCap, resistanceCap)) {
                        continue;
                    }
                    breakFlashBlock(block);
                }
            }
        }
    }

    private boolean shouldBreakBlock(Block block, float hardnessCap, float resistanceCap) {
        Material type = block.getType();
        if (block.isEmpty() || block.isLiquid() || block.isPassable()) {
            return false;
        }
        if (type.getHardness() < 0.0F || type.getHardness() > hardnessCap || type.getBlastResistance() > resistanceCap) {
            return false;
        }
        return switch (type) {
            case BEDROCK,
                 BARRIER,
                 COMMAND_BLOCK,
                 CHAIN_COMMAND_BLOCK,
                 REPEATING_COMMAND_BLOCK,
                 STRUCTURE_BLOCK,
                 JIGSAW,
                 END_PORTAL,
                 END_PORTAL_FRAME,
                 END_GATEWAY,
                 NETHER_PORTAL,
                 RESPAWN_ANCHOR,
                 REINFORCED_DEEPSLATE,
                 LIGHT,
                 SPAWNER -> false;
            default -> true;
        };
    }

    private void breakFlashBlock(Block block) {
        World world = block.getWorld();
        Location blockCenter = block.getLocation().add(0.5, 0.5, 0.5);
        BlockData blockData = block.getBlockData();
        SoundGroup soundGroup = blockData.getSoundGroup();
        Material type = block.getType();
        Collection<ItemStack> drops = block.getDrops();

        clearFloatingDecorationsAbove(block);
        dropFlashBlockItems(world, blockCenter, drops, type, FLASH_EXPLOSION_BLOCK_DROP_KEEP_RATE);
        world.spawnParticle(Particle.BLOCK, blockCenter, 16, 0.2, 0.2, 0.2, blockData);
        world.playSound(blockCenter, getFlashBreakSound(type, soundGroup), Math.max(0.6f, soundGroup.getVolume()), getFlashBreakPitch(type, soundGroup));
        block.setType(Material.AIR, true);
    }

    private void clearFloatingDecorationsAbove(Block support) {
        for (int offset = 1; offset <= 3; offset++) {
            Block decoration = support.getRelative(BlockFace.UP, offset);
            if (decoration.isEmpty()) {
                continue;
            }
            if (!isFloatingDecoration(decoration)) {
                return;
            }
            BlockData blockData = decoration.getBlockData();
            Location location = decoration.getLocation().add(0.5, 0.35, 0.5);
            decoration.getWorld().spawnParticle(Particle.BLOCK, location, 6, 0.16, 0.08, 0.16, blockData);
            decoration.setType(Material.AIR, true);
        }
    }

    private boolean isFloatingDecoration(Block block) {
        Material type = block.getType();
        if (type.isAir() || block.isLiquid() || !block.isPassable()) {
            return false;
        }

        String name = type.name();
        return name.contains("GRASS")
                || name.contains("FERN")
                || name.contains("FLOWER")
                || name.endsWith("_TULIP")
                || name.endsWith("_SAPLING")
                || name.endsWith("_MUSHROOM")
                || name.endsWith("_FUNGUS")
                || name.endsWith("_ROOTS")
                || name.endsWith("_SPROUTS")
                || name.equals("DEAD_BUSH")
                || name.equals("DANDELION")
                || name.equals("POPPY")
                || name.equals("BLUE_ORCHID")
                || name.equals("ALLIUM")
                || name.equals("AZURE_BLUET")
                || name.equals("OXEYE_DAISY")
                || name.equals("CORNFLOWER")
                || name.equals("LILY_OF_THE_VALLEY")
                || name.equals("WITHER_ROSE")
                || name.equals("TORCHFLOWER")
                || name.equals("PITCHER_PLANT")
                || name.equals("SNOW")
                || name.equals("MOSS_CARPET")
                || name.equals("PALE_MOSS_CARPET")
                || name.equals("PINK_PETALS")
                || name.equals("WILDFLOWERS")
                || name.equals("LEAF_LITTER");
    }

    private void applyRawDamage(Player owner, LivingEntity target, double damage) {
        if (target.isDead() || damage <= 0.0D) {
            return;
        }

        double newHealth = Math.max(0.0D, target.getHealth() - damage);
        target.setNoDamageTicks(0);
        target.setHealth(newHealth);
        if (owner != null) {
            target.playHurtAnimation(owner.getYaw());
        }
    }

    private void spawnWaveParticle(World world, Location current, WaveFrame frame, ItemStack sword, double travelled) {
        Particle coreParticle = getWaveCoreParticle(sword);
        Color primaryColor = getWavePrimaryColor(sword);
        Color secondaryColor = getWaveSecondaryColor(sword);
        Particle.DustTransition trailColor = new Particle.DustTransition(primaryColor, secondaryColor, 1.22F);

        for (Location sample : buildBoomerangSamplePoints(current, frame, travelled)) {
            world.spawnParticle(Particle.DUST_COLOR_TRANSITION, sample, 1, 0.0, 0.0, 0.0, 0.0, trailColor);
            world.spawnParticle(coreParticle, sample, 1, 0.01, 0.01, 0.01, 0.0);
        }

        int particleFrame = (int) Math.floor(travelled / WAVE_PARTICLE_FRAME_SPACING);
        if (particleFrame % 4 == 0) {
            world.spawnParticle(Particle.SWEEP_ATTACK, current, 1, 0.0, 0.0, 0.0, 0.0);
        }
        if (particleFrame % 3 == 0) {
            world.spawnParticle(Particle.ENCHANTED_HIT, current, 1, 0.04, 0.04, 0.04, 0.0);
        }

        if (sword.getEnchantmentLevel(Enchantment.FIRE_ASPECT) > 0) {
            for (double wing = -BOOMERANG_HALF_WIDTH; wing <= BOOMERANG_HALF_WIDTH; wing += 1.25D) {
                Location flame = current.clone().add(frame.right().clone().multiply(wing * 0.6D)).add(frame.forward().clone().multiply(-0.25D));
                world.spawnParticle(Particle.FLAME, flame, 1, 0.02, 0.02, 0.02, 0.0);
            }
        }
        if (sword.getEnchantmentLevel(Enchantment.KNOCKBACK) > 0) {
            world.spawnParticle(Particle.GUST, current, 1, 0.09, 0.06, 0.09, 0.0);
        }
        if (sword.getEnchantmentLevel(Enchantment.SHARPNESS) > 0) {
            world.spawnParticle(Particle.ELECTRIC_SPARK, current, 1, 0.12, 0.06, 0.12, 0.01);
            world.spawnParticle(Particle.CRIT, current, 1, 0.10, 0.06, 0.10, 0.01);
        }
    }

    private boolean shouldRenderWaveParticleFrame(double travelled) {
        int frame = (int) Math.floor(travelled / WAVE_PARTICLE_FRAME_SPACING);
        int previousFrame = (int) Math.floor(Math.max(0.0D, travelled - 0.92D) / WAVE_PARTICLE_FRAME_SPACING);
        return frame != previousFrame || travelled <= 0.9D;
    }

    private double getHorizontalBurstShapeValue(Location center, Location target, WaveFrame frame, double lengthRadius, double widthRadius, double verticalRadius) {
        Vector relative = target.toVector().subtract(center.toVector());
        double forward = relative.dot(frame.forward()) / Math.max(0.01D, lengthRadius);
        double lateral = relative.dot(frame.right()) / Math.max(0.01D, widthRadius);
        double vertical = relative.getY() / Math.max(0.01D, verticalRadius);
        return forward * forward + lateral * lateral + vertical * vertical;
    }

    private List<Location> buildBoomerangSamplePoints(Location current, Vector visualForward, double travelled) {
        return buildBoomerangSamplePoints(current, createWaveFrame(visualForward, travelled), travelled);
    }

    private List<Location> buildBoomerangSamplePoints(Location current, WaveFrame frame, double travelled) {
        List<Location> points = new ArrayList<>();

        for (double lateral = -BOOMERANG_HALF_WIDTH; lateral <= BOOMERANG_HALF_WIDTH + 0.01D; lateral += WAVE_PARTICLE_SAMPLE_STEP) {
            double normalized = Math.abs(lateral) / BOOMERANG_HALF_WIDTH;
            double backCurve = -1.18D * normalized * normalized;
            double frontCurve = 0.28D * (1.0D - normalized);

            Location point = current.clone()
                    .add(frame.right().clone().multiply(lateral))
                    .add(frame.forward().clone().multiply(backCurve + frontCurve));
            points.add(point);

            if (normalized > 0.72D) {
                points.add(point.clone().add(frame.forward().clone().multiply(-0.46D)));
            }
        }

        points.add(current.clone().add(frame.forward().clone().multiply(0.36D)));
        points.add(current.clone().add(frame.forward().clone().multiply(-0.88D)));
        return points;
    }

    private Vector createCollisionForward(Vector direction) {
        Vector forward = new Vector(direction.getX(), 0.0D, direction.getZ());
        if (forward.lengthSquared() < 0.0001D) {
            forward = new Vector(0.0D, 0.0D, 1.0D);
        }
        return forward.normalize();
    }

    private WaveFrame createVisualFrame(Vector direction) {
        Vector forward = direction.clone().normalize();
        Vector right = forward.clone().crossProduct(new Vector(0.0D, 1.0D, 0.0D));
        if (right.lengthSquared() < 0.0001D) {
            right = new Vector(1.0D, 0.0D, 0.0D);
        }
        right.normalize();
        Vector viewUp = right.clone().crossProduct(forward).normalize();
        return new WaveFrame(right, viewUp, forward);
    }

    private WaveFrame createWaveFrame(Vector visualForward, double travelled) {
        Vector forward = new Vector(visualForward.getX(), 0.0D, visualForward.getZ());
        if (forward.lengthSquared() < 0.0001D) {
            forward = new Vector(0.0D, 0.0D, 1.0D);
        } else {
            forward.normalize();
        }
        Vector right = new Vector(-forward.getZ(), 0.0D, forward.getX());
        if (right.lengthSquared() < 0.0001D) {
            right = new Vector(1.0D, 0.0D, 0.0D);
        } else {
            right.normalize();
        }
        return new WaveFrame(right, new Vector(0.0D, 1.0D, 0.0D), forward);
    }

    private Particle getWaveCoreParticle(ItemStack sword) {
        return switch (sword.getType().name()) {
            case "WOODEN_SWORD" -> Particle.CRIT;
            case "STONE_SWORD" -> Particle.SMOKE;
            case "COPPER_SWORD", "IRON_SWORD", "DIAMOND_SWORD" -> Particle.ELECTRIC_SPARK;
            case "NETHERITE_SWORD" -> Particle.SOUL_FIRE_FLAME;
            case "GOLDEN_SWORD" -> Particle.WITCH;
            default -> Particle.SWEEP_ATTACK;
        };
    }

    private Color getWavePrimaryColor(ItemStack sword) {
        return switch (sword.getType().name()) {
            case "WOODEN_SWORD" -> Color.fromRGB(195, 135, 85);
            case "STONE_SWORD" -> Color.fromRGB(150, 156, 170);
            case "COPPER_SWORD" -> Color.fromRGB(232, 132, 78);
            case "IRON_SWORD" -> Color.fromRGB(224, 230, 244);
            case "DIAMOND_SWORD" -> Color.fromRGB(80, 255, 230);
            case "NETHERITE_SWORD" -> Color.fromRGB(120, 90, 150);
            case "GOLDEN_SWORD" -> Color.fromRGB(255, 224, 94);
            default -> Color.fromRGB(220, 220, 220);
        };
    }

    private Color getWaveSecondaryColor(ItemStack sword) {
        return switch (sword.getType().name()) {
            case "WOODEN_SWORD" -> Color.fromRGB(255, 214, 170);
            case "STONE_SWORD" -> Color.fromRGB(214, 224, 235);
            case "COPPER_SWORD" -> Color.fromRGB(255, 188, 124);
            case "IRON_SWORD" -> Color.fromRGB(170, 215, 255);
            case "DIAMOND_SWORD" -> Color.fromRGB(170, 255, 248);
            case "NETHERITE_SWORD" -> Color.fromRGB(222, 160, 255);
            case "GOLDEN_SWORD" -> Color.fromRGB(255, 244, 170);
            default -> Color.fromRGB(255, 255, 255);
        };
    }

    private WaveMotion createWaveMotion(ItemStack sword) {
        ThreadLocalRandom random = ThreadLocalRandom.current();
        return switch (sword.getType().name()) {
            case "WOODEN_SWORD" -> new WaveMotion(0.78D, 4, random.nextDouble(30.0D, 45.0D));
            case "STONE_SWORD" -> new WaveMotion(0.72D, 2, random.nextDouble(10.0D, 25.0D));
            case "COPPER_SWORD" -> new WaveMotion(0.72D, 2, random.nextDouble(20.0D, 35.0D));
            case "IRON_SWORD" -> new WaveMotion(0.78D, 4, random.nextDouble(30.0D, 35.0D));
            case "GOLDEN_SWORD" -> new WaveMotion(0.82D, 5, random.nextDouble(40.0D, 90.0D));
            case "DIAMOND_SWORD" -> new WaveMotion(0.74D, 3, random.nextDouble(25.0D, 40.0D));
            case "NETHERITE_SWORD" -> new WaveMotion(0.62D, 2, random.nextDouble(15.0D, 25.0D));
            default -> new WaveMotion(0.72D, 2, random.nextDouble(18.0D, 28.0D));
        };
    }

    private double getWaveDamage(ItemStack sword) {
        double base = switch (sword.getType().name()) {
            case "WOODEN_SWORD", "GOLDEN_SWORD" -> 4.5D;
            case "STONE_SWORD" -> 5.5D;
            case "COPPER_SWORD" -> 6.0D;
            case "IRON_SWORD" -> 6.5D;
            case "DIAMOND_SWORD" -> 7.5D;
            case "NETHERITE_SWORD" -> 8.5D;
            default -> 5.0D;
        };
        int sharpnessLevel = Math.max(0, sword.getEnchantmentLevel(Enchantment.SHARPNESS));
        if (sharpnessLevel > 0) {
            // 剑气伤害跟随剑本体的锋利等级增长，弩装剑和发射器/投掷器剑气也共用这里。
            base += 0.80D + sharpnessLevel * 1.05D;
        }
        base += sword.getEnchantmentLevel(Enchantment.SMITE) * 0.45D;
        base += sword.getEnchantmentLevel(Enchantment.BANE_OF_ARTHROPODS) * 0.45D;
        return base;
    }

    private boolean canDamage(GameRoom room, Player attacker, Player target) {
        if (attacker == null || target == null) {
            return false;
        }
        if (room == null) {
            return !attacker.getUniqueId().equals(target.getUniqueId())
                    && isStandaloneFlashContext(attacker)
                    && plugin.getRoomManager().getPlayerRoom(target.getUniqueId()) == null;
        }
        if (room.isSpectator(target.getUniqueId()) || room.isSpectator(attacker.getUniqueId())) {
            return false;
        }
        if (room.isHunter(attacker.getUniqueId()) && room.isHunter(target.getUniqueId())) {
            if (room.getGameMode().isFlashTournament()) {
                return true;
            }
            return plugin.getConfigManager().getConfig().getBoolean("hunter_game.pvp.hunter_friendly_fire", false);
        }
        if (room.isPrey(attacker.getUniqueId()) && room.isPrey(target.getUniqueId())) {
            return false;
        }
        return room.getAllPlayerUUIDs().contains(target.getUniqueId());
    }


    public void handleHeroTrialSpawnerSpawn(TrialSpawnerSpawnEvent event) {
        TrialSpawner spawner = event.getTrialSpawner();
        if (spawner == null) {
            return;
        }
        HeroTrialContext context = findHeroTrialContext(spawner);
        if (context == null) {
            return;
        }
        Player hero = context.player();
        GameRoom room = context.room();
        boolean ominous = spawner.isOminous();
        event.setCancelled(true);
        if (event.getEntity() != null) {
            event.getEntity().remove();
        }
        enrichHeroTrialRewards(spawner);
        Location spawnLocation = event.getLocation();
        if (spawnLocation == null) {
            spawnLocation = spawner.getLocation().add(0.5D, 1.0D, 0.5D);
        }
        long now = System.currentTimeMillis();
        long until = heroTrialCooldowns.getOrDefault(hero.getUniqueId(), 0L);
        if (now >= until) {
            heroTrialCooldowns.put(hero.getUniqueId(), now + 6000L);
            sendFlashMessage(hero, plugin.getConfigManager().getHunterGamePrefix() + "§x§F§F§D§D§8§8✦ §e村庄英雄的气息唤醒了试练刷怪笼，袭击者正在涌出！");
        }
        spawnHeroTrialSpawnerRaiders(hero, room, spawnLocation, ominous);
    }

    private HeroTrialContext findHeroTrialContext(TrialSpawner spawner) {
        for (Player player : spawner.getTrackedPlayers()) {
            if (player == null || !player.isOnline() || !player.hasPotionEffect(PotionEffectType.HERO_OF_THE_VILLAGE)) {
                continue;
            }
            GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
            if (isFlashCombatAvailable(player, room)) {
                return new HeroTrialContext(player, room);
            }
        }
        return null;
    }

    private void enrichHeroTrialRewards(TrialSpawner spawner) {
        try {
            spawner.getNormalConfiguration().addPossibleReward(LootTables.EVOKER.getLootTable(), 7);
            spawner.getNormalConfiguration().addPossibleReward(LootTables.TRIAL_CHAMBERS_REWARD_UNIQUE.getLootTable(), 3);
            spawner.getOminousConfiguration().addPossibleReward(LootTables.EVOKER.getLootTable(), 12);
            spawner.getOminousConfiguration().addPossibleReward(LootTables.TRIAL_CHAMBERS_REWARD_OMINOUS_UNIQUE.getLootTable(), 5);
            spawner.update(true, false);
        } catch (RuntimeException ignored) {
            // 有些服务端实现不允许运行中改 TrialSpawner 配置，实体掉落仍然会给不死图腾。
        }
    }

    private void spawnHeroTrialSpawnerRaiders(Player hero, GameRoom room, Location center, boolean ominous) {
        if (!hero.isOnline() || !isFlashCombatAvailable(hero, room)) {
            return;
        }
        World world = center.getWorld();
        if (world == null) {
            return;
        }
        int count = ominous ? 4 : 3;
        world.playSound(center, Sound.BLOCK_TRIAL_SPAWNER_SPAWN_MOB, 1.0f, ominous ? 0.75f : 0.95f);
        world.playSound(center, Sound.EVENT_RAID_HORN, 0.82f, ominous ? 0.86f : 1.08f);
        world.spawnParticle(ominous ? Particle.OMINOUS_SPAWNING : Particle.TRIAL_SPAWNER_DETECTION,
                center.clone().add(0.0D, 0.8D, 0.0D), 46, 0.7D, 0.45D, 0.7D, 0.04D);
        for (int i = 0; i < count; i++) {
            double angle = Math.toRadians((360.0D / count) * i + ThreadLocalRandom.current().nextDouble(-26.0D, 26.0D));
            double radius = ThreadLocalRandom.current().nextDouble(1.25D, ominous ? 3.35D : 2.65D);
            Location spawn = findHeroTrialSpawnLocation(center.clone().add(Math.cos(angle) * radius, 0.0D, Math.sin(angle) * radius));
            LivingEntity mob = spawnHeroTrialRaider(world, spawn, hero, ominous, i);
            if (mob == null) {
                continue;
            }
            mob.getPersistentDataContainer().set(heroTrialRaiderKey, PersistentDataType.BYTE, (byte) 1);
            mob.setRemoveWhenFarAway(true);
            if (mob instanceof Mob hostile) {
                hostile.setTarget(hero);
            }
            if (mob.getEquipment() != null) {
                mob.getEquipment().setItemInMainHand(new ItemStack(Material.TOTEM_OF_UNDYING));
                mob.getEquipment().setItemInMainHandDropChance(ominous ? 0.36F : 0.24F);
            }
            world.spawnParticle(Particle.RAID_OMEN, spawn.clone().add(0.0D, 1.1D, 0.0D), 18, 0.35D, 0.45D, 0.35D, 0.03D);
        }
    }

    private LivingEntity spawnHeroTrialRaider(World world, Location spawn, Player hero, boolean ominous, int index) {
        int pick = ThreadLocalRandom.current().nextInt(ominous ? 6 : 4);
        if (pick == 0) {
            return world.spawn(spawn, org.bukkit.entity.Pillager.class);
        }
        if (pick == 1) {
            return world.spawn(spawn, Vindicator.class);
        }
        if (pick == 2 && ominous) {
            return world.spawn(spawn, org.bukkit.entity.Evoker.class);
        }
        if ((pick == 3 && ominous) || (ominous && index == 0 && ThreadLocalRandom.current().nextBoolean())) {
            return world.spawn(spawn, Vex.class);
        }
        if (pick >= 4 || (!ominous && index == 0 && ThreadLocalRandom.current().nextInt(4) == 0)) {
            return world.spawn(spawn, org.bukkit.entity.Ravager.class);
        }
        return world.spawn(spawn, org.bukkit.entity.Pillager.class);
    }

    private Location findHeroTrialSpawnLocation(Location base) {
        World world = base.getWorld();
        if (world == null) {
            return base;
        }
        Location scan = base.clone();
        for (int yOffset = 0; yOffset <= 4; yOffset++) {
            Location up = scan.clone().add(0.0D, yOffset, 0.0D);
            if (isHeroTrialSpawnSpace(up)) {
                return up.add(0.5D - up.getX() + up.getBlockX(), 0.0D, 0.5D - up.getZ() + up.getBlockZ());
            }
            if (yOffset > 0) {
                Location down = scan.clone().subtract(0.0D, yOffset, 0.0D);
                if (isHeroTrialSpawnSpace(down)) {
                    return down.add(0.5D - down.getX() + down.getBlockX(), 0.0D, 0.5D - down.getZ() + down.getBlockZ());
                }
            }
        }
        return base.clone().add(0.0D, 1.0D, 0.0D);
    }

    private boolean isHeroTrialSpawnSpace(Location location) {
        Block feet = location.getBlock();
        Block head = feet.getRelative(BlockFace.UP);
        Block ground = feet.getRelative(BlockFace.DOWN);
        return ground.getType().isSolid() && feet.isPassable() && head.isPassable();
    }

    public void handleShieldWindChargeAirBounceLanding(Player player, GameRoom room) {
        if (player == null || shieldWindChargeAirBounceCounts.isEmpty()) {
            return;
        }
        UUID playerId = player.getUniqueId();
        if (!shieldWindChargeAirBounceCounts.containsKey(playerId)) {
            return;
        }
        if (!isFlashCombatAvailable(player, room)
                || isShieldWindChargeGrounded(player)
                || player.isInWater()
                || player.isSwimming()) {
            shieldWindChargeAirBounceCounts.remove(playerId);
        }
    }

    private boolean isShieldWindChargeGrounded(Player player) {
        if (player == null || player.getWorld() == null) {
            return false;
        }
        if (player.isOnGround()) {
            return true;
        }

        BoundingBox playerBox = player.getBoundingBox();
        if (playerBox == null) {
            return false;
        }

        // 1.21.11 的高速位移/风弹位移有时会在刚落地时让 Player#isOnGround 短暂保持 false，
        // 导致空中弹射次数没有重置，下一次站在地面右键也会按“空中概率”判定失败。
        // 这里用脚下很薄的一层碰撞盒额外确认真实落地状态。
        BoundingBox feetProbe = new BoundingBox(
                playerBox.getMinX() + 0.045D,
                playerBox.getMinY() - 0.12D,
                playerBox.getMinZ() + 0.045D,
                playerBox.getMaxX() - 0.045D,
                playerBox.getMinY() + 0.025D,
                playerBox.getMaxZ() - 0.045D
        );

        World world = player.getWorld();
        int minX = (int) Math.floor(feetProbe.getMinX());
        int maxX = (int) Math.floor(feetProbe.getMaxX());
        int minY = Math.max(world.getMinHeight(), (int) Math.floor(feetProbe.getMinY()));
        int maxY = Math.min(world.getMaxHeight() - 1, (int) Math.floor(feetProbe.getMaxY()));
        int minZ = (int) Math.floor(feetProbe.getMinZ());
        int maxZ = (int) Math.floor(feetProbe.getMaxZ());

        for (int x = minX; x <= maxX; x++) {
            for (int y = minY; y <= maxY; y++) {
                for (int z = minZ; z <= maxZ; z++) {
                    Block block = world.getBlockAt(x, y, z);
                    if (isShieldWindChargeGroundBlock(block, feetProbe)) {
                        return true;
                    }
                }
            }
        }
        return false;
    }

    private boolean isShieldWindChargeGroundBlock(Block block, BoundingBox feetProbe) {
        if (block == null || block.isEmpty() || block.isLiquid() || block.getType().isAir()) {
            return false;
        }
        if (!block.getType().isSolid() && block.isPassable()) {
            return false;
        }
        BoundingBox blockBox = block.getBoundingBox();
        return blockBox != null
                && blockBox.getMaxY() > blockBox.getMinY()
                && blockBox.getMaxX() > blockBox.getMinX()
                && blockBox.getMaxZ() > blockBox.getMinZ()
                && blockBox.overlaps(feetProbe);
    }

    private double getShieldWindChargeAirBounceChance(int airBounceCount) {
        int halves = Math.max(0, Math.min(SHIELD_WIND_CHARGE_AIR_BOUNCE_MAX_HALVES, airBounceCount));
        return SHIELD_WIND_CHARGE_AIR_BOUNCE_BASE_CHANCE / (1 << halves);
    }

    private boolean rollShieldWindChargeAirBounce(Player player, UUID playerId) {
        int airBounceCount = Math.max(0, shieldWindChargeAirBounceCounts.getOrDefault(playerId, 0));
        double chance = getShieldWindChargeAirBounceChance(airBounceCount);
        if (ThreadLocalRandom.current().nextDouble() < chance) {
            shieldWindChargeAirBounceCounts.put(playerId, Math.min(airBounceCount + 1, SHIELD_WIND_CHARGE_AIR_BOUNCE_MAX_HALVES));
            return true;
        }
        Location effect = player.getLocation().add(0.0D, 0.72D, 0.0D);
        player.getWorld().spawnParticle(Particle.SMALL_GUST, effect, 18, 0.28D, 0.16D, 0.28D, 0.028D);
        player.playSound(player.getLocation(), Sound.ENTITY_BREEZE_CHARGE, 0.48f, 0.72f);
        player.playSound(player.getLocation(), Sound.BLOCK_AMETHYST_CLUSTER_HIT, 0.34f, 1.82f);
        return false;
    }

    public boolean handleShieldWindChargeDash(PlayerInteractEvent event) {
        if ((event.getHand() != EquipmentSlot.HAND && event.getHand() != EquipmentSlot.OFF_HAND)
                || (event.getAction() != Action.RIGHT_CLICK_AIR && event.getAction() != Action.RIGHT_CLICK_BLOCK)) {
            return false;
        }
        Player player = event.getPlayer();
        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        if (!isFlashCombatAvailable(player, room)) {
            return false;
        }
        ItemStack main = player.getInventory().getItemInMainHand();
        ItemStack offhand = player.getInventory().getItemInOffHand();
        if (main.getType() != Material.SHIELD || !isUsableWindChargeItem(offhand)) {
            return false;
        }
        boolean unstableCoreShield = hasUnstableCoreShield(main);
        boolean enhancedWindCharge = isEnhancedWindCharge(offhand);
        event.setCancelled(true);
        event.setUseInteractedBlock(Event.Result.DENY);
        event.setUseItemInHand(Event.Result.DENY);
        long now = System.currentTimeMillis();
        UUID playerId = player.getUniqueId();
        if (unstableCoreShield) {
            return handleUnstableCoreShieldWindCharge(player, now);
        }
        Long lastUse = shieldWindChargeLastUseMillis.get(playerId);
        if (lastUse != null && now - lastUse < 180L) {
            return true;
        }
        shieldWindChargeLastUseMillis.put(playerId, now);
        boolean onGround = isShieldWindChargeGrounded(player);
        if (onGround) {
            shieldWindChargeAirBounceCounts.remove(playerId);
        }
        if (!onGround && !rollShieldWindChargeAirBounce(player, playerId)) {
            player.swingHand(EquipmentSlot.OFF_HAND);
            return true;
        }
        Vector direction = player.getEyeLocation().getDirection();
        if (direction.lengthSquared() < 0.0001D) {
            direction = player.getLocation().getDirection();
        }
        if (direction.lengthSquared() < 0.0001D) {
            player.playSound(player.getLocation(), Sound.ENTITY_BREEZE_CHARGE, 0.48f, 0.72f);
            return true;
        }
        direction.normalize();
        double strength = (onGround ? 1.02D : 0.86D) * SHIELD_WIND_CHARGE_DASH_SPEED_MULTIPLIER;
        if (unstableCoreShield) {
            strength *= UNSTABLE_CORE_SHIELD_WIND_SPEED_MULTIPLIER;
        }
        Vector velocity = direction.multiply(strength);
        if (onGround && velocity.getY() < 0.16D) {
            velocity.setY(0.16D);
        }
        double maxDashSpeed = 1.14D * SHIELD_WIND_CHARGE_DASH_SPEED_MULTIPLIER;
        if (unstableCoreShield) {
            maxDashSpeed *= UNSTABLE_CORE_SHIELD_WIND_SPEED_MULTIPLIER;
        }
        if (velocity.length() > maxDashSpeed) {
            velocity.normalize().multiply(maxDashSpeed);
        }
        consumeHandItem(player, EquipmentSlot.OFF_HAND, 1);
        player.clearActiveItem();
        player.setVelocity(velocity);
        player.setFallDistance(0.0F);
        shieldWindChargeSafeFallExpires.put(playerId, now + 6500L);
        Location effect = player.getLocation().add(0.0D, 0.75D, 0.0D);
        player.getWorld().spawnParticle(Particle.GUST, effect, 28, 0.42D, 0.22D, 0.42D, 0.08D);
        player.getWorld().spawnParticle(Particle.SMALL_GUST, effect, 34, 0.38D, 0.20D, 0.38D, 0.06D);
        if (unstableCoreShield) {
            player.getWorld().spawnParticle(Particle.ELECTRIC_SPARK, effect, 18, 0.34D, 0.18D, 0.34D, 0.05D);
            player.playSound(player.getLocation(), Sound.BLOCK_RESPAWN_ANCHOR_CHARGE, 0.36f, 1.72f);
            player.sendActionBar("§x§8§8§D§D§F§F✦ §b核心盾过载：§7盾牌风弹飞行速度 §c-80%");
        } else if (enhancedWindCharge) {
            player.getWorld().spawnParticle(Particle.GUST, effect, 16, 0.36D, 0.18D, 0.36D, 0.06D);
            player.sendActionBar("§x§B§B§F§F§F§F✦ §b强化风弹盾跃 §8| §7已消耗1个强化风弹");
        }
        player.playSound(player.getLocation(), Sound.ITEM_SHIELD_BLOCK, 0.95f, 1.0f);
        player.playSound(player.getLocation(), Sound.ENTITY_WIND_CHARGE_WIND_BURST, 0.95f, 1.0f);
        return true;
    }

    private boolean handleUnstableCoreShieldWindCharge(Player player, long now) {
        UUID playerId = player.getUniqueId();
        long cooldownUntil = coreShieldWindChargeCooldowns.getOrDefault(playerId, 0L);
        if (now < cooldownUntil || player.hasCooldown(Material.SHIELD)) {
            long remaining = Math.max(1L, (Math.max(cooldownUntil, now + player.getCooldown(Material.SHIELD) * 50L) - now + 999L) / 1000L);
            player.swingHand(EquipmentSlot.OFF_HAND);
            player.playSound(player.getLocation(), Sound.BLOCK_NOTE_BLOCK_BASS, 0.45f, 0.72f);
            player.sendActionBar("§x§6§0§6§0§6§0沉重盾牌冷却中 §8| §7还需 §c" + remaining + "秒");
            return true;
        }

        Long lastUse = shieldWindChargeLastUseMillis.get(playerId);
        if (lastUse != null && now - lastUse < 180L) {
            return true;
        }
        shieldWindChargeLastUseMillis.put(playerId, now);

        ItemStack offhand = player.getInventory().getItemInOffHand();
        if (isEmpty(offhand) || !isUsableWindChargeItem(offhand)) {
            return true;
        }
        boolean enhancedWindCharge = isEnhancedWindCharge(offhand);
        consumeHandItem(player, EquipmentSlot.OFF_HAND, 1);

        CoreShieldWindChargeSession session = coreShieldWindChargeSessions.get(playerId);
        if (session == null) {
            int maxCharges = ThreadLocalRandom.current().nextBoolean() ? 5 : 3;
            session = new CoreShieldWindChargeSession(maxCharges);
            coreShieldWindChargeSessions.put(playerId, session);
            player.playSound(player.getLocation(), Sound.BLOCK_RESPAWN_ANCHOR_CHARGE, 0.42f, maxCharges >= 5 ? 1.58f : 1.28f);
        }

        int chargeGain = enhancedWindCharge ? 3 : 1;
        session.charges = Math.min(session.maxCharges, session.charges + chargeGain);
        session.revision++;
        int revision = session.revision;
        int charges = session.charges;
        int maxCharges = session.maxCharges;
        Location effect = player.getLocation().add(0.0D, 0.82D, 0.0D);
        player.getWorld().spawnParticle(Particle.GUST, effect, 12 + charges * 5, 0.30D, 0.18D, 0.30D, 0.035D);
        player.getWorld().spawnParticle(Particle.ELECTRIC_SPARK, effect, 8 + charges * 4, 0.24D, 0.16D, 0.24D, 0.04D);
        player.playSound(player.getLocation(), Sound.ENTITY_BREEZE_CHARGE, 0.58f, 0.88f + charges * 0.12f);
        if (enhancedWindCharge) {
            player.playSound(player.getLocation(), Sound.ENTITY_BREEZE_WIND_BURST, 0.45f, 1.55f);
        }
        player.swingHand(EquipmentSlot.OFF_HAND);

        if (charges >= maxCharges) {
            launchUnstableCoreShieldWindCharge(player, charges, true);
            return true;
        }

        player.sendActionBar("§x§6§0§6§0§6§0沉重盾牌蓄力 §f" + charges + "§7/§f" + maxCharges
                + " §8| §73秒内继续副手风弹可叠加");
        Bukkit.getScheduler().runTaskLater(plugin, () -> {
            CoreShieldWindChargeSession current = coreShieldWindChargeSessions.get(playerId);
            Player online = Bukkit.getPlayer(playerId);
            if (current == null || current.revision != revision || online == null || !online.isOnline()) {
                return;
            }
            launchUnstableCoreShieldWindCharge(online, current.charges, false);
        }, UNSTABLE_CORE_SHIELD_WIND_CHARGE_WINDOW_TICKS);
        return true;
    }

    private void launchUnstableCoreShieldWindCharge(Player player, int charges, boolean fullCharge) {
        if (player == null || !player.isOnline()) {
            return;
        }
        UUID playerId = player.getUniqueId();
        coreShieldWindChargeSessions.remove(playerId);
        long now = System.currentTimeMillis();
        coreShieldWindChargeCooldowns.put(playerId, now + UNSTABLE_CORE_SHIELD_WIND_COOLDOWN_MILLIS);
        player.setCooldown(Material.SHIELD, UNSTABLE_CORE_SHIELD_WIND_COOLDOWN_TICKS);

        boolean onGround = isShieldWindChargeGrounded(player);
        if (onGround) {
            shieldWindChargeAirBounceCounts.remove(playerId);
        }
        Vector direction = player.getEyeLocation().getDirection();
        if (direction.lengthSquared() < 0.0001D) {
            direction = player.getLocation().getDirection();
        }
        if (direction.lengthSquared() < 0.0001D) {
            direction = new Vector(0.0D, 0.25D, 1.0D);
        }
        direction.normalize();

        int safeCharges = Math.max(1, Math.min(5, charges));
        double strength = (onGround ? 1.02D : 0.86D)
                * SHIELD_WIND_CHARGE_DASH_SPEED_MULTIPLIER
                * UNSTABLE_CORE_SHIELD_WIND_SPEED_MULTIPLIER
                * safeCharges;
        Vector velocity = direction.multiply(strength);
        if (onGround && velocity.getY() < 0.16D + safeCharges * 0.035D) {
            velocity.setY(0.16D + safeCharges * 0.035D);
        }
        double maxDashSpeed = 1.14D
                * SHIELD_WIND_CHARGE_DASH_SPEED_MULTIPLIER
                * UNSTABLE_CORE_SHIELD_WIND_SPEED_MULTIPLIER
                * safeCharges;
        if (velocity.length() > maxDashSpeed) {
            velocity.normalize().multiply(maxDashSpeed);
        }

        player.clearActiveItem();
        player.setVelocity(velocity);
        player.setFallDistance(0.0F);
        shieldWindChargeSafeFallExpires.put(playerId, now + 6500L + safeCharges * 850L);

        Location effect = player.getLocation().add(0.0D, 0.86D, 0.0D);
        player.getWorld().spawnParticle(Particle.GUST, effect, 30 + safeCharges * 18, 0.46D, 0.26D, 0.46D, 0.09D);
        player.getWorld().spawnParticle(Particle.SMALL_GUST, effect, 36 + safeCharges * 16, 0.42D, 0.24D, 0.42D, 0.07D);
        player.getWorld().spawnParticle(Particle.ELECTRIC_SPARK, effect, 18 + safeCharges * 8, 0.34D, 0.20D, 0.34D, 0.06D);
        player.playSound(player.getLocation(), Sound.ITEM_SHIELD_BLOCK, 0.82f, 0.74f);
        player.playSound(player.getLocation(), Sound.ENTITY_WIND_CHARGE_WIND_BURST, 0.96f, fullCharge ? 0.88f : 1.08f);
        player.playSound(player.getLocation(), Sound.BLOCK_RESPAWN_ANCHOR_DEPLETE, 0.34f, 1.52f);
        player.sendActionBar("§x§6§0§6§0§6§0沉重盾牌释放 §8| §f" + safeCharges
                + "层蓄力 §7已进入 §c10秒§7 冷却");
    }

    public boolean handleEnhancedWindChargeUse(PlayerInteractEvent event) {
        if (event == null || event.getHand() != EquipmentSlot.HAND
                || (event.getAction() != Action.RIGHT_CLICK_AIR && event.getAction() != Action.RIGHT_CLICK_BLOCK)) {
            return false;
        }
        Player player = event.getPlayer();
        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        if (!isFlashCombatAvailable(player, room)) {
            return false;
        }
        ItemStack main = player.getInventory().getItemInMainHand();
        if (!isEnhancedWindCharge(main)) {
            return false;
        }
        event.setCancelled(true);
        event.setUseInteractedBlock(Event.Result.DENY);
        event.setUseItemInHand(Event.Result.DENY);
        consumeHandItem(player, EquipmentSlot.HAND, 1);
        player.swingHand(EquipmentSlot.HAND);
        spawnWindCharges(player, main, false, 1.0F, true);
        player.sendActionBar("§x§B§B§F§F§F§F✦ §b强化风弹 §7已同时发射 §f3 §7枚风弹");
        return true;
    }

    public boolean handleFlashCrossbowLoad(PlayerInteractEvent event) {
        if (handleExtendedFishingRodReel(event)) {
            return true;
        }
        if (event.getAction() != Action.RIGHT_CLICK_AIR && event.getAction() != Action.RIGHT_CLICK_BLOCK) {
            return false;
        }
        Player player = event.getPlayer();
        if (event.getHand() == EquipmentSlot.OFF_HAND && shouldCancelOffhandCrossbowLoadUse(player)) {
            cancelCrossbowLoadInteract(event);
            rememberCrossbowLoadOffhandCancel(player);
            Bukkit.getScheduler().runTask(plugin, () -> tryLoadFlashCrossbowPayload(player));
            return true;
        }
        if (event.getHand() != EquipmentSlot.HAND) {
            return false;
        }
        if (!canLoadFlashCrossbowPayload(player)) {
            return false;
        }
        cancelCrossbowLoadInteract(event);
        rememberCrossbowLoadOffhandCancel(player);
        return tryLoadFlashCrossbowPayload(player);
    }

    public boolean handleFlashCrossbowLoad(EntityLoadCrossbowEvent event) {
        if (event == null || !(event.getEntity() instanceof Player player)) {
            return false;
        }
        if (!canLoadFlashCrossbowPayload(player)) {
            return false;
        }
        event.setCancelled(true);
        event.setConsumeItem(false);
        rememberCrossbowLoadOffhandCancel(player);
        Bukkit.getScheduler().runTask(plugin, () -> tryLoadFlashCrossbowPayload(player));
        Bukkit.getScheduler().runTaskLater(plugin, () -> tryLoadFlashCrossbowPayload(player), 1L);
        return true;
    }

    private boolean canLoadFlashCrossbowPayload(Player player) {
        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        if (!isFlashCombatAvailable(player, room)) {
            return false;
        }
        PlayerInventory inventory = player.getInventory();
        ItemStack crossbow = inventory.getItemInMainHand();
        ItemStack offhand = inventory.getItemInOffHand();
        if (crossbow.getType() != Material.CROSSBOW || offhand.getType() == Material.AIR || !(crossbow.getItemMeta() instanceof CrossbowMeta meta)) {
            return false;
        }
        if (meta.hasChargedProjectiles()) {
            return false;
        }

        CrossbowPayload payload = resolveCrossbowPayload(offhand);
        if (payload == null) {
            return false;
        }
        if (payload == CrossbowPayload.TRIDENT && isRiptideTridentCooldownActive(player, offhand)) {
            return false;
        }
        return true;
    }

    private boolean tryLoadFlashCrossbowPayload(Player player) {
        if (player == null || !player.isOnline() || !canLoadFlashCrossbowPayload(player)) {
            return false;
        }
        PlayerInventory inventory = player.getInventory();
        ItemStack crossbow = inventory.getItemInMainHand();
        ItemStack offhand = inventory.getItemInOffHand();
        if (!(crossbow.getItemMeta() instanceof CrossbowMeta meta)) {
            return false;
        }
        CrossbowPayload payload = resolveCrossbowPayload(offhand);
        if (payload == null) {
            return false;
        }
        UnstableMacePearlTrigger unstablePearlTrigger = payload == CrossbowPayload.ENDER_PEARL
                ? consumeOpenUnstableMacePearlTrigger(player)
                : null;
        ItemStack payloadItem = offhand.clone();
        payloadItem.setAmount(1);
        boolean keepOffhandPayload = payload == CrossbowPayload.TRIDENT && offhand.getEnchantmentLevel(Enchantment.RIPTIDE) > 0;
        if (!keepOffhandPayload && !consumeOffhandItems(player, 1, offhand.getType())) {
            return false;
        }

        meta.addChargedProjectile(new ItemStack(Material.ARROW));
        meta.getPersistentDataContainer().set(crossbowPayloadTypeKey, PersistentDataType.STRING, payload.name());
        meta.getPersistentDataContainer().set(crossbowPayloadDataKey, PersistentDataType.BYTE_ARRAY, payloadItem.serializeAsBytes());
        if (payload == CrossbowPayload.WIND_CHARGE || payload == CrossbowPayload.ENHANCED_WIND_CHARGE) {
            meta.getPersistentDataContainer().set(windChargedCrossbowKey, PersistentDataType.BYTE, (byte) 1);
        } else {
            meta.getPersistentDataContainer().remove(windChargedCrossbowKey);
        }
        if (unstablePearlTrigger != null) {
            unstableMaceLoadedPearls.put(player.getUniqueId(),
                    unstablePearlTrigger.withExpires(System.currentTimeMillis() + UNSTABLE_MACE_LOADED_PEARL_EXPIRE_MS));
            player.sendActionBar("§x§B§B§8§8§F§F✦ §d不稳定珍珠已锁定，§f发射后将折跃回猛击点");
        }
        crossbow.setItemMeta(meta);
        inventory.setItemInMainHand(crossbow);
        player.updateInventory();
        ItemStack loadedSnapshot = crossbow.clone();
        Bukkit.getScheduler().runTask(plugin, () -> ensureFlashCrossbowLoadApplied(player, loadedSnapshot));
        Bukkit.getScheduler().runTaskLater(plugin, () -> ensureFlashCrossbowLoadApplied(player, loadedSnapshot), 2L);
        Bukkit.getScheduler().runTaskLater(plugin, () -> ensureFlashCrossbowLoadApplied(player, loadedSnapshot), 5L);

        player.playSound(player.getLocation(), payload.loadSound(), 0.85f, payload.loadPitch());
        player.playSound(player.getLocation(), Sound.ITEM_CROSSBOW_LOADING_START, 0.55f, 1.45f);
        Bukkit.getScheduler().runTaskLater(plugin, () -> {
            if (player.isOnline()) {
                player.playSound(player.getLocation(), Sound.ITEM_CROSSBOW_LOADING_END, 0.75f, 1.25f);
                player.updateInventory();
            }
        }, 3L);
        return true;
    }

    private void ensureFlashCrossbowLoadApplied(Player player, ItemStack loadedSnapshot) {
        if (player == null || !player.isOnline() || loadedSnapshot == null || loadedSnapshot.getType() != Material.CROSSBOW) {
            return;
        }
        if (isRecentCrossbowPayloadShot(player)) {
            return;
        }
        ItemMeta snapshotMeta = loadedSnapshot.getItemMeta();
        if (!(snapshotMeta instanceof CrossbowMeta snapshotCrossbowMeta)
                || !snapshotCrossbowMeta.hasChargedProjectiles()
                || getCrossbowPayload(loadedSnapshot) == null) {
            return;
        }

        PlayerInventory inventory = player.getInventory();
        ItemStack current = inventory.getItemInMainHand();
        if (current == null || current.getType() != Material.CROSSBOW) {
            return;
        }

        if (current.getItemMeta() instanceof CrossbowMeta currentMeta
                && currentMeta.hasChargedProjectiles()
                && getCrossbowPayload(current) != null) {
            player.updateInventory();
            return;
        }

        current.setItemMeta(snapshotMeta.clone());
        inventory.setItemInMainHand(current);
        player.updateInventory();
    }

    public boolean handleFlashBowShoot(EntityShootBowEvent event) {
        if (!(event.getEntity() instanceof Player player)) {
            return false;
        }
        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        if (!isFlashCombatAvailable(player, room)) {
            return false;
        }

        ItemStack bow = event.getBow();
        if (bow == null || (bow.getType() != Material.BOW && bow.getType() != Material.CROSSBOW)) {
            return false;
        }

        boolean crossbow = bow.getType() == Material.CROSSBOW;
        ItemStack loadedCrossbow = crossbow ? resolveLoadedFlashCrossbowForShot(player, bow) : bow;
        CrossbowPayload payload = crossbow ? getCrossbowPayload(loadedCrossbow) : null;
        ItemStack payloadItem = crossbow ? getCrossbowPayloadItem(loadedCrossbow) : null;
        if (crossbow && payload == null && handleFireworkCrossbowTntSwap(event, player, bow)) {
            return true;
        }

        if (payload == null && applyDragonBreathArrowShot(event, player, bow, crossbow)) {
            if (crossbow) {
                applyJukeboxCrossbowProjectileBonuses(player, event.getProjectile());
            }
            return true;
        }

        if (crossbow && payload == null) {
            applyJukeboxCrossbowProjectileBonuses(player, event.getProjectile());
        }

        boolean downwardBowWindChargeDash = false;
        if (!crossbow) {
            ItemStack offhand = player.getInventory().getItemInOffHand();
            if (isEnhancedWindCharge(offhand)) {
                consumeHandItem(player, EquipmentSlot.OFF_HAND, 1);
                payload = CrossbowPayload.ENHANCED_WIND_CHARGE;
                payloadItem = createEnhancedWindCharge();
            } else if (offhand.getType() == Material.WIND_CHARGE) {
                boolean canDownwardDash = shouldTriggerDownwardBowWindChargeDash(player) && offhand.getAmount() >= 2;
                int consumeAmount = canDownwardDash ? 2 : 1;
                if (consumeOffhandItems(player, consumeAmount, Material.WIND_CHARGE)) {
                    downwardBowWindChargeDash = canDownwardDash;
                    payload = CrossbowPayload.WIND_CHARGE;
                    payloadItem = new ItemStack(Material.WIND_CHARGE);
                }
            }
        }

        if (payload == null || payloadItem == null) {
            return false;
        }

        event.setCancelled(true);
        event.setConsumeArrow(false);
        event.setConsumeItem(false);
        if (event.getProjectile() != null) {
            event.getProjectile().remove();
        }
        if (crossbow) {
            rememberCrossbowPayloadShot(player);
            clearCrossbowPayload(player, loadedCrossbow);
            damageLoadedCrossbow(player, loadedCrossbow, payload);
            player.updateInventory();
        }

        switch (payload) {
            case WIND_CHARGE -> {
                if (downwardBowWindChargeDash) {
                    applyDownwardBowWindChargeDash(player);
                } else {
                    spawnWindCharges(player, bow, crossbow, event.getForce());
                }
            }
            case ENHANCED_WIND_CHARGE -> spawnWindCharges(player, bow, crossbow, event.getForce(), true);
            case TNT -> launchTntPayload(player, room, event.getForce(), getCrossbowProjectileMultiplier(player, bow));
            case TMT -> player.sendActionBar("§x§F§F§5§5§3§3✦ §cTMT §7现在只能放置，不能作为弩弹药");
            case FOOD -> applyFoodPayload(player, payloadItem);
            case SWORD -> launchCrossbowSwordPayload(player, room, payloadItem);
            case ENDER_PEARL -> launchEnderPearlPayload(player, event.getForce(), getCrossbowProjectileMultiplier(player, bow));
            case TRIDENT -> launchTridentPayload(player, room, payloadItem, getCrossbowProjectileMultiplier(player, bow));
        }
        return true;
    }

    private boolean shouldTriggerDownwardBowWindChargeDash(Player player) {
        if (player == null || isShieldWindChargeGrounded(player)) {
            return false;
        }
        return player.getLocation().getPitch() >= FLASH_BOW_DOWN_WIND_CHARGE_PITCH_DEGREES;
    }

    private void applyDownwardBowWindChargeDash(Player player) {
        UUID playerId = player.getUniqueId();
        double shieldAirStrength = 0.86D * SHIELD_WIND_CHARGE_DASH_SPEED_MULTIPLIER;
        double upwardY = shieldAirStrength * FLASH_BOW_DOWN_WIND_CHARGE_SHIELD_Y_MULTIPLIER;
        Vector velocity = player.getVelocity().clone();
        velocity.setY(Math.max(velocity.getY(), upwardY));
        player.setVelocity(velocity);
        player.setFallDistance(0.0F);
        shieldWindChargeSafeFallExpires.put(playerId, System.currentTimeMillis() + 6500L);
        shieldWindChargeAirBounceCounts.put(playerId, 1);

        Location effect = player.getLocation().add(0.0D, 0.76D, 0.0D);
        player.getWorld().spawnParticle(Particle.GUST, effect, 24, 0.34D, 0.18D, 0.34D, 0.055D);
        player.getWorld().spawnParticle(Particle.SMALL_GUST, effect, 36, 0.38D, 0.22D, 0.38D, 0.048D);
        player.playSound(player.getLocation(), Sound.ENTITY_WIND_CHARGE_THROW, 0.82f, 0.92f);
        player.playSound(player.getLocation(), Sound.ENTITY_BREEZE_WIND_BURST, 0.58f, 1.34f);
        player.sendActionBar("§x§8§8§D§D§F§F✦ §b弓风弹下压 §8| §7消耗 §e2 §7个风弹，盾风弹空中概率重置为 §a50%");
    }

    private boolean shouldCancelOffhandCrossbowLoadUse(Player player) {
        PlayerInventory inventory = player.getInventory();
        ItemStack crossbow = inventory.getItemInMainHand();
        ItemStack offhand = inventory.getItemInOffHand();
        if (crossbow == null || crossbow.getType() != Material.CROSSBOW || offhand == null || offhand.getType() == Material.AIR) {
            return false;
        }
        if (!(crossbow.getItemMeta() instanceof CrossbowMeta meta) || meta.hasChargedProjectiles()) {
            return false;
        }
        CrossbowPayload payload = resolveCrossbowPayload(offhand);
        return payload != null && !(payload == CrossbowPayload.TRIDENT && isRiptideTridentCooldownActive(player, offhand));
    }

    private void cancelCrossbowLoadInteract(PlayerInteractEvent event) {
        event.setCancelled(true);
        event.setUseInteractedBlock(Event.Result.DENY);
        event.setUseItemInHand(Event.Result.DENY);
    }

    private void rememberCrossbowLoadOffhandCancel(Player player) {
        if (player != null) {
            recentCrossbowLoadOffhandCancels.put(player.getUniqueId(), System.currentTimeMillis() + 350L);
        }
    }

    public boolean shouldBlockRecentCrossbowLoadOffhandUse(Player player) {
        if (player == null) {
            return false;
        }
        long now = System.currentTimeMillis();
        long until = recentCrossbowLoadOffhandCancels.getOrDefault(player.getUniqueId(), 0L);
        if (until <= now) {
            recentCrossbowLoadOffhandCancels.remove(player.getUniqueId());
            return false;
        }
        return true;
    }

    private void rememberCrossbowPayloadShot(Player player) {
        if (player != null) {
            recentCrossbowPayloadShots.put(player.getUniqueId(), System.currentTimeMillis() + 360L);
        }
    }

    private boolean isRecentCrossbowPayloadShot(Player player) {
        if (player == null) {
            return false;
        }
        long now = System.currentTimeMillis();
        long until = recentCrossbowPayloadShots.getOrDefault(player.getUniqueId(), 0L);
        if (until <= now) {
            recentCrossbowPayloadShots.remove(player.getUniqueId());
            return false;
        }
        return true;
    }

    private UnstableMacePearlTrigger consumeOpenUnstableMacePearlTrigger(Player player) {
        if (player == null) {
            return null;
        }
        UUID playerId = player.getUniqueId();
        UnstableMacePearlTrigger trigger = unstableMacePearlTriggers.get(playerId);
        if (trigger == null) {
            return null;
        }

        long now = System.currentTimeMillis();
        if (now > trigger.expiresAtMillis()) {
            unstableMacePearlTriggers.remove(playerId);
            return null;
        }
        if (now < trigger.opensAtMillis()) {
            return null;
        }

        Entity target = Bukkit.getEntity(trigger.targetUuid());
        if (!(target instanceof LivingEntity living) || !living.isValid() || living.isDead()
                || !target.getWorld().equals(player.getWorld())) {
            unstableMacePearlTriggers.remove(playerId);
            return null;
        }

        GameRoom room = plugin.getRoomManager().getPlayerRoom(playerId);
        if (!trigger.roomId().equals(getFlashContextId(player, room))) {
            unstableMacePearlTriggers.remove(playerId);
            return null;
        }

        unstableMacePearlTriggers.remove(playerId);
        return trigger;
    }

    private void triggerUnstableMacePearlTeleport(Player player, EnderPearl pearl) {
        if (player == null) {
            return;
        }
        UUID playerId = player.getUniqueId();
        UnstableMacePearlTrigger trigger = unstableMaceLoadedPearls.remove(playerId);
        if (trigger == null) {
            return;
        }
        long now = System.currentTimeMillis();
        if (now > trigger.expiresAtMillis()) {
            return;
        }

        Bukkit.getScheduler().runTaskLater(plugin, () -> {
            Player online = Bukkit.getPlayer(playerId);
            if (online == null || !online.isOnline()) {
                return;
            }
            if (pearl != null && pearl.isValid() && !pearl.isDead()) {
                pearl.remove();
            }
            performUnstableMacePearlTeleport(online, trigger);
        }, 3L);
    }

    private void performUnstableMacePearlTeleport(Player player, UnstableMacePearlTrigger trigger) {
        Entity entity = Bukkit.getEntity(trigger.targetUuid());
        if (!(entity instanceof LivingEntity target) || !target.isValid() || target.isDead()
                || target.getWorld() == null || !target.getWorld().equals(player.getWorld())) {
            player.playSound(player.getLocation(), Sound.BLOCK_NOTE_BLOCK_BASS, 0.52f, 0.72f);
            player.sendActionBar("§x§F§F§6§6§6§6✖ §7不稳定折跃目标已经丢失");
            return;
        }

        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        String currentRoomId = getFlashContextId(player, room);
        if (!trigger.roomId().equals(currentRoomId)) {
            return;
        }
        if (target instanceof Player targetPlayer && !canDamage(room, player, targetPlayer)) {
            return;
        }

        boolean behind = ThreadLocalRandom.current().nextDouble() < UNSTABLE_MACE_BACK_TELEPORT_CHANCE;
        Location destination = getUnstableMacePearlDestination(target, behind);
        player.teleport(destination, PlayerTeleportEvent.TeleportCause.PLUGIN);
        player.setFallDistance(0.0F);
        Vector down = target.getLocation().toVector().subtract(player.getLocation().toVector());
        if (down.lengthSquared() > 0.001D) {
            down.normalize().multiply(0.18D);
            down.setY(Math.min(-0.08D, down.getY()));
            player.setVelocity(down);
        }

        unstableMaceAmbushBonuses.put(player.getUniqueId(), new UnstableMaceAmbushBonus(
                target.getUniqueId(), currentRoomId, System.currentTimeMillis() + UNSTABLE_MACE_AMBUSH_EXPIRE_MS, trigger.level()));
        Location effect = player.getLocation().add(0.0D, 0.85D, 0.0D);
        player.getWorld().spawnParticle(Particle.REVERSE_PORTAL, effect, 54, 0.36D, 0.42D, 0.36D, 0.16D);
        player.getWorld().spawnParticle(Particle.ELECTRIC_SPARK, effect, 26, 0.28D, 0.28D, 0.28D, 0.08D);
        player.playSound(player.getLocation(), Sound.ENTITY_ENDERMAN_TELEPORT, 0.92f, behind ? 1.36f : 0.92f);
        player.playSound(player.getLocation(), Sound.BLOCK_RESPAWN_ANCHOR_CHARGE, 0.48f, 1.66f);
        player.sendActionBar((behind ? "§x§B§B§8§8§F§F✦ §d后位折跃" : "§x§9§8§D§D§F§F✦ §b前位折跃")
                + " §7完成，§f只改变位置，下一击不加伤害");
    }

    private Location getUnstableMacePearlDestination(LivingEntity target, boolean behind) {
        Location base = target.getLocation().clone();
        Vector forward = base.getDirection();
        forward.setY(0.0D);
        if (forward.lengthSquared() < 0.001D) {
            forward = new Vector(0.0D, 0.0D, 1.0D);
        }
        forward.normalize();
        Vector offset = behind ? forward.clone().multiply(-1.18D) : forward.clone().multiply(1.18D);
        Location destination = base.add(offset).add(0.0D, 2.65D, 0.0D);
        Vector look = target.getLocation().add(0.0D, Math.min(1.2D, target.getHeight() * 0.62D), 0.0D)
                .toVector().subtract(destination.toVector());
        if (look.lengthSquared() > 0.001D) {
            destination.setDirection(look);
        }
        return destination;
    }

    private double getCrossbowProjectileMultiplier(ItemStack bow) {
        double multiplier = 1.0D;
        if (isAmethystCrossbow(bow)) {
            multiplier *= AMETHYST_CROSSBOW_SPEED_MULTIPLIER;
        }
        if (isWindRodCrossbow(bow)) {
            multiplier *= WIND_ROD_CROSSBOW_SPEED_MULTIPLIER;
        }
        return multiplier;
    }

    private double getCrossbowProjectileMultiplier(Player player, ItemStack bow) {
        return getCrossbowProjectileMultiplier(bow) * getJukeboxCrossbowProjectileSpeedMultiplier(player);
    }

    private boolean applyDragonBreathArrowShot(EntityShootBowEvent event, Player player, ItemStack bow, boolean crossbow) {
        boolean dragonBreath = isDragonBreathWeapon(bow);
        boolean amethyst = crossbow && isAmethystCrossbow(bow);
        if ((!dragonBreath && !amethyst) || !(event.getProjectile() instanceof AbstractArrow arrow)) {
            return false;
        }

        Vector velocity = arrow.getVelocity();
        if (velocity.lengthSquared() > 0.001D) {
            double multiplier = (dragonBreath ? DRAGON_BREATH_ARROW_MULTIPLIER : 1.0D) * (amethyst ? AMETHYST_CROSSBOW_SPEED_MULTIPLIER : 1.0D);
            arrow.setVelocity(velocity.multiply(multiplier));
        }
        if (dragonBreath) {
            arrow.setDamage(arrow.getDamage() * DRAGON_BREATH_ARROW_MULTIPLIER);
        }
        if (crossbow && dragonBreath) {
            arrow.setGravity(false);
        }
        if (dragonBreath) {
            monitorDragonBreathArrow(player, arrow, crossbow, arrow.getLocation().clone());
            player.playSound(player.getLocation(), Sound.ENTITY_ENDER_DRAGON_SHOOT, 0.38f, crossbow ? 1.55f : 1.35f);
        } else {
            player.playSound(player.getLocation(), Sound.BLOCK_AMETHYST_BLOCK_CHIME, 0.38f, 1.7f);
        }
        return true;
    }

    private void monitorDragonBreathArrow(Player shooter, AbstractArrow arrow, boolean crossbow, Location start) {
        new BukkitRunnable() {
            @Override
            public void run() {
                if (arrow.isDead() || !arrow.isValid() || arrow.isOnGround() || arrow.isInBlock()) {
                    cancel();
                    return;
                }
                if (crossbow && arrow.getWorld().equals(start.getWorld())
                        && arrow.getLocation().distanceSquared(start) > DRAGON_BREATH_CROSSBOW_MAX_DISTANCE * DRAGON_BREATH_CROSSBOW_MAX_DISTANCE) {
                    arrow.getWorld().spawnParticle(Particle.DRAGON_BREATH, arrow.getLocation(), 18, 0.12, 0.12, 0.12, 0.03);
                    arrow.remove();
                    cancel();
                    return;
                }
                Location loc = arrow.getLocation();
                loc.getWorld().spawnParticle(Particle.DRAGON_BREATH, loc, 3, 0.045, 0.045, 0.045, 0.01);
                if (arrow.getTicksLived() % 5 == 0) {
                    loc.getWorld().spawnParticle(Particle.WITCH, loc, 1, 0.025, 0.025, 0.025, 0.0);
                }
            }
        }.runTaskTimer(plugin, 1L, 1L);
    }

    public boolean handleDispenserSwordWave(BlockDispenseEvent event) {
        Block block = event.getBlock();
        Material sourceType = block.getType();
        if ((sourceType != Material.DISPENSER && sourceType != Material.DROPPER) || !isSword(event.getItem())) {
            return false;
        }
        GameRoom room = getFlashRoomByWorld(block.getWorld());
        if (!isFlashWorldActive(block.getWorld())) {
            return false;
        }
        if (!consumeOneFromContainer(block, event.getItem())) {
            return false;
        }
        event.setCancelled(true);
        Vector direction = getDispenserDirection(block).normalize();
        Location start = block.getLocation().add(0.5D, 0.5D, 0.5D).add(direction.clone().multiply(0.92D));
        ItemStack sword = event.getItem().clone();
        sword.setAmount(1);
        block.getWorld().playSound(start, Sound.ITEM_CROSSBOW_SHOOT, 0.78f, 1.22f);
        block.getWorld().playSound(start, Sound.ITEM_TRIDENT_THROW, 0.68f, 1.38f);
        block.getWorld().spawnParticle(Particle.ITEM, start, 12, 0.14D, 0.10D, 0.14D, 0.02D, sword);
        block.getWorld().spawnParticle(Particle.ENCHANT, start, 12, 0.16D, 0.10D, 0.16D, 0.02D);
        launchFlyingSwordDisplay(null, room, sword, start, direction);
        return true;
    }

    public void handleJukeboxAuraInteract(PlayerInteractEvent event) {
        if (event.getHand() != EquipmentSlot.HAND || event.getAction() != Action.RIGHT_CLICK_BLOCK) {
            return;
        }
        Player player = event.getPlayer();
        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        if (!isFlashCombatAvailable(player, room)) {
            return;
        }
        Block clicked = event.getClickedBlock();
        if (clicked == null || clicked.getType() != Material.JUKEBOX) {
            return;
        }
        scheduleJukeboxAuraScan(clicked.getLocation(), 1L, true);
        scheduleJukeboxAuraScan(clicked.getLocation(), 5L, true);
        scheduleJukeboxAuraScan(clicked.getLocation(), 12L, true);
        scheduleJukeboxAuraScan(clicked.getLocation(), 24L, true);
    }

    public void handleFlashNoteBlockInteract(PlayerInteractEvent event) {
        if (event.getHand() != EquipmentSlot.HAND || event.getAction() != Action.LEFT_CLICK_BLOCK) {
            return;
        }
        Player player = event.getPlayer();
        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        if (!isFlashCombatAvailable(player, room)) {
            return;
        }
        Block clicked = event.getClickedBlock();
        if (clicked == null || clicked.getType() != Material.NOTE_BLOCK) {
            return;
        }

        Bukkit.getScheduler().runTaskLater(plugin, () -> {
            if (!player.isOnline() || clicked.getType() != Material.NOTE_BLOCK) {
                return;
            }
            GameRoom currentRoom = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
            if (!isFlashCombatAvailable(player, currentRoom)) {
                return;
            }
            if (!(clicked.getBlockData() instanceof org.bukkit.block.data.type.NoteBlock noteBlock)) {
                return;
            }
            int tone = noteBlock.getNote().getId();
            FlashNoteMelody melody = rememberFlashNoteAndMatch(player, tone);
            if (melody == null) {
                clicked.getWorld().spawnParticle(Particle.NOTE, clicked.getLocation().add(0.5D, 0.92D, 0.5D),
                        1, 0.08D, 0.04D, 0.08D, 0.0D);
                return;
            }
            long now = System.currentTimeMillis();
            FlashNoteSpell spell = melody.spell();
            boolean finale = isFlashNoteFinale(spell);
            long cooldown = finale ? FLASH_NOTE_BLOCK_FINALE_COOLDOWN_MS
                    : spell.damage() > 0.0D ? FLASH_NOTE_BLOCK_DAMAGE_COOLDOWN_MS : FLASH_NOTE_BLOCK_DEFAULT_COOLDOWN_MS;
            Map<UUID, Long> cooldowns = finale ? flashNoteFinaleCooldowns : flashNoteBlockCooldowns;
            if (cooldowns.getOrDefault(player.getUniqueId(), 0L) > now) {
                return;
            }
            cooldowns.put(player.getUniqueId(), now + cooldown);
            if (finale) {
                flashNoteMelodyBuffers.remove(player.getUniqueId());
            }
            player.sendActionBar("§x§B§B§8§8§F§F♫ §f" + melody.displayName() + " §8» §a" + describeFlashNoteSpell(spell));
            triggerFlashNoteSpell(player, currentRoom, clicked.getLocation().add(0.5D, 0.75D, 0.5D), spell);
        }, 0L);
    }

    private FlashNoteMelody rememberFlashNoteAndMatch(Player player, int tone) {
        long now = System.currentTimeMillis();
        FlashNoteMelodyBuffer buffer = flashNoteMelodyBuffers.computeIfAbsent(player.getUniqueId(), ignored -> new FlashNoteMelodyBuffer());
        if (now - buffer.lastNoteAt() > FLASH_NOTE_MELODY_RESET_MS) {
            buffer.notes().clear();
            buffer.times().clear();
        }
        buffer.notes().addLast(Math.floorMod(tone, 25));
        buffer.times().addLast(now);
        while (buffer.notes().size() > FLASH_NOTE_MELODY_MAX_NOTES) {
            buffer.notes().removeFirst();
            buffer.times().removeFirst();
        }
        buffer.setLastNoteAt(now);

        for (FlashNoteMelody melody : getFlashNoteFinaleMelodies()) {
            if (melodyMatches(buffer.notes(), buffer.times(), melody.tones(), melody.rhythm())) {
                return melody;
            }
        }
        for (FlashNoteMelody melody : getFlashNoteMelodies()) {
            if (melodyMatches(buffer.notes(), buffer.times(), melody.tones(), melody.rhythm())) {
                return melody;
            }
        }
        return null;
    }

    private boolean melodyMatches(Deque<Integer> notes, Deque<Long> times, int[] pattern, int[] rhythm) {
        if (pattern == null || notes.size() < pattern.length || !hasEnoughFlashNoteMelodyShape(pattern, 0, pattern.length)) {
            return false;
        }
        Integer[] noteArray = notes.toArray(new Integer[0]);
        Long[] timeArray = times.toArray(new Long[0]);
        int offset = noteArray.length - pattern.length;
        for (int i = 0; i < pattern.length; i++) {
            if (noteArray[offset + i] == null || noteArray[offset + i] != Math.floorMod(pattern[i], 25)) {
                return false;
            }
        }
        if (!hasEnoughFlashNoteMelodyShape(noteArray, offset, pattern.length)) {
            return false;
        }
        if (rhythm == null || rhythm.length != pattern.length - 1 || rhythm.length == 0) {
            return true;
        }
        double actualTotal = 0.0D;
        int expectedTotal = 0;
        double[] actual = new double[rhythm.length];
        for (int i = 0; i < rhythm.length; i++) {
            actual[i] = Math.max(50.0D, timeArray[offset + i + 1] - timeArray[offset + i]);
            actualTotal += actual[i];
            expectedTotal += Math.max(1, rhythm[i]);
        }
        if (actualTotal <= 0.0D || expectedTotal <= 0) {
            return true;
        }
        double unit = actualTotal / expectedTotal;
        for (int i = 0; i < rhythm.length; i++) {
            double expected = Math.max(1, rhythm[i]) * unit;
            double tolerance = Math.max(190.0D, expected * 0.52D);
            if (Math.abs(actual[i] - expected) > tolerance) {
                return false;
            }
        }
        return true;
    }

    private boolean hasEnoughFlashNoteMelodyShape(int[] notes, int offset, int length) {
        if (notes == null || length <= 0 || offset < 0 || offset + length > notes.length) {
            return false;
        }
        int requiredDistinct = Math.min(FLASH_NOTE_MELODY_MIN_DISTINCT_TONES, Math.max(1, length));
        int requiredChanges = Math.min(FLASH_NOTE_MELODY_MIN_CHANGES, Math.max(0, length - 1));
        Set<Integer> distinct = new HashSet<>();
        int changes = 0;
        Integer previous = null;
        for (int i = 0; i < length; i++) {
            int tone = Math.floorMod(notes[offset + i], 25);
            distinct.add(tone);
            if (previous != null && previous != tone) {
                changes++;
            }
            previous = tone;
        }
        return distinct.size() >= requiredDistinct && changes >= requiredChanges;
    }

    private boolean hasEnoughFlashNoteMelodyShape(Integer[] notes, int offset, int length) {
        if (notes == null || length <= 0 || offset < 0 || offset + length > notes.length) {
            return false;
        }
        int requiredDistinct = Math.min(FLASH_NOTE_MELODY_MIN_DISTINCT_TONES, Math.max(1, length));
        int requiredChanges = Math.min(FLASH_NOTE_MELODY_MIN_CHANGES, Math.max(0, length - 1));
        Set<Integer> distinct = new HashSet<>();
        int changes = 0;
        Integer previous = null;
        for (int i = 0; i < length; i++) {
            Integer rawTone = notes[offset + i];
            if (rawTone == null) {
                return false;
            }
            int tone = Math.floorMod(rawTone, 25);
            distinct.add(tone);
            if (previous != null && previous != tone) {
                changes++;
            }
            previous = tone;
        }
        return distinct.size() >= requiredDistinct && changes >= requiredChanges;
    }

    private boolean melodyNotesMatch(Deque<Integer> notes, int[] pattern) {
        if (notes.size() < pattern.length) {
            return false;
        }
        Iterator<Integer> iterator = notes.descendingIterator();
        for (int i = pattern.length - 1; i >= 0; i--) {
            if (!iterator.hasNext() || iterator.next() != Math.floorMod(pattern[i], 25)) {
                return false;
            }
        }
        return true;
    }

    private List<FlashNoteMelody> getFlashNoteMelodies() {
        ensureFlashNoteMelodiesLoaded();
        return cachedFlashNoteMelodies;
    }

    private List<FlashNoteMelody> getFlashNoteFinaleMelodies() {
        ensureFlashNoteMelodiesLoaded();
        return cachedFlashNoteFinaleMelodies;
    }

    public List<String> getFlashNoteMusicNames() {
        ensureFlashNoteMelodiesLoaded();
        List<FlashNoteMelody> melodies = new ArrayList<>();
        melodies.addAll(cachedFlashNoteFinaleMelodies);
        melodies.addAll(cachedFlashNoteMelodies);
        melodies.sort(this::compareFlashMusic);
        List<String> names = new ArrayList<>();
        Set<String> seen = new HashSet<>();
        for (FlashNoteMelody melody : melodies) {
            if (seen.add(melody.displayName().toLowerCase(Locale.ROOT))) {
                names.add(melody.displayName());
            }
        }
        return names;
    }

    public List<String> getFlashNoteMusicNameHints() {
        ConfigurationSection root = plugin.getConfigManager().getConfig()
                .getConfigurationSection("hunter_game.flash_mode.note_block_melodies");
        if (root == null || !root.getBoolean("enabled", true)) {
            return List.of();
        }
        List<String> names = new ArrayList<>();
        Set<String> seen = new HashSet<>();
        ConfigurationSection configuredSongs = root.getConfigurationSection("songs");
        if (configuredSongs != null) {
            for (String key : configuredSongs.getKeys(false)) {
                ConfigurationSection section = configuredSongs.getConfigurationSection(key);
                if (section == null || !section.getBoolean("enabled", true)) {
                    continue;
                }
                addFlashNoteMusicNameHint(names, seen, section.getString("name", key));
            }
        }
        if (root.getBoolean("scan_files", true)) {
            File folder = new File(plugin.getDataFolder(), root.getString("source_folder", "flash-note-songs"));
            if (folder.isDirectory()) {
                List<File> files = new ArrayList<>();
                collectFlashNoteMelodyFiles(folder, root.getBoolean("scan_subfolders", true), files);
                files.sort(Comparator.comparing(File::getAbsolutePath, String.CASE_INSENSITIVE_ORDER));
                for (File file : files) {
                    addFlashNoteMusicNameHint(names, seen,
                            prettyFlashNoteSongName(folder.toPath().relativize(file.toPath()).toString().replace(File.separatorChar, '/')));
                }
            }
        }
        names.sort(Comparator.comparingInt(this::flashMusicPreferredRank).thenComparing(String::compareToIgnoreCase));
        return List.copyOf(names);
    }

    private void addFlashNoteMusicNameHint(List<String> names, Set<String> seen, String name) {
        if (name == null || name.isBlank()) {
            return;
        }
        if (seen.add(name.toLowerCase(Locale.ROOT))) {
            names.add(name);
        }
    }

    public FlashMusicPlayResult playFlashNoteMusic(Collection<Player> listeners, String query, int intervalTicks, float volume) {
        return playFlashNoteMusic(listeners, query, intervalTicks, volume, false);
    }

    public FlashMusicPlayResult playFlashNoteMusic(Collection<Player> listeners, String query, int intervalTicks, float volume, boolean fullMode) {
        if (fullMode) {
            return playFullFlashNoteMusic(listeners, query, volume);
        }
        FlashNoteMelody melody = findFlashNoteMusic(query);
        if (melody == null) {
            return new FlashMusicPlayResult(false, "", 0, 0);
        }
        List<Player> targets = listeners == null ? List.of() : listeners.stream()
                .filter(player -> player != null && player.isOnline())
                .toList();
        if (targets.isEmpty()) {
            return new FlashMusicPlayResult(false, melody.displayName(), melody.tones().length, 0);
        }
        int safeInterval = Math.max(1, Math.min(20, intervalTicks));
        float safeVolume = Math.max(0.05f, Math.min(2.0f, volume));
        for (Player target : targets) {
            startFlashMusicForPlayer(target, melody, safeInterval, safeVolume);
        }
        return new FlashMusicPlayResult(true, melody.displayName(), melody.tones().length, targets.size());
    }

    private FlashMusicPlayResult playFullFlashNoteMusic(Collection<Player> listeners, String query, float volume) {
        FlashFullMusicData song = loadFullFlashNoteMusic(query);
        if (song == null || song.notes().isEmpty()) {
            return new FlashMusicPlayResult(false, "", 0, 0);
        }
        List<Player> targets = listeners == null ? List.of() : listeners.stream()
                .filter(player -> player != null && player.isOnline())
                .toList();
        if (targets.isEmpty()) {
            return new FlashMusicPlayResult(false, song.displayName(), song.notes().size(), 0);
        }
        float safeVolume = Math.max(0.05f, Math.min(2.0f, volume));
        for (Player target : targets) {
            startFullFlashMusicForPlayer(target, song, safeVolume);
        }
        return new FlashMusicPlayResult(true, song.displayName(), song.notes().size(), targets.size());
    }

    public boolean stopFlashNoteMusic(Player player) {
        if (player == null) {
            return false;
        }
        BukkitTask task = flashMusicTasks.remove(player.getUniqueId());
        if (task == null) {
            return false;
        }
        task.cancel();
        return true;
    }

    public int stopAllFlashNoteMusic() {
        int stopped = flashMusicTasks.size();
        for (BukkitTask task : new ArrayList<>(flashMusicTasks.values())) {
            task.cancel();
        }
        flashMusicTasks.clear();
        return stopped;
    }

    public int getActiveFlashNoteMusicCount() {
        return flashMusicTasks.size();
    }

