    private void startFlashMusicForPlayer(Player player, FlashNoteMelody melody, int intervalTicks, float volume) {
        stopFlashNoteMusic(player);
        UUID playerId = player.getUniqueId();
        int[] tones = melody.tones();
        int[] playbackTicks = melody.playbackTicks();
        if (playbackTicks.length == tones.length && playbackTicks.length > 0) {
            BukkitTask task = new BukkitRunnable() {
                private int index = 0;
                private int tick = 0;

                @Override
                public void run() {
                    Player target = Bukkit.getPlayer(playerId);
                    if (target == null || !target.isOnline() || index >= tones.length) {
                        flashMusicTasks.remove(playerId);
                        cancel();
                        return;
                    }
                    while (index < tones.length && playbackTicks[index] <= tick) {
                        playFlashMusicTone(target, tones[index], volume);
                        index++;
                    }
                    tick++;
                }
            }.runTaskTimer(plugin, 0L, 1L);
            flashMusicTasks.put(playerId, task);
            return;
        }
        BukkitTask task = new BukkitRunnable() {
            private int index = 0;

            @Override
            public void run() {
                Player target = Bukkit.getPlayer(playerId);
                if (target == null || !target.isOnline() || index >= tones.length) {
                    flashMusicTasks.remove(playerId);
                    cancel();
                    return;
                }
                playFlashMusicTone(target, tones[index], volume);
                index++;
            }
        }.runTaskTimer(plugin, 0L, intervalTicks);
        flashMusicTasks.put(playerId, task);
    }

    private void startFullFlashMusicForPlayer(Player player, FlashFullMusicData song, float volume) {
        stopFlashNoteMusic(player);
        UUID playerId = player.getUniqueId();
        List<FlashFullNoteEvent> notes = song.notes();
        BukkitTask task = new BukkitRunnable() {
            private int tick = 0;
            private int index = 0;

            @Override
            public void run() {
                Player target = Bukkit.getPlayer(playerId);
                if (target == null || !target.isOnline()) {
                    flashMusicTasks.remove(playerId);
                    cancel();
                    return;
                }
                while (index < notes.size() && notes.get(index).playbackTick() <= tick) {
                    FlashFullNoteEvent note = notes.get(index);
                    target.playSound(target.getLocation(), note.sound(), SoundCategory.RECORDS,
                            Math.max(0.02f, Math.min(2.0f, volume * note.volume())),
                            note.pitch());
                    index++;
                }
                if (index >= notes.size() && tick > song.lengthTicks()) {
                    flashMusicTasks.remove(playerId);
                    cancel();
                    return;
                }
                tick++;
            }
        }.runTaskTimer(plugin, 0L, 1L);
        flashMusicTasks.put(playerId, task);
    }

    private void playFlashMusicTone(Player player, int tone, float volume) {
        float pitch = flashToneToPitch(tone);
        Location location = player.getLocation();
        player.playSound(location, Sound.BLOCK_NOTE_BLOCK_HARP, SoundCategory.RECORDS, volume, pitch);
    }

    private FlashNoteMelody findFlashNoteMusic(String query) {
        String normalizedQuery = normalizeFlashMusicName(query);
        if (normalizedQuery.isBlank()) {
            return null;
        }
        ensureFlashNoteMelodiesLoaded();
        List<FlashNoteMelody> melodies = new ArrayList<>();
        melodies.addAll(cachedFlashNoteFinaleMelodies);
        melodies.addAll(cachedFlashNoteMelodies);
        melodies.sort(this::compareFlashMusic);

        FlashNoteMelody startsWith = null;
        FlashNoteMelody contains = null;
        for (FlashNoteMelody melody : melodies) {
            String normalizedName = normalizeFlashMusicName(melody.displayName());
            if (normalizedName.equals(normalizedQuery)) {
                return melody;
            }
            if (startsWith == null && normalizedName.startsWith(normalizedQuery)) {
                startsWith = melody;
            }
            if (contains == null && normalizedName.contains(normalizedQuery)) {
                contains = melody;
            }
        }
        return startsWith != null ? startsWith : contains;
    }

    private int compareFlashMusic(FlashNoteMelody first, FlashNoteMelody second) {
        int rankCompare = Integer.compare(flashMusicPreferredRank(first.displayName()), flashMusicPreferredRank(second.displayName()));
        if (rankCompare != 0) {
            return rankCompare;
        }
        int shortCompare = Boolean.compare(first.displayName().contains("短谱攻击"), second.displayName().contains("短谱攻击"));
        if (shortCompare != 0) {
            return shortCompare;
        }
        return first.displayName().compareToIgnoreCase(second.displayName());
    }

    private int flashMusicPreferredRank(String displayName) {
        String normalized = normalizeFlashMusicName(displayName);
        if (normalized.contains("onimai") || normalized.contains("欧尼")) {
            return 0;
        }
        if (normalized.contains("pigstep")) {
            return 1;
        }
        if (normalized.contains("蜘蛛糸") || normalized.contains("蜘蛛丝") || normalized.contains("monopoly")) {
            return 2;
        }
        if (normalized.contains("seeyou")) {
            return 3;
        }
        if (normalized.contains("masquerade")) {
            return 4;
        }
        if (normalized.contains("sleepwalker")) {
            return 5;
        }
        if (normalized.contains("lnotheme") || normalized.contains("lのテーマ")) {
            return 6;
        }
        return 1000;
    }

    private String normalizeFlashMusicName(String value) {
        if (value == null) {
            return "";
        }
        StringBuilder builder = new StringBuilder();
        for (int i = 0; i < value.length(); i++) {
            char ch = Character.toLowerCase(value.charAt(i));
            if (Character.isLetterOrDigit(ch) || Character.UnicodeScript.of(ch) == Character.UnicodeScript.HAN
                    || Character.UnicodeScript.of(ch) == Character.UnicodeScript.HIRAGANA
                    || Character.UnicodeScript.of(ch) == Character.UnicodeScript.KATAKANA) {
                builder.append(ch);
            }
        }
        return builder.toString();
    }

    private void ensureFlashNoteMelodiesLoaded() {
        long now = System.currentTimeMillis();
        long reloadMs = Math.max(1000L, plugin.getConfigManager().getConfig()
                .getLong("hunter_game.flash_mode.note_block_melodies.reload_interval_ms", 5000L));
        if (now - cachedFlashNoteMelodiesAt < reloadMs) {
            return;
        }
        cachedFlashNoteMelodiesAt = now;
        LoadedFlashNoteMelodies loaded = loadFlashNoteMelodiesFromConfigAndFiles();
        cachedFlashNoteMelodies = loaded.shortMelodies();
        cachedFlashNoteFinaleMelodies = loaded.longMelodies();
    }

    private LoadedFlashNoteMelodies loadFlashNoteMelodiesFromConfigAndFiles() {
        List<FlashNoteMelody> shortMelodies = new ArrayList<>();
        List<FlashNoteMelody> longMelodies = new ArrayList<>();
        ConfigurationSection root = plugin.getConfigManager().getConfig()
                .getConfigurationSection("hunter_game.flash_mode.note_block_melodies");
        if (root == null || !root.getBoolean("enabled", true)) {
            return new LoadedFlashNoteMelodies(List.of(), List.of());
        }

        ConfigurationSection configuredSongs = root.getConfigurationSection("songs");
        if (configuredSongs != null) {
            for (String key : configuredSongs.getKeys(false)) {
                ConfigurationSection section = configuredSongs.getConfigurationSection(key);
                if (section == null || !section.getBoolean("enabled", true)) {
                    continue;
                }
                FlashNoteMelody melody = loadConfiguredFlashNoteMelody(key, section, root);
                if (melody == null) {
                    continue;
                }
                if (section.getBoolean("long", false) || melody.tones().length >= root.getInt("long_min_notes", 48)) {
                    longMelodies.add(melody);
                } else {
                    shortMelodies.add(melody);
                }
            }
        }

        if (root.getBoolean("scan_files", true)) {
            File folder = new File(plugin.getDataFolder(), root.getString("source_folder", "flash-note-songs"));
            if (!folder.exists() && !folder.mkdirs()) {
                plugin.getLogger().warning("无法创建音符盒谱源文件夹: " + folder.getAbsolutePath());
            }
            loadFlashNoteMelodyFiles(folder, root, shortMelodies, longMelodies);
        }

        shortMelodies.sort(Comparator.comparing(FlashNoteMelody::displayName));
        longMelodies.sort(Comparator.comparing(FlashNoteMelody::displayName));
        return new LoadedFlashNoteMelodies(List.copyOf(shortMelodies), List.copyOf(longMelodies));
    }

    private FlashNoteMelody loadConfiguredFlashNoteMelody(String key, ConfigurationSection section, ConfigurationSection root) {
        String display = section.getString("name", key);
        int[] tones;
        int[] playbackTicks = new int[0];
        String source = section.getString("source", "");
        if (!source.isBlank()) {
            File sourceFile = resolveFlashNoteSourceFile(root, source);
            FlashNoteMusicData data = loadFlashNoteMusicDataFromFile(sourceFile, Math.max(1, section.getInt("max_notes", root.getInt("max_notes_per_song", FLASH_NOTE_MELODY_MAX_NOTES))));
            tones = data.tones();
            playbackTicks = data.playbackTicks();
        } else {
            tones = parseFlashNoteToneText(String.join(",", section.getStringList("tones")),
                    Math.max(1, section.getInt("max_notes", root.getInt("max_notes_per_song", FLASH_NOTE_MELODY_MAX_NOTES))));
        }
        if (tones.length == 0) {
            plugin.getLogger().warning("音符盒谱源为空或无法解析: " + display);
            return null;
        }
        return new FlashNoteMelody(display, tones, null, createConfiguredFlashNoteSpell(section, root, tones.length), playbackTicks);
    }

    private File resolveFlashNoteSourceFile(ConfigurationSection root, String source) {
        File file = new File(source);
        if (file.isAbsolute()) {
            return file;
        }
        File folder = new File(plugin.getDataFolder(), root.getString("source_folder", "flash-note-songs"));
        return new File(folder, source);
    }

    private void loadFlashNoteMelodyFiles(File folder, ConfigurationSection root, List<FlashNoteMelody> shortMelodies, List<FlashNoteMelody> longMelodies) {
        List<File> files = new ArrayList<>();
        collectFlashNoteMelodyFiles(folder, root.getBoolean("scan_subfolders", true), files);
        if (files.isEmpty()) {
            return;
        }
        files.sort(Comparator.comparing(File::getAbsolutePath, String.CASE_INSENSITIVE_ORDER));
        int maxNotes = Math.max(1, root.getInt("max_notes_per_song", FLASH_NOTE_MELODY_MAX_NOTES));
        int longMin = Math.max(8, root.getInt("long_min_notes", 48));
        for (File file : files) {
            FlashNoteMusicData data = loadFlashNoteMusicDataFromFile(file, maxNotes);
            int[] tones = data.tones();
            if (tones.length == 0) {
                plugin.getLogger().warning("音符盒谱源无法解析: " + file.getName());
                continue;
            }
            String display = prettyFlashNoteSongName(folder.toPath().relativize(file.toPath()).toString().replace(File.separatorChar, '/'));
            FlashNoteMelody melody = new FlashNoteMelody(display, tones, null, createDefaultImportedFlashNoteSpell(root, display, tones.length), data.playbackTicks());
            if (tones.length >= longMin || file.getName().toLowerCase(Locale.ROOT).contains("long")) {
                longMelodies.add(melody);
                if (root.getBoolean("auto_short_attacks", true)) {
                    int[] shortAttackTones = createFlashNoteShortAttackTones(root, display, data);
                    if (shortAttackTones.length > 0) {
                        shortMelodies.add(new FlashNoteMelody(display + " 短谱攻击", shortAttackTones, null,
                                createDefaultImportedFlashNoteShortAttackSpell(display, shortAttackTones.length)));
                    }
                }
            } else {
                shortMelodies.add(melody);
            }
        }
    }

    private int[] createFlashNoteShortAttackTones(ConfigurationSection root, String displayName, FlashNoteMusicData data) {
        int[] tones = data == null ? null : data.tones();
        if (tones == null || tones.length == 0) {
            return new int[0];
        }
        int longMin = Math.max(8, root.getInt("long_min_notes", 48));
        int minNotes = Math.max(3, Math.min(longMin - 1, root.getInt("short_attack_min_notes", 8)));
        int maxNotes = Math.max(minNotes, Math.min(longMin - 1, root.getInt("short_attack_max_notes", 16)));
        int targetLength = Math.min(tones.length, minNotes + Math.floorMod((displayName == null ? "" : displayName).hashCode(), maxNotes - minNotes + 1));
        targetLength = Math.max(1, Math.min(targetLength, maxNotes));
        int offset = chooseFlashNoteShortAttackOffset(tones, data == null ? new int[0] : data.playbackTicks(), targetLength);
        int[] result = new int[targetLength];
        System.arraycopy(tones, offset, result, 0, targetLength);
        return result;
    }

    private int chooseFlashNoteShortAttackOffset(int[] tones, int[] playbackTicks, int length) {
        if (tones == null || tones.length <= length) {
            return 0;
        }
        int openingOffset = findFirstUsableFlashNoteSegment(tones, length, 0, Math.max(0, Math.min(tones.length - length, length * 2)));
        int chorusOffset = findBestFlashNoteChorusSegment(tones, playbackTicks, length);
        if (chorusOffset < 0) {
            return Math.max(0, openingOffset);
        }
        if (openingOffset < 0) {
            return chorusOffset;
        }
        double openingScore = scoreFlashNoteSegment(tones, playbackTicks, openingOffset, length);
        double chorusScore = scoreFlashNoteSegment(tones, playbackTicks, chorusOffset, length);
        return chorusScore >= openingScore * 1.18D ? chorusOffset : openingOffset;
    }

    private int findFirstUsableFlashNoteSegment(int[] tones, int length, int from, int to) {
        int maxOffset = Math.max(0, tones.length - length);
        int start = Math.max(0, Math.min(from, maxOffset));
        int end = Math.max(start, Math.min(to, maxOffset));
        for (int offset = start; offset <= end; offset++) {
            if (hasEnoughFlashNoteMelodyShape(tones, offset, length)) {
                return offset;
            }
        }
        for (int offset = 0; offset <= maxOffset; offset++) {
            if (hasEnoughFlashNoteMelodyShape(tones, offset, length)) {
                return offset;
            }
        }
        return 0;
    }

    private int findBestFlashNoteChorusSegment(int[] tones, int[] playbackTicks, int length) {
        int maxOffset = Math.max(0, tones.length - length);
        if (maxOffset <= 0) {
            return 0;
        }
        int from = Math.min(maxOffset, Math.max(length, tones.length / 5));
        int to = Math.max(from, Math.min(maxOffset, tones.length - length - Math.max(0, tones.length / 12)));
        int step = Math.max(1, length / 3);
        double bestScore = Double.NEGATIVE_INFINITY;
        int bestOffset = -1;
        for (int offset = from; offset <= to; offset += step) {
            int usableOffset = findFirstUsableFlashNoteSegment(tones, length, offset, Math.min(to, offset + step - 1));
            if (usableOffset < from || usableOffset > to) {
                continue;
            }
            double score = scoreFlashNoteSegment(tones, playbackTicks, usableOffset, length);
            double center = (usableOffset + length / 2.0D) / Math.max(1.0D, tones.length);
            double chorusBias = 1.0D + Math.max(0.0D, 1.0D - Math.abs(center - 0.58D) / 0.38D) * 0.22D;
            score *= chorusBias;
            if (score > bestScore) {
                bestScore = score;
                bestOffset = usableOffset;
            }
        }
        return bestOffset;
    }

    private double scoreFlashNoteSegment(int[] tones, int[] playbackTicks, int offset, int length) {
        if (tones == null || tones.length == 0 || length <= 0) {
            return 0.0D;
        }
        int safeOffset = Math.max(0, Math.min(offset, Math.max(0, tones.length - length)));
        int end = Math.min(tones.length, safeOffset + length);
        Set<Integer> distinct = new HashSet<>();
        int changes = 0;
        int pitchSum = 0;
        int leapSum = 0;
        for (int i = safeOffset; i < end; i++) {
            int tone = Math.floorMod(tones[i], 25);
            distinct.add(tone);
            pitchSum += tone;
            if (i > safeOffset) {
                int prev = Math.floorMod(tones[i - 1], 25);
                int diff = Math.abs(tone - prev);
                leapSum += Math.min(diff, 25 - diff);
                if (tone != prev) {
                    changes++;
                }
            }
        }
        double count = Math.max(1, end - safeOffset);
        double durationScore = 0.0D;
        if (playbackTicks != null && playbackTicks.length == tones.length && end - safeOffset > 1) {
            int duration = Math.max(1, playbackTicks[end - 1] - playbackTicks[safeOffset]);
            durationScore = Math.min(18.0D, count * 8.0D / duration);
        }
        return distinct.size() * 6.0D + changes * 4.0D + (pitchSum / count) * 0.38D + leapSum * 0.42D + durationScore;
    }

    private void collectFlashNoteMelodyFiles(File folder, boolean recursive, List<File> files) {
        File[] children = folder.listFiles();
        if (children == null) {
            return;
        }
        for (File child : children) {
            if (child.isFile() && isFlashNoteSourceFile(child)) {
                files.add(child);
            } else if (recursive && child.isDirectory()) {
                collectFlashNoteMelodyFiles(child, true, files);
            }
        }
    }

    private boolean isFlashNoteSourceFile(File file) {
        String name = file.getName().toLowerCase(Locale.ROOT);
        return name.endsWith(".txt") || name.endsWith(".csv") || name.endsWith(".mid") || name.endsWith(".midi") || name.endsWith(".nbs");
    }

    private int[] loadFlashNoteTonesFromFile(File file, int maxNotes) {
        return loadFlashNoteMusicDataFromFile(file, maxNotes).tones();
    }

    private FlashNoteMusicData loadFlashNoteMusicDataFromFile(File file, int maxNotes) {
        if (file == null || !file.isFile()) {
            return FlashNoteMusicData.empty();
        }
        String name = file.getName().toLowerCase(Locale.ROOT);
        try {
            if (name.endsWith(".txt") || name.endsWith(".csv")) {
                return FlashNoteMusicData.sequential(parseFlashNoteToneText(java.nio.file.Files.readString(file.toPath(), java.nio.charset.StandardCharsets.UTF_8), maxNotes), 3);
            }
            if (name.endsWith(".mid") || name.endsWith(".midi")) {
                return loadFlashNoteMusicDataFromMidi(file, maxNotes);
            }
            if (name.endsWith(".nbs")) {
                return loadFlashNoteMusicDataFromNbs(file, maxNotes);
            }
        } catch (IOException | InvalidMidiDataException | RuntimeException | LinkageError ex) {
            plugin.getLogger().warning("读取音符盒谱源失败 " + file.getName() + ": " + ex);
        }
        return FlashNoteMusicData.empty();
    }

    private FlashFullMusicData loadFullFlashNoteMusic(String query) {
        FlashNoteSourceCandidate candidate = findFlashNoteSourceFile(query);
        if (candidate == null || candidate.file() == null || !candidate.file().isFile()) {
            return null;
        }
        String name = candidate.file().getName().toLowerCase(Locale.ROOT);
        try {
            if (name.endsWith(".nbs")) {
                return loadFullFlashNoteMusicFromNbs(candidate.file(), candidate.displayName());
            }
            if (name.endsWith(".mid") || name.endsWith(".midi")) {
                return loadFullFlashNoteMusicFromMidi(candidate.file(), candidate.displayName());
            }
            FlashNoteMusicData fallback = loadFlashNoteMusicDataFromFile(candidate.file(), Integer.MAX_VALUE);
            List<FlashFullNoteEvent> notes = new ArrayList<>();
            int[] tones = fallback.tones();
            int[] playbackTicks = fallback.playbackTicks();
            for (int i = 0; i < tones.length; i++) {
                int tick = playbackTicks.length == tones.length ? playbackTicks[i] : i * 3;
                notes.add(new FlashFullNoteEvent(tick, Sound.BLOCK_NOTE_BLOCK_HARP, flashToneToPitch(tones[i]), 1.0f));
            }
            int length = notes.isEmpty() ? 0 : notes.get(notes.size() - 1).playbackTick() + 20;
            return new FlashFullMusicData(candidate.displayName(), List.copyOf(notes), length);
        } catch (IOException | InvalidMidiDataException | RuntimeException | LinkageError exception) {
            plugin.getLogger().warning("完整读取音符盒谱源失败 " + candidate.file().getName() + ": " + exception);
            return null;
        }
    }

    private FlashNoteSourceCandidate findFlashNoteSourceFile(String query) {
        String normalizedQuery = normalizeFlashMusicName(query);
        if (normalizedQuery.isBlank()) {
            return null;
        }
        ConfigurationSection root = plugin.getConfigManager().getConfig()
                .getConfigurationSection("hunter_game.flash_mode.note_block_melodies");
        if (root == null) {
            return null;
        }
        List<FlashNoteSourceCandidate> candidates = new ArrayList<>();
        ConfigurationSection configuredSongs = root.getConfigurationSection("songs");
        if (configuredSongs != null) {
            for (String key : configuredSongs.getKeys(false)) {
                ConfigurationSection section = configuredSongs.getConfigurationSection(key);
                if (section == null || !section.getBoolean("enabled", true)) {
                    continue;
                }
                String source = section.getString("source", "");
                if (source.isBlank()) {
                    continue;
                }
                File file = resolveFlashNoteSourceFile(root, source);
                if (file.isFile()) {
                    candidates.add(new FlashNoteSourceCandidate(section.getString("name", key), file));
                }
            }
        }
        if (root.getBoolean("scan_files", true)) {
            File folder = new File(plugin.getDataFolder(), root.getString("source_folder", "flash-note-songs"));
            List<File> files = new ArrayList<>();
            collectFlashNoteMelodyFiles(folder, root.getBoolean("scan_subfolders", true), files);
            files.sort(Comparator.comparing(File::getAbsolutePath, String.CASE_INSENSITIVE_ORDER));
            for (File file : files) {
                String display = prettyFlashNoteSongName(folder.toPath().relativize(file.toPath()).toString().replace(File.separatorChar, '/'));
                candidates.add(new FlashNoteSourceCandidate(display, file));
            }
        }
        FlashNoteSourceCandidate startsWith = null;
        FlashNoteSourceCandidate contains = null;
        for (FlashNoteSourceCandidate candidate : candidates) {
            String normalizedName = normalizeFlashMusicName(candidate.displayName());
            if (normalizedName.equals(normalizedQuery)) {
                return candidate;
            }
            if (startsWith == null && normalizedName.startsWith(normalizedQuery)) {
                startsWith = candidate;
            }
            if (contains == null && normalizedName.contains(normalizedQuery)) {
                contains = candidate;
            }
        }
        return startsWith != null ? startsWith : contains;
    }

    private FlashFullMusicData loadFullFlashNoteMusicFromNbs(File file, String displayName) throws IOException {
        List<NbsRawNote> rawNotes = new ArrayList<>();
        int songLength;
        int tempo;
        int version = 0;
        int layers;
        List<NbsLayerInfo> layerInfos;
        try (BufferedInputStream input = new BufferedInputStream(new FileInputStream(file))) {
            songLength = readLittleEndianShort(input);
            if (songLength == 0) {
                version = input.read();
                input.read();
                songLength = readLittleEndianShort(input);
            }
            layers = readLittleEndianShort(input);
            skipNbsString(input);
            skipNbsString(input);
            skipNbsString(input);
            skipNbsString(input);
            tempo = Math.max(1, readLittleEndianShort(input));
            skipFully(input, 1 + 1 + 1 + 4 + 4 + 4 + 4 + 4);
            skipNbsString(input);
            if (version >= 4) {
                skipFully(input, 1 + 1 + 2);
            }
            int tick = -1;
            while (true) {
                int tickJump = readLittleEndianShort(input);
                if (tickJump <= 0) {
                    break;
                }
                tick += tickJump;
                int layer = -1;
                while (true) {
                    int layerJump = readLittleEndianShort(input);
                    if (layerJump <= 0) {
                        break;
                    }
                    layer += layerJump;
                    int instrument = input.read();
                    int key = input.read();
                    if (instrument < 0 || key < 0) {
                        break;
                    }
                    int velocity = 100;
                    if (version >= 4) {
                        int readVelocity = input.read();
                        input.read();
                        skipFully(input, 2);
                        if (readVelocity >= 0) {
                            velocity = readVelocity;
                        }
                    }
                    rawNotes.add(new NbsRawNote(tick, layer, instrument, key, velocity));
                }
            }
            layerInfos = readNbsLayerInfo(input, layers, version);
        }
        if (rawNotes.isEmpty()) {
            return new FlashFullMusicData(displayName, List.of(), 0);
        }
        Map<Integer, NbsLayerInfo> layerInfoMap = new HashMap<>();
        for (NbsLayerInfo info : layerInfos) {
            layerInfoMap.put(info.layer(), info);
        }
        int firstTick = rawNotes.stream().mapToInt(NbsRawNote::tick).min().orElse(0);
        double minecraftTicksPerNbsTick = 2000.0D / tempo;
        List<FlashFullNoteEvent> notes = new ArrayList<>(rawNotes.size());
        for (NbsRawNote rawNote : rawNotes) {
            NbsLayerInfo info = layerInfoMap.getOrDefault(rawNote.layer(), new NbsLayerInfo(rawNote.layer(), "", 100));
            float noteVolume = (float) Math.max(0.02D, Math.min(1.0D, rawNote.velocity() / 100.0D * info.volume() / 100.0D));
            int playbackTick = Math.max(0, (int) Math.round((rawNote.tick() - firstTick) * minecraftTicksPerNbsTick));
            notes.add(new FlashFullNoteEvent(playbackTick, mapNbsInstrumentSound(rawNote.instrument()), nbsKeyToPitch(rawNote.key()), noteVolume));
        }
        notes.sort(Comparator.comparingInt(FlashFullNoteEvent::playbackTick));
        int length = notes.isEmpty() ? 0 : notes.get(notes.size() - 1).playbackTick() + 20;
        if (songLength > 0) {
            length = Math.max(length, (int) Math.round(songLength * minecraftTicksPerNbsTick) + 20);
        }
        return new FlashFullMusicData(displayName, List.copyOf(notes), length);
    }

    private FlashFullMusicData loadFullFlashNoteMusicFromMidi(File file, String displayName) throws IOException, InvalidMidiDataException {
        Sequence sequence = MidiSystem.getSequence(file);
        List<MidiRawNote> rawNotes = readMidiRawNotes(sequence, true);
        if (rawNotes.isEmpty()) {
            return new FlashFullMusicData(displayName, List.of(), 0);
        }
        rawNotes.sort(Comparator.comparingLong(MidiRawNote::tick)
                .thenComparingInt(MidiRawNote::track)
                .thenComparing(Comparator.comparingInt(MidiRawNote::midiNote).reversed()));
        List<MidiTempoPoint> tempoMap = buildMidiTempoMap(sequence);
        long firstTick = rawNotes.stream().mapToLong(MidiRawNote::tick).min().orElse(0L);
        double firstMinecraftTick = midiTickToMinecraftTicks(sequence, tempoMap, firstTick);
        List<FlashFullNoteEvent> notes = new ArrayList<>(rawNotes.size());
        for (MidiRawNote rawNote : rawNotes) {
            int playbackTick = Math.max(0, (int) Math.round(midiTickToMinecraftTicks(sequence, tempoMap, rawNote.tick()) - firstMinecraftTick));
            float noteVolume = (float) Math.max(0.04D, Math.min(1.0D, rawNote.velocity() / 127.0D));
            Sound sound = mapMidiInstrumentSound(rawNote);
            float pitch = rawNote.channel() == 9 ? 1.0f : midiNoteToPitch(rawNote.midiNote());
            notes.add(new FlashFullNoteEvent(playbackTick, sound, pitch, noteVolume));
        }
        notes.sort(Comparator.comparingInt(FlashFullNoteEvent::playbackTick));
        int length = notes.isEmpty() ? 0 : notes.get(notes.size() - 1).playbackTick() + 20;
        long sequenceLength = Math.max(firstTick, sequence.getTickLength());
        length = Math.max(length, (int) Math.round(midiTickToMinecraftTicks(sequence, tempoMap, sequenceLength) - firstMinecraftTick) + 20);
        return new FlashFullMusicData(displayName, List.copyOf(notes), length);
    }

    private int[] parseFlashNoteToneText(String raw, int maxNotes) {
        if (raw == null || raw.isBlank()) {
            return new int[0];
        }
        List<Integer> tones = new ArrayList<>();
        java.util.regex.Matcher matcher = java.util.regex.Pattern.compile("-?\\d+").matcher(raw);
        while (matcher.find() && tones.size() < maxNotes) {
            tones.add(Math.floorMod(Integer.parseInt(matcher.group()), 25));
        }
        return tones.stream().mapToInt(Integer::intValue).toArray();
    }

    private int[] loadFlashNoteTonesFromMidi(File file, int maxNotes) throws IOException, InvalidMidiDataException {
        return loadFlashNoteMusicDataFromMidi(file, maxNotes).tones();
    }

    private FlashNoteMusicData loadFlashNoteMusicDataFromMidi(File file, int maxNotes) throws IOException, InvalidMidiDataException {
        Sequence sequence = MidiSystem.getSequence(file);
        List<MidiRawNote> rawNotes = readMidiRawNotes(sequence, false);
        if (rawNotes.isEmpty()) {
            return FlashNoteMusicData.empty();
        }
        int bestTrack = selectMidiMainTrack(sequence.getTracks());
        List<MidiRawNote> melodySource = rawNotes.stream()
                .filter(note -> note.track() == bestTrack)
                .toList();
        if (melodySource.size() < Math.min(8, rawNotes.size())) {
            melodySource = rawNotes;
        }
        List<MidiRawNote> notes = new ArrayList<>(melodySource);
        notes.sort(Comparator.comparingLong(MidiRawNote::tick)
                .thenComparing(Comparator.comparingDouble(this::scoreMidiMainNote).reversed()));
        Map<Long, MidiRawNote> mainByTick = new LinkedHashMap<>();
        for (MidiRawNote note : notes) {
            MidiRawNote existing = mainByTick.get(note.tick());
            if (existing == null || scoreMidiMainNote(note) > scoreMidiMainNote(existing)) {
                mainByTick.put(note.tick(), note);
            }
            if (mainByTick.size() >= maxNotes) {
                break;
            }
        }
        List<MidiRawNote> selected = new ArrayList<>(mainByTick.values());
        selected.sort(Comparator.comparingLong(MidiRawNote::tick));
        int[] tones = new int[selected.size()];
        int[] playbackTicks = new int[selected.size()];
        List<MidiTempoPoint> tempoMap = buildMidiTempoMap(sequence);
        long firstTick = selected.isEmpty() ? 0L : selected.get(0).tick();
        double firstMinecraftTick = midiTickToMinecraftTicks(sequence, tempoMap, firstTick);
        for (int i = 0; i < selected.size(); i++) {
            MidiRawNote note = selected.get(i);
            tones[i] = midiNoteToFlashTone(note.midiNote());
            playbackTicks[i] = Math.max(0, (int) Math.round(midiTickToMinecraftTicks(sequence, tempoMap, note.tick()) - firstMinecraftTick));
        }
        return new FlashNoteMusicData(tones, playbackTicks);
    }

    private List<MidiRawNote> readMidiRawNotes(Sequence sequence, boolean includePercussion) {
        List<MidiTimedShortMessage> messages = new ArrayList<>();
        int order = 0;
        Track[] tracks = sequence.getTracks();
        for (int trackIndex = 0; trackIndex < tracks.length; trackIndex++) {
            Track track = tracks[trackIndex];
            for (int i = 0; i < track.size(); i++) {
                MidiEvent event = track.get(i);
                if (event.getMessage() instanceof ShortMessage message) {
                    messages.add(new MidiTimedShortMessage(event.getTick(), order++, trackIndex, message));
                }
            }
        }
        messages.sort(Comparator.comparingLong(MidiTimedShortMessage::tick).thenComparingInt(MidiTimedShortMessage::order));
        int[] programs = new int[16];
        List<MidiRawNote> notes = new ArrayList<>();
        for (MidiTimedShortMessage timed : messages) {
            ShortMessage message = timed.message();
            int channel = message.getChannel();
            if (message.getCommand() == ShortMessage.PROGRAM_CHANGE) {
                programs[channel] = message.getData1();
                continue;
            }
            if (message.getCommand() == ShortMessage.NOTE_ON && message.getData2() > 0) {
                if (!includePercussion && channel == 9) {
                    continue;
                }
                notes.add(new MidiRawNote(timed.tick(), timed.track(), channel, message.getData1(), message.getData2(), programs[channel]));
            }
        }
        return notes;
    }

    private double scoreMidiMainNote(MidiRawNote note) {
        if (note.channel() == 9) {
            return -10_000.0D;
        }
        int program = note.program();
        double programBonus = 0.0D;
        if ((program >= 24 && program <= 31) || (program >= 72 && program <= 87)) {
            programBonus += 24.0D;
        }
        if (program >= 0 && program <= 7) {
            programBonus += 8.0D;
        }
        if (program >= 32 && program <= 39) {
            programBonus -= 22.0D;
        }
        return note.midiNote() * 1.35D + note.velocity() * 0.18D + programBonus;
    }

    private List<MidiTempoPoint> buildMidiTempoMap(Sequence sequence) {
        if (sequence.getDivisionType() != Sequence.PPQ) {
            return List.of(new MidiTempoPoint(0L, 500_000, 0.0D));
        }
        List<MidiTempoEvent> tempoEvents = new ArrayList<>();
        for (Track track : sequence.getTracks()) {
            for (int i = 0; i < track.size(); i++) {
                MidiEvent event = track.get(i);
                if (event.getMessage() instanceof MetaMessage meta && meta.getType() == 0x51 && meta.getData().length >= 3) {
                    tempoEvents.add(new MidiTempoEvent(event.getTick(), readMidiTempo(meta)));
                }
            }
        }
        tempoEvents.sort(Comparator.comparingLong(MidiTempoEvent::tick));
        List<MidiTempoPoint> points = new ArrayList<>();
        long currentTick = 0L;
        int currentTempo = 500_000;
        double currentMinecraftTick = 0.0D;
        points.add(new MidiTempoPoint(0L, currentTempo, currentMinecraftTick));
        for (MidiTempoEvent tempoEvent : tempoEvents) {
            if (tempoEvent.tick() < currentTick) {
                continue;
            }
            currentMinecraftTick += (tempoEvent.tick() - currentTick) * midiMinecraftTicksPerSequenceTick(sequence, currentTempo);
            currentTick = tempoEvent.tick();
            currentTempo = tempoEvent.tempoMicrosPerQuarter();
            if (!points.isEmpty() && points.get(points.size() - 1).tick() == currentTick) {
                points.set(points.size() - 1, new MidiTempoPoint(currentTick, currentTempo, currentMinecraftTick));
            } else {
                points.add(new MidiTempoPoint(currentTick, currentTempo, currentMinecraftTick));
            }
        }
        return List.copyOf(points);
    }

    private int readMidiTempo(MetaMessage meta) {
        byte[] data = meta.getData();
        return ((data[0] & 0xFF) << 16) | ((data[1] & 0xFF) << 8) | (data[2] & 0xFF);
    }

    private double midiTickToMinecraftTicks(Sequence sequence, List<MidiTempoPoint> tempoMap, long midiTick) {
        if (sequence.getDivisionType() != Sequence.PPQ) {
            return midiTick * midiMinecraftTicksPerSequenceTick(sequence, 500_000);
        }
        if (tempoMap == null || tempoMap.isEmpty()) {
            return midiTick * midiMinecraftTicksPerSequenceTick(sequence, 500_000);
        }
        int low = 0;
        int high = tempoMap.size() - 1;
        int selected = 0;
        while (low <= high) {
            int mid = (low + high) >>> 1;
            if (tempoMap.get(mid).tick() <= midiTick) {
                selected = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        MidiTempoPoint point = tempoMap.get(selected);
        return point.minecraftTick() + (midiTick - point.tick()) * midiMinecraftTicksPerSequenceTick(sequence, point.tempoMicrosPerQuarter());
    }

    private double midiMinecraftTicksPerSequenceTick(Sequence sequence, int tempoMicrosPerQuarter) {
        if (sequence.getDivisionType() == Sequence.PPQ) {
            return (tempoMicrosPerQuarter / 1_000_000.0D) * 20.0D / Math.max(1, sequence.getResolution());
        }
        return 20.0D / Math.max(1.0D, sequence.getDivisionType() * sequence.getResolution());
    }

    private Sound mapMidiInstrumentSound(MidiRawNote note) {
        if (note.channel() == 9) {
            int midiNote = note.midiNote();
            if (midiNote == 35 || midiNote == 36 || midiNote == 41 || midiNote == 43) {
                return Sound.BLOCK_NOTE_BLOCK_BASEDRUM;
            }
            if (midiNote == 38 || midiNote == 40 || midiNote == 37 || midiNote == 39) {
                return Sound.BLOCK_NOTE_BLOCK_SNARE;
            }
            if (midiNote == 42 || midiNote == 44 || midiNote == 46 || midiNote == 51 || midiNote == 59) {
                return Sound.BLOCK_NOTE_BLOCK_HAT;
            }
            if (midiNote == 49 || midiNote == 52 || midiNote == 55 || midiNote == 57) {
                return Sound.BLOCK_NOTE_BLOCK_BELL;
            }
            return Sound.BLOCK_NOTE_BLOCK_BASEDRUM;
        }
        int program = note.program();
        if (program >= 32 && program <= 39) {
            return Sound.BLOCK_NOTE_BLOCK_BASS;
        }
        if (program >= 24 && program <= 31) {
            return Sound.BLOCK_NOTE_BLOCK_GUITAR;
        }
        if (program >= 8 && program <= 15) {
            return Sound.BLOCK_NOTE_BLOCK_CHIME;
        }
        if (program >= 16 && program <= 23) {
            return Sound.BLOCK_NOTE_BLOCK_XYLOPHONE;
        }
        if (program >= 40 && program <= 55) {
            return Sound.BLOCK_NOTE_BLOCK_HARP;
        }
        if (program >= 56 && program <= 63) {
            return Sound.BLOCK_NOTE_BLOCK_DIDGERIDOO;
        }
        if (program >= 72 && program <= 79) {
            return Sound.BLOCK_NOTE_BLOCK_FLUTE;
        }
        if (program >= 80 && program <= 87) {
            return Sound.BLOCK_NOTE_BLOCK_PLING;
        }
        if (program >= 104 && program <= 111) {
            return Sound.BLOCK_NOTE_BLOCK_BANJO;
        }
        return Sound.BLOCK_NOTE_BLOCK_HARP;
    }

    private int[] loadFlashNoteTonesFromNbs(File file, int maxNotes) throws IOException {
        return loadFlashNoteMusicDataFromNbs(file, maxNotes).tones();
    }

    private FlashNoteMusicData loadFlashNoteMusicDataFromNbs(File file, int maxNotes) throws IOException {
        List<NbsRawNote> rawNotes = new ArrayList<>();
        try (BufferedInputStream input = new BufferedInputStream(new FileInputStream(file))) {
            int songLength = readLittleEndianShort(input);
            int version = 0;
            if (songLength == 0) {
                version = input.read();
                input.read(); // vanilla instrument count
                songLength = readLittleEndianShort(input);
            }
            int layers = readLittleEndianShort(input);
            skipNbsString(input); // name
            skipNbsString(input); // author
            skipNbsString(input); // original author
            skipNbsString(input); // description
            int tempo = Math.max(1, readLittleEndianShort(input));
            skipFully(input, 1 + 1 + 1 + 4 + 4 + 4 + 4 + 4);
            skipNbsString(input); // midi/schematic name
            if (version >= 4) {
                skipFully(input, 1 + 1 + 2); // loop enabled, max loop count, loop start tick
            }
            int tick = -1;
            while (true) {
                int tickJump = readLittleEndianShort(input);
                if (tickJump <= 0) {
                    break;
                }
                tick += tickJump;
                int layer = -1;
                boolean tickHasNote = false;
                int bestNote = -1;
                while (true) {
                    int layerJump = readLittleEndianShort(input);
                    if (layerJump <= 0) {
                        break;
                    }
                    layer += layerJump;
                    int instrument = input.read();
                    int key = input.read();
                    if (instrument < 0 || key < 0) {
                        break;
                    }
                    int velocity = 100;
                    if (version >= 4) {
                        int readVelocity = input.read();
                        input.read(); // panning
                        skipFully(input, 2); // pitch
                        if (readVelocity >= 0) {
                            velocity = readVelocity;
                        }
                    }
                    rawNotes.add(new NbsRawNote(tick, layer, instrument, key, velocity));
                    if (!tickHasNote || key > bestNote) {
                        bestNote = key;
                        tickHasNote = true;
                    }
                }
            }

            List<NbsLayerInfo> layerInfos = readNbsLayerInfo(input, layers, version);
            int mainLayer = selectNbsMainMelodyLayer(rawNotes, layerInfos);
            List<NbsRawNote> mainNotes = new ArrayList<>();
            Map<Integer, NbsRawNote> mainByTick = new LinkedHashMap<>();
            for (NbsRawNote note : rawNotes) {
                if (note.layer() != mainLayer) {
                    continue;
                }
                NbsRawNote existing = mainByTick.get(note.tick());
                if (existing == null || note.key() > existing.key()) {
                    mainByTick.put(note.tick(), note);
                }
            }
            mainNotes.addAll(mainByTick.values());
            mainNotes.sort(Comparator.comparingInt(NbsRawNote::tick));
            if (mainNotes.isEmpty()) {
                return FlashNoteMusicData.empty();
            }
            int count = Math.min(maxNotes, mainNotes.size());
            int[] tones = new int[count];
            int[] playbackTicks = new int[count];
            int firstTick = mainNotes.get(0).tick();
            double minecraftTicksPerNbsTick = 2000.0D / tempo;
            for (int i = 0; i < count; i++) {
                NbsRawNote note = mainNotes.get(i);
                tones[i] = nbsKeyToFlashTone(note.key());
                playbackTicks[i] = Math.max(0, (int) Math.round((note.tick() - firstTick) * minecraftTicksPerNbsTick));
            }
            return new FlashNoteMusicData(tones, playbackTicks);
        }
    }

    private int selectMidiMainTrack(Track[] tracks) {
        int bestTrack = 0;
        double bestScore = Double.NEGATIVE_INFINITY;
        for (int trackIndex = 0; trackIndex < tracks.length; trackIndex++) {
            Track track = tracks[trackIndex];
            int count = 0;
            int pitchSum = 0;
            Set<Long> activeTicks = new HashSet<>();
            for (int i = 0; i < track.size(); i++) {
                MidiEvent event = track.get(i);
                if (!(event.getMessage() instanceof ShortMessage message)) {
                    continue;
                }
                if (message.getCommand() != ShortMessage.NOTE_ON || message.getData2() <= 0 || message.getChannel() == 9) {
                    continue;
                }
                count++;
                pitchSum += message.getData1();
                activeTicks.add(event.getTick());
            }
            if (count == 0) {
                continue;
            }
            double avgPitch = pitchSum / (double) count;
            double score = activeTicks.size() * 3.0D + avgPitch * 0.45D - Math.max(0, count - activeTicks.size()) * 0.22D;
            if (score > bestScore) {
                bestScore = score;
                bestTrack = trackIndex;
            }
        }
        return bestTrack;
    }

    private double midiMinecraftTicksPerSequenceTick(Sequence sequence) {
        if (sequence.getDivisionType() == Sequence.PPQ) {
            int tempo = findFirstMidiTempo(sequence);
            return (tempo / 1_000_000.0D) * 20.0D / Math.max(1, sequence.getResolution());
        }
        return 20.0D / Math.max(1.0D, sequence.getDivisionType() * sequence.getResolution());
    }

    private int findFirstMidiTempo(Sequence sequence) {
        for (Track track : sequence.getTracks()) {
            for (int i = 0; i < track.size(); i++) {
                MidiEvent event = track.get(i);
                if (event.getMessage() instanceof MetaMessage meta && meta.getType() == 0x51 && meta.getData().length >= 3) {
                    byte[] data = meta.getData();
                    return ((data[0] & 0xFF) << 16) | ((data[1] & 0xFF) << 8) | (data[2] & 0xFF);
                }
            }
        }
        return 500_000;
    }

    private List<NbsLayerInfo> readNbsLayerInfo(BufferedInputStream input, int layers, int version) throws IOException {
        List<NbsLayerInfo> infos = new ArrayList<>();
        for (int layer = 0; layer < layers; layer++) {
            String name = readNbsString(input);
            if (version >= 4) {
                input.read(); // lock
            }
            int volume = input.read();
            if (volume < 0) {
                volume = 100;
            }
            input.read(); // stereo
            infos.add(new NbsLayerInfo(layer, name == null ? "" : name, volume));
        }
        return infos;
    }

    private int selectNbsMainMelodyLayer(List<NbsRawNote> notes, List<NbsLayerInfo> layerInfos) {
        if (notes.isEmpty()) {
            return 0;
        }
        Map<Integer, List<NbsRawNote>> byLayer = new HashMap<>();
        for (NbsRawNote note : notes) {
            if (isLikelyPercussionNbsInstrument(note.instrument())) {
                continue;
            }
            byLayer.computeIfAbsent(note.layer(), ignored -> new ArrayList<>()).add(note);
        }
        if (byLayer.isEmpty()) {
            for (NbsRawNote note : notes) {
                byLayer.computeIfAbsent(note.layer(), ignored -> new ArrayList<>()).add(note);
            }
        }
        Map<Integer, NbsLayerInfo> infos = new HashMap<>();
        for (NbsLayerInfo info : layerInfos) {
            infos.put(info.layer(), info);
        }
        int bestLayer = byLayer.keySet().iterator().next();
        double bestScore = Double.NEGATIVE_INFINITY;
        for (Map.Entry<Integer, List<NbsRawNote>> entry : byLayer.entrySet()) {
            List<NbsRawNote> layerNotes = entry.getValue();
            Set<Integer> tickCount = new HashSet<>();
            int pitchSum = 0;
            int velocitySum = 0;
            for (NbsRawNote note : layerNotes) {
                tickCount.add(note.tick());
                pitchSum += note.key();
                velocitySum += note.velocity();
            }
            NbsLayerInfo info = infos.getOrDefault(entry.getKey(), new NbsLayerInfo(entry.getKey(), "", 100));
            String name = info.name().toLowerCase(Locale.ROOT);
            double avgPitch = pitchSum / (double) Math.max(1, layerNotes.size());
            double avgVelocity = velocitySum / (double) Math.max(1, layerNotes.size());
            double score = tickCount.size() * 3.0D + avgPitch * 0.95D + avgVelocity * 0.22D + info.volume() * 0.18D;
            if (containsAny(name, "melody", "lead", "main", "vocal", "voice", "song", "唱", "主", "旋律", "メロディ")) {
                score += 500.0D;
            }
            if (containsAny(name, "bass", "drum", "kick", "snare", "hat", "chord", "pad", "back", "伴奏", "低音", "鼓", "和弦")) {
                score -= 260.0D;
            }
            if (score > bestScore) {
                bestScore = score;
                bestLayer = entry.getKey();
            }
        }
        return bestLayer;
    }

    private boolean isLikelyPercussionNbsInstrument(int instrument) {
        return instrument == 2 || instrument == 3 || instrument == 4;
    }

    private int midiNoteToFlashTone(int midiNote) {
        int folded = midiNote;
        while (folded < 54) {
            folded += 12;
        }
        while (folded > 78) {
            folded -= 12;
        }
        return Math.max(0, Math.min(24, folded - 54));
    }

    private int nbsKeyToFlashTone(int key) {
        int folded = key;
        while (folded < 33) {
            folded += 12;
        }
        while (folded > 57) {
            folded -= 12;
        }
        return Math.max(0, Math.min(24, folded - 33));
    }

    private float flashToneToPitch(int tone) {
        return (float) Math.pow(2.0D, (Math.floorMod(tone, 25) - 12) / 12.0D);
    }

    private float midiNoteToPitch(int midiNote) {
        return flashToneToPitch(midiNoteToFlashTone(midiNote));
    }

    private float nbsKeyToPitch(int key) {
        return flashToneToPitch(nbsKeyToFlashTone(key));
    }

    private Sound mapNbsInstrumentSound(int instrument) {
        return switch (instrument) {
            case 1 -> Sound.BLOCK_NOTE_BLOCK_BASS;
            case 2 -> Sound.BLOCK_NOTE_BLOCK_BASEDRUM;
            case 3 -> Sound.BLOCK_NOTE_BLOCK_SNARE;
            case 4 -> Sound.BLOCK_NOTE_BLOCK_HAT;
            case 5 -> Sound.BLOCK_NOTE_BLOCK_GUITAR;
            case 6 -> Sound.BLOCK_NOTE_BLOCK_FLUTE;
            case 7 -> Sound.BLOCK_NOTE_BLOCK_BELL;
            case 8 -> Sound.BLOCK_NOTE_BLOCK_CHIME;
            case 9 -> Sound.BLOCK_NOTE_BLOCK_XYLOPHONE;
            case 10 -> Sound.BLOCK_NOTE_BLOCK_IRON_XYLOPHONE;
            case 11 -> Sound.BLOCK_NOTE_BLOCK_COW_BELL;
            case 12 -> Sound.BLOCK_NOTE_BLOCK_DIDGERIDOO;
            case 13 -> Sound.BLOCK_NOTE_BLOCK_BIT;
            case 14 -> Sound.BLOCK_NOTE_BLOCK_BANJO;
            case 15 -> Sound.BLOCK_NOTE_BLOCK_PLING;
            default -> Sound.BLOCK_NOTE_BLOCK_HARP;
        };
    }

    private int readLittleEndianShort(BufferedInputStream input) throws IOException {
        int low = input.read();
        int high = input.read();
        if (low < 0 || high < 0) {
            return 0;
        }
        return low | (high << 8);
    }

    private int readLittleEndianInt(BufferedInputStream input) throws IOException {
        int b1 = input.read();
        int b2 = input.read();
        int b3 = input.read();
        int b4 = input.read();
        if (b1 < 0 || b2 < 0 || b3 < 0 || b4 < 0) {
            return 0;
        }
        return b1 | (b2 << 8) | (b3 << 16) | (b4 << 24);
    }

    private void skipNbsString(BufferedInputStream input) throws IOException {
        int length = readLittleEndianInt(input);
        if (length > 0) {
            skipFully(input, length);
        }
    }

    private String readNbsString(BufferedInputStream input) throws IOException {
        int length = readLittleEndianInt(input);
        if (length <= 0) {
            return "";
        }
        byte[] bytes = input.readNBytes(length);
        return new String(bytes, StandardCharsets.UTF_8);
    }

    private void skipFully(BufferedInputStream input, int bytes) throws IOException {
        int remaining = Math.max(0, bytes);
        while (remaining > 0) {
            long skipped = input.skip(remaining);
            if (skipped <= 0) {
                if (input.read() < 0) {
                    return;
                }
                skipped = 1;
            }
            remaining -= (int) skipped;
        }
    }

    private String prettyFlashNoteSongName(String fileName) {
        String name = fileName.replaceFirst("(?i)\\.(txt|csv|mid|midi|nbs)$", "");
        return name.replace('_', ' ').replace('-', ' ').trim();
    }

    private FlashNoteSpell createConfiguredFlashNoteSpell(ConfigurationSection section, ConfigurationSection root, int noteCount) {
        String spellName = section.getString("spell.name", noteCount >= root.getInt("long_min_notes", 48) ? "真实谱源长谱" : "真实谱源短谱");
        double radius = section.getDouble("spell.radius", noteCount >= root.getInt("long_min_notes", 48) ? 116.0D : 12.0D);
        double damage = section.getDouble("spell.damage", noteCount >= root.getInt("long_min_notes", 48) ? 16.0D : 7.0D);
        PotionEffectType buff = parsePotionEffectType(section.getString("spell.effect", "SLOWNESS"));
        int durationTicks = Math.max(1, section.getInt("spell.duration_ticks", noteCount >= root.getInt("long_min_notes", 48) ? 140 : 110));
        int amplifier = Math.max(0, section.getInt("spell.amplifier", 1));
        Sound sound = parseSound(section.getString("spell.sound", "BLOCK_NOTE_BLOCK_PLING"), Sound.BLOCK_NOTE_BLOCK_PLING);
        float volume = (float) section.getDouble("spell.volume", 0.72D);
        float pitch = (float) section.getDouble("spell.pitch", 1.45D);
        Color color = parseColor(section.getString("spell.color", "120,210,255"));
        return new FlashNoteSpell(spellName, radius, damage, buff, durationTicks, amplifier, sound, volume, pitch, color);
    }

    private FlashNoteSpell createDefaultImportedFlashNoteSpell(ConfigurationSection root, String displayName, int noteCount) {
        boolean longSong = noteCount >= root.getInt("long_min_notes", 48);
        FlashNoteAutoSpell auto = autoFlashNoteSpell(displayName, longSong);
        PotionEffectType buff = auto.buff();
        return new FlashNoteSpell(auto.name(),
                longSong ? Math.max(110.0D, auto.radius()) : auto.radius(),
                longSong ? Math.max(14.0D, auto.damage() + 7.0D) : auto.damage(),
                buff,
                longSong ? Math.max(140, auto.durationTicks() + 40) : auto.durationTicks(),
                auto.amplifier(),
                auto.sound(),
                auto.volume(),
                auto.pitch(),
                auto.color());
    }

