    private boolean containsAny(String text, String... keywords) {
        if (text == null || text.isBlank()) {
            return false;
        }
        for (String keyword : keywords) {
            if (text.contains(keyword)) {
                return true;
            }
        }
        return false;
    }

    private FlashNoteAutoSpell flashAttackSpell(String effectName, boolean longSong, int hash, double baseDamage,
                                                PotionEffectType buff, int amplifier, Sound sound, Color color) {
        double radius = longSong ? 112.0D + hash % 21 : 12.0D + hash % 10;
        double damage = baseDamage + (hash % 17) * 0.23D + ((hash / 17) % 5) * 0.17D;
        if (longSong) {
            damage += 2.4D + ((hash / 7) % 9) * 0.31D;
        }
        int duration = (longSong ? 112 : 72) + (hash % 9) * 10;
        float volume = 0.62f + (hash % 4) * 0.04f;
        float pitch = 0.96f + (hash % 9) * 0.07f;
        return new FlashNoteAutoSpell(longSong ? "全章-" + effectName.substring(effectName.indexOf('-') + 1) : effectName,
                radius, damage, buff, duration, amplifier, sound, volume, pitch, color);
    }

    private FlashNoteAutoSpell flashBuffSpell(String effectName, boolean longSong, int hash, PotionEffectType buff,
                                              int amplifier, Sound sound, Color color) {
        double radius = longSong ? 112.0D + hash % 17 : 9.0D + hash % 6;
        double damage = longSong ? 7.2D + (hash % 13) * 0.27D + ((hash / 13) % 6) * 0.19D : 0.0D;
        int duration = (longSong ? 142 : 104) + (hash % 8) * 14;
        float volume = 0.58f + (hash % 5) * 0.035f;
        float pitch = 1.10f + (hash % 10) * 0.065f;
        return new FlashNoteAutoSpell(longSong ? "全章-" + effectName : effectName,
                radius, damage, buff, duration, amplifier, sound, volume, pitch, color);
    }

    private PotionEffectType parsePotionEffectType(String name) {
        if (name == null || name.isBlank()) {
            return PotionEffectType.SLOWNESS;
        }
        PotionEffectType type = Registry.EFFECT.get(NamespacedKey.minecraft(name.toLowerCase(Locale.ROOT)));
        return type == null ? PotionEffectType.SLOWNESS : type;
    }

    private Sound parseSound(String name, Sound fallback) {
        if (name == null || name.isBlank()) {
            return fallback;
        }
        try {
            return Sound.valueOf(name.toUpperCase(Locale.ROOT));
        } catch (IllegalArgumentException ignored) {
            return fallback;
        }
    }

    private Color parseColor(String raw) {
        if (raw == null || raw.isBlank()) {
            return Color.fromRGB(120, 210, 255);
        }
        String[] parts = raw.replace("#", "").split(",");
        try {
            if (parts.length == 1 && parts[0].length() == 6) {
                return Color.fromRGB(Integer.parseInt(parts[0], 16));
            }
            if (parts.length >= 3) {
                return Color.fromRGB(clampColor(Integer.parseInt(parts[0].trim())), clampColor(Integer.parseInt(parts[1].trim())), clampColor(Integer.parseInt(parts[2].trim())));
            }
        } catch (NumberFormatException ignored) {
        }
        return Color.fromRGB(120, 210, 255);
    }

    private int clampColor(int value) {
        return Math.max(0, Math.min(255, value));
    }

    private String describeFlashNoteSpell(FlashNoteSpell spell) {
        if (isFlashNoteFinale(spell)) {
            StringBuilder builder = new StringBuilder(spell.name()).append(" ")
                    .append(formatOneDecimal(spell.radius())).append("格，伤害 ")
                    .append(formatOneDecimal(spell.damage())).append("点（70%破甲）");
            if (isHarmfulFlashNoteBuff(spell.buff())) {
                builder.append(" + 敌人").append(potionEffectText(spell.buff(), spell.amplifier())).append(" ")
                        .append(formatSeconds(spell.durationTicks())).append("秒");
            } else if (isBeneficialFlashNoteBuff(spell.buff())) {
                builder.append(" + 自身/队友").append(potionEffectText(spell.buff(), spell.amplifier())).append(" ")
                        .append(formatSeconds(spell.durationTicks())).append("秒");
            }
            return builder.toString();
        }
        if (isFlashNoteParticleWave(spell)) {
            return spell.name() + " " + formatOneDecimal(getFlashNoteRemoteRange(spell)) + "格，伤害 "
                    + formatOneDecimal(spell.damage()) + "点（70%破甲） + 敌人"
                    + potionEffectText(spell.buff(), spell.amplifier()) + " "
                    + formatSeconds(spell.durationTicks()) + "秒";
        }
        if ("风跃滑音".equals(spell.name())) {
            return "向前跃起 + 缓降 I " + formatSeconds(spell.durationTicks()) + "秒";
        }
        String buffText = potionEffectText(spell.buff(), spell.amplifier());
        if (spell.damage() > 0.0D) {
            StringBuilder builder = new StringBuilder(spell.name()).append(" ")
                    .append(formatOneDecimal(getFlashNoteRemoteRange(spell))).append("格，伤害 ")
                    .append(formatOneDecimal(spell.damage())).append("点（70%破甲）");
            if (isHarmfulFlashNoteBuff(spell.buff())) {
                builder.append(" + 敌人").append(buffText).append(" ")
                        .append(formatSeconds(spell.durationTicks())).append("秒");
            } else if (isBeneficialFlashNoteBuff(spell.buff())) {
                builder.append(" + 自身").append(buffText).append(" ")
                        .append(formatSeconds(spell.durationTicks())).append("秒");
            }
            return builder.toString();
        }
        return buffText + " " + formatSeconds(spell.durationTicks()) + "秒";
    }

    private String potionEffectText(PotionEffectType type, int amplifier) {
        String name;
        if (type == PotionEffectType.SPEED) {
            name = "速度";
        } else if (type == PotionEffectType.SLOWNESS) {
            name = "缓慢";
        } else if (type == PotionEffectType.STRENGTH) {
            name = "力量";
        } else if (type == PotionEffectType.REGENERATION) {
            name = "生命恢复";
        } else if (type == PotionEffectType.SLOW_FALLING) {
            name = "缓降";
        } else if (type == PotionEffectType.WEAKNESS) {
            name = "虚弱";
        } else if (type == PotionEffectType.RESISTANCE) {
            name = "抗性";
        } else if (type == PotionEffectType.HASTE) {
            name = "急迫";
        } else if (type == PotionEffectType.ABSORPTION) {
            name = "伤害吸收";
        } else if (type == PotionEffectType.GLOWING) {
            name = "发光";
        } else if (type == PotionEffectType.FIRE_RESISTANCE) {
            name = "防火";
        } else if (type == PotionEffectType.WATER_BREATHING) {
            name = "水下呼吸";
        } else if (type == PotionEffectType.INVISIBILITY) {
            name = "隐身";
        } else if (type == PotionEffectType.JUMP_BOOST) {
            name = "跳跃提升";
        } else if (type == PotionEffectType.POISON) {
            name = "中毒";
        } else if (type == PotionEffectType.BLINDNESS) {
            name = "失明";
        } else if (type == PotionEffectType.DARKNESS) {
            name = "黑暗";
        } else if (type == PotionEffectType.MINING_FATIGUE) {
            name = "挖掘疲劳";
        } else if (type == PotionEffectType.LEVITATION) {
            name = "漂浮";
        } else if (type == PotionEffectType.WITHER) {
            name = "凋零";
        } else if (type == PotionEffectType.HUNGER) {
            name = "饥饿";
        } else if (type == PotionEffectType.NAUSEA) {
            name = "反胃";
        } else if (type == PotionEffectType.UNLUCK) {
            name = "霉运";
        } else if (type == PotionEffectType.WEAVING) {
            name = "盘丝";
        } else if (type == PotionEffectType.OOZING) {
            name = "渗浆";
        } else if (type == PotionEffectType.INFESTED) {
            name = "虫蚀";
        } else if (type == PotionEffectType.WIND_CHARGED) {
            name = "蓄风";
        } else if (type == PotionEffectType.NIGHT_VISION) {
            name = "夜视";
        } else if (type == PotionEffectType.DOLPHINS_GRACE) {
            name = "海豚恩惠";
        } else if (type == PotionEffectType.LUCK) {
            name = "幸运";
        } else if (type == PotionEffectType.HEALTH_BOOST) {
            name = "生命提升";
        } else if (type == PotionEffectType.CONDUIT_POWER) {
            name = "潮涌能量";
        } else if (type == PotionEffectType.BREATH_OF_THE_NAUTILUS) {
            name = "鹦鹉螺吐息";
        } else if (type == PotionEffectType.SATURATION) {
            name = "饱和";
        } else {
            name = type.getKey().getKey();
        }
        return name + " " + romanLevel(amplifier + 1);
    }

    private String romanLevel(int level) {
        return switch (Math.max(1, level)) {
            case 1 -> "I";
            case 2 -> "II";
            case 3 -> "III";
            case 4 -> "IV";
            case 5 -> "V";
            default -> String.valueOf(level);
        };
    }

    private String formatSeconds(int ticks) {
        return formatOneDecimal(ticks / 20.0D);
    }

    private boolean isBeneficialFlashNoteBuff(PotionEffectType type) {
        return type == PotionEffectType.SPEED
                || type == PotionEffectType.STRENGTH
                || type == PotionEffectType.REGENERATION
                || type == PotionEffectType.SLOW_FALLING
                || type == PotionEffectType.RESISTANCE
                || type == PotionEffectType.HASTE
                || type == PotionEffectType.ABSORPTION
                || type == PotionEffectType.FIRE_RESISTANCE
                || type == PotionEffectType.WATER_BREATHING
                || type == PotionEffectType.INVISIBILITY
                || type == PotionEffectType.JUMP_BOOST
                || type == PotionEffectType.NIGHT_VISION
                || type == PotionEffectType.DOLPHINS_GRACE
                || type == PotionEffectType.LUCK
                || type == PotionEffectType.HEALTH_BOOST
                || type == PotionEffectType.CONDUIT_POWER
                || type == PotionEffectType.BREATH_OF_THE_NAUTILUS
                || type == PotionEffectType.SATURATION;
    }

    private boolean isHarmfulFlashNoteBuff(PotionEffectType type) {
        return type == PotionEffectType.SLOWNESS
                || type == PotionEffectType.WEAKNESS
                || type == PotionEffectType.POISON
                || type == PotionEffectType.GLOWING
                || type == PotionEffectType.BLINDNESS
                || type == PotionEffectType.DARKNESS
                || type == PotionEffectType.MINING_FATIGUE
                || type == PotionEffectType.LEVITATION
                || type == PotionEffectType.WITHER
                || type == PotionEffectType.HUNGER
                || type == PotionEffectType.NAUSEA
                || type == PotionEffectType.UNLUCK
                || type == PotionEffectType.WEAVING
                || type == PotionEffectType.OOZING
                || type == PotionEffectType.INFESTED
                || type == PotionEffectType.WIND_CHARGED;
    }

    private boolean isFlashNoteParticleWave(FlashNoteSpell spell) {
        return spell != null && spell.name().startsWith("粒子波-");
    }

    private boolean isFlashNoteFinale(FlashNoteSpell spell) {
        return spell != null && spell.name().startsWith("全章-");
    }

    private void triggerFlashNoteSpell(Player caster, GameRoom room, Location center, FlashNoteSpell spell) {
        World world = center.getWorld();
        if (world == null) {
            return;
        }

        world.playSound(center, spell.sound(), spell.volume(), spell.pitch());
        world.playSound(center, Sound.BLOCK_NOTE_BLOCK_PLING, 0.46f, Math.min(2.0f, spell.pitch() + 0.22f));
        world.spawnParticle(Particle.NOTE, center, 10, 0.72D, 0.42D, 0.72D, 0.0D);
        world.spawnParticle(Particle.DUST, center, 28, 0.72D, 0.34D, 0.72D, 0.0D,
                new Particle.DustOptions(spell.color(), 1.15F));

        drawFlashNoteRing(world, center, spell);

        if (isFlashNoteFinale(spell)) {
            triggerFlashNoteFinale(caster, room, center, spell);
            return;
        }

        if (isFlashNoteParticleWave(spell)) {
            launchFlashNoteParticleWave(caster, room, spell);
            return;
        }

        if ("风跃滑音".equals(spell.name())) {
            Vector direction = caster.getLocation().getDirection();
            if (direction.lengthSquared() < 0.0001D) {
                direction = new Vector(0.0D, 0.0D, 1.0D);
            }
            direction.normalize().multiply(0.82D);
            direction.setY(Math.max(0.56D, direction.getY() + 0.34D));
            caster.setVelocity(caster.getVelocity().multiply(0.35D).add(direction));
            caster.addPotionEffect(new PotionEffect(PotionEffectType.SLOW_FALLING, spell.durationTicks(), 0, false, true, true));
            world.spawnParticle(Particle.GUST, caster.getLocation().add(0.0D, 0.65D, 0.0D), 22, 0.36D, 0.18D, 0.36D, 0.07D);
            return;
        }

        if (spell.damage() > 0.0D) {
            launchFlashNoteParticleWave(caster, room, spell);
            applyFlashNoteAllyEffect(caster, spell, center);
            return;
        }

        for (Entity entity : world.getNearbyEntities(center, spell.radius(), Math.max(2.6D, spell.radius() * 0.62D), spell.radius())) {
            if (!(entity instanceof LivingEntity living) || living.isDead()) {
                continue;
            }

            if (living instanceof Player target) {
                if (isFlashNoteAlly(room, caster, target)) {
                    applyFlashNoteAllyEffect(target, spell, center);
                    continue;
                }
                if (!canDamage(room, caster, target)) {
                    continue;
                }
            } else if (isOwnedOrFriendlyTame(caster.getUniqueId(), living)) {
                continue;
            }

            if (spell.damage() > 0.0D && !living.getUniqueId().equals(caster.getUniqueId())) {
                applyFlashNoteDamage(caster, room, living, center, spell);
            }
        }

        applyFlashNoteAllyEffect(caster, spell, center);
    }

    private void triggerFlashNoteFinale(Player caster, GameRoom room, Location center, FlashNoteSpell spell) {
        World world = center.getWorld();
        if (world == null) {
            return;
        }
        caster.addPotionEffect(new PotionEffect(PotionEffectType.RESISTANCE, 120, 1, false, true, true));
        caster.addPotionEffect(new PotionEffect(PotionEffectType.ABSORPTION, 160, 1, false, true, true));
        if (isBeneficialFlashNoteBuff(spell.buff())) {
            applyFlashNoteAllyEffect(caster, spell, center);
            for (Entity entity : world.getNearbyEntities(caster.getLocation(), 18.0D, 9.0D, 18.0D)) {
                if (entity instanceof Player target
                        && !target.getUniqueId().equals(caster.getUniqueId())
                        && isFlashNoteAlly(room, caster, target)) {
                    applyFlashNoteAllyEffect(target, spell, center);
                }
            }
        }
        world.playSound(center, spell.sound(), spell.volume(), spell.pitch());
        world.playSound(center, Sound.BLOCK_END_PORTAL_SPAWN, 0.42f, 1.55f);
        world.playSound(center, Sound.BLOCK_BEACON_POWER_SELECT, 0.72f, 1.75f);
        launchFlashNoteParticleWave(caster, room, spell);

        new BukkitRunnable() {
            private int pulse = 0;
            private final Set<UUID> hit = new HashSet<>();

            @Override
            public void run() {
                if (!caster.isOnline() || !isFlashEffectStillActive(caster, room) || pulse >= 6) {
                    cancel();
                    return;
                }
                double radius = 4.5D + pulse * (spell.radius() / 6.0D);
                Particle.DustOptions dust = new Particle.DustOptions(spell.color(), 1.35F);
                for (int i = 0; i < 72; i++) {
                    double angle = Math.toRadians(i * 5.0D);
                    Location point = caster.getLocation().clone().add(Math.cos(angle) * radius, 0.18D + pulse * 0.06D, Math.sin(angle) * radius);
                    world.spawnParticle(Particle.DUST, point, 1, 0.015D, 0.015D, 0.015D, 0.0D, dust);
                    if (i % 6 == 0) {
                        world.spawnParticle(Particle.END_ROD, point.clone().add(0.0D, 0.35D, 0.0D), 1, 0.03D, 0.03D, 0.03D, 0.035D);
                    }
                }
                world.spawnParticle(Particle.SONIC_BOOM, caster.getLocation().add(0.0D, 1.1D, 0.0D), 1, 0.0D, 0.0D, 0.0D, 0.0D);
                world.playSound(caster.getLocation(), Sound.BLOCK_AMETHYST_BLOCK_RESONATE, 0.48f, Math.min(2.0f, 1.0f + pulse * 0.12f));

                for (Entity entity : world.getNearbyEntities(caster.getLocation(), radius, Math.max(3.0D, radius * 0.5D), radius)) {
                    if (!(entity instanceof LivingEntity living) || living.isDead()
                            || living.getUniqueId().equals(caster.getUniqueId()) || hit.contains(living.getUniqueId())) {
                        continue;
                    }
                    if (living instanceof Player target && !canDamage(room, caster, target)) {
                        continue;
                    }
                    if (isOwnedOrFriendlyTame(caster.getUniqueId(), living)) {
                        continue;
                    }
                    hit.add(living.getUniqueId());
                    applyFlashNoteArmorPiercingDamage(caster, living, spell.damage());
                    if (isHarmfulFlashNoteBuff(spell.buff())) {
                        living.addPotionEffect(new PotionEffect(spell.buff(), spell.durationTicks(), spell.amplifier(), false, true, true));
                    }
                    living.addPotionEffect(new PotionEffect(PotionEffectType.GLOWING, 100, 0, false, true, true));
                    Vector push = living.getLocation().toVector().subtract(caster.getLocation().toVector());
                    if (push.lengthSquared() > 0.0001D) {
                        push.normalize().multiply(0.82D);
                        push.setY(0.34D);
                        living.setVelocity(living.getVelocity().multiply(0.45D).add(push));
                    }
                    world.spawnParticle(Particle.CRIT, living.getLocation().add(0.0D, Math.min(1.0D, living.getHeight() * 0.55D), 0.0D), 18, 0.28D, 0.28D, 0.28D, 0.08D);
                }
                pulse++;
            }
        }.runTaskTimer(plugin, 0L, 7L);
    }

    private double getFlashNoteRemoteRange(FlashNoteSpell spell) {
        if (spell == null) {
            return 0.0D;
        }
        if (isFlashNoteFinale(spell)) {
            return Math.max(110.0D, spell.radius());
        }
        if (isFlashNoteParticleWave(spell)) {
            return Math.min(128.0D, Math.max(88.0D, spell.radius() * 5.6D));
        }
        if (spell.damage() > 0.0D) {
            return Math.min(104.0D, Math.max(64.0D, spell.radius() * 10.0D));
        }
        return spell.radius();
    }

    private void launchFlashNoteParticleWave(Player caster, GameRoom room, FlashNoteSpell spell) {
        if (caster == null || !caster.isOnline()) {
            return;
        }
        World world = caster.getWorld();
        double maxDistance = getFlashNoteRemoteRange(spell);
        Vector initialDirection = caster.getEyeLocation().getDirection();
        if (initialDirection.lengthSquared() < 0.0001D) {
            initialDirection = new Vector(0.0D, 0.0D, 1.0D);
        }
        initialDirection.normalize();
        final Vector startDirection = initialDirection.clone();
        Location start = caster.getEyeLocation().add(startDirection.clone().multiply(0.9D)).add(0.0D, -0.15D, 0.0D);
        Particle.DustOptions dust = new Particle.DustOptions(spell.color(), 1.18F);
        world.playSound(caster.getLocation(), spell.sound(), spell.volume(), spell.pitch());
        world.playSound(caster.getLocation(), Sound.BLOCK_AMETHYST_BLOCK_RESONATE, 0.48f, Math.min(2.0f, spell.pitch() + 0.24f));

        new BukkitRunnable() {
            private final Set<UUID> hit = new HashSet<>();
            private Location current = start.clone();
            private Vector direction = startDirection.clone();
            private double travelled = 0.0D;
            private UUID homingTargetId = findFlashNoteHomingTarget(caster, room, current, direction, maxDistance, hit);

            @Override
            public void run() {
                if (!caster.isOnline() || !isFlashEffectStillActive(caster, room) || travelled > maxDistance) {
                    cancel();
                    return;
                }

                LivingEntity homingTarget = resolveFlashNoteHomingTarget(homingTargetId, caster, room, world, hit);
                if (homingTarget == null && homingTargetId != null) {
                    homingTargetId = findFlashNoteHomingTarget(caster, room, current, direction, Math.max(18.0D, maxDistance - travelled), hit);
                    homingTarget = resolveFlashNoteHomingTarget(homingTargetId, caster, room, world, hit);
                }
                if (homingTarget != null) {
                    Location aim = homingTarget.getLocation().add(0.0D, Math.min(1.15D, Math.max(0.45D, homingTarget.getHeight() * 0.58D)), 0.0D);
                    Vector desired = aim.toVector().subtract(current.toVector());
                    if (desired.lengthSquared() > 0.0001D) {
                        desired.normalize();
                        direction.multiply(0.62D).add(desired.multiply(0.48D));
                        if (direction.lengthSquared() > 0.0001D) {
                            direction.normalize();
                        }
                    }
                } else if (direction.lengthSquared() > 0.0001D) {
                    direction.normalize();
                }

                current.add(direction.clone().multiply(2.25D));
                travelled += 2.25D;
                if (!current.getBlock().isPassable() && travelled > 1.2D) {
                    world.spawnParticle(Particle.EXPLOSION, current, 1, 0.05D, 0.05D, 0.05D, 0.0D);
                    world.playSound(current, Sound.BLOCK_AMETHYST_BLOCK_BREAK, 0.58f, 1.15f);
                    cancel();
                    return;
                }

                Vector right = new Vector(-direction.getZ(), 0.0D, direction.getX());
                if (right.lengthSquared() < 0.0001D) {
                    right = new Vector(1.0D, 0.0D, 0.0D);
                }
                right.normalize();
                Vector up = direction.clone().crossProduct(right);
                if (up.lengthSquared() < 0.0001D) {
                    up = new Vector(0.0D, 1.0D, 0.0D);
                }
                up.normalize();

                double width = Math.min(2.65D, 0.82D + travelled * 0.028D);
                for (int i = -4; i <= 4; i++) {
                    double side = i * width / 4.0D;
                    Location point = current.clone().add(right.clone().multiply(side));
                    world.spawnParticle(Particle.DUST, point, 1, 0.015D, 0.015D, 0.015D, 0.0D, dust);
                    if ((i & 1) == 0) {
                        world.spawnParticle(Particle.END_ROD, point.clone().add(up.clone().multiply(0.12D)), 1, 0.02D, 0.02D, 0.02D, 0.02D);
                    }
                }
                world.spawnParticle(homingTarget == null ? Particle.SONIC_BOOM : Particle.ENCHANTED_HIT, current, 1, 0.0D, 0.0D, 0.0D, 0.0D);

                for (Entity entity : world.getNearbyEntities(current, width + 0.75D, 1.35D, width + 0.75D)) {
                    if (!(entity instanceof LivingEntity living) || living.isDead()
                            || living.getUniqueId().equals(caster.getUniqueId()) || hit.contains(living.getUniqueId())) {
                        continue;
                    }
                    if (!canFlashNoteHitLiving(caster, room, living)) {
                        continue;
                    }
                    hit.add(living.getUniqueId());
                    applyFlashNoteArmorPiercingDamage(caster, living, spell.damage());
                    if (isHarmfulFlashNoteBuff(spell.buff())) {
                        living.addPotionEffect(new PotionEffect(spell.buff(), spell.durationTicks(), spell.amplifier(), false, true, true));
                    }
                    if (living.getUniqueId().equals(homingTargetId)) {
                        homingTargetId = findFlashNoteHomingTarget(caster, room, current, direction, Math.max(18.0D, maxDistance - travelled), hit);
                    }
                    Vector push = living.getLocation().toVector().subtract(caster.getLocation().toVector());
                    if (push.lengthSquared() < 0.0001D) {
                        push = direction.clone();
                    }
                    push.normalize().multiply(0.46D);
                    push.setY(Math.max(0.18D, push.getY() + 0.12D));
                    living.setVelocity(living.getVelocity().multiply(0.55D).add(push));
                    world.spawnParticle(Particle.CRIT, living.getLocation().add(0.0D, Math.min(1.0D, living.getHeight() * 0.55D), 0.0D), 14, 0.24D, 0.24D, 0.24D, 0.06D);
                    world.playSound(living.getLocation(), Sound.ENTITY_PLAYER_ATTACK_SWEEP, 0.46f, 1.35f);
                }
            }
        }.runTaskTimer(plugin, 0L, 1L);
    }

    private UUID findFlashNoteHomingTarget(Player caster, GameRoom room, Location origin, Vector forward, double range, Set<UUID> ignored) {
        if (caster == null || origin == null || origin.getWorld() == null || range <= 0.0D) {
            return null;
        }
        Vector look = forward == null || forward.lengthSquared() < 0.0001D ? caster.getEyeLocation().getDirection() : forward.clone();
        if (look.lengthSquared() < 0.0001D) {
            look = new Vector(0.0D, 0.0D, 1.0D);
        }
        look.normalize();
        UUID best = null;
        double bestScore = Double.MAX_VALUE;
        double maxDistanceSquared = range * range;
        for (Entity entity : origin.getWorld().getNearbyEntities(origin, range, range, range)) {
            if (!(entity instanceof Player target) || target.equals(caster) || target.isDead()
                    || (ignored != null && ignored.contains(target.getUniqueId())) || !canDamage(room, caster, target)) {
                continue;
            }
            Location targetPoint = target.getLocation().add(0.0D, Math.min(1.15D, Math.max(0.45D, target.getHeight() * 0.58D)), 0.0D);
            Vector toTarget = targetPoint.toVector().subtract(origin.toVector());
            double distanceSquared = toTarget.lengthSquared();
            if (distanceSquared > maxDistanceSquared || distanceSquared < 0.01D) {
                continue;
            }
            Vector normalized = toTarget.clone().normalize();
            double dot = normalized.dot(look);
            double score = distanceSquared - Math.max(0.0D, dot) * range * 14.0D;
            if (dot < -0.25D) {
                score += range * range * 0.8D;
            }
            if (score < bestScore) {
                bestScore = score;
                best = target.getUniqueId();
            }
        }
        return best;
    }

    private LivingEntity resolveFlashNoteHomingTarget(UUID targetId, Player caster, GameRoom room, World world, Set<UUID> ignored) {
        if (targetId == null || world == null || ignored != null && ignored.contains(targetId)) {
            return null;
        }
        Entity entity = Bukkit.getEntity(targetId);
        if (!(entity instanceof LivingEntity living) || living.isDead() || !world.equals(living.getWorld())) {
            return null;
        }
        return canFlashNoteHitLiving(caster, room, living) ? living : null;
    }

    private boolean canFlashNoteHitLiving(Player caster, GameRoom room, LivingEntity living) {
        if (caster == null || living == null || living.isDead() || living.getUniqueId().equals(caster.getUniqueId())) {
            return false;
        }
        if (living instanceof Player target) {
            return canDamage(room, caster, target);
        }
        return !isOwnedOrFriendlyTame(caster.getUniqueId(), living);
    }

    private void applyFlashNoteAllyEffect(Player target, FlashNoteSpell spell, Location center) {
        if (isBeneficialFlashNoteBuff(spell.buff())) {
            target.addPotionEffect(new PotionEffect(spell.buff(), spell.durationTicks(), spell.amplifier(), false, true, true));
        }
        if ("低音护幕".equals(spell.name())) {
            target.addPotionEffect(new PotionEffect(PotionEffectType.ABSORPTION, 120, 0, false, true, true));
        } else if ("回生命弦".equals(spell.name())) {
            AttributeInstance maxHealth = target.getAttribute(Attribute.MAX_HEALTH);
            double limit = maxHealth == null ? 20.0D : maxHealth.getValue();
            target.setHealth(Math.min(limit, target.getHealth() + 4.0D));
        } else if ("终曲星鸣".equals(spell.name())) {
            target.addPotionEffect(new PotionEffect(PotionEffectType.SPEED, 100, 0, false, true, true));
        }
        target.getWorld().spawnParticle(Particle.HAPPY_VILLAGER, target.getLocation().add(0.0D, 1.0D, 0.0D), 8, 0.24D, 0.22D, 0.24D, 0.02D);
        if (target.getLocation().distanceSquared(center) < 64.0D) {
            target.playSound(target.getLocation(), Sound.BLOCK_AMETHYST_CLUSTER_HIT, 0.32f, Math.min(2.0f, spell.pitch() + 0.15f));
        }
    }

    private void applyFlashNoteArmorPiercingDamage(Player caster, LivingEntity living, double damage) {
        if (living == null || living.isDead() || damage <= 0.0D) {
            return;
        }
        double normalDamage = damage * 0.30D;
        double piercingDamage = damage * 0.70D;
        if (normalDamage > 0.0D) {
            living.damage(normalDamage, caster);
        }
        if (living.isDead() || !living.isValid() || piercingDamage <= 0.0D) {
            return;
        }
        double health = living.getHealth();
        double nextHealth = health - piercingDamage;
        if (nextHealth <= 0.0D) {
            living.setHealth(0.0D);
            return;
        }
        living.setHealth(Math.max(0.01D, nextHealth));
    }

    private void applyFlashNoteDamage(Player caster, GameRoom room, LivingEntity living, Location center, FlashNoteSpell spell) {
        if (living instanceof Player target && !canDamage(room, caster, target)) {
            return;
        }
        applyFlashNoteArmorPiercingDamage(caster, living, spell.damage());
        if (isHarmfulFlashNoteBuff(spell.buff())) {
            living.addPotionEffect(new PotionEffect(spell.buff(), Math.max(55, spell.durationTicks() / 2), Math.min(2, spell.amplifier()), false, true, true));
        }
        if (spell.name().contains("雷鸣") || spell.name().contains("星鸣")) {
            living.getWorld().strikeLightningEffect(living.getLocation());
            living.addPotionEffect(new PotionEffect(PotionEffectType.GLOWING, 80, 0, false, true, true));
        }
        if (spell.name().contains("爆音") || spell.name().contains("震荡")) {
            Vector push = living.getLocation().toVector().subtract(center.toVector());
            if (push.lengthSquared() > 0.0001D) {
                push.normalize().multiply(0.74D);
                push.setY(0.32D);
                living.setVelocity(living.getVelocity().multiply(0.42D).add(push));
            }
        }
        living.getWorld().spawnParticle(Particle.CRIT, living.getLocation().add(0.0D, Math.min(1.0D, living.getHeight() * 0.55D), 0.0D), 12, 0.22D, 0.22D, 0.22D, 0.05D);
    }

    private boolean isFlashNoteAlly(GameRoom room, Player caster, Player target) {
        if (caster == null || target == null) {
            return false;
        }
        if (caster.getUniqueId().equals(target.getUniqueId())) {
            return true;
        }
        return room != null
                && room.getAllPlayerUUIDs().contains(target.getUniqueId())
                && !room.isSpectator(target.getUniqueId())
                && !canDamage(room, caster, target);
    }

    private void drawFlashNoteRing(World world, Location center, FlashNoteSpell spell) {
        double radius = Math.min(3.4D, Math.max(1.2D, spell.radius() * 0.42D));
        Particle.DustOptions dust = new Particle.DustOptions(spell.color(), 0.88F);
        for (int i = 0; i < 42; i++) {
            double angle = Math.toRadians(i * (360.0D / 42.0D));
            Location point = center.clone().add(Math.cos(angle) * radius, 0.04D + Math.sin(angle * 2.0D) * 0.05D, Math.sin(angle) * radius);
            world.spawnParticle(Particle.DUST, point, 1, 0.01D, 0.01D, 0.01D, 0.0D, dust);
            if (i % 7 == 0) {
                world.spawnParticle(Particle.END_ROD, point.clone().add(0.0D, 0.12D, 0.0D), 1, 0.02D, 0.02D, 0.02D, 0.025D);
            }
        }
    }

    public boolean handlePseudoPoisonPotatoInteract(PlayerInteractEvent event) {
        if (event == null || event.getHand() == null || event.getAction() != Action.RIGHT_CLICK_BLOCK) {
            return false;
        }
        Player player = event.getPlayer();
        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        if (!isFlashCombatAvailable(player, room)) {
            return false;
        }
        Block clicked = event.getClickedBlock();
        if (clicked == null) {
            return false;
        }
        ItemStack item = event.getItem();
        if (isFlashSpecialFood(item) && clicked.getType() == Material.FARMLAND) {
            event.setCancelled(true);
            event.setUseInteractedBlock(Event.Result.DENY);
            event.setUseItemInHand(Event.Result.DENY);
            player.sendActionBar("§x§B§B§8§8§F§F✦ §d闪光特殊食物只能吃，§7不能当普通种子种下");
            player.playSound(player.getLocation(), Sound.BLOCK_NOTE_BLOCK_CHIME, 0.32f, 0.72f);
            return true;
        }
        if (isPseudoPoisonPotato(item) && clicked.getType() == Material.FARMLAND) {
            return plantPseudoPoisonPotato(event, player, room, clicked);
        }
        String cropKey = blockKey(clicked.getLocation());
        PseudoPoisonPotatoCrop crop = pseudoPoisonPotatoCrops.get(cropKey);
        if (crop == null || event.getHand() != EquipmentSlot.HAND) {
            return false;
        }
        event.setCancelled(true);
        event.setUseInteractedBlock(Event.Result.DENY);
        event.setUseItemInHand(Event.Result.DENY);
        showPseudoPoisonPotatoStatus(player, clicked, crop);
        return true;
    }

    private boolean plantPseudoPoisonPotato(PlayerInteractEvent event, Player player, GameRoom room, Block farmland) {
        Block cropBlock = farmland.getRelative(BlockFace.UP);
        if (!cropBlock.isEmpty() && !cropBlock.isPassable()) {
            event.setCancelled(true);
            event.setUseInteractedBlock(Event.Result.DENY);
            event.setUseItemInHand(Event.Result.DENY);
            player.sendActionBar("§x§F§F§B§B§6§6✦ §e上方被挡住了，§7伪毒苗没有位置钻出来");
            player.playSound(player.getLocation(), Sound.BLOCK_NOTE_BLOCK_BASS, 0.45f, 0.72f);
            return true;
        }

        event.setCancelled(true);
        event.setUseInteractedBlock(Event.Result.DENY);
        event.setUseItemInHand(Event.Result.DENY);
        consumeInteractItem(player, event.getHand(), 1);
        keepFlashWetFarmlandMoist(farmland);

        cropBlock.setType(Material.POTATOES, false);
        if (cropBlock.getBlockData() instanceof Ageable ageable) {
            ageable.setAge(0);
            cropBlock.setBlockData(ageable, false);
        }

        long now = System.currentTimeMillis();
        long growMillis = ThreadLocalRandom.current().nextLong(PSEUDO_POISON_POTATO_MIN_GROW_MILLIS,
                PSEUDO_POISON_POTATO_MAX_GROW_MILLIS + 1L);
        String roomId = room == null ? "standalone:" + player.getUniqueId() : room.getRoomId();
        pseudoPoisonPotatoCrops.put(blockKey(cropBlock.getLocation()),
                new PseudoPoisonPotatoCrop(player.getUniqueId(), roomId, cropBlock.getLocation().clone(),
                        now, now + growMillis, -1));

        Location effect = cropBlock.getLocation().add(0.5D, 0.35D, 0.5D);
        cropBlock.getWorld().spawnParticle(Particle.COMPOSTER, effect, 18, 0.28D, 0.12D, 0.28D, 0.04D);
        cropBlock.getWorld().spawnParticle(Particle.WITCH, effect, 8, 0.22D, 0.12D, 0.22D, 0.015D);
        cropBlock.getWorld().playSound(effect, Sound.ITEM_CROP_PLANT, 0.76f, 0.82f);
        cropBlock.getWorld().playSound(effect, Sound.BLOCK_AMETHYST_BLOCK_CHIME, 0.38f, 1.72f);
        player.swingHand(event.getHand());
        player.sendActionBar("§x§9§C§E§D§5§8✦ §a伪毒马铃薯已种下 §8| §f"
                + formatDurationZh(growMillis) + "§7后成熟");
        return true;
    }

    public boolean handlePseudoPoisonPotatoCropBreak(BlockBreakEvent event, Player player, GameRoom room) {
        if (event == null || player == null) {
            return false;
        }
        String key = blockKey(event.getBlock().getLocation());
        PseudoPoisonPotatoCrop crop = pseudoPoisonPotatoCrops.get(key);
        if (crop == null) {
            return false;
        }
        if (!isFlashCombatAvailable(player, room) || !isSamePseudoPoisonCropRoom(crop, room, player)) {
            return false;
        }
        pseudoPoisonPotatoCrops.remove(key);
        event.setCancelled(false);
        event.setDropItems(false);
        event.setExpToDrop(0);

        Location drop = event.getBlock().getLocation().add(0.5D, 0.32D, 0.5D);
        if (System.currentTimeMillis() >= crop.growAtMillis()) {
            World world = event.getBlock().getWorld();
            int potatoCount = rollMaturePseudoPoisonPotatoCount();
            if (potatoCount > 0) {
                ItemStack potato = createPseudoPoisonPotato();
                potato.setAmount(potatoCount);
                world.dropItemNaturally(drop, potato);
            }
            boolean droppedSpecialFood = ThreadLocalRandom.current().nextDouble() < 0.30D;
            boolean droppedMineral = ThreadLocalRandom.current().nextDouble() < 0.70D;
            ItemStack specialFood = null;
            ItemStack mineral = null;
            if (droppedSpecialFood) {
                int id = ThreadLocalRandom.current().nextInt(1, FLASH_SPECIAL_FOOD_MAX_ID + 1);
                specialFood = createFlashSpecialFood(id);
                world.dropItemNaturally(drop, specialFood);
            }
            if (droppedMineral) {
                mineral = new ItemStack(rollPseudoPoisonPotatoMineralDrop());
                world.dropItemNaturally(drop, mineral);
            }

            player.addPotionEffect(new PotionEffect(PotionEffectType.POISON, 20 * 8, 0, false, true, true), true);
            world.spawnParticle(Particle.TOTEM_OF_UNDYING, drop.clone().add(0.0D, 0.25D, 0.0D),
                    droppedSpecialFood ? 32 : 18, 0.36D, 0.24D, 0.36D, 0.08D);
            world.spawnParticle(Particle.WITCH, drop.clone().add(0.0D, 0.16D, 0.0D),
                    24, 0.34D, 0.16D, 0.34D, 0.035D);
            world.spawnParticle(Particle.GLOW, drop.clone().add(0.0D, 0.16D, 0.0D),
                    droppedMineral ? 24 : 12, 0.34D, 0.16D, 0.34D, 0.02D);
            world.playSound(drop, Sound.ENTITY_ALLAY_ITEM_GIVEN, 0.58f, droppedSpecialFood ? 1.18f : 0.86f);
            world.playSound(drop, Sound.BLOCK_RESPAWN_ANCHOR_CHARGE, 0.34f, 1.48f);

            List<String> dropNames = new ArrayList<>();
            if (potatoCount > 0) {
                dropNames.add("§x§9§C§E§D§5§8伪毒马铃薯×" + potatoCount);
            }
            if (specialFood != null) {
                dropNames.add("§d" + plainItemName(specialFood));
            }
            if (mineral != null) {
                dropNames.add("§b" + plainItemName(mineral));
            }
            String summary = dropNames.isEmpty() ? "§7什么也没掉" : String.join("§8、", dropNames);
            player.sendActionBar("§x§B§B§8§8§F§F✦ §f成熟伪毒苗掉落：§r" + summary + " §8| §2中毒8秒");
        } else {
            event.getBlock().getWorld().dropItemNaturally(drop, createPseudoPoisonPotato());
            event.getBlock().getWorld().spawnParticle(Particle.WITCH, drop, 14, 0.24D, 0.14D, 0.24D, 0.02D);
            event.getBlock().getWorld().playSound(drop, Sound.BLOCK_NOTE_BLOCK_BASS, 0.58f, 0.72f);
            long remaining = Math.max(0L, crop.growAtMillis() - System.currentTimeMillis());
            player.sendActionBar("§x§F§F§B§B§6§6✦ §e伪毒苗还没熟 §8| §7还差 §f" + formatDurationZh(remaining));
        }
        return true;
    }

    private int rollMaturePseudoPoisonPotatoCount() {
        double roll = ThreadLocalRandom.current().nextDouble();
        if (roll < 0.70D) {
            return 1;
        }
        if (roll < 0.80D) {
            return 2;
        }
        return 0;
    }

    private Material rollPseudoPoisonPotatoMineralDrop() {
        int roll = ThreadLocalRandom.current().nextInt(100);
        if (roll < 35) {
            return Material.COAL;
        }
        if (roll < 61) {
            return Material.RAW_COPPER;
        }
        if (roll < 83) {
            return Material.RAW_IRON;
        }
        if (roll < 95) {
            return Material.RAW_GOLD;
        }
        return Material.DIAMOND;
    }

    public void handleFlashFoodConsume(PlayerItemConsumeEvent event) {
        if (event == null || event.isCancelled()) {
            return;
        }
        Player player = event.getPlayer();
        ItemStack item = event.getItem();
        if (isPseudoPoisonPotato(item)) {
            event.setCancelled(true);
            consumeConsumedItem(player, event.getHand(), item);
            player.addPotionEffect(new PotionEffect(PotionEffectType.NAUSEA, 20 * 60, 0, false, true, true));
            double health = Math.max(0.0D, player.getHealth());
            player.setHealth(Math.max(1.0D, health * 0.75D));
            player.getWorld().spawnParticle(Particle.WITCH, player.getLocation().add(0.0D, 1.0D, 0.0D),
                    24, 0.28D, 0.35D, 0.28D, 0.04D);
            player.playSound(player.getLocation(), Sound.ENTITY_GENERIC_DRINK, 0.58f, 0.68f);
            player.playSound(player.getLocation(), Sound.BLOCK_AMETHYST_BLOCK_CHIME, 0.38f, 0.62f);
            player.sendActionBar("§x§9§C§E§D§5§8✦ §d反胃60秒 §8| §c当前生命 -25%");
            return;
        }
        int specialFoodId = getFlashSpecialFoodId(item);
        if (specialFoodId <= 0) {
            return;
        }
        FlashSpecialFoodProfile profile = getFlashSpecialFoodProfile(specialFoodId);
        if (profile == null) {
            return;
        }
        event.setCancelled(true);
        consumeConsumedItem(player, event.getHand(), item);
        applyFlashSpecialFoodEffect(player, profile);
    }

    private void showPseudoPoisonPotatoStatus(Player player, Block cropBlock, PseudoPoisonPotatoCrop crop) {
        long now = System.currentTimeMillis();
        long total = Math.max(1L, crop.growAtMillis() - crop.plantedAtMillis());
        long elapsed = Math.max(0L, now - crop.plantedAtMillis());
        int percent = (int) Math.max(0L, Math.min(100L, elapsed * 100L / total));
        if (now >= crop.growAtMillis()) {
            player.sendActionBar("§x§B§B§8§8§F§F✦ §d伪毒马铃薯已经成熟 §8| §f挖掉会判定种薯、特殊食物和矿物");
            player.playSound(player.getLocation(), Sound.BLOCK_AMETHYST_BLOCK_CHIME, 0.42f, 1.82f);
            cropBlock.getWorld().spawnParticle(Particle.GLOW, cropBlock.getLocation().add(0.5D, 0.7D, 0.5D),
                    8, 0.24D, 0.16D, 0.24D, 0.02D);
            return;
        }
        player.sendActionBar("§x§9§C§E§D§5§8✦ §a伪毒苗状态 §f" + percent + "% §8| §7还差 §f"
                + formatDurationZh(crop.growAtMillis() - now));
        player.playSound(player.getLocation(), Sound.BLOCK_NOTE_BLOCK_CHIME, 0.32f, 1.35f);
    }

    private boolean isSamePseudoPoisonCropRoom(PseudoPoisonPotatoCrop crop, GameRoom room, Player player) {
        if (crop == null || player == null) {
            return false;
        }
        if (crop.roomId().startsWith("standalone:")) {
            return crop.roomId().equals("standalone:" + player.getUniqueId());
        }
        String currentRoomId = room == null ? "standalone:" + player.getUniqueId() : room.getRoomId();
        return crop.roomId().equals(currentRoomId);
    }

    private void consumeConsumedItem(Player player, EquipmentSlot hand, ItemStack consumed) {
        if (player == null || player.getGameMode() == org.bukkit.GameMode.CREATIVE) {
            return;
        }
        EquipmentSlot actualHand = hand == null ? findConsumedItemHand(player, consumed) : hand;
        consumeHandItem(player, actualHand, 1);
    }

    private EquipmentSlot findConsumedItemHand(Player player, ItemStack consumed) {
        if (isSimilarFlashConsumeItem(player.getInventory().getItemInMainHand(), consumed)) {
            return EquipmentSlot.HAND;
        }
        if (isSimilarFlashConsumeItem(player.getInventory().getItemInOffHand(), consumed)) {
            return EquipmentSlot.OFF_HAND;
        }
        return EquipmentSlot.HAND;
    }

    private boolean isSimilarFlashConsumeItem(ItemStack current, ItemStack consumed) {
        if (isEmpty(current) || isEmpty(consumed) || current.getType() != consumed.getType()) {
            return false;
        }
        if (isPseudoPoisonPotato(consumed)) {
            return isPseudoPoisonPotato(current);
        }
        int id = getFlashSpecialFoodId(consumed);
        return id > 0 && getFlashSpecialFoodId(current) == id;
    }

    private String plainItemName(ItemStack item) {
        if (item == null || !item.hasItemMeta()) {
            return "闪光食物";
        }
        String name = item.getItemMeta().getItemName();
        if (name == null || name.isBlank()) {
            return "闪光食物";
        }
        return name.replaceAll("§.", "");
    }

    private String formatDurationZh(long millis) {
        long seconds = Math.max(0L, (millis + 999L) / 1000L);
        long minutes = seconds / 60L;
        long remainSeconds = seconds % 60L;
        if (minutes <= 0L) {
            return remainSeconds + "秒";
        }
        if (remainSeconds <= 0L) {
            return minutes + "分钟";
        }
        return minutes + "分" + remainSeconds + "秒";
    }

    public boolean handleFlashCoarseDirtPlace(BlockPlaceEvent event, Player player, GameRoom room) {
        if (event == null || player == null || event.getBlockPlaced().getType() != Material.COARSE_DIRT) {
            return false;
        }
        if (!isFlashCombatAvailable(player, room)) {
            return false;
        }
        if (event.isCancelled()) {
            event.setCancelled(false);
        }
        Location placed = event.getBlockPlaced().getLocation().clone();
        String roomId = room == null ? "standalone:" + player.getUniqueId() : room.getRoomId();
        rememberFlashPlayerPlacedBlock(event.getBlockPlaced(), player, room);
        flashCoarseDirtPatches.put(blockKey(placed),
                new FlashCoarseDirtPatch(player.getUniqueId(), roomId, placed.clone(), 0, System.currentTimeMillis()));
        flashPermanentWetFarmlands.remove(blockKey(placed));
        flashHoeTraps.remove(blockKey(placed));
        player.sendActionBar("§x§B§B§8§8§F§F✦ §6闪光砂土母体 §f已落地，§e骨粉§f只能喂这块原始砂土");
        return true;
    }

    public void handleFlashPlayerBlockPlace(BlockPlaceEvent event, Player player, GameRoom room) {
        if (event == null || event.isCancelled() || player == null || event.getBlockPlaced() == null) {
            return;
        }
        if (!isFlashCombatAvailable(player, room)) {
            return;
        }
        rememberFlashPlayerPlacedBlock(event.getBlockPlaced(), player, room);
    }

    public boolean handleFlashWetFarmlandCropPlace(BlockPlaceEvent event, Player player, GameRoom room) {
        if (event == null || player == null || !isFlashFarmCrop(event.getBlockPlaced().getType())) {
            return false;
        }
        if (!isFlashCombatAvailable(player, room)) {
            return false;
        }
        Block below = event.getBlockPlaced().getRelative(BlockFace.DOWN);
        FlashWetFarmland farmland = flashPermanentWetFarmlands.get(blockKey(below.getLocation()));
        if (farmland == null || !player.getUniqueId().equals(farmland.ownerUuid())) {
            return false;
        }
        String currentRoomId = room == null ? "standalone:" + player.getUniqueId() : room.getRoomId();
        if (!farmland.roomId().equals(currentRoomId)) {
            return false;
        }
        if (event.isCancelled()) {
            event.setCancelled(false);
        }
        keepFlashWetFarmlandMoist(below);
        return true;
    }

    public void handleFlashWetFarmlandMoistureChange(MoistureChangeEvent event) {
        if (event == null || event.getBlock() == null) {
            return;
        }
        String key = blockKey(event.getBlock().getLocation());
        if (!flashPermanentWetFarmlands.containsKey(key)) {
            return;
        }
        keepFlashWetFarmlandMoist(event.getBlock());
        event.setCancelled(true);
    }

    public void handleFlashWetFarmlandFade(BlockFadeEvent event) {
        if (event == null || event.getBlock() == null) {
            return;
        }
        String key = blockKey(event.getBlock().getLocation());
        if (!flashPermanentWetFarmlands.containsKey(key)) {
            return;
        }
        keepFlashWetFarmlandMoist(event.getBlock());
        event.setCancelled(true);
    }

    public boolean handleFlashCoarseDirtInteract(PlayerInteractEvent event) {
        if (event == null || event.getHand() == null
                || (event.getAction() != Action.RIGHT_CLICK_BLOCK && event.getAction() != Action.RIGHT_CLICK_AIR)) {
            return false;
        }
        Player player = event.getPlayer();
        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        if (!isFlashCombatAvailable(player, room)) {
            return false;
        }
        Block clicked = event.getClickedBlock();
        ItemStack item = event.getItem();
        if (clicked == null || isEmpty(item)) {
            return false;
        }
        if (item.getType() == Material.BONE_MEAL && clicked.getType() == Material.COARSE_DIRT) {
            return feedFlashCoarseDirt(event, player, clicked, room);
        }
        if (isHoe(item) && clicked.getType() == Material.COARSE_DIRT) {
            return tillFlashCoarseDirtToWetFarmland(event, player, clicked, room);
        }
        return false;
    }

    private boolean feedFlashCoarseDirt(PlayerInteractEvent event, Player player, Block clicked, GameRoom room) {
        String key = blockKey(clicked.getLocation());
        FlashCoarseDirtPatch patch = flashCoarseDirtPatches.get(key);
        if (!isOwnFlashCoarseDirt(player, patch, room)) {
            event.setCancelled(true);
            event.setUseInteractedBlock(Event.Result.DENY);
            event.setUseItemInHand(Event.Result.DENY);
            player.sendActionBar("§x§F§F§B§B§6§6✦ §e这块砂土不是你放出来的，§7骨粉没有回应");
            player.playSound(player.getLocation(), Sound.BLOCK_NOTE_BLOCK_BASS, 0.45f, 0.78f);
            return true;
        }
        if (!isOriginalFlashCoarseDirtBlock(clicked, patch)) {
            event.setCancelled(true);
            event.setUseInteractedBlock(Event.Result.DENY);
            event.setUseItemInHand(Event.Result.DENY);
            player.sendActionBar("§x§F§F§B§B§6§6✦ §e催出来的砂土不是母体，§7只能喂最开始亲手放下的那一块");
            player.playSound(player.getLocation(), Sound.BLOCK_NOTE_BLOCK_BASS, 0.42f, 0.72f);
            return true;
        }

        event.setCancelled(true);
        event.setUseInteractedBlock(Event.Result.DENY);
        event.setUseItemInHand(Event.Result.DENY);
        player.swingHand(event.getHand());
        consumeInteractItem(player, event.getHand(), 1);

        int oldRadius = Math.max(0, Math.min(FLASH_COARSE_DIRT_MAX_RADIUS, patch.radius()));
        int newRadius = Math.min(FLASH_COARSE_DIRT_MAX_RADIUS, oldRadius + FLASH_COARSE_DIRT_RADIUS_PER_BONEMEAL);
        int changed = spreadFlashCoarseDirtPatch(patch, newRadius);
        Location effect = clicked.getLocation().add(0.5D, 0.65D, 0.5D);
        clicked.getWorld().spawnParticle(Particle.HAPPY_VILLAGER, effect, 14, 0.45D, 0.18D, 0.45D, 0.04D);
        clicked.getWorld().spawnParticle(Particle.FALLING_DUST, effect, 18, 0.52D, 0.18D, 0.52D, 0.02D, Material.COARSE_DIRT.createBlockData());
        clicked.getWorld().playSound(effect, Sound.ITEM_BONE_MEAL_USE, 0.72f, oldRadius >= FLASH_COARSE_DIRT_MAX_RADIUS ? 0.72f : 1.18f);
        clicked.getWorld().playSound(effect, Sound.BLOCK_ROOTED_DIRT_PLACE, 0.48f, 1.36f);

        if (oldRadius >= FLASH_COARSE_DIRT_MAX_RADIUS) {
            player.sendActionBar("§x§B§B§8§8§F§F✦ §6砂土细胞 §f已到80格边界 §8| §a本次随机生长 " + changed + " 格");
        } else {
            player.sendActionBar("§x§B§B§8§8§F§F✦ §6砂土细胞半径 §f" + newRadius + "§7/§f"
                    + FLASH_COARSE_DIRT_MAX_RADIUS + " §8| §a随机生长 " + changed + " 格");
        }
        return true;
    }

    private int spreadFlashCoarseDirtPatch(FlashCoarseDirtPatch patch, int newRadius) {
        Location origin = patch.origin();
        World world = origin == null ? null : origin.getWorld();
        if (world == null) {
            return 0;
        }
        int changed = 0;
        String originKey = blockKey(origin);
        FlashCoarseDirtPatch updated = new FlashCoarseDirtPatch(patch.ownerUuid(), patch.roomId(),
                origin.clone(), newRadius, patch.createdAtMillis());
        Set<String> existingKeys = new HashSet<>();
        Set<String> candidateKeys = new HashSet<>();
        List<Block> activeCells = new ArrayList<>();
        List<FlashCoarseDirtCandidate> candidates = new ArrayList<>();

        for (Map.Entry<String, FlashCoarseDirtPatch> entry : new ArrayList<>(flashCoarseDirtPatches.entrySet())) {
            FlashCoarseDirtPatch cellPatch = entry.getValue();
            if (!isSameFlashCoarseDirtOrigin(cellPatch, originKey)) {
                continue;
            }
            Block cell = blockFromKey(world, entry.getKey());
            if (cell == null || cell.getType() != Material.COARSE_DIRT) {
                flashCoarseDirtPatches.remove(entry.getKey());
                continue;
            }
            existingKeys.add(entry.getKey());
            activeCells.add(cell);
            flashCoarseDirtPatches.put(entry.getKey(), updated);
        }
        if (activeCells.isEmpty()) {
            Block originBlock = world.getBlockAt(origin);
            if (originBlock.getType() == Material.COARSE_DIRT) {
                existingKeys.add(originKey);
                activeCells.add(originBlock);
                flashCoarseDirtPatches.put(originKey, updated);
            }
        }

        for (Block cell : activeCells) {
            addFlashCoarseDirtGrowthCandidates(cell, origin, newRadius, existingKeys, candidateKeys, candidates);
        }

        int budget = getFlashCoarseDirtCellularGrowthBudget(newRadius, activeCells.size());
        ThreadLocalRandom random = ThreadLocalRandom.current();
        while (changed < budget && !candidates.isEmpty()) {
            Block block = removeWeightedFlashCoarseDirtCandidate(candidates, random);
            if (block == null) {
                continue;
            }
            String key = blockKey(block.getLocation());
            candidateKeys.remove(key);
            if (existingKeys.contains(key) || !isInsideFlashCoarseDirtRadius(block, origin, newRadius)
                    || !canFlashCoarseDirtReplace(block)) {
                continue;
            }
            block.setType(Material.COARSE_DIRT, false);
            flashPermanentWetFarmlands.remove(key);
            flashHoeTraps.remove(key);
            flashCoarseDirtPatches.put(key, updated);
            existingKeys.add(key);
            changed++;
            if (changed <= 10 || random.nextBoolean()) {
                block.getWorld().spawnParticle(Particle.FALLING_DUST, block.getLocation().add(0.5D, 0.82D, 0.5D),
                        5, 0.28D, 0.05D, 0.28D, 0.01D, Material.COARSE_DIRT.createBlockData());
            }
            addFlashCoarseDirtGrowthCandidates(block, origin, newRadius, existingKeys, candidateKeys, candidates);
        }
        return changed;
    }

    private int getFlashCoarseDirtCellularGrowthBudget(int radius, int activeCells) {
        int radiusBonus = Math.min(6, Math.max(0, radius / 12));
        int colonyBonus = Math.min(5, Math.max(0, activeCells / 96));
        return Math.min(24, ThreadLocalRandom.current().nextInt(5, 11) + radiusBonus + colonyBonus);
    }

    private void addFlashCoarseDirtGrowthCandidates(Block cell, Location origin, int radius,
                                                   Set<String> existingKeys, Set<String> candidateKeys,
                                                   List<FlashCoarseDirtCandidate> candidates) {
        if (cell == null || origin == null || cell.getWorld() == null) {
            return;
        }
        ThreadLocalRandom random = ThreadLocalRandom.current();
        for (int[] offset : FLASH_COARSE_DIRT_GROWTH_OFFSETS) {
            if (Math.abs(offset[0]) + Math.abs(offset[1]) == 2 && random.nextDouble() < 0.42D) {
                continue;
            }
            Block candidate = pickFlashCoarseDirtGrowthBlock(
                    cell.getWorld().getBlockAt(cell.getX() + offset[0], cell.getY(), cell.getZ() + offset[1]));
            if (candidate == null) {
                continue;
            }
            int weight = getFlashCoarseDirtReplaceWeight(candidate);
            if (weight <= 0) {
                continue;
            }
            String key = blockKey(candidate.getLocation());
            if (existingKeys.contains(key) || candidateKeys.contains(key)
                    || !isInsideFlashCoarseDirtRadius(candidate, origin, radius)
                    || !canFlashCoarseDirtReplace(candidate)) {
                continue;
            }
            candidateKeys.add(key);
            candidates.add(new FlashCoarseDirtCandidate(candidate, weight));
        }
    }

    private Block removeWeightedFlashCoarseDirtCandidate(List<FlashCoarseDirtCandidate> candidates, ThreadLocalRandom random) {
        int totalWeight = 0;
        for (FlashCoarseDirtCandidate candidate : candidates) {
            if (candidate != null) {
                totalWeight += Math.max(1, candidate.weight());
            }
        }
        if (totalWeight <= 0) {
            return candidates.remove(random.nextInt(candidates.size())).block();
        }
        int roll = random.nextInt(totalWeight);
        for (int i = 0; i < candidates.size(); i++) {
            FlashCoarseDirtCandidate candidate = candidates.get(i);
            roll -= Math.max(1, candidate.weight());
            if (roll < 0) {
                candidates.remove(i);
                return candidate.block();
            }
        }
        return candidates.remove(candidates.size() - 1).block();
    }

    private Block pickFlashCoarseDirtGrowthBlock(Block candidate) {
        if (candidate == null) {
            return null;
        }
        Block upper = candidate.getRelative(BlockFace.UP);
        if (canFlashCoarseDirtReplace(upper)) {
            return upper;
        }
        if (canFlashCoarseDirtReplace(candidate)) {
            return candidate;
        }
        return null;
    }

    private boolean isInsideFlashCoarseDirtRadius(Block block, Location origin, int radius) {
        if (block == null || origin == null || block.getWorld() == null || origin.getWorld() == null
                || !block.getWorld().equals(origin.getWorld())) {
            return false;
        }
        int dx = block.getX() - origin.getBlockX();
        int dz = block.getZ() - origin.getBlockZ();
        return dx * dx + dz * dz <= radius * radius;
    }

    private boolean isOriginalFlashCoarseDirtBlock(Block block, FlashCoarseDirtPatch patch) {
        return block != null && patch != null && patch.origin() != null
                && blockKey(block.getLocation()).equals(blockKey(patch.origin()));
    }

    private boolean isSameFlashCoarseDirtOrigin(FlashCoarseDirtPatch patch, String originKey) {
        return patch != null && patch.origin() != null && originKey != null
                && blockKey(patch.origin()).equals(originKey);
    }

    private Block blockFromKey(World world, String key) {
        if (world == null || key == null) {
            return null;
        }
        String[] parts = key.split(":");
        if (parts.length < 4) {
            return null;
        }
        try {
            int x = Integer.parseInt(parts[parts.length - 3]);
            int y = Integer.parseInt(parts[parts.length - 2]);
            int z = Integer.parseInt(parts[parts.length - 1]);
            return world.getBlockAt(x, y, z);
        } catch (NumberFormatException ignored) {
            return null;
        }
    }

