        return switch (type) {
            case WHEAT, CARROTS, POTATOES, BEETROOTS,
                 MELON_STEM, PUMPKIN_STEM,
                 TORCHFLOWER_CROP, PITCHER_CROP -> true;
            default -> false;
        };
