    private boolean isFlashPlayerPlacedBlock(Block block) {
        if (block == null || block.getWorld() == null) {
            return false;
        }
        return flashPlayerPlacedBlocks.containsKey(blockKey(block.getLocation()));
    }

    private boolean canFlashCoarseDirtReplace(Block block) {
        if (block == null || block.getWorld() == null || block.isEmpty() || block.isLiquid()) {
            return false;
        }
        if (isFlashPlayerPlacedBlock(block)) {
            return false;
        }
        Material type = block.getType();
        if (type == Material.COARSE_DIRT) {
            return false;
        }
        if (!type.isBlock() || !type.isSolid()) {
            return false;
        }
        if (!isFlashCoarseDirtSurface(block)) {
            return false;
        }
        if (type.getHardness() < 0.0F
                || type.getHardness() > FLASH_COARSE_DIRT_MAX_HARDNESS
                || type.getBlastResistance() > FLASH_COARSE_DIRT_MAX_RESISTANCE) {
            return false;
        }
        String name = type.name();
        if (name.contains("BEDROCK") || name.contains("BARRIER") || name.contains("COMMAND_BLOCK")
                || name.contains("PORTAL") || name.contains("SPAWNER") || name.contains("VAULT")
                || name.contains("CHEST") || name.contains("SHULKER_BOX") || name.contains("FURNACE")
                || name.contains("BARREL") || name.contains("BEACON") || name.contains("ANVIL")) {
            return false;
        }
        BlockData data = block.getBlockData();
        return data != null && data.isOccluding();
    }

    private boolean isFlashCoarseDirtSurface(Block block) {
        Block above = block == null ? null : block.getRelative(BlockFace.UP);
        if (above == null || above.isLiquid()) {
            return false;
        }
        Material aboveType = above.getType();
        return aboveType.isAir() || (!aboveType.isSolid() && above.isPassable());
    }

    private int getFlashCoarseDirtReplaceWeight(Block block) {
        if (block == null) {
            return 0;
        }
        Material type = block.getType();
        if (type == Material.FARMLAND || isEarthLikeBlock(type)) {
            return 7;
        }
        float hardness = type.getHardness();
        if (hardness < 0.0F || hardness > FLASH_COARSE_DIRT_MAX_HARDNESS) {
            return 0;
        }
        if (hardness <= FLASH_COARSE_DIRT_SOFT_HARDNESS) {
            return 6;
        }
        if (hardness <= FLASH_COARSE_DIRT_MEDIUM_HARDNESS) {
            return 3;
        }
        return 1;
    }

