    public void handleFlashGlobalMobSpawn(EntitySpawnEvent event) {
        if (event == null || !(event.getEntity() instanceof LivingEntity living) || !isFlashWorldActive(living.getWorld())) {
            return;
        }
        if (!shouldEquipFlashGlobalMob(living)) {
            return;
        }
        if (living.getPersistentDataContainer().get(flashGlobalMobGearKey, PersistentDataType.BYTE) != null) {
            return;
        }
        EntityEquipment equipment = living.getEquipment();
        if (equipment == null) {
            return;
        }
        living.getPersistentDataContainer().set(flashGlobalMobGearKey, PersistentDataType.BYTE, (byte) 1);
        living.setCanPickupItems(false);
        ThreadLocalRandom random = ThreadLocalRandom.current();
        if (living instanceof AbstractSkeleton) {
            equipFlashGlobalSkeleton(equipment, random);
        } else if (living instanceof Zombie && random.nextDouble() < 0.05D) {
            living.getPersistentDataContainer().set(flashGlobalMobMinerKey, PersistentDataType.BYTE, (byte) 1);
            equipment.setItemInMainHand(markFlashGlobalMobGear(createRandomFlashGlobalMobMiningTool(random)), true);
            equipment.setItemInMainHandDropChance(0.0F);
        } else {
            equipment.setItemInMainHand(markFlashGlobalMobGear(createRandomFlashGlobalMobWeapon(random)), true);
            equipment.setItemInMainHandDropChance(0.0F);
        }
        equipFlashGlobalMobArmor(equipment, random);
        equipment.setItemInOffHandDropChance(0.0F);
        equipment.setHelmetDropChance(0.0F);
        equipment.setChestplateDropChance(0.0F);
        equipment.setLeggingsDropChance(0.0F);
        equipment.setBootsDropChance(0.0F);
    }

