    public boolean handleUnstableMaceParticleToggle(InventoryClickEvent event, Player player, GameRoom room) {
        if (event == null || player == null || !event.getClick().isRightClick()) {
            return false;
        }
        if (event.getClickedInventory() == null) {
            return false;
        }

        ItemStack cursor = event.getCursor();
        ItemStack current = event.getCurrentItem();
        if (isUnstableMaceParticleCatalyst(cursor) && isUnstableMace(current)) {
            event.setCancelled(true);
            boolean enabled = cursor.getType() == Material.GLOW_INK_SAC;
            ItemStack updated = setUnstableMaceParticles(current, enabled);
            event.setCurrentItem(updated);
            consumeCursorItem(event, cursor);
            playUnstableMaceParticleToggleFeedback(player, enabled);
            return true;
        }
        if (isUnstableMaceParticleCatalyst(current) && isUnstableMace(cursor)) {
            event.setCancelled(true);
            boolean enabled = current.getType() == Material.GLOW_INK_SAC;
            ItemStack updated = setUnstableMaceParticles(cursor, enabled);
            event.setCursor(updated);
            consumeCurrentItem(event, current);
            playUnstableMaceParticleToggleFeedback(player, enabled);
            return true;
        }
        return false;
    }

    private boolean isUnstableMaceParticleCatalyst(ItemStack item) {
        return !isEmpty(item) && (item.getType() == Material.INK_SAC || item.getType() == Material.GLOW_INK_SAC);
    }

    private boolean isUnstableMace(ItemStack item) {
        return item != null && item.getType() == Material.MACE && getUnstableMaceLevel(item) > 0;
    }

    private ItemStack setUnstableMaceParticles(ItemStack mace, boolean enabled) {
        if (!isUnstableMace(mace)) {
            return mace;
        }
        ItemStack result = mace.clone();
        ItemMeta meta = result.getItemMeta();
        if (meta == null) {
            return result;
        }
        if (enabled) {
            meta.getPersistentDataContainer().set(unstableMaceParticlesKey, PersistentDataType.BYTE, (byte) 1);
        } else {
            meta.getPersistentDataContainer().remove(unstableMaceParticlesKey);
        }
        result.setItemMeta(meta);
        return result;
    }

    private boolean isUnstableMaceParticlesEnabled(ItemStack mace) {
        return !isEmpty(mace) && hasPersistentByte(mace, unstableMaceParticlesKey);
    }

    private void playUnstableMaceParticleToggleFeedback(Player player, boolean enabled) {
        if (player == null) {
            return;
        }
        if (enabled) {
            player.sendActionBar("§x§B§B§8§8§F§F✦ §d不稳定重锤粒子 §a已开启");
            player.playSound(player.getLocation(), Sound.BLOCK_AMETHYST_BLOCK_CHIME, 0.72f, 1.72f);
            player.playSound(player.getLocation(), Sound.ENTITY_EXPERIENCE_ORB_PICKUP, 0.42f, 1.82f);
        } else {
            player.sendActionBar("§x§F§F§A§A§6§6✦ §7不稳定重锤粒子 §c已关闭");
            player.playSound(player.getLocation(), Sound.BLOCK_CANDLE_EXTINGUISH, 0.75f, 0.86f);
            player.playSound(player.getLocation(), Sound.BLOCK_AMETHYST_CLUSTER_BREAK, 0.38f, 0.92f);
        }
    }

    public void handleFlashLingeringCloudSpawn(EntitySpawnEvent event) {
        if (event == null || !(event.getEntity() instanceof AreaEffectCloud cloud) || !isFlashWorldActive(cloud.getWorld())) {
            return;
        }
        boolean windCharged = isWindChargedAreaCloud(cloud);
        int startDuration = Math.max(20, cloud.getDuration());
        float startRadius = Math.max(0.1F, cloud.getRadius());
        float maxRadius = Math.min(48.0F, startRadius + startDuration / 20.0F * 0.5F);
        cloud.setRadiusPerTick(0.0F);

        new BukkitRunnable() {
            @Override
            public void run() {
                if (!cloud.isValid() || cloud.isDead() || cloud.getDuration() <= 0 || cloud.getWorld() == null) {
                    cancel();
                    return;
                }
                cloud.setRadius(Math.min(maxRadius, cloud.getRadius() + 0.5F));
                if (windCharged && ThreadLocalRandom.current().nextDouble() < 0.25D) {
                    burstWindChargedLingeringCloud(randomPointInAreaCloud(cloud), cloud);
                }
            }
        }.runTaskTimer(plugin, 20L, 20L);
    }

    private boolean isWindChargedAreaCloud(AreaEffectCloud cloud) {
        if (cloud == null) {
            return false;
        }
        if (cloud.hasCustomEffect(PotionEffectType.WIND_CHARGED)) {
            return true;
        }
        PotionType baseType = cloud.getBasePotionType();
        if (baseType == PotionType.WIND_CHARGED) {
            return true;
        }
        return baseType != null && baseType.getPotionEffects().stream()
                .anyMatch(effect -> effect.getType() == PotionEffectType.WIND_CHARGED);
    }

    private Location randomPointInAreaCloud(AreaEffectCloud cloud) {
        Location center = cloud.getLocation();
        ThreadLocalRandom random = ThreadLocalRandom.current();
        double radius = Math.max(0.35D, cloud.getRadius());
        double distance = Math.sqrt(random.nextDouble()) * radius;
        double angle = random.nextDouble(Math.PI * 2.0D);
        return center.clone().add(Math.cos(angle) * distance, 0.16D + random.nextDouble(0.24D), Math.sin(angle) * distance);
    }

    private void burstWindChargedLingeringCloud(Location location, AreaEffectCloud cloud) {
        if (location == null || location.getWorld() == null) {
            return;
        }
        World world = location.getWorld();
        Location burst = location.clone();
        world.spawnParticle(Particle.GUST_EMITTER_SMALL, burst, 1, 0.0D, 0.0D, 0.0D, 0.0D);
        world.spawnParticle(Particle.GUST, burst, 10, 0.28D, 0.18D, 0.28D, 0.02D);
        world.spawnParticle(Particle.SMALL_GUST, burst, 18, 0.46D, 0.24D, 0.46D, 0.035D);
        world.playSound(burst, Sound.ENTITY_WIND_CHARGE_THROW, 0.48f, 1.18f);
        applyManualWindCloudBurst(burst);
    }

    private void applyManualWindCloudBurst(Location burst) {
        if (burst == null || burst.getWorld() == null) {
            return;
        }
        World world = burst.getWorld();
        world.spawnParticle(Particle.GUST_EMITTER_SMALL, burst, 1, 0.0D, 0.0D, 0.0D, 0.0D);
        world.spawnParticle(Particle.SMALL_GUST, burst, 26, 0.55D, 0.28D, 0.55D, 0.045D);
        world.playSound(burst, Sound.ENTITY_WIND_CHARGE_WIND_BURST, 0.92f, 1.0f);
        double radius = 3.25D;
        for (Entity entity : world.getNearbyEntities(burst, radius, radius, radius)) {
            if (!(entity instanceof LivingEntity living) || living.isDead()) {
                continue;
            }
            Vector push = living.getLocation().toVector().subtract(burst.toVector());
            if (push.lengthSquared() < 0.05D) {
                double angle = ThreadLocalRandom.current().nextDouble(Math.PI * 2.0D);
                push = new Vector(Math.cos(angle), 0.0D, Math.sin(angle));
            }
            push.normalize().multiply(0.65D).setY(0.35D);
            living.setVelocity(living.getVelocity().add(push));
            living.setFallDistance(0.0F);
        }
    }

    private boolean shouldEquipFlashGlobalMob(LivingEntity living) {
        if (living == null || living instanceof Player || living instanceof EnderDragon || living instanceof HappyGhast
                || living instanceof org.bukkit.entity.ArmorStand || living instanceof org.bukkit.entity.Villager
                || living instanceof org.bukkit.entity.WanderingTrader || living instanceof org.bukkit.entity.IronGolem
                || living instanceof org.bukkit.entity.Snowman) {
            return false;
        }
        if (isFlashTamed(living) || (living instanceof Tameable tameable && tameable.isTamed())) {
            return false;
        }
        return living instanceof org.bukkit.entity.Monster || living instanceof org.bukkit.entity.Raider;
    }

    private void equipFlashGlobalSkeleton(EntityEquipment equipment, ThreadLocalRandom random) {
        if (equipment == null) {
            return;
        }
        ItemStack main = random.nextBoolean()
                ? new ItemStack(Material.BOW)
                : new ItemStack(Material.CROSSBOW);
        equipment.setItemInMainHand(markFlashGlobalMobGear(main), true);
        equipment.setItemInOffHand(null, true);
        equipment.setItemInMainHandDropChance(0.0F);
        equipment.setItemInOffHandDropChance(0.0F);
    }

    private void equipFlashGlobalMobArmor(EntityEquipment equipment, ThreadLocalRandom random) {
        if (equipment == null) {
            return;
        }
        Material[] helmets = {Material.LEATHER_HELMET, Material.CHAINMAIL_HELMET, Material.IRON_HELMET};
        Material[] chests = {Material.LEATHER_CHESTPLATE, Material.CHAINMAIL_CHESTPLATE, Material.IRON_CHESTPLATE};
        Material[] legs = {Material.LEATHER_LEGGINGS, Material.CHAINMAIL_LEGGINGS, Material.IRON_LEGGINGS};
        Material[] boots = {Material.LEATHER_BOOTS, Material.CHAINMAIL_BOOTS, Material.IRON_BOOTS};
        if (random.nextDouble() < 0.85D) {
            equipment.setHelmet(markFlashGlobalMobGear(new ItemStack(helmets[random.nextInt(helmets.length)])), true);
        }
        if (random.nextDouble() < 0.8D) {
            equipment.setChestplate(markFlashGlobalMobGear(new ItemStack(chests[random.nextInt(chests.length)])), true);
        }
        if (random.nextDouble() < 0.8D) {
            equipment.setLeggings(markFlashGlobalMobGear(new ItemStack(legs[random.nextInt(legs.length)])), true);
        }
        if (random.nextDouble() < 0.85D) {
            equipment.setBoots(markFlashGlobalMobGear(new ItemStack(boots[random.nextInt(boots.length)])), true);
        }
    }

    private ItemStack createRandomFlashGlobalMobMiningTool(ThreadLocalRandom random) {
        Material[] pool = {Material.WOODEN_PICKAXE, Material.STONE_PICKAXE, Material.IRON_PICKAXE, Material.WOODEN_SHOVEL, Material.STONE_SHOVEL, Material.IRON_SHOVEL};
        return new ItemStack(pool[random.nextInt(pool.length)]);
    }

    private ItemStack createRandomFlashGlobalMobWeapon(ThreadLocalRandom random) {
        Material[] pool = {Material.WOODEN_SWORD, Material.STONE_SWORD, Material.IRON_SWORD, Material.WOODEN_AXE, Material.STONE_AXE, Material.IRON_AXE};
        return new ItemStack(pool[random.nextInt(pool.length)]);
    }

    private ItemStack markFlashGlobalMobGear(ItemStack item) {
        if (isEmpty(item)) {
            return item;
        }
        ItemStack result = item.clone();
        ItemMeta meta = result.getItemMeta();
        if (meta != null) {
            meta.getPersistentDataContainer().set(flashGlobalMobGearKey, PersistentDataType.BYTE, (byte) 1);
            meta.setLore(null);
            result.setItemMeta(meta);
        }
        return result;
    }

    private boolean isFlashGlobalMobGear(ItemStack item) {
        return hasPersistentByte(item, flashGlobalMobGearKey);
    }

    public boolean handleTmtBlockPlace(BlockPlaceEvent event, Player player, GameRoom room) {
        if (event == null || player == null || event.getBlockPlaced().getType() != Material.TNT || !isTmt(event.getItemInHand())) {
            return false;
        }
        if (!isFlashCombatAvailable(player, room)) {
            return false;
        }
        event.setCancelled(false);
        event.setBuild(true);
        Block placed = event.getBlockPlaced();
        String placedKey = blockKey(placed.getLocation());
        if (placedTmtBlocks.contains(placedKey)) {
            return true;
        }
        if (hasActivePrimedTmtNear(placed.getLocation(), TMT_REPEL_RADIUS)) {
            Location drop = placed.getLocation().add(0.5D, 0.45D, 0.5D);
            placed.setType(Material.AIR, false);
            placed.getWorld().dropItemNaturally(drop, createTmt());
            placed.getWorld().spawnParticle(Particle.SMOKE, drop, 22, 0.28D, 0.18D, 0.28D, 0.03D);
            placed.getWorld().spawnParticle(Particle.FLAME, drop, 8, 0.20D, 0.12D, 0.20D, 0.018D);
            placed.getWorld().playSound(drop, Sound.BLOCK_FIRE_EXTINGUISH, 0.62f, 0.62f);
            placed.getWorld().playSound(drop, Sound.ENTITY_ITEM_PICKUP, 0.38f, 0.78f);
            player.sendActionBar("§x§F§F§5§5§3§3✦ §cTMT §7附近已有点燃TMT §8| §f新TMT已变成掉落物");
            return true;
        }
        rememberFlashPlayerPlacedBlock(placed, player, room);
        int droppedNearby = dropNearbyPlacedTmtBlocks(placed.getLocation());
        placedTmtBlocks.add(placedKey);
        player.sendActionBar("§x§F§F§5§5§3§3✦ §cTMT §f已放置，§7120秒后爆炸范围约 §f40格§7，威力 §c1000%"
                + (droppedNearby > 0 ? " §8| §7排斥掉落 §f" + droppedNearby + "§7 个旧TMT" : ""));
        return true;
    }

    private boolean hasActivePrimedTmtNear(Location center, double radius) {
        if (center == null || center.getWorld() == null) {
            return false;
        }
        double radiusSquared = radius * radius;
        for (Entity entity : center.getWorld().getNearbyEntities(center, radius, radius, radius)) {
            if (entity instanceof TNTPrimed tnt && hasTmtPrimed(tnt)
                    && tnt.isValid() && !tnt.isDead()
                    && tnt.getLocation().distanceSquared(center) <= radiusSquared) {
                return true;
            }
        }
        return false;
    }

    private int dropNearbyPlacedTmtBlocks(Location center) {
        if (center == null || center.getWorld() == null || placedTmtBlocks.isEmpty()) {
            return 0;
        }
        World world = center.getWorld();
        double radiusSquared = TMT_REPEL_RADIUS * TMT_REPEL_RADIUS;
        List<String> toDrop = new ArrayList<>();
        for (String key : placedTmtBlocks) {
            Location location = parseLocationKey(key);
            if (location == null || location.getWorld() == null || !location.getWorld().equals(world)) {
                continue;
            }
            if (location.distanceSquared(center) <= radiusSquared) {
                toDrop.add(key);
            }
        }
        int dropped = 0;
        for (String key : toDrop) {
            Location location = parseLocationKey(key);
            if (location == null || location.getWorld() == null) {
                placedTmtBlocks.remove(key);
                flashPlayerPlacedBlocks.remove(key);
                continue;
            }
            Block block = location.getBlock();
            placedTmtBlocks.remove(key);
            flashPlayerPlacedBlocks.remove(key);
            if (block.getType() == Material.TNT) {
                block.setType(Material.AIR, false);
                Location drop = location.add(0.5D, 0.45D, 0.5D);
                world.dropItemNaturally(drop, createTmt());
                world.spawnParticle(Particle.SMOKE, drop, 12, 0.22D, 0.14D, 0.22D, 0.025D);
                world.spawnParticle(Particle.FLAME, drop, 4, 0.16D, 0.10D, 0.16D, 0.01D);
                world.playSound(drop, Sound.BLOCK_FIRE_EXTINGUISH, 0.42f, 0.74f);
                dropped++;
            }
        }
        return dropped;
    }

    public boolean handleTmtBlockBreak(BlockBreakEvent event, Player player, GameRoom room) {
        if (event == null || event.isCancelled() || player == null || event.getBlock().getType() != Material.TNT) {
            return false;
        }
        String key = blockKey(event.getBlock().getLocation());
        if (!placedTmtBlocks.contains(key)) {
            return false;
        }
        if (!isFlashCombatAvailable(player, room)) {
            return false;
        }
        placedTmtBlocks.remove(key);
        flashPlayerPlacedBlocks.remove(key);
        event.setDropItems(false);
        event.setExpToDrop(0);
        if (player.getGameMode() != org.bukkit.GameMode.CREATIVE) {
            event.getBlock().getWorld().dropItemNaturally(event.getBlock().getLocation().add(0.5D, 0.45D, 0.5D), createTmt());
        }
        event.getBlock().getWorld().playSound(event.getBlock().getLocation(), Sound.BLOCK_GRAVEL_BREAK, 0.48f, 0.78f);
        return true;
    }

    public void handleTmtPrimedSpawn(EntitySpawnEvent event) {
        if (!(event.getEntity() instanceof TNTPrimed tnt)) {
            return;
        }
        String key = findPlacedTmtKeyNear(tnt.getLocation());
        if (key == null) {
            return;
        }
        placedTmtBlocks.remove(key);
        flashPlayerPlacedBlocks.remove(key);
        byte tmtState = isTmtChainSpawn(tnt) ? TMT_PRIMED_CHAIN_SUPPRESSED : TMT_PRIMED_NORMAL;
        tnt.getPersistentDataContainer().set(tmtPrimedKey, PersistentDataType.BYTE, tmtState);
        tnt.setBlockData(Material.TNT.createBlockData());
        World world = tnt.getWorld();
        if (tmtState == TMT_PRIMED_CHAIN_SUPPRESSED) {
            tnt.setFuseTicks(Math.min(tnt.getFuseTicks(), 2));
            world.spawnParticle(Particle.SMOKE, tnt.getLocation(), 12, 0.26D, 0.16D, 0.26D, 0.02D);
            world.playSound(tnt.getLocation(), Sound.BLOCK_FIRE_EXTINGUISH, 0.55f, 0.68f);
        } else {
            tnt.setFuseTicks(TMT_FUSE_TICKS);
            startTmtImplosionParticles(tnt);
            world.spawnParticle(Particle.FLAME, tnt.getLocation(), 18, 0.28D, 0.18D, 0.28D, 0.025D);
            world.playSound(tnt.getLocation(), Sound.ENTITY_TNT_PRIMED, 0.95f, 0.72f);
        }
    }

    private void startTmtImplosionParticles(TNTPrimed tnt) {
        if (tnt == null || !tnt.isValid()) {
            return;
        }
        UUID entityId = tnt.getUniqueId();
        new BukkitRunnable() {
            private int ticks;

            @Override
            public void run() {
                Entity entity = Bukkit.getEntity(entityId);
                if (!(entity instanceof TNTPrimed current) || !current.isValid() || current.isDead()) {
                    cancel();
                    return;
                }
                ticks += 5;
                Location center = current.getLocation().add(0.0D, 0.45D, 0.0D);
                World world = center.getWorld();
                if (world == null) {
                    cancel();
                    return;
                }
                double progress = Math.max(0.0D, Math.min(1.0D, ticks / (double) TMT_FUSE_TICKS));
                double pulse = 0.5D + 0.5D * Math.sin(ticks * 0.08D);
                double radius = Math.max(1.15D, TMT_EXPLOSION_POWER * (1.0D - progress) + 1.15D + pulse * 1.25D);
                int points = 24 + (int) Math.round(progress * 44.0D);
                for (int i = 0; i < points; i++) {
                    double angle = (ticks * 0.19D) + i * (Math.PI * 2.0D / points);
                    double yWave = Math.sin(angle * 1.7D + ticks * 0.05D) * (0.75D + radius * 0.035D);
                    Location outer = center.clone().add(Math.cos(angle) * radius, yWave, Math.sin(angle) * radius);
                    Vector inward = center.toVector().subtract(outer.toVector());
                    if (inward.lengthSquared() > 0.0001D) {
                        inward.normalize().multiply(0.34D + progress * 0.38D);
                    }
                    world.spawnParticle(Particle.END_ROD, outer, 0, inward.getX(), inward.getY(), inward.getZ(), 1.0D);
                    if (i % 2 == 0) {
                        world.spawnParticle(Particle.FLAME, outer, 0, inward.getX() * 0.8D, inward.getY() * 0.8D, inward.getZ() * 0.8D, 1.0D);
                    }
                    if (i % 5 == 0) {
                        world.spawnParticle(Particle.PORTAL, outer, 0, inward.getX() * 0.45D, inward.getY() * 0.45D, inward.getZ() * 0.45D, 1.0D);
                    }
                }
                world.spawnParticle(Particle.SMOKE, center, 8, Math.max(0.10D, radius * 0.04D), 0.06D,
                        Math.max(0.08D, radius * 0.05D), 0.01D);
                if (ticks % 40 == 0) {
                    world.playSound(center, Sound.BLOCK_RESPAWN_ANCHOR_CHARGE, 0.28f, (float) (0.72D + progress * 0.85D));
                }
                if (ticks >= TMT_FUSE_TICKS) {
                    cancel();
                }
            }
        }.runTaskTimer(plugin, 1L, 5L);
    }

    private String findPlacedTmtKeyNear(Location location) {
        if (location == null || location.getWorld() == null || placedTmtBlocks.isEmpty()) {
            return null;
        }
        String direct = blockKey(location);
        if (placedTmtBlocks.contains(direct)) {
            return direct;
        }
        World world = location.getWorld();
        int bx = location.getBlockX();
        int by = location.getBlockY();
        int bz = location.getBlockZ();
        for (int dx = -1; dx <= 1; dx++) {
            for (int dy = -1; dy <= 1; dy++) {
                for (int dz = -1; dz <= 1; dz++) {
                    String key = blockKey(new Location(world, bx + dx, by + dy, bz + dz));
                    if (placedTmtBlocks.contains(key)) {
                        return key;
                    }
                }
            }
        }
        return null;
    }

    public void handleTmtExplosionPrime(ExplosionPrimeEvent event) {
        if (event == null || !(event.getEntity() instanceof TNTPrimed tnt)) {
            return;
        }
        byte tmtState = getTmtPrimedState(tnt);
        if (tmtState == 0) {
            return;
        }
        if (tmtState == TMT_PRIMED_CHAIN_SUPPRESSED) {
            event.setCancelled(true);
            Location location = tnt.getLocation();
            World world = tnt.getWorld();
            world.spawnParticle(Particle.SMOKE, location, 18, 0.30D, 0.18D, 0.30D, 0.03D);
            world.playSound(location, Sound.BLOCK_FIRE_EXTINGUISH, 0.62f, 0.74f);
            tnt.remove();
            return;
        }
        rememberRecentTmtExplosion(tnt.getLocation());
        event.setRadius(TMT_EXPLOSION_POWER);
        event.setFire(false);
    }

    public void handleTmtEntityExplode(EntityExplodeEvent event) {
        if (event == null) {
            return;
        }
        if (event.getEntity() instanceof TNTPrimed tnt && hasTmtPrimed(tnt)) {
            clearNearbyFlashTrapsByExplosion(event.getLocation(), TMT_EXPLOSION_POWER);
        }
        suppressChainedTmtBlocks(event.blockList());
    }

    public void handleTmtBlockExplode(BlockExplodeEvent event) {
        if (event == null) {
            return;
        }
        suppressChainedTmtBlocks(event.blockList());
    }

    private void suppressChainedTmtBlocks(List<Block> blockList) {
        if (blockList == null || blockList.isEmpty() || placedTmtBlocks.isEmpty()) {
            return;
        }
        List<Location> suppressed = new ArrayList<>();
        blockList.removeIf(block -> {
            String key = blockKey(block.getLocation());
            if (placedTmtBlocks.remove(key) && block.getType() == Material.TNT) {
                flashPlayerPlacedBlocks.remove(key);
                suppressed.add(block.getLocation().add(0.5D, 0.5D, 0.5D));
                block.setType(Material.AIR, false);
                return true;
            }
            return false;
        });
        for (Location location : suppressed) {
            World world = location.getWorld();
            if (world == null) {
                continue;
            }
            world.spawnParticle(Particle.SMOKE, location, 14, 0.24D, 0.16D, 0.24D, 0.025D);
            world.spawnParticle(Particle.FLAME, location, 6, 0.18D, 0.12D, 0.18D, 0.01D);
            world.playSound(location, Sound.BLOCK_FIRE_EXTINGUISH, 0.45f, 0.74f);
        }
    }

    private boolean isTmtChainSpawn(TNTPrimed tnt) {
        if (tnt == null) {
            return false;
        }
        Entity source = tnt.getSource();
        if (source instanceof TNTPrimed sourceTnt && hasTmtPrimed(sourceTnt)) {
            return true;
        }
        pruneRecentTmtExplosions();
        Location location = tnt.getLocation();
        for (RecentTmtExplosion recent : recentTmtExplosions) {
            if (recent != null && recent.location() != null && recent.location().getWorld() != null
                    && location.getWorld() != null
                    && recent.location().getWorld().equals(location.getWorld())
                    && recent.location().distanceSquared(location) <= TMT_EXPLOSION_POWER * TMT_EXPLOSION_POWER + 4.0D) {
                return true;
            }
        }
        return false;
    }

    private void rememberRecentTmtExplosion(Location location) {
        if (location == null || location.getWorld() == null) {
            return;
        }
        pruneRecentTmtExplosions();
        recentTmtExplosions.addLast(new RecentTmtExplosion(location.clone(),
                System.currentTimeMillis() + TMT_CHAIN_SUPPRESS_WINDOW_MILLIS));
        while (recentTmtExplosions.size() > 32) {
            recentTmtExplosions.removeFirst();
        }
    }

    private void pruneRecentTmtExplosions() {
        long now = System.currentTimeMillis();
        while (!recentTmtExplosions.isEmpty() && recentTmtExplosions.peekFirst().expiresAtMillis() < now) {
            recentTmtExplosions.removeFirst();
        }
    }

    private boolean hasTmtPrimed(TNTPrimed tnt) {
        return getTmtPrimedState(tnt) != 0;
    }

    private byte getTmtPrimedState(TNTPrimed tnt) {
        if (tnt == null) {
            return 0;
        }
        Byte flag = tnt.getPersistentDataContainer().get(tmtPrimedKey, PersistentDataType.BYTE);
        return flag == null ? 0 : flag;
    }

    public void handleFlashSoilBlockBreak(BlockBreakEvent event) {
        if (event == null || event.isCancelled()) {
            return;
        }
        String key = blockKey(event.getBlock().getLocation());
        flashCoarseDirtPatches.remove(key);
        flashPermanentWetFarmlands.remove(key);
        flashPlayerPlacedBlocks.remove(key);
        flashHoeTraps.remove(key);
        pseudoPoisonPotatoCrops.remove(key);
    }

    private void startJukeboxAuraTask() {
        if (jukeboxAuraTaskStarted) {
            return;
        }
        jukeboxAuraTaskStarted = true;
        new BukkitRunnable() {
            @Override
            public void run() {
                tickJukeboxAuras();
            }
        }.runTaskTimer(plugin, 40L, 20L);
    }

    private void startTurtleShellSpeedTask() {
        if (turtleShellSpeedTaskStarted) {
            return;
        }
        turtleShellSpeedTaskStarted = true;
        new BukkitRunnable() {
            @Override
            public void run() {
                for (Player player : Bukkit.getOnlinePlayers()) {
                    tickTurtleShellSpeed(player);
                    tickCondensedSlimeCrawlSpeed(player);
                }
            }
        }.runTaskTimer(plugin, 20L, 10L);
    }

    private void tickTurtleShellSpeed(Player player) {
        if (player == null || !player.isOnline()) {
            return;
        }
        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        ItemStack helmet = player.getInventory().getHelmet();
        if (!isFlashCombatAvailable(player, room) || helmet == null || helmet.getType() != Material.TURTLE_HELMET) {
            removeTurtleShellSpeedModifier(player);
            return;
        }
        double bonus = player.isInWaterOrBubbleColumn() || player.isSwimming() ? 0.50D : 0.25D;
        applyTurtleShellSpeedModifier(player, bonus);
    }

    private void applyTurtleShellSpeedModifier(Player player, double bonus) {
        AttributeInstance movementSpeed = player.getAttribute(Attribute.MOVEMENT_SPEED);
        if (movementSpeed == null) {
            return;
        }
        AttributeModifier existing = movementSpeed.getModifier(turtleShellSpeedModifierKey);
        if (existing != null && Math.abs(existing.getAmount() - bonus) < 1.0E-6D) {
            return;
        }
        movementSpeed.removeModifier(turtleShellSpeedModifierKey);
        movementSpeed.addTransientModifier(new AttributeModifier(
                turtleShellSpeedModifierKey,
                Math.max(0.0D, bonus),
                AttributeModifier.Operation.MULTIPLY_SCALAR_1
        ));
    }

    private void removeTurtleShellSpeedModifier(Player player) {
        if (player == null) {
            return;
        }
        AttributeInstance movementSpeed = player.getAttribute(Attribute.MOVEMENT_SPEED);
        if (movementSpeed != null) {
            movementSpeed.removeModifier(turtleShellSpeedModifierKey);
        }
    }

    private void tickCondensedSlimeCrawlSpeed(Player player) {
        if (player == null || !player.isOnline()) {
            return;
        }
        GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
        ItemStack boots = player.getInventory().getBoots();
        double bonus = getCondensedSlimeBootBonus(boots);
        if (!isFlashCombatAvailable(player, room) || bonus <= 0.0D || !isCrawlingOnLand(player)) {
            removeCondensedSlimeCrawlSpeedModifier(player);
            return;
        }
        applyCondensedSlimeCrawlSpeedModifier(player, bonus);
    }

    private boolean isCrawlingOnLand(Player player) {
        return player != null
                && (player.isSwimming() || player.getPose() == Pose.SWIMMING || player.getHeight() <= 0.72D)
                && !player.isInWaterOrBubbleColumn()
                && !player.isFlying()
                && !player.isGliding()
                && player.getVehicle() == null;
    }

    private void applyCondensedSlimeCrawlSpeedModifier(Player player, double bonus) {
        boolean appliedMovement = applyAttributeSpeedModifier(player, Attribute.MOVEMENT_SPEED, condensedSlimeCrawlSpeedModifierKey, bonus);
        boolean appliedSneaking = applyAttributeSpeedModifier(player, Attribute.SNEAKING_SPEED, condensedSlimeSneakSpeedModifierKey, bonus);
        if (!appliedMovement && !appliedSneaking) {
            return;
        }
    }

    private void removeCondensedSlimeCrawlSpeedModifier(Player player) {
        if (player == null) {
            return;
        }
        removeAttributeSpeedModifier(player, Attribute.MOVEMENT_SPEED, condensedSlimeCrawlSpeedModifierKey);
        removeAttributeSpeedModifier(player, Attribute.SNEAKING_SPEED, condensedSlimeSneakSpeedModifierKey);
    }

    private boolean applyAttributeSpeedModifier(Player player, Attribute attribute, NamespacedKey key, double bonus) {
        AttributeInstance instance = player.getAttribute(attribute);
        if (instance == null) {
            return false;
        }
        double amount = Math.max(0.0D, bonus);
        AttributeModifier existing = instance.getModifier(key);
        if (existing != null && Math.abs(existing.getAmount() - amount) < 1.0E-6D) {
            return true;
        }
        instance.removeModifier(key);
        instance.addTransientModifier(new AttributeModifier(
                key,
                amount,
                AttributeModifier.Operation.MULTIPLY_SCALAR_1
        ));
        return true;
    }

    private void removeAttributeSpeedModifier(Player player, Attribute attribute, NamespacedKey key) {
        AttributeInstance instance = player.getAttribute(attribute);
        if (instance != null) {
            instance.removeModifier(key);
        }
    }

    private void tickJukeboxAuras() {
        long now = System.currentTimeMillis();
        scanJukeboxesNearFlashPlayers();
        Iterator<Map.Entry<String, ActiveJukeboxAura>> iterator = activeJukeboxAuras.entrySet().iterator();
        while (iterator.hasNext()) {
            Map.Entry<String, ActiveJukeboxAura> entry = iterator.next();
            ActiveJukeboxAura aura = entry.getValue();
            if (aura.expiresAtMillis() < now || !isJukeboxStillPlaying(aura)) {
                iterator.remove();
                continue;
            }
            applyJukeboxAura(aura, now);
        }
        jukeboxBuffStates.entrySet().removeIf(entry -> entry.getValue().expiresAtMillis() < now);
    }

    private void scanJukeboxesNearFlashPlayers() {
        for (Player player : Bukkit.getOnlinePlayers()) {
            GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
            if (!isFlashCombatAvailable(player, room)) {
                continue;
            }
            World world = player.getWorld();
            int centerChunkX = player.getLocation().getBlockX() >> 4;
            int centerChunkZ = player.getLocation().getBlockZ() >> 4;
            int chunkRadius = (int) Math.ceil(JUKEBOX_AURA_RADIUS / 16.0D) + 1;
            double radiusSquared = JUKEBOX_AURA_RADIUS * JUKEBOX_AURA_RADIUS;
            for (int cx = centerChunkX - chunkRadius; cx <= centerChunkX + chunkRadius; cx++) {
                for (int cz = centerChunkZ - chunkRadius; cz <= centerChunkZ + chunkRadius; cz++) {
                    if (!world.isChunkLoaded(cx, cz)) {
                        continue;
                    }
                    for (org.bukkit.block.BlockState state : world.getChunkAt(cx, cz).getTileEntities()) {
                        if (state instanceof Jukebox jukebox && state.getLocation().distanceSquared(player.getLocation()) <= radiusSquared) {
                            rememberJukeboxAura(jukebox);
                        }
                    }
                }
            }
        }
    }

    private void scanAndRememberJukebox(Location location) {
        scanAndRememberJukebox(location, false);
    }

    private void scheduleJukeboxAuraScan(Location location, long delayTicks, boolean allowRecordOnly) {
        if (location == null) {
            return;
        }
        Location snapshot = location.clone();
        Bukkit.getScheduler().runTaskLater(plugin, () -> scanAndRememberJukebox(snapshot, allowRecordOnly), Math.max(0L, delayTicks));
    }

    private void scanAndRememberJukebox(Location location, boolean allowRecordOnly) {
        if (location == null || location.getWorld() == null) {
            return;
        }
        Block block = location.getBlock();
        if (block.getState() instanceof Jukebox jukebox) {
            rememberJukeboxAura(jukebox, allowRecordOnly);
        }
    }

    private void rememberJukeboxAura(Jukebox jukebox) {
        rememberJukeboxAura(jukebox, false);
    }

    private void rememberJukeboxAura(Jukebox jukebox, boolean allowRecordOnly) {
        if (jukebox == null || !jukebox.hasRecord()) {
            return;
        }
        if (!allowRecordOnly && !jukebox.isPlaying()) {
            return;
        }
        ItemStack record = jukebox.getRecord();
        JukeboxAuraEffect effect = getJukeboxAuraEffect(record == null ? Material.AIR : record.getType());
        if (effect == null) {
            return;
        }
        Location location = jukebox.getLocation();
        String key = locationKey(location);
        if (hasActiveJukeboxAuraNear(location, JUKEBOX_AURA_RADIUS, key)) {
            return;
        }
        long durationMs = Math.max(5000L, (long) (effect.seconds() * 1000L));
        activeJukeboxAuras.put(key, new ActiveJukeboxAura(location, record.getType(), effect, System.currentTimeMillis() + durationMs + 2000L));
    }

    private boolean hasActiveJukeboxAuraNear(Location location, double radius, String ignoredKey) {
        if (location == null || location.getWorld() == null) {
            return false;
        }
        double radiusSquared = radius * radius;
        long now = System.currentTimeMillis();
        for (Map.Entry<String, ActiveJukeboxAura> entry : activeJukeboxAuras.entrySet()) {
            if (entry.getKey().equals(ignoredKey)) {
                continue;
            }
            ActiveJukeboxAura aura = entry.getValue();
            Location other = aura.location();
            if (aura.expiresAtMillis() < now || other == null || other.getWorld() == null || !other.getWorld().equals(location.getWorld())) {
                continue;
            }
            if (other.distanceSquared(location) <= radiusSquared) {
                return true;
            }
        }
        return false;
    }

    private boolean hasNearbyJukebox(Location location, double radius, Location ignoredBlock) {
        if (location == null || location.getWorld() == null) {
            return false;
        }
        World world = location.getWorld();
        double radiusSquared = radius * radius;
        int chunkRadius = (int) Math.ceil(radius / 16.0D) + 1;
        int centerChunkX = location.getBlockX() >> 4;
        int centerChunkZ = location.getBlockZ() >> 4;
        for (int cx = centerChunkX - chunkRadius; cx <= centerChunkX + chunkRadius; cx++) {
            for (int cz = centerChunkZ - chunkRadius; cz <= centerChunkZ + chunkRadius; cz++) {
                if (!world.isChunkLoaded(cx, cz)) {
                    continue;
                }
                for (org.bukkit.block.BlockState state : world.getChunkAt(cx, cz).getTileEntities()) {
                    if (!(state instanceof Jukebox)) {
                        continue;
                    }
                    Location other = state.getLocation();
                    if (ignoredBlock != null
                            && other.getBlockX() == ignoredBlock.getBlockX()
                            && other.getBlockY() == ignoredBlock.getBlockY()
                            && other.getBlockZ() == ignoredBlock.getBlockZ()
                            && other.getWorld() != null
                            && other.getWorld().equals(ignoredBlock.getWorld())) {
                        continue;
                    }
                    if (other.distanceSquared(location) <= radiusSquared) {
                        return true;
                    }
                }
            }
        }
        return false;
    }

    private boolean isJukeboxStillPlaying(ActiveJukeboxAura aura) {
        Location location = aura.location();
        if (location == null || location.getWorld() == null || location.getBlock().getType() != Material.JUKEBOX) {
            return false;
        }
        if (!(location.getBlock().getState() instanceof Jukebox jukebox) || !jukebox.hasRecord()) {
            return false;
        }
        ItemStack record = jukebox.getRecord();
        return record != null && record.getType() == aura.record();
    }

    private void applyJukeboxAura(ActiveJukeboxAura aura, long now) {
        Location center = aura.location().clone().add(0.5D, 0.6D, 0.5D);
        JukeboxAuraEffect effect = aura.effect();
        for (Player player : center.getWorld().getPlayers()) {
            if (player.getLocation().distanceSquared(center) > JUKEBOX_AURA_RADIUS * JUKEBOX_AURA_RADIUS) {
                continue;
            }
            GameRoom room = plugin.getRoomManager().getPlayerRoom(player.getUniqueId());
            if (!isFlashCombatAvailable(player, room)) {
                continue;
            }
            for (PotionEffect potionEffect : effect.effects()) {
                player.addPotionEffect(potionEffect, true);
            }
            if (effect.hasStateBonus()) {
                JukeboxBuffState old = jukeboxBuffStates.get(player.getUniqueId());
                double meleeBonus = Math.max(effect.meleeBonus(), old == null ? 0.0D : old.meleeBonus());
                double reduction = Math.max(effect.damageReduction(), old == null ? 0.0D : old.damageReduction());
                double crossbowDamageBonus = Math.max(effect.crossbowDamageBonus(), old == null ? 0.0D : old.crossbowDamageBonus());
                double crossbowProjectileSpeedBonus = Math.max(effect.crossbowProjectileSpeedBonus(), old == null ? 0.0D : old.crossbowProjectileSpeedBonus());
                double swordFlightSpeedBonus = Math.max(effect.swordFlightSpeedBonus(), old == null ? 0.0D : old.swordFlightSpeedBonus());
                double swordDamageBonus = Math.max(effect.swordDamageBonus(), old == null ? 0.0D : old.swordDamageBonus());
                jukeboxBuffStates.put(player.getUniqueId(), new JukeboxBuffState(meleeBonus, reduction, crossbowDamageBonus,
                        crossbowProjectileSpeedBonus, swordFlightSpeedBonus, swordDamageBonus, now + JUKEBOX_AURA_REFRESH_TICKS * 50L));
            }
            if (effect.armorRepairPerThreeSeconds() > 0) {
                Long lastRepair = jukeboxArmorRepairTimes.get(player.getUniqueId());
                if (lastRepair == null || now - lastRepair >= 3000L) {
                    if (repairArmorByJukeboxAura(player, effect.armorRepairPerThreeSeconds())) {
                        jukeboxArmorRepairTimes.put(player.getUniqueId(), now);
                    }
                }
            }
        }
        if (center.getWorld() != null) {
            center.getWorld().spawnParticle(Particle.NOTE, center, 4, 0.55D, 0.28D, 0.55D, 0.01D);
        }
    }

    private void applyJukeboxAuraCombat(EntityDamageByEntityEvent event, Player attacker, LivingEntity victim) {
        if (attacker != null && event.getDamager() instanceof Player) {
            JukeboxBuffState state = getActiveJukeboxBuff(attacker);
            if (state != null && state.meleeBonus() > 0.0D && state.expiresAtMillis() >= System.currentTimeMillis()) {
                event.setDamage(event.getDamage() * (1.0D + state.meleeBonus()));
            }
        }
        if (victim instanceof Player player) {
            JukeboxBuffState state = getActiveJukeboxBuff(player);
            if (state != null && state.damageReduction() > 0.0D && state.expiresAtMillis() >= System.currentTimeMillis()) {
                event.setDamage(event.getDamage() * (1.0D - Math.min(0.85D, state.damageReduction())));
            }
        }
    }

    private JukeboxBuffState getActiveJukeboxBuff(Player player) {
        if (player == null) {
            return null;
        }
        JukeboxBuffState state = jukeboxBuffStates.get(player.getUniqueId());
        if (state == null) {
            return null;
        }
        if (state.expiresAtMillis() < System.currentTimeMillis()) {
            jukeboxBuffStates.remove(player.getUniqueId());
            return null;
        }
        return state;
    }

    private void applyJukeboxCrossbowProjectileBonuses(Player player, Entity projectile) {
        if (projectile == null) {
            return;
        }
        JukeboxBuffState state = getActiveJukeboxBuff(player);
        if (state == null) {
            return;
        }
        if (state.crossbowProjectileSpeedBonus() > 0.0D) {
            Vector velocity = projectile.getVelocity();
            if (velocity.lengthSquared() > 0.001D) {
                projectile.setVelocity(velocity.multiply(1.0D + state.crossbowProjectileSpeedBonus()));
            }
        }
        if (projectile instanceof AbstractArrow arrow && state.crossbowDamageBonus() > 0.0D) {
            arrow.setDamage(arrow.getDamage() * (1.0D + state.crossbowDamageBonus()));
        }
    }

    private double getJukeboxCrossbowProjectileSpeedMultiplier(Player player) {
        JukeboxBuffState state = getActiveJukeboxBuff(player);
        return state == null ? 1.0D : 1.0D + Math.max(0.0D, state.crossbowProjectileSpeedBonus());
    }

    private double getJukeboxSwordFlightSpeedMultiplier(Player player) {
        JukeboxBuffState state = getActiveJukeboxBuff(player);
        return state == null ? 1.0D : 1.0D + Math.max(0.0D, state.swordFlightSpeedBonus());
    }

    private double getJukeboxSwordDamageMultiplier(Player player) {
        JukeboxBuffState state = getActiveJukeboxBuff(player);
        return state == null ? 1.0D : 1.0D + Math.max(0.0D, state.swordDamageBonus());
    }

    private boolean repairArmorByJukeboxAura(Player player, int amount) {
        ItemStack[] armor = player.getInventory().getArmorContents();
        boolean changed = false;
        for (ItemStack item : armor) {
            if (item == null || item.getType() == Material.AIR) {
                continue;
            }
            ItemMeta meta = item.getItemMeta();
            if (!(meta instanceof Damageable damageable)) {
                continue;
            }
            int damage = damageable.getDamage();
            if (damage <= 0) {
                continue;
            }
            damageable.setDamage(Math.max(0, damage - amount));
            item.setItemMeta(meta);
            changed = true;
        }
        if (changed) {
            player.getInventory().setArmorContents(armor);
            player.getWorld().spawnParticle(Particle.WAX_ON, player.getLocation().add(0.0D, 1.0D, 0.0D), 12, 0.26D, 0.24D, 0.26D, 0.03D);
            player.playSound(player.getLocation(), Sound.BLOCK_AMETHYST_BLOCK_CHIME, 0.34f, 1.72f);
        }
        return changed;
    }

