    private void executeMagicBrushDoubleCircle(Player player, GameRoom room, BrushDrawingSession session) {
        World world = session.origin().getWorld();
        if (world == null) {
            return;
        }
        drawBrushTemplate(world, session, createDoubleCircleTemplate(), Particle.END_ROD, 0.015D, 0.045D);
        drawBrushTemplate(world, session, createDoubleCircleTemplate(), Particle.HAPPY_VILLAGER, 0.012D, 0.018D);
        Location center = session.origin();
        for (Entity entity : world.getNearbyEntities(center, 6.0D, 3.6D, 6.0D)) {
            if (!(entity instanceof LivingEntity living)) {
                continue;
            }
            if (living instanceof Player target && (target.equals(player) || !canDamage(room, player, target))) {
                healMagicBrushAlly(target, 7.0D);
                target.addPotionEffect(new PotionEffect(PotionEffectType.RESISTANCE, 120, 0, false, true, true));
                target.addPotionEffect(new PotionEffect(PotionEffectType.SPEED, 120, 1, false, true, true));
                target.addPotionEffect(new PotionEffect(PotionEffectType.ABSORPTION, 160, 1, false, true, true));
                continue;
            }
            if (!canFlashNoteHitLiving(player, room, living)) {
                continue;
            }
            living.damage(MAGIC_BRUSH_DOUBLE_CIRCLE_DAMAGE, player);
            living.addPotionEffect(new PotionEffect(PotionEffectType.WEAKNESS, 90, 1, false, true, true));
            living.addPotionEffect(new PotionEffect(PotionEffectType.GLOWING, 70, 0, false, true, true));
            Vector push = living.getLocation().toVector().subtract(center.toVector());
            push.setY(0.0D);
            if (push.lengthSquared() > 0.0001D) {
                push.normalize().multiply(0.52D);
            }
            push.setY(0.24D);
            living.setVelocity(living.getVelocity().multiply(0.38D).add(push));
        }
        world.playSound(center, Sound.BLOCK_BEACON_POWER_SELECT, 0.74f, 1.92f);
        world.playSound(center, Sound.BLOCK_AMETHYST_BLOCK_CHIME, 0.82f, 1.55f);
        world.playSound(center, Sound.ENTITY_ILLUSIONER_PREPARE_BLINDNESS, 0.45f, 1.34f);
    }

    private void executeMagicBrushSpiralSeeker(Player player, GameRoom room, BrushDrawingSession session) {
        World world = session.origin().getWorld();
        if (world == null) {
            return;
        }
        drawBrushTemplate(world, session, createSpiralTemplate(), Particle.END_ROD, 0.015D, 0.055D);
        drawBrushTemplate(world, session, createSpiralTemplate(), Particle.WITCH, 0.012D, 0.025D);
        world.playSound(session.origin(), Sound.ENTITY_EVOKER_PREPARE_ATTACK, 0.68f, 1.42f);
        world.playSound(session.origin(), Sound.BLOCK_AMETHYST_BLOCK_RESONATE, 0.62f, 1.8f);
        new BukkitRunnable() {
            private int tick;
            private final Set<UUID> hit = new HashSet<>();
            private final List<Location> sparks = new ArrayList<>();
            private final List<Vector> velocities = new ArrayList<>();

            @Override
            public void run() {
                if (tick == 0) {
                    for (int i = 0; i < 5; i++) {
                        double angle = Math.PI * 2.0D * i / 5.0D;
                        Location start = session.origin().clone()
                                .add(session.right().clone().multiply(Math.cos(angle) * 0.82D))
                                .add(session.up().clone().multiply(Math.sin(angle) * 0.82D))
                                .add(session.normal().clone().multiply(0.28D));
                        sparks.add(start);
                        velocities.add(session.normal().clone()
                                .add(session.right().clone().multiply(Math.cos(angle) * 0.18D))
                                .add(session.up().clone().multiply(Math.sin(angle) * 0.18D))
                                .normalize().multiply(0.78D));
                    }
                }
                if (!isFlashEffectStillActive(player, room) || tick > 46 || sparks.isEmpty()) {
                    cancel();
                    return;
                }
                for (int i = 0; i < sparks.size(); i++) {
                    Location spark = sparks.get(i);
                    Vector velocity = velocities.get(i);
                    LivingEntity target = findNearestMagicBrushTarget(player, room, spark, 18.0D, hit);
                    if (target != null) {
                        Vector toward = getMagicBrushLivingCenter(target).subtract(spark.toVector());
                        if (toward.lengthSquared() > 0.0001D) {
                            velocity.multiply(0.70D).add(toward.normalize().multiply(0.34D)).normalize().multiply(0.86D);
                        }
                    } else {
                        velocity.multiply(0.88D).add(session.normal().clone().normalize().multiply(0.16D)).normalize().multiply(0.78D);
                    }
                    spark.add(velocity);
                    sparks.set(i, spark);
                    velocities.set(i, velocity);
                    world.spawnParticle(Particle.END_ROD, spark, 2, 0.035D, 0.035D, 0.035D, 0.035D);
                    world.spawnParticle(Particle.ENCHANTED_HIT, spark, 1, 0.05D, 0.05D, 0.05D, 0.025D);
                    for (Entity entity : world.getNearbyEntities(spark, 0.78D, 0.78D, 0.78D)) {
                        if (!(entity instanceof LivingEntity living) || !hit.add(entity.getUniqueId()) || !canFlashNoteHitLiving(player, room, living)) {
                            continue;
                        }
                        living.damage(MAGIC_BRUSH_SPIRAL_DAMAGE, player);
                        living.addPotionEffect(new PotionEffect(PotionEffectType.SLOWNESS, 75, 1, false, true, true));
                        living.addPotionEffect(new PotionEffect(PotionEffectType.GLOWING, 60, 0, false, true, true));
                        pullLivingToBrushCenter(living, spark, 0.18D, 0.18D);
                        world.spawnParticle(Particle.WITCH, spark, 12, 0.18D, 0.18D, 0.18D, 0.04D);
                        world.playSound(spark, Sound.BLOCK_AMETHYST_CLUSTER_BREAK, 0.38f, 1.78f);
                    }
                }
                if (tick % 6 == 0) {
                    world.playSound(session.origin().clone().add(session.normal().clone().multiply(2.0D + tick * 0.12D)),
                            Sound.ENTITY_BREEZE_SHOOT, 0.28f, 1.74f);
                }
                tick += 2;
            }
        }.runTaskTimer(plugin, 0L, 2L);
    }

    private void executeMagicBrushDiamondPrison(Player player, GameRoom room, BrushDrawingSession session) {
        World world = session.origin().getWorld();
        if (world == null) {
            return;
        }
        drawBrushTemplate(world, session, createDiamondTemplate(), Particle.END_ROD, 0.014D, 0.045D);
        drawBrushTemplate(world, session, createDiamondTemplate(), Particle.ELECTRIC_SPARK, 0.018D, 0.032D);
        List<LivingEntity> trapped = new ArrayList<>();
        for (Entity entity : world.getNearbyEntities(session.origin(), 5.1D, 3.2D, 5.1D)) {
            if (!(entity instanceof LivingEntity living) || !canFlashNoteHitLiving(player, room, living)) {
                continue;
            }
            trapped.add(living);
            living.damage(MAGIC_BRUSH_DIAMOND_DAMAGE, player);
            living.addPotionEffect(new PotionEffect(PotionEffectType.SLOWNESS, 120, 3, false, true, true));
            living.addPotionEffect(new PotionEffect(PotionEffectType.WEAKNESS, 100, 1, false, true, true));
            living.addPotionEffect(new PotionEffect(PotionEffectType.GLOWING, 120, 0, false, true, true));
            living.setVelocity(living.getVelocity().multiply(0.08D));
        }
        new BukkitRunnable() {
            private int tick;

            @Override
            public void run() {
                if (!isFlashEffectStillActive(player, room) || tick > 36) {
                    cancel();
                    return;
                }
                for (LivingEntity living : trapped) {
                    if (living == null || living.isDead() || !living.isValid() || living.getWorld() != world) {
                        continue;
                    }
                    Location base = living.getLocation().add(0.0D, Math.min(1.05D, living.getHeight() * 0.54D), 0.0D);
                    for (int i = 0; i < 4; i++) {
                        double angle = Math.toRadians(90.0D * i + tick * 8.0D);
                        Location point = base.clone().add(Math.cos(angle) * 0.72D, 0.0D, Math.sin(angle) * 0.72D);
                        world.spawnParticle(Particle.ELECTRIC_SPARK, point, 2, 0.04D, 0.18D, 0.04D, 0.018D);
                    }
                    living.setVelocity(living.getVelocity().multiply(0.22D));
                }
                tick += 3;
            }
        }.runTaskTimer(plugin, 0L, 3L);
        world.playSound(session.origin(), Sound.BLOCK_BEACON_ACTIVATE, 0.62f, 1.7f);
        world.playSound(session.origin(), Sound.BLOCK_TRIAL_SPAWNER_SPAWN_MOB, 0.42f, 1.58f);
    }

    private void executeMagicBrushHourglass(Player player, GameRoom room, BrushDrawingSession session) {
        World world = session.origin().getWorld();
        if (world == null) {
            return;
        }
        drawBrushTemplate(world, session, createHourglassTemplate(), Particle.END_ROD, 0.014D, 0.038D);
        drawBrushTemplate(world, session, createHourglassTemplate(), Particle.ENCHANTED_HIT, 0.016D, 0.02D);
        world.playSound(session.origin(), Sound.BLOCK_RESPAWN_ANCHOR_CHARGE, 0.48f, 1.92f);
        new BukkitRunnable() {
            private int pulse;

            @Override
            public void run() {
                if (!isFlashEffectStillActive(player, room) || pulse >= 5) {
                    cancel();
                    return;
                }
                double radius = 5.6D - pulse * 0.62D;
                for (int i = 0; i < 72; i++) {
                    double angle = Math.toRadians(i * 5.0D);
                    double squeeze = 0.38D + Math.abs(Math.sin(angle)) * 0.62D;
                    Location point = session.origin().clone()
                            .add(session.right().clone().multiply(Math.cos(angle) * radius * squeeze))
                            .add(session.up().clone().multiply(Math.sin(angle) * radius * 0.42D));
                    world.spawnParticle(Particle.ENCHANTED_HIT, point, 1, 0.02D, 0.02D, 0.02D, 0.015D);
                }
                for (Entity entity : world.getNearbyEntities(session.origin(), radius, 3.4D, radius)) {
                    if (!(entity instanceof LivingEntity living) || !canFlashNoteHitLiving(player, room, living)) {
                        continue;
                    }
                    living.damage(MAGIC_BRUSH_HOURGLASS_PULSE_DAMAGE + pulse * 0.65D, player);
                    living.addPotionEffect(new PotionEffect(PotionEffectType.SLOWNESS, 90, Math.min(3, pulse), false, true, true));
                    living.addPotionEffect(new PotionEffect(PotionEffectType.WEAKNESS, 70, 0, false, true, true));
                    living.setVelocity(living.getVelocity().multiply(Math.max(0.18D, 0.56D - pulse * 0.08D)));
                }
                world.playSound(session.origin(), Sound.BLOCK_AMETHYST_BLOCK_RESONATE, 0.46f, 1.15f + pulse * 0.14f);
                pulse++;
            }
        }.runTaskTimer(plugin, 4L, 12L);
    }

    private void executeMagicBrushCrescentSlash(Player player, GameRoom room, BrushDrawingSession session) {
        World world = session.origin().getWorld();
        if (world == null) {
            return;
        }
        drawBrushTemplate(world, session, createCrescentTemplate(), Particle.END_ROD, 0.015D, 0.052D);
        drawBrushTemplate(world, session, createCrescentTemplate(), Particle.ENCHANTED_HIT, 0.012D, 0.025D);
        Vector forward = session.normal().clone().normalize();
        world.playSound(session.origin(), Sound.ENTITY_BREEZE_SHOOT, 0.75f, 1.28f);
        new BukkitRunnable() {
            private int tick;
            private final Set<UUID> hit = new HashSet<>();

            @Override
            public void run() {
                if (!isFlashEffectStillActive(player, room) || tick > 34) {
                    cancel();
                    return;
                }
                double distance = 0.65D + tick * 0.62D;
                Location center = session.origin().clone().add(forward.clone().multiply(distance));
                for (int i = -10; i <= 10; i++) {
                    double curve = i / 10.0D;
                    double arch = Math.sqrt(Math.max(0.0D, 1.0D - curve * curve));
                    Location point = center.clone()
                            .add(session.right().clone().multiply(curve * 2.85D))
                            .add(session.up().clone().multiply(arch * 0.92D - 0.30D));
                    world.spawnParticle(Particle.END_ROD, point, 1, 0.018D, 0.018D, 0.018D, 0.018D);
                    if (i % 2 == 0) {
                        world.spawnParticle(Particle.ENCHANTED_HIT, point, 1, 0.02D, 0.02D, 0.02D, 0.015D);
                    }
                    for (Entity entity : world.getNearbyEntities(point, 0.72D, 0.72D, 0.72D)) {
                        if (!(entity instanceof LivingEntity living) || !hit.add(entity.getUniqueId()) || !canFlashNoteHitLiving(player, room, living)) {
                            continue;
                        }
                        living.damage(MAGIC_BRUSH_CRESCENT_DAMAGE, player);
                        living.addPotionEffect(new PotionEffect(PotionEffectType.WEAKNESS, 70, 0, false, true, true));
                        living.addPotionEffect(new PotionEffect(PotionEffectType.GLOWING, 55, 0, false, true, true));
                        living.setVelocity(living.getVelocity().add(forward.clone().multiply(0.54D)).setY(Math.max(0.16D, living.getVelocity().getY())));
                    }
                }
                if (distance > MAGIC_BRUSH_CRESCENT_RANGE) {
                    cancel();
                    return;
                }
                if (tick % 6 == 0) {
                    world.playSound(center, Sound.BLOCK_AMETHYST_CLUSTER_HIT, 0.34f, 1.8f);
                }
                tick += 2;
            }
        }.runTaskTimer(plugin, 0L, 2L);
    }

    private void executeMagicBrushLightningRune(Player player, GameRoom room, BrushDrawingSession session) {
        World world = session.origin().getWorld();
        if (world == null) {
            return;
        }
        drawBrushTemplate(world, session, createLightningRuneTemplate(), Particle.ELECTRIC_SPARK, 0.018D, 0.06D);
        drawBrushTemplate(world, session, createLightningRuneTemplate(), Particle.END_ROD, 0.012D, 0.035D);
        Vector direction = session.normal().clone().normalize();
        Set<UUID> hit = new HashSet<>();
        world.playSound(session.origin(), Sound.ENTITY_LIGHTNING_BOLT_THUNDER, 0.58f, 1.65f);
        for (double distance = 1.0D; distance <= 26.0D; distance += 1.15D) {
            Location point = session.origin().clone().add(direction.clone().multiply(distance));
            world.spawnParticle(Particle.ELECTRIC_SPARK, point, 5, 0.16D, 0.16D, 0.16D, 0.05D);
            if (((int) distance) % 5 == 0) {
                world.strikeLightningEffect(point);
            }
            for (Entity entity : world.getNearbyEntities(point, 1.08D, 1.08D, 1.08D)) {
                if (!(entity instanceof LivingEntity living) || !hit.add(entity.getUniqueId()) || !canFlashNoteHitLiving(player, room, living)) {
                    continue;
                }
                Location hitPoint = getMagicBrushLivingCenterLocation(living);
                world.strikeLightningEffect(hitPoint);
                living.damage(MAGIC_BRUSH_LIGHTNING_DAMAGE, player);
                living.addPotionEffect(new PotionEffect(PotionEffectType.SLOWNESS, 60, 1, false, true, true));
                living.addPotionEffect(new PotionEffect(PotionEffectType.GLOWING, 80, 0, false, true, true));
                LivingEntity chain = findNearestMagicBrushTarget(player, room, living.getLocation(), 7.5D, hit);
                if (chain != null && hit.add(chain.getUniqueId())) {
                    Location chainPoint = getMagicBrushLivingCenterLocation(chain);
                    spawnMagicBrushParticleLine(world, hitPoint, chainPoint, Particle.ELECTRIC_SPARK, 0.22D);
                    world.strikeLightningEffect(chainPoint);
                    chain.damage(MAGIC_BRUSH_LIGHTNING_DAMAGE * 0.62D, player);
                    chain.addPotionEffect(new PotionEffect(PotionEffectType.GLOWING, 70, 0, false, true, true));
                }
            }
        }
        world.playSound(session.origin(), Sound.BLOCK_BEACON_POWER_SELECT, 0.56f, 1.98f);
        world.playSound(session.origin(), Sound.BLOCK_RESPAWN_ANCHOR_CHARGE, 0.50f, 1.78f);
    }

    private void launchMagicBrushRemoteBolt(Player player, GameRoom room, Location origin, Vector direction, double range,
                                            double damage, double radius, Particle particle, PotionEffectType effect,
                                            int effectTicks, int amplifier) {
        if (player == null || origin == null || origin.getWorld() == null || direction == null || direction.lengthSquared() < 0.0001D) {
            return;
        }
        World world = origin.getWorld();
        Vector normalized = direction.clone().normalize();
        new BukkitRunnable() {
            private double travelled;
            private final Set<UUID> hit = new HashSet<>();

            @Override
            public void run() {
                if (!isFlashEffectStillActive(player, room) || travelled > range) {
                    cancel();
                    return;
                }
                Location point = origin.clone().add(normalized.clone().multiply(travelled));
                world.spawnParticle(particle, point, 4, 0.08D, 0.08D, 0.08D, 0.04D);
                world.spawnParticle(Particle.END_ROD, point, 2, 0.05D, 0.05D, 0.05D, 0.035D);
                if (travelled % 2.4D < 0.62D) {
                    world.playSound(point, Sound.BLOCK_AMETHYST_BLOCK_RESONATE, 0.24f, 1.72f);
                }
                for (Entity entity : world.getNearbyEntities(point, radius, radius, radius)) {
                    if (!(entity instanceof LivingEntity living) || living.equals(player) || !hit.add(entity.getUniqueId())) {
                        continue;
                    }
                    if (living instanceof Player target && !canDamage(room, player, target)) {
                        continue;
                    }
                    if (!(living instanceof Player) && isOwnedOrFriendlyTame(player.getUniqueId(), living)) {
                        continue;
                    }
                    living.damage(damage, player);
                    if (effect != null && effectTicks > 0) {
                        living.addPotionEffect(new PotionEffect(effect, effectTicks, Math.max(0, amplifier), false, true, true));
                    }
                    living.addPotionEffect(new PotionEffect(PotionEffectType.GLOWING, 45, 0, false, true, true));
                    living.setVelocity(living.getVelocity().add(normalized.clone().multiply(0.25D)));
                }
                travelled += 0.72D;
            }
        }.runTaskTimer(plugin, 0L, 1L);
    }

    private void healMagicBrushAlly(Player target, double amount) {
        if (target == null || amount <= 0.0D) {
            return;
        }
        AttributeInstance maxHealthAttribute = target.getAttribute(Attribute.MAX_HEALTH);
        double maxHealth = maxHealthAttribute == null ? 20.0D : maxHealthAttribute.getValue();
        target.setHealth(Math.min(maxHealth, target.getHealth() + amount));
        target.getWorld().spawnParticle(Particle.HAPPY_VILLAGER, target.getLocation().add(0.0D, 1.0D, 0.0D),
                10, 0.24D, 0.28D, 0.24D, 0.025D);
    }

    private LivingEntity findNearestMagicBrushTarget(Player player, GameRoom room, Location center, double radius, Set<UUID> ignored) {
        if (player == null || center == null || center.getWorld() == null || radius <= 0.0D) {
            return null;
        }
        LivingEntity best = null;
        double bestDistance = radius * radius;
        for (Entity entity : center.getWorld().getNearbyEntities(center, radius, radius, radius)) {
            if (!(entity instanceof LivingEntity living) || living.equals(player) || living.isDead()) {
                continue;
            }
            if (ignored != null && ignored.contains(living.getUniqueId())) {
                continue;
            }
            if (!canFlashNoteHitLiving(player, room, living)) {
                continue;
            }
            double distance = living.getLocation().distanceSquared(center);
            if (distance < bestDistance) {
                bestDistance = distance;
                best = living;
            }
        }
        return best;
    }

    private Vector getMagicBrushLivingCenter(LivingEntity living) {
        return getMagicBrushLivingCenterLocation(living).toVector();
    }

    private Location getMagicBrushLivingCenterLocation(LivingEntity living) {
        double yOffset = living == null ? 0.8D : Math.min(1.2D, Math.max(0.45D, living.getHeight() * 0.58D));
        return living == null ? new Location(null, 0.0D, 0.0D, 0.0D) : living.getLocation().add(0.0D, yOffset, 0.0D);
    }

    private void spawnMagicBrushParticleLine(World world, Location from, Location to, Particle particle, double stepSize) {
        if (world == null || from == null || to == null || from.getWorld() == null || to.getWorld() == null || !from.getWorld().equals(to.getWorld())) {
            return;
        }
        Vector delta = to.toVector().subtract(from.toVector());
        double distance = delta.length();
        if (distance < 0.001D) {
            world.spawnParticle(particle, from, 2, 0.04D, 0.04D, 0.04D, 0.02D);
            return;
        }
        Vector step = delta.normalize().multiply(Math.max(0.08D, stepSize));
        int samples = Math.max(1, (int) Math.ceil(distance / Math.max(0.08D, stepSize)));
        Location cursor = from.clone();
        for (int i = 0; i <= samples; i++) {
            world.spawnParticle(particle, cursor, 1, 0.04D, 0.04D, 0.04D, 0.03D);
            cursor.add(step);
        }
    }

