    private boolean isTmt(ItemStack item) {
        if (item == null || item.getType() != Material.TNT) {
            return false;
        }
        if (hasPersistentByte(item, tmtItemKey)) {
            return true;
        }
        if (!item.hasItemMeta()) {
            return false;
        }
        ItemMeta meta = item.getItemMeta();
        String name = meta == null ? null : meta.getItemName();
        if ((name == null || name.isBlank()) && meta != null && meta.hasDisplayName()) {
            name = meta.getDisplayName();
        }
        return normalizeTmtDisplayName(name).equals("TMT");
    }

    private String normalizeTmtDisplayName(String name) {
        if (name == null) {
            return "";
        }
        return name.replaceAll("(?i)§[0-9A-FK-ORX]", "")
                .replaceAll("(?i)&[0-9A-FK-ORX]", "")
                .replaceAll("[^A-Za-z]", "")
                .toUpperCase(Locale.ROOT);
    }

