    private SwordMaterialUpgrade getSwordMaterialUpgrade(Material sword, Material material) {
        if (sword == Material.WOODEN_SWORD && isWoodUpgradeMaterial(material)) {
            return new SwordMaterialUpgrade(0.30D, 0.10D);
        }
        if (sword == Material.STONE_SWORD && material == Material.COBBLESTONE) {
            return new SwordMaterialUpgrade(0.30D, 0.15D);
        }
        if (sword == Material.COPPER_SWORD && material == Material.COPPER_BLOCK) {
            return new SwordMaterialUpgrade(0.30D, 0.10D);
        }
        if (sword == Material.IRON_SWORD && material == Material.IRON_BLOCK) {
            return new SwordMaterialUpgrade(0.45D, 0.20D);
        }
        if (sword == Material.GOLDEN_SWORD && material == Material.GOLD_BLOCK) {
            return new SwordMaterialUpgrade(0.55D, 0.25D);
        }
        if (sword == Material.DIAMOND_SWORD && material == Material.DIAMOND_BLOCK) {
            return new SwordMaterialUpgrade(0.40D, 0.25D);
        }
        if (sword == Material.NETHERITE_SWORD && material == Material.NETHERITE_INGOT) {
            return new SwordMaterialUpgrade(0.35D, 0.30D);
        }
        return null;
    }

    private AxeMaterialUpgrade getAxeMaterialUpgrade(Material axe, Material material) {
        if (axe == Material.WOODEN_AXE && isWoodUpgradeMaterial(material)) {
            return new AxeMaterialUpgrade(0.10D, 0.30D);
        }
        if (axe == Material.STONE_AXE && material == Material.COBBLESTONE) {
            return new AxeMaterialUpgrade(0.15D, 0.30D);
        }
        if (axe == Material.COPPER_AXE && material == Material.COPPER_BLOCK) {
            return new AxeMaterialUpgrade(0.10D, 0.30D);
        }
        if (axe == Material.IRON_AXE && material == Material.IRON_BLOCK) {
            return new AxeMaterialUpgrade(0.30D, 0.80D);
        }
        if (axe == Material.GOLDEN_AXE && material == Material.GOLD_BLOCK) {
            return new AxeMaterialUpgrade(0.20D, 0.40D);
        }
        if (axe == Material.DIAMOND_AXE && material == Material.DIAMOND_BLOCK) {
            return new AxeMaterialUpgrade(0.40D, 1.00D);
        }
        if (axe == Material.NETHERITE_AXE && material == Material.NETHERITE_INGOT) {
            return new AxeMaterialUpgrade(1.00D, 2.00D);
        }
        return null;
    }

    private boolean isArmorUpgradeMaterial(Material armor, Material material) {
        String armorName = armor.name();
        if (armor == Material.ELYTRA) {
            return material == Material.PHANTOM_MEMBRANE;
        }
        if (armor == Material.TURTLE_HELMET) {
            return material == Material.TURTLE_SCUTE;
        }
        if (armorName.startsWith("LEATHER_")) {
            return material == Material.LEATHER;
        }
        if (armorName.startsWith("CHAINMAIL_")) {
            return material == Material.IRON_NUGGET;
        }
        if (armorName.startsWith("COPPER_")) {
            return material == Material.COPPER_BLOCK;
        }
        if (armorName.startsWith("IRON_")) {
            return material == Material.IRON_BLOCK;
        }
        if (armorName.startsWith("GOLDEN_")) {
            return material == Material.GOLD_BLOCK;
        }
        if (armorName.startsWith("DIAMOND_")) {
            return material == Material.DIAMOND_BLOCK;
        }
        if (armorName.startsWith("NETHERITE_")) {
            return material == Material.NETHERITE_INGOT;
        }
        return false;
    }

    private boolean isWoodUpgradeMaterial(Material material) {
        String name = material.name();
        return name.endsWith("_LOG")
                || name.endsWith("_WOOD")
                || name.endsWith("_STEM")
                || name.endsWith("_HYPHAE")
                || name.endsWith("_PLANKS")
                || name.equals("BAMBOO_BLOCK")
                || name.equals("STRIPPED_BAMBOO_BLOCK");
    }

    private boolean hasPersistentByte(ItemStack item, NamespacedKey key) {
        if (item == null || !item.hasItemMeta()) {
            return false;
        }
        Byte flag = item.getItemMeta().getPersistentDataContainer().get(key, PersistentDataType.BYTE);
        return flag != null && flag == (byte) 1;
    }

    private boolean hasUnstableCoreShield(ItemStack item) {
        return item != null && item.getType() == Material.SHIELD && hasPersistentByte(item, unstableCoreShieldKey);
    }

    private boolean hasUnstableCoreShieldInOffhand(LivingEntity entity) {
        if (!(entity instanceof Player player)) {
            return false;
        }
        return hasUnstableCoreShield(player.getInventory().getItemInOffHand());
    }

    private double reduceUnstableCoreDamage(LivingEntity victim, double unstableDamage) {
        return unstableDamage;
    }

    private int applyUnstableCoreShieldBreakCooldown(ItemStack shield, int baseTicks) {
        return baseTicks;
    }

    public void normalizeUnstableCoreShieldBlockingDelay(Player player) {
        if (player == null) {
            return;
        }
        long now = System.currentTimeMillis();
        unstableCoreShieldVanillaDisableCancelUntil.entrySet().removeIf(entry -> entry.getValue() <= now);
        ItemStack shield = findBlockingShield(player);
        boolean heavyShieldStillRaised = player.isBlocking() && hasUnstableCoreShield(shield);
        if (!heavyShieldStillRaised && !isActuallyShieldBlocking(player)) {
            unstableCoreShieldImmuneBreakUsed.remove(player.getUniqueId());
        }
        int expectedDelay = NORMAL_SHIELD_BLOCKING_DELAY_TICKS;
        if (player.getShieldBlockingDelay() != expectedDelay) {
            player.setShieldBlockingDelay(expectedDelay);
        }
    }

    public void handleUnstableCoreShieldDisable(PlayerShieldDisableEvent event) {
        if (event == null) {
            return;
        }
        Player target = event.getPlayer();
        if (target == null || !target.isOnline()) {
            return;
        }
        ItemStack shield = findBlockingShield(target);
        if (!hasUnstableCoreShield(shield)) {
            return;
        }

        UUID targetId = target.getUniqueId();
        long now = System.currentTimeMillis();
        Long cancelUntil = unstableCoreShieldVanillaDisableCancelUntil.get(targetId);
        boolean firstBreakJustHandled = cancelUntil != null && cancelUntil > now;
        boolean firstBreakNotUsed = !unstableCoreShieldImmuneBreakUsed.contains(targetId);
        if (!firstBreakJustHandled && !firstBreakNotUsed) {
            return;
        }

        event.setCooldown(0);
        event.setCancelled(true);
        unstableCoreShieldVanillaDisableCancelUntil.put(targetId, now + 350L);
        keepUnstableCoreShieldRaised(target, shield);
    }

    private boolean hasPersistentDouble(ItemStack item, NamespacedKey key) {
        return item != null
                && item.hasItemMeta()
                && item.getItemMeta().getPersistentDataContainer().has(key, PersistentDataType.DOUBLE);
    }

    private boolean hasMaterialArmorLayer(Player player) {
        return countMaterialArmorPieces(player) > 0;
    }

    private int countMaterialArmorPieces(Player player) {
        int count = 0;
        for (ItemStack item : player.getInventory().getArmorContents()) {
            if (hasPersistentByte(item, materialArmorLayerKey)) {
                count++;
            }
        }
        return count;
    }

    private double getMaterialArmorAxeBonusReduction(Player player) {
        if (player == null) {
            return 0.0D;
        }
        double reduction = 0.0D;
        for (ItemStack item : player.getInventory().getArmorContents()) {
            if (hasPersistentByte(item, materialArmorLayerKey)) {
                reduction += getMaterialArmorAxeBonusReduction(item);
            }
        }
        return Math.max(0.0D, reduction);
    }

    private double getMaterialArmorAxeBonusReduction(ItemStack item) {
        if (!isArmor(item)) {
            return 0.0D;
        }
        String name = item.getType().name();
        if (name.startsWith("IRON_")) {
            return 0.05D;
        }
        if (name.startsWith("DIAMOND_")) {
            return 0.10D;
        }
        if (name.startsWith("NETHERITE_")) {
            return 0.18D;
        }
        return 0.03D;
    }

    private int countTntArmorLayers(Player player) {
        if (player == null) {
            return 0;
        }
        int layers = 0;
        for (ItemStack item : player.getInventory().getArmorContents()) {
            layers += getTntArmorLayers(item);
        }
        return Math.max(0, layers);
    }

    private int getTntArmorLayers(ItemStack item) {
        if (item == null || !item.hasItemMeta()) {
            return 0;
        }
        Integer layers = item.getItemMeta().getPersistentDataContainer().get(tntArmorExplosionImmunityLayersKey, PersistentDataType.INTEGER);
        return Math.max(0, Math.min(TNT_ARMOR_MAX_LAYERS, layers == null ? 0 : layers));
    }

