    private boolean feedFlashTameSword(Player player, LivingEntity entity, ItemStack sword) {
        if (entity instanceof Skeleton) {
            sendFlashMessage(player, plugin.getConfigManager().getHunterGamePrefix() + "§x§B§B§D§D§F§F✦ §b小白是远程宠物，要喂弓来提高远程伤害。");
            player.playSound(player.getLocation(), Sound.BLOCK_NOTE_BLOCK_BASS, 0.62f, 0.9f);
            return false;
        }
        if (entity.getPersistentDataContainer().has(flashTamedSwordFedKey, PersistentDataType.BYTE)) {
            sendFlashMessage(player, plugin.getConfigManager().getHunterGamePrefix() + "§x§F§F§B§B§6§6✦ §e这只生物已经喂过剑了。");
            player.playSound(player.getLocation(), Sound.BLOCK_NOTE_BLOCK_BASS, 0.65f, 0.85f);
            return false;
        }
        double swordPower = switch (sword.getType()) {
            case WOODEN_SWORD, GOLDEN_SWORD -> 1.5D;
            case STONE_SWORD -> 2.0D;
            case COPPER_SWORD, IRON_SWORD -> 2.5D;
            case DIAMOND_SWORD -> 3.0D;
            case NETHERITE_SWORD -> 4.0D;
            default -> 2.0D;
        };
        swordPower += sword.getEnchantmentLevel(Enchantment.SHARPNESS) * 0.65D;
        entity.getPersistentDataContainer().set(flashTamedSwordFedKey, PersistentDataType.BYTE, (byte) 1);
        entity.getPersistentDataContainer().set(flashTamedDamageBoostKey, PersistentDataType.DOUBLE, swordPower);
        AttributeInstance attack = entity.getAttribute(Attribute.ATTACK_DAMAGE);
        if (attack != null) {
            attack.setBaseValue(attack.getBaseValue() + swordPower);
        }
        sendFlashMessage(player, plugin.getConfigManager().getHunterGamePrefix() + "§x§F§F§8§8§8§8✦ §c剑刃喂养完成§7，宠物伤害提高。");
        entity.getWorld().spawnParticle(Particle.CRIT, entity.getLocation().add(0.0D, 1.0D, 0.0D), 18, 0.3, 0.25, 0.3, 0.04);
        entity.getWorld().playSound(entity.getLocation(), Sound.ITEM_TRIDENT_HIT, 0.75f, 1.38f);
        return true;
    }

    private boolean feedFlashTameBow(Player player, LivingEntity entity, ItemStack bow) {
        if (!(entity instanceof Skeleton)) {
            return false;
        }
        if (entity.getPersistentDataContainer().has(flashTamedBowFedKey, PersistentDataType.BYTE)) {
            sendFlashMessage(player, plugin.getConfigManager().getHunterGamePrefix() + "§x§F§F§B§B§6§6✦ §e这只小白已经喂过弓了。");
            player.playSound(player.getLocation(), Sound.BLOCK_NOTE_BLOCK_BASS, 0.65f, 0.85f);
            return false;
        }
        double bowPower = 1.4D
                + bow.getEnchantmentLevel(Enchantment.POWER) * 0.72D
                + bow.getEnchantmentLevel(Enchantment.PUNCH) * 0.28D
                + bow.getEnchantmentLevel(Enchantment.FLAME) * 0.35D
                + bow.getEnchantmentLevel(Enchantment.INFINITY) * 0.25D;
        entity.getPersistentDataContainer().set(flashTamedBowFedKey, PersistentDataType.BYTE, (byte) 1);
        entity.getPersistentDataContainer().set(flashTamedRangedDamageBoostKey, PersistentDataType.DOUBLE, bowPower);
        sendFlashMessage(player, plugin.getConfigManager().getHunterGamePrefix() + "§x§B§B§D§D§F§F✦ §b弓弦喂养完成§7，小白箭矢伤害提高。");
        entity.getWorld().spawnParticle(Particle.CRIT, entity.getLocation().add(0.0D, 1.0D, 0.0D), 18, 0.28D, 0.22D, 0.28D, 0.04D);
        entity.getWorld().spawnParticle(Particle.ENCHANT, entity.getLocation().add(0.0D, 1.0D, 0.0D), 14, 0.24D, 0.18D, 0.24D, 0.02D);
        entity.getWorld().playSound(entity.getLocation(), Sound.ITEM_CROSSBOW_LOADING_END, 0.72f, 1.48f);
        return true;
    }

    private void consumeHandItem(Player player, EquipmentSlot hand, int amount) {
        ItemStack item = hand == EquipmentSlot.OFF_HAND ? player.getInventory().getItemInOffHand() : player.getInventory().getItemInMainHand();
        if (isEmpty(item)) {
            return;
        }
        item.setAmount(item.getAmount() - amount);
        if (hand == EquipmentSlot.OFF_HAND) {
            player.getInventory().setItemInOffHand(item.getAmount() <= 0 ? null : item);
        } else {
            player.getInventory().setItemInMainHand(item.getAmount() <= 0 ? null : item);
        }
    }

    public void handleFlashTamedTarget(EntityTargetEvent event) {
        if (!(event.getEntity() instanceof Mob mob) || !isFlashTamed(mob)) {
            return;
        }
        UUID ownerId = getFlashTameOwner(mob);
        if (ownerId == null) {
            event.setCancelled(true);
            return;
        }
        Player owner = Bukkit.getPlayer(ownerId);
        if (owner == null) {
            event.setCancelled(true);
            return;
        }
        Entity target = event.getTarget();
        UUID wanted = tameLastOwnerTargets.get(ownerId);
        if (target instanceof LivingEntity targetLiving && isOwnedOrFriendlyTame(ownerId, targetLiving)) {
            event.setCancelled(true);
            mob.setTarget(null);
            return;
        }
        if (!(target instanceof LivingEntity living) || wanted == null || !wanted.equals(living.getUniqueId()) || living.isDead() || !living.isValid()) {
            tameLastOwnerTargets.remove(ownerId);
            event.setCancelled(true);
            mob.setTarget(null);
            return;
        }
        if (isOwnedOrFriendlyTame(ownerId, living)) {
            event.setCancelled(true);
            mob.setTarget(null);
            return;
        }
        if (living instanceof Player playerTarget) {
            GameRoom room = plugin.getRoomManager().getPlayerRoom(ownerId);
            if (!canDamage(room, owner, playerTarget)) {
                event.setCancelled(true);
                mob.setTarget(null);
            }
        }
    }

    public void handleFlashTamedDamage(EntityDamageByEntityEvent event) {
        LivingEntity pet = resolveFlashTameDamager(event.getDamager());
        if (event.getEntity() instanceof LivingEntity victimTame && isFlashTamed(victimTame)
                && event.getDamager() instanceof Player attacker
                && isFlashTamedBy(victimTame, attacker)) {
            event.setDamage(0.0D);
            event.setCancelled(true);
            return;
        }
        if (pet == null || !isFlashTamed(pet)) {
            if (event.getEntity() instanceof Player playerVictim) {
                applyCondensedEnderPearlPetDamageReduction(event, playerVictim, pet);
            }
            return;
        }
        UUID ownerId = getFlashTameOwner(pet);
        Player owner = ownerId == null ? null : Bukkit.getPlayer(ownerId);
        if (owner == null) {
            event.setCancelled(true);
            return;
        }
        GameRoom room = plugin.getRoomManager().getPlayerRoom(ownerId);
        if (!isFlashCombatAvailable(owner, room)) {
            event.setCancelled(true);
            return;
        }
        if (event.getDamager() instanceof Projectile projectile && projectile.getShooter() instanceof LivingEntity shooter && isFlashTamed(shooter)) {
            pet = shooter;
            ownerId = getFlashTameOwner(pet);
            owner = ownerId == null ? null : Bukkit.getPlayer(ownerId);
            if (owner == null) {
                event.setCancelled(true);
                return;
            }
            room = plugin.getRoomManager().getPlayerRoom(ownerId);
        }
        if (event.getEntity() instanceof LivingEntity targetTame && isOwnedOrFriendlyTame(ownerId, targetTame)) {
            if (event.getDamager() instanceof Projectile projectile && projectile instanceof AbstractArrow arrow && isFlashTamedPiercingProjectile(projectile)) {
                arrow.setPierceLevel(Math.max(arrow.getPierceLevel(), 127));
            }
            event.setDamage(0.0D);
            event.setCancelled(true);
            if (pet instanceof Mob mob) {
                mob.setTarget(null);
            }
            return;
        }
        if (event.getEntity() instanceof Player playerTarget && !canDamage(room, owner, playerTarget)) {
            event.setDamage(0.0D);
            event.setCancelled(true);
            return;
        }
        Double boost = event.getDamager() instanceof Projectile
                ? pet.getPersistentDataContainer().get(flashTamedRangedDamageBoostKey, PersistentDataType.DOUBLE)
                : pet.getPersistentDataContainer().get(flashTamedDamageBoostKey, PersistentDataType.DOUBLE);
        if (boost != null && boost > 0.0D) {
            event.setDamage((event.getDamage() + boost) * TAME_DAMAGE_BOOST_MULTIPLIER);
        }
        if (event.getEntity() instanceof Player playerVictim) {
            applyCondensedEnderPearlPetDamageReduction(event, playerVictim, pet);
            applyCondensedEnderPearlEndermanDamageReduction(event, playerVictim, pet);
        }
    }

    private void applyCondensedEnderPearlPetDamageReduction(EntityDamageByEntityEvent event, Player victim, LivingEntity pet) {
        if (event == null || victim == null || pet == null || event.isCancelled() || event.getDamage() <= 0.0D) {
            return;
        }
        if (!isCondensedEnderPearlPetDamageSource(pet)) {
            return;
        }
        GameRoom victimRoom = plugin.getRoomManager().getPlayerRoom(victim.getUniqueId());
        if (!isFlashCombatAvailable(victim, victimRoom)) {
            return;
        }
        double reduction = getCondensedEnderPearlPetReduction(victim);
        if (reduction <= 0.0D) {
            return;
        }
        event.setDamage(event.getDamage() * (1.0D - reduction));
        victim.getWorld().spawnParticle(Particle.PORTAL, victim.getLocation().add(0.0D, 1.0D, 0.0D),
                8, 0.18D, 0.22D, 0.18D, 0.04D);
    }

    public void handleCondensedEnderPearlEndermanDamage(EntityDamageByEntityEvent event) {
        if (event == null || event.isCancelled() || event.getDamage() <= 0.0D || !(event.getEntity() instanceof Player victim)) {
            return;
        }
        LivingEntity damager = resolveFlashTameDamager(event.getDamager());
        if (isCondensedEnderPearlPetDamageSource(damager)) {
            return;
        }
        applyCondensedEnderPearlEndermanDamageReduction(event, victim, damager);
    }

    private void applyCondensedEnderPearlEndermanDamageReduction(EntityDamageByEntityEvent event, Player victim, LivingEntity damager) {
        if (event == null || event.isCancelled() || event.getDamage() <= 0.0D || victim == null || !(damager instanceof Enderman)) {
            return;
        }
        GameRoom victimRoom = plugin.getRoomManager().getPlayerRoom(victim.getUniqueId());
        if (!isFlashCombatAvailable(victim, victimRoom)) {
            return;
        }
        double reduction = getCondensedEnderPearlEndermanReduction(victim);
        if (reduction <= 0.0D) {
            return;
        }
        event.setDamage(event.getDamage() * (1.0D - reduction));
        victim.getWorld().spawnParticle(Particle.REVERSE_PORTAL, victim.getLocation().add(0.0D, 1.05D, 0.0D),
                10, 0.20D, 0.25D, 0.20D, 0.05D);
    }

    private boolean isCondensedEnderPearlPetDamageSource(LivingEntity entity) {
        return entity != null
                && (isFlashTamed(entity) || (entity instanceof Tameable tameable && tameable.isTamed()));
    }

    private Player resolveDamagePetOwner(LivingEntity pet) {
        if (pet == null) {
            return null;
        }
        UUID ownerId = getFlashTameOwner(pet);
        if (ownerId == null && pet instanceof Tameable tameable && tameable.isTamed()) {
            ownerId = tameable.getOwnerUniqueId();
        }
        return ownerId == null ? null : Bukkit.getPlayer(ownerId);
    }

    private double getCondensedEnderPearlPetReduction(Player player) {
        if (player == null) {
            return 0.0D;
        }
        int pieces = 0;
        for (ItemStack item : player.getInventory().getArmorContents()) {
            if (hasPersistentByte(item, condensedEnderPearlArmorKey)) {
                pieces++;
            }
        }
        return Math.min(0.60D, pieces * CONDENSED_ENDER_PEARL_PET_DAMAGE_REDUCTION);
    }

    private double getCondensedEnderPearlEndermanReduction(Player player) {
        if (player == null) {
            return 0.0D;
        }
        int pieces = 0;
        for (ItemStack item : player.getInventory().getArmorContents()) {
            if (hasPersistentByte(item, condensedEnderPearlArmorKey)) {
                pieces++;
            }
        }
        return Math.min(0.50D, pieces * CONDENSED_ENDER_PEARL_ENDERMAN_DAMAGE_REDUCTION);
    }

    private boolean isFlashTamedPiercingProjectile(Projectile projectile) {
        return projectile != null && flashTamedPiercingProjectiles.contains(projectile.getUniqueId());
    }

    private LivingEntity resolveFlashTameDamager(Entity damager) {
        if (damager instanceof LivingEntity living) {
            return living;
        }
        if (damager instanceof Projectile projectile && projectile.getShooter() instanceof LivingEntity living) {
            return living;
        }
        return null;
    }

    public void handleFlashTamedProjectileLaunch(ProjectileLaunchEvent event) {
        Projectile projectile = event.getEntity();
        if (!(projectile.getShooter() instanceof LivingEntity shooter) || !isFlashTamed(shooter)) {
            return;
        }
        if (projectile instanceof AbstractArrow arrow) {
            arrow.setPierceLevel(Math.max(arrow.getPierceLevel(), 127));
            flashTamedPiercingProjectiles.add(projectile.getUniqueId());
            Bukkit.getScheduler().runTaskLater(plugin, () -> flashTamedPiercingProjectiles.remove(projectile.getUniqueId()), 20L * 30L);
            Double boost = shooter.getPersistentDataContainer().get(flashTamedRangedDamageBoostKey, PersistentDataType.DOUBLE);
            if (boost != null && boost > 0.0D) {
                arrow.setDamage(arrow.getDamage() + boost);
            }
        }
    }

    public void rememberOwnerCombatTarget(Player owner, LivingEntity target) {
        if (owner == null || target == null || target.getUniqueId().equals(owner.getUniqueId())) {
            return;
        }
        GameRoom room = plugin.getRoomManager().getPlayerRoom(owner.getUniqueId());
        if (!isFlashCombatAvailable(owner, room)) {
            return;
        }
        if (isFlashTamedBy(target, owner) || isOwnedOrFriendlyTame(owner.getUniqueId(), target)) {
            return;
        }
        if (target instanceof Player playerTarget && !canDamage(room, owner, playerTarget)) {
            return;
        }
        tameLastOwnerTargets.put(owner.getUniqueId(), target.getUniqueId());
        for (LivingEntity pet : findOwnedFlashTames(owner.getUniqueId())) {
            if (pet instanceof Mob mob && pet.getWorld().equals(target.getWorld())) {
                mob.setTarget(target);
            }
        }
    }

    private boolean isOwnedOrFriendlyTame(UUID ownerId, LivingEntity entity) {
        if (ownerId == null || entity == null) {
            return false;
        }
        if (isFlashTamed(entity)) {
            return true;
        }
        return entity instanceof Tameable tameable && tameable.isTamed() && ownerId.equals(tameable.getOwnerUniqueId());
    }

    public void handleOwnerCrossDimensionTeleport(PlayerTeleportEvent event) {
        Player owner = event.getPlayer();
        Location to = event.getTo();
        if (to == null || event.getFrom().getWorld() == null || to.getWorld() == null || event.getFrom().getWorld().equals(to.getWorld())) {
            return;
        }
        GameRoom room = plugin.getRoomManager().getPlayerRoom(owner.getUniqueId());
        if (!isFlashCombatAvailable(owner, room)) {
            return;
        }
        Bukkit.getScheduler().runTaskLater(plugin, () -> teleportOwnedTamesToOwner(owner, to), 4L);
    }

    private void teleportOwnedTamesToOwner(Player owner, Location targetLocation) {
        if (!owner.isOnline() || targetLocation.getWorld() == null) {
            return;
        }
        for (LivingEntity entity : findAllOwnedTames(owner.getUniqueId())) {
            Location destination = targetLocation.clone().add(ThreadLocalRandom.current().nextDouble(-1.8D, 1.8D), 0.2D, ThreadLocalRandom.current().nextDouble(-1.8D, 1.8D));
            entity.teleport(destination, PlayerTeleportEvent.TeleportCause.PLUGIN);
            entity.getWorld().spawnParticle(Particle.PORTAL, entity.getLocation().add(0.0D, 0.8D, 0.0D), 28, 0.25, 0.3, 0.25, 0.08);
            if (entity instanceof Mob mob) {
                mob.setTarget(null);
            }
        }
    }

    private List<LivingEntity> findOwnedFlashTames(UUID ownerId) {
        List<LivingEntity> result = new ArrayList<>();
        for (World world : Bukkit.getWorlds()) {
            for (LivingEntity entity : world.getLivingEntities()) {
                if (isFlashTamed(entity) && ownerId.equals(getFlashTameOwner(entity))) {
                    result.add(entity);
                }
            }
        }
        return result;
    }

    private List<LivingEntity> findAllOwnedTames(UUID ownerId) {
        List<LivingEntity> result = new ArrayList<>();
        for (World world : Bukkit.getWorlds()) {
            for (LivingEntity entity : world.getLivingEntities()) {
                if (isFlashTamed(entity) && ownerId.equals(getFlashTameOwner(entity))) {
                    result.add(entity);
                    continue;
                }
                if (entity instanceof Tameable tameable && tameable.isTamed() && ownerId.equals(tameable.getOwnerUniqueId())) {
                    result.add(entity);
                }
            }
        }
        return result;
    }

    private void startFlashTameFollowTask(UUID ownerId, UUID entityId, double followDistance) {
        new BukkitRunnable() {
            @Override
            public void run() {
                Player owner = Bukkit.getPlayer(ownerId);
                Entity rawEntity = Bukkit.getEntity(entityId);
                if (owner == null || !owner.isOnline() || !(rawEntity instanceof LivingEntity entity) || entity.isDead() || !entity.isValid() || !isFlashTamed(entity)) {
                    cancel();
                    return;
                }
                if (!TAME_FOLLOWING_ENABLED.equals(entity.getPersistentDataContainer().get(flashTamedFollowingKey, PersistentDataType.STRING))) {
                    return;
                }
                GameRoom room = plugin.getRoomManager().getPlayerRoom(ownerId);
                if (!isFlashCombatAvailable(owner, room)) {
                    return;
                }
                if (!entity.getWorld().equals(owner.getWorld())) {
                    if (isSafeTameTeleportOwnerLocation(owner)) {
                        entity.teleport(owner.getLocation(), PlayerTeleportEvent.TeleportCause.PLUGIN);
                    }
                    return;
                }
                if (entity instanceof Mob mob && mob.getTarget() instanceof LivingEntity target && (target.isDead() || !target.isValid())) {
                    mob.setTarget(null);
                    UUID wanted = tameLastOwnerTargets.get(ownerId);
                    if (wanted != null && wanted.equals(target.getUniqueId())) {
                        tameLastOwnerTargets.remove(ownerId);
                    }
                }
                double distanceSq = entity.getLocation().distanceSquared(owner.getLocation());
                if (distanceSq > 144.0D) {
                    if (isSafeTameTeleportOwnerLocation(owner)) {
                        entity.teleport(owner.getLocation().clone().add(1.2D, 0.0D, 1.2D), PlayerTeleportEvent.TeleportCause.PLUGIN);
                    }
                    return;
                }
                if (distanceSq <= followDistance * followDistance) {
                    return;
                }
                if (entity instanceof Enderman enderman && distanceSq > 64.0D && ThreadLocalRandom.current().nextInt(4) == 0) {
                    enderman.teleportTowards(owner);
                    return;
                }
                if (entity instanceof Mob mob) {
                    mob.getPathfinder().moveTo(owner, entity instanceof Enderman ? 1.32D : 1.18D);
                }
            }
        }.runTaskTimer(plugin, 10L, 10L);
    }

    private boolean isSafeTameTeleportOwnerLocation(Player owner) {
        return owner != null && owner.isOnGround() && owner.getFallDistance() < 1.0F && !owner.isGliding() && !owner.isFlying();
    }

    private boolean isFlashTamed(LivingEntity entity) {
        return getFlashTameOwner(entity) != null;
    }

    private boolean isFlashTamedBy(LivingEntity entity, Player player) {
        UUID owner = getFlashTameOwner(entity);
        return owner != null && player != null && owner.equals(player.getUniqueId());
    }

    private UUID getFlashTameOwner(LivingEntity entity) {
        String raw = entity.getPersistentDataContainer().get(flashTamedOwnerKey, PersistentDataType.STRING);
        if (raw == null || raw.isBlank()) {
            return null;
        }
        try {
            return UUID.fromString(raw);
        } catch (IllegalArgumentException ignored) {
            return null;
        }
    }

    private List<Block> getAreaMineBlocks(Block center, BlockFace face) {
        List<Block> blocks = new ArrayList<>();
        for (int a = -1; a <= 1; a++) {
            for (int b = -1; b <= 1; b++) {
                Block block = switch (face) {
                    case UP, DOWN -> center.getRelative(a, 0, b);
                    case NORTH, SOUTH -> center.getRelative(a, b, 0);
                    case EAST, WEST -> center.getRelative(0, a, b);
                    default -> center.getRelative(a, 0, b);
                };
                blocks.add(block);
            }
        }
        return blocks;
    }

    private BlockFace getMiningPlaneFace(Player player, Block block) {
        Location eye = player.getEyeLocation();
        Location center = block.getLocation().add(0.5D, 0.5D, 0.5D);
        Vector diff = eye.toVector().subtract(center.toVector());
        double ax = Math.abs(diff.getX());
        double ay = Math.abs(diff.getY());
        double az = Math.abs(diff.getZ());
        if (ay >= ax && ay >= az) {
            return diff.getY() > 0 ? BlockFace.UP : BlockFace.DOWN;
        }
        if (ax >= az) {
            return diff.getX() > 0 ? BlockFace.EAST : BlockFace.WEST;
        }
        return diff.getZ() > 0 ? BlockFace.SOUTH : BlockFace.NORTH;
    }

    private boolean canFlashAreaMineBlock(Block block, ItemStack tool, Block center) {
        if (block == null || block.isEmpty() || block.isLiquid() || block.getType() == Material.AIR) {
            return false;
        }
        Material type = block.getType();
        if (!type.isBlock() || type.getHardness() < 0.0F) {
            return false;
        }
        if (center != null && type.getHardness() > Math.max(0.2F, center.getType().getHardness() * 1.35F + 0.8F)) {
            return false;
        }
        if (type.getHardness() > 18.0F || type.getBlastResistance() > 80.0F) {
            return false;
        }
        if (!block.isPreferredTool(tool) && type.getHardness() > 1.5F) {
            return false;
        }
        return switch (type) {
            case BEDROCK,
                 BARRIER,
                 COMMAND_BLOCK,
                 CHAIN_COMMAND_BLOCK,
                 REPEATING_COMMAND_BLOCK,
                 STRUCTURE_BLOCK,
                 JIGSAW,
                 END_PORTAL,
                 END_PORTAL_FRAME,
                 END_GATEWAY,
                 NETHER_PORTAL,
                 SPAWNER,
                 REINFORCED_DEEPSLATE,
                 VAULT,
                 TRIAL_SPAWNER -> false;
            default -> true;
        };
    }

    private void dropFlashBlockItems(World world, Location blockCenter, Collection<ItemStack> drops, Material type) {
        dropFlashBlockItems(world, blockCenter, drops, type, 1.0D);
    }

    private void dropFlashBlockItems(World world, Location blockCenter, Collection<ItemStack> drops, Material type, double keepRate) {
        double clampedKeepRate = Math.max(0.0D, Math.min(1.0D, keepRate));
        ThreadLocalRandom random = ThreadLocalRandom.current();
        boolean dropped = false;
        for (ItemStack drop : drops) {
            if (drop == null || drop.getType() == Material.AIR || drop.getAmount() <= 0) {
                continue;
            }
            ItemStack keptDrop = reduceFlashDropAmount(drop, clampedKeepRate, random);
            if (keptDrop == null) {
                continue;
            }
            world.dropItemNaturally(blockCenter, keptDrop);
            dropped = true;
        }
        if (!dropped && type.isItem() && random.nextDouble() < clampedKeepRate) {
            world.dropItemNaturally(blockCenter, new ItemStack(type));
        }
    }

    private ItemStack reduceFlashDropAmount(ItemStack drop, double keepRate, ThreadLocalRandom random) {
        if (keepRate >= 0.999D) {
            return drop.clone();
        }
        int keptAmount = 0;
        for (int i = 0; i < drop.getAmount(); i++) {
            if (random.nextDouble() < keepRate) {
                keptAmount++;
            }
        }
        if (keptAmount <= 0) {
            return null;
        }
        ItemStack reduced = drop.clone();
        reduced.setAmount(keptAmount);
        return reduced;
    }

    private Sound getFlashBreakSound(Material type, SoundGroup soundGroup) {
        return isEarthLikeBlock(type) ? Sound.BLOCK_GRAVEL_BREAK : soundGroup.getBreakSound();
    }

    private float getFlashBreakPitch(Material type, SoundGroup soundGroup) {
        return isEarthLikeBlock(type) ? 0.86f : Math.min(1.4f, soundGroup.getPitch());
    }

    private boolean isEarthLikeBlock(Material type) {
        String name = type.name();
        return name.contains("DIRT") || name.contains("GRASS_BLOCK") || name.contains("PODZOL") || name.contains("MYCELIUM") || name.contains("FARMLAND") || name.contains("MUD");
    }

    private void applyUpgradedTridentSharpness(EntityDamageByEntityEvent event, Trident trident, Player attacker) {
        ItemStack tridentItem = getBestTridentItem(trident);
        if (tridentItem == null || tridentItem.getType() == Material.AIR || !isUpgradeApplied(tridentItem)) {
            return;
        }
        int sharpness = tridentItem.getEnchantmentLevel(Enchantment.SHARPNESS);
        if (sharpness <= 0) {
            return;
        }
        event.setDamage(event.getDamage() + 0.5D + sharpness * 0.5D);
        Location hit = event.getEntity().getLocation().add(0.0D, Math.min(1.0D, event.getEntity().getHeight() * 0.5D), 0.0D);
        hit.getWorld().spawnParticle(Particle.CRIT, hit, 12, 0.18, 0.18, 0.18, 0.04);
        hit.getWorld().spawnParticle(Particle.ENCHANTED_HIT, hit, 8, 0.16, 0.16, 0.16, 0.02);
        attacker.playSound(attacker.getLocation(), Sound.ITEM_TRIDENT_HIT, 0.75f, 1.28f);
    }

    private boolean applyFlashMaceSmash(EntityDamageByEntityEvent event, Player attacker, LivingEntity victim, GameRoom room) {
        ItemStack weapon = attacker.getInventory().getItemInMainHand();
        if (weapon == null || weapon.getType() != Material.MACE) {
            return false;
        }
        if (unstableMaceSpecialDamageGuards.contains(attacker.getUniqueId())) {
            return false;
        }
        if (!isRecordedAttackWeapon(attacker, weapon)) {
            return false;
        }

        float fallDistance = attacker.getFallDistance();
        if (fallDistance < MACE_SMASH_MIN_FALL_DISTANCE) {
            return false;
        }

        event.setDamage(event.getDamage() * 1.25D);
        int unstableLevel = getUnstableMaceLevel(weapon);
        if (unstableLevel > 0) {
            applyUnstableMaceSmashDamage(event, attacker, victim, room, unstableLevel);
            if (unstableLevel >= 2) {
                scheduleUnstableMaceEcho(attacker, victim, room);
            }
            if (unstableLevel >= 4) {
                scheduleUnstableMacePhaseAfterimage(attacker, victim, room);
            }
            if (unstableLevel >= 5) {
                applyUnstableMaceFallingStar(attacker, victim, room, fallDistance);
            }
        }
        Location hit = victim.getLocation().add(0.0D, Math.min(1.15D, Math.max(0.45D, victim.getHeight() * 0.55D)), 0.0D);
        World world = hit.getWorld();
        if (world == null) {
            return false;
        }
        world.spawnParticle(Particle.END_ROD, hit, 34, 0.32, 0.28, 0.32, 0.85);
        world.spawnParticle(Particle.GUST, hit, 6, 0.22, 0.18, 0.22, 0.04);
        world.playSound(hit, Sound.ITEM_MACE_SMASH_GROUND, 0.95f, 1.05f);
        world.playSound(hit, Sound.ENTITY_BREEZE_WIND_BURST, 0.55f, 1.45f);
        if (unstableLevel > 0) {
            world.spawnParticle(Particle.ELECTRIC_SPARK, hit, 12 + unstableLevel * 3, 0.32D, 0.32D, 0.32D, 0.08D);
            maybeTriggerUnstableMaceRebound(attacker, victim, room, unstableLevel);
        }

        return applyRecordedAxeShieldMaceCombo(event, attacker, victim, room);
    }

    private void applyUnstableMaceSmashDamage(EntityDamageByEntityEvent event, Player attacker, LivingEntity victim,
                                             GameRoom room, int unstableLevel) {
        UnstableMaceAmbushBonus ambush = getActiveUnstableMaceAmbushBonus(attacker, victim, room);
        if (ambush != null) {
            unstableMaceAmbushBonuses.remove(attacker.getUniqueId());
            Location hit = victim.getLocation().add(0.0D, Math.min(1.25D, victim.getHeight() * 0.64D), 0.0D);
            World world = hit.getWorld();
            if (world != null) {
                world.spawnParticle(Particle.REVERSE_PORTAL, hit, 62, 0.38D, 0.38D, 0.38D, 0.18D);
                world.spawnParticle(Particle.SONIC_BOOM, hit, 1, 0.0D, 0.0D, 0.0D, 0.0D);
                world.playSound(hit, Sound.ENTITY_WARDEN_SONIC_BOOM, 0.82f, 1.46f);
                world.playSound(hit, Sound.ITEM_MACE_SMASH_AIR, 0.9f, 0.78f);
            }
            attacker.sendActionBar("§x§B§B§8§8§F§F✦ §d不稳定折跃猛击 §7已触发，§f本次不增加伤害");
            if (ambush.level() >= 8) {
                applyUnstableMaceGravityCollapse(attacker, victim, room);
            }
            if (ambush.level() >= 10) {
                applyUnstableMaceFinalResonance(attacker, victim, room);
            }
        }

        if (unstableLevel >= 3) {
            applyUnstableMaceShieldCrack(attacker, victim, unstableLevel, ambush != null);
        }
        if (unstableLevel >= 6) {
            applyUnstableMaceDisplacementLock(attacker, victim, room, unstableLevel);
        }
        if (unstableLevel >= 9) {
            maybeApplyUnstableMaceCoreBoom(event, attacker, victim, unstableLevel);
        }
    }

    private void scheduleUnstableMaceEcho(Player attacker, LivingEntity victim, GameRoom room) {
        if (attacker == null || victim == null) {
            return;
        }
        UUID attackerId = attacker.getUniqueId();
        UUID victimId = victim.getUniqueId();
        String roomId = getFlashContextId(attacker, room);
        Location hitLocation = victim.getLocation().clone();
        Bukkit.getScheduler().runTaskLater(plugin, () -> {
            Player onlineAttacker = Bukkit.getPlayer(attackerId);
            Entity entity = Bukkit.getEntity(victimId);
            if (onlineAttacker == null || !onlineAttacker.isOnline() || !(entity instanceof LivingEntity target)
                    || !target.isValid() || target.isDead() || target.getWorld() == null
                    || !target.getWorld().equals(hitLocation.getWorld())) {
                return;
            }
            GameRoom activeRoom = plugin.getRoomManager().getPlayerRoom(attackerId);
            if (!roomId.equals(getFlashContextId(onlineAttacker, activeRoom))) {
                return;
            }
            if (target.getLocation().distanceSquared(hitLocation) > 9.0D) {
                target.getWorld().spawnParticle(Particle.SMOKE, hitLocation.add(0.0D, 0.85D, 0.0D),
                        12, 0.20D, 0.16D, 0.20D, 0.02D);
                onlineAttacker.playSound(onlineAttacker.getLocation(), Sound.BLOCK_NOTE_BLOCK_HAT, 0.28f, 0.72f);
                return;
            }
            Location echo = target.getLocation().add(0.0D, Math.min(1.15D, target.getHeight() * 0.58D), 0.0D);
            target.getWorld().spawnParticle(Particle.CRIT, echo, 22, 0.24D, 0.22D, 0.24D, 0.06D);
            target.getWorld().spawnParticle(Particle.ELECTRIC_SPARK, echo, 14, 0.18D, 0.18D, 0.18D, 0.04D);
            target.getWorld().playSound(echo, Sound.ITEM_MACE_SMASH_AIR, 0.58f, 1.62f);
        }, 7L);
    }

    private void scheduleUnstableMacePhaseAfterimage(Player attacker, LivingEntity victim, GameRoom room) {
        if (attacker == null || victim == null) {
            return;
        }
        UUID attackerId = attacker.getUniqueId();
        UUID victimId = victim.getUniqueId();
        String roomId = getFlashContextId(attacker, room);
        Bukkit.getScheduler().runTaskLater(plugin, () -> {
            Player onlineAttacker = Bukkit.getPlayer(attackerId);
            Entity entity = Bukkit.getEntity(victimId);
            if (onlineAttacker == null || !onlineAttacker.isOnline() || !(entity instanceof LivingEntity target)
                    || !target.isValid() || target.isDead() || target.getWorld() == null) {
                return;
            }
            GameRoom activeRoom = plugin.getRoomManager().getPlayerRoom(attackerId);
            if (!roomId.equals(getFlashContextId(onlineAttacker, activeRoom))) {
                return;
            }
            if (target instanceof Player playerTarget && !canDamage(activeRoom, onlineAttacker, playerTarget)) {
                return;
            }
            Location center = target.getLocation().add(0.0D, Math.min(1.18D, target.getHeight() * 0.60D), 0.0D);
            World world = center.getWorld();
            if (world != null) {
                for (int i = 0; i < 3; i++) {
                    double angle = Math.toRadians(target.getTicksLived() * 18.0D + i * 120.0D);
                    Location shadow = center.clone().add(Math.cos(angle) * 0.72D, 0.0D, Math.sin(angle) * 0.72D);
                    world.spawnParticle(Particle.REVERSE_PORTAL, shadow, 18, 0.10D, 0.18D, 0.10D, 0.04D);
                    world.spawnParticle(Particle.ELECTRIC_SPARK, shadow, 8, 0.08D, 0.12D, 0.08D, 0.03D);
                }
                world.playSound(center, Sound.ENTITY_ENDERMAN_TELEPORT, 0.42f, 1.82f);
                world.playSound(center, Sound.ITEM_MACE_SMASH_AIR, 0.48f, 1.48f);
            }
        }, 5L);
    }

    private void applyUnstableMaceShieldCrack(Player attacker, LivingEntity victim, int level, boolean ambush) {
        if (!(victim instanceof Player target) || !isActuallyShieldBlocking(target)) {
            return;
        }
        ItemStack shield = findBlockingShield(target);
        int cooldown = ambush ? 105 : 55 + Math.min(60, level * 6);
        target.setCooldown(Material.SHIELD, applyUnstableCoreShieldBreakCooldown(shield, cooldown));
        target.playSound(target.getLocation(), Sound.ITEM_SHIELD_BREAK, 0.95f, ambush ? 0.72f : 0.92f);
        attacker.playSound(attacker.getLocation(), Sound.BLOCK_AMETHYST_BLOCK_BREAK, 0.42f, 1.34f);
        target.getWorld().spawnParticle(Particle.ELECTRIC_SPARK, target.getLocation().add(0.0D, 1.0D, 0.0D),
                24, 0.34D, 0.36D, 0.34D, 0.12D);
    }

    private void applyUnstableMaceDisplacementLock(Player attacker, LivingEntity victim, GameRoom room, int level) {
        if (!(victim instanceof Player target) || target.isDead() || !target.isOnline()) {
            return;
        }
        long now = System.currentTimeMillis();
        long duration = 560L + Math.min(240L, Math.max(0, level - 6) * 45L);
        unstableMaceDisplacementLocks.merge(target.getUniqueId(), now + duration, Math::max);
        target.addPotionEffect(new PotionEffect(PotionEffectType.SLOWNESS, 16, 1, false, true, true));
        Location center = target.getLocation().add(0.0D, 0.82D, 0.0D);
        target.getWorld().spawnParticle(Particle.SCULK_SOUL, center, 14, 0.24D, 0.28D, 0.24D, 0.03D);
        target.getWorld().spawnParticle(Particle.ELECTRIC_SPARK, center, 12, 0.22D, 0.24D, 0.22D, 0.06D);
        target.playSound(target.getLocation(), Sound.BLOCK_SCULK_SENSOR_CLICKING, 0.48f, 1.35f);
        attacker.playSound(attacker.getLocation(), Sound.BLOCK_AMETHYST_BLOCK_RESONATE, 0.38f, 1.82f);
    }

    private void applyUnstableMaceFallingStar(Player attacker, LivingEntity victim, GameRoom room, float fallDistance) {
        int layers = Math.max(0, Math.min(3, (int) Math.floor((fallDistance - MACE_SMASH_MIN_FALL_DISTANCE) / 2.0F)));
        if (layers <= 0 || victim.getWorld() == null) {
            return;
        }
        Location center = victim.getLocation().add(0.0D, 0.35D, 0.0D);
        double radius = 2.2D + layers * 0.45D;
        World world = center.getWorld();
        world.spawnParticle(Particle.EXPLOSION, center, layers, radius * 0.16D, 0.10D, radius * 0.16D, 0.01D);
        world.spawnParticle(Particle.END_ROD, center, 16 + layers * 8, radius * 0.20D, 0.18D, radius * 0.20D, 0.08D);
        world.playSound(center, Sound.BLOCK_TRIAL_SPAWNER_SPAWN_MOB, 0.46f, 0.82f + layers * 0.1f);
        for (LivingEntity nearby : world.getNearbyLivingEntities(center, radius, 1.65D, radius)) {
            if (nearby.equals(victim) || nearby.equals(attacker) || nearby.isDead() || !nearby.isValid()) {
                continue;
            }
            if (nearby instanceof Player playerTarget && !canDamage(room, attacker, playerTarget)) {
                continue;
            }
            Vector push = nearby.getLocation().toVector().subtract(center.toVector());
            if (push.lengthSquared() > 0.001D) {
                push.normalize().multiply(0.24D + layers * 0.06D);
                push.setY(0.18D + layers * 0.035D);
                nearby.setVelocity(nearby.getVelocity().add(push));
            }
        }
    }

    private void maybeApplyUnstableMaceCoreBoom(EntityDamageByEntityEvent event, Player attacker, LivingEntity victim, int level) {
        double chance = 0.08D + Math.min(0.06D, (level - 9) * 0.04D);
        if (ThreadLocalRandom.current().nextDouble() >= chance) {
            return;
        }
        Location hit = victim.getLocation().add(0.0D, Math.min(1.25D, victim.getHeight() * 0.62D), 0.0D);
        World world = hit.getWorld();
        if (world != null) {
            world.spawnParticle(Particle.SONIC_BOOM, hit, 1, 0.0D, 0.0D, 0.0D, 0.0D);
            world.spawnParticle(Particle.REVERSE_PORTAL, hit, 34, 0.28D, 0.28D, 0.28D, 0.12D);
            world.playSound(hit, Sound.BLOCK_RESPAWN_ANCHOR_DEPLETE, 0.72f, 0.66f);
        }
        attacker.damage(Math.min(4.0D, 1.3D + level * 0.18D));
        attacker.setNoDamageTicks(Math.min(attacker.getNoDamageTicks(), 2));
    }

    private void applyUnstableMaceGravityCollapse(Player attacker, LivingEntity victim, GameRoom room) {
        Location center = victim.getLocation().add(0.0D, Math.min(1.05D, victim.getHeight() * 0.55D), 0.0D);
        World world = center.getWorld();
        if (world == null) {
            return;
        }
        double radius = 4.0D;
        world.spawnParticle(Particle.REVERSE_PORTAL, center, 72, 0.75D, 0.45D, 0.75D, 0.22D);
        world.playSound(center, Sound.BLOCK_RESPAWN_ANCHOR_CHARGE, 0.72f, 0.58f);
        for (LivingEntity nearby : world.getNearbyLivingEntities(center, radius, 2.1D, radius)) {
            if (nearby.equals(attacker) || nearby.equals(victim) || nearby.isDead() || !nearby.isValid()) {
                continue;
            }
            if (nearby instanceof Player playerTarget && !canDamage(room, attacker, playerTarget)) {
                continue;
            }
            Vector pull = center.toVector().subtract(nearby.getLocation().toVector());
            if (pull.lengthSquared() > 0.001D) {
                pull.normalize().multiply(0.36D);
                pull.setY(Math.max(0.08D, pull.getY() + 0.10D));
                nearby.setVelocity(nearby.getVelocity().add(pull));
            }
        }
    }

