    private record FlashNoteMusicData(int[] tones, int[] playbackTicks) {
        private static FlashNoteMusicData empty() {
            return new FlashNoteMusicData(new int[0], new int[0]);
        }

        private static FlashNoteMusicData sequential(int[] tones, int intervalTicks) {
            if (tones == null || tones.length == 0) {
                return empty();
            }
            int safeInterval = Math.max(1, intervalTicks);
            int[] playbackTicks = new int[tones.length];
            for (int i = 0; i < playbackTicks.length; i++) {
                playbackTicks[i] = i * safeInterval;
            }
            return new FlashNoteMusicData(tones, playbackTicks);
        }

        private FlashNoteMusicData {
            tones = tones == null ? new int[0] : tones;
            playbackTicks = playbackTicks == null || playbackTicks.length != tones.length ? new int[0] : playbackTicks;
        }
    }

