    private static final class FlashNoteMelody {
        private final String displayName;
        private final int[] tones;
        private final int[] rhythm;
        private final FlashNoteSpell spell;
        private final int[] playbackTicks;

        private FlashNoteMelody(String displayName, int[] tones, int[] rhythm, FlashNoteSpell spell) {
            this(displayName, tones, rhythm, spell, null);
        }

        private FlashNoteMelody(String displayName, int[] tones, int[] rhythm, FlashNoteSpell spell, int[] playbackTicks) {
            this.displayName = displayName;
            this.tones = tones == null ? new int[0] : tones;
            this.rhythm = rhythm;
            this.spell = spell;
            this.playbackTicks = playbackTicks == null || playbackTicks.length != this.tones.length ? new int[0] : playbackTicks;
        }

        private String displayName() {
            return displayName;
        }

        private int[] tones() {
            return tones;
        }

        private int[] rhythm() {
            return rhythm;
        }

        private FlashNoteSpell spell() {
            return spell;
        }

        private int[] playbackTicks() {
            return playbackTicks;
        }
    }

