    private record BrushPoint(double x, double y) {
        private double distance(BrushPoint other) {
            return Math.hypot(x - other.x, y - other.y);
        }
    }

    private static final class BrushDrawingSession {
        private final Location origin;
        private final Vector normal;
        private final Vector right;
        private final Vector up;
        private final List<BrushPoint> points = new ArrayList<>();
        private Location lastWorldPoint;
        private long lastUseMillis = System.currentTimeMillis();
        private boolean monitoring;
        private boolean casting;
        private int monitorTicks;

        private BrushDrawingSession(Location origin, Vector normal, Vector right, Vector up) {
            this.origin = origin;
            this.normal = normal;
            this.right = right;
            this.up = up;
        }

        private Location origin() {
            return origin;
        }

        private Vector normal() {
            return normal;
        }

        private Vector right() {
            return right;
        }

        private Vector up() {
            return up;
        }

        private List<BrushPoint> points() {
            return points;
        }

        private Location lastWorldPoint() {
            return lastWorldPoint;
        }

        private void lastWorldPoint(Location lastWorldPoint) {
            this.lastWorldPoint = lastWorldPoint;
        }

        private long lastUseMillis() {
            return lastUseMillis;
        }

        private void lastUseMillis(long lastUseMillis) {
            this.lastUseMillis = lastUseMillis;
        }

        private boolean monitoring() {
            return monitoring;
        }

        private void monitoring(boolean monitoring) {
            this.monitoring = monitoring;
        }

        private boolean casting() {
            return casting;
        }

        private void casting(boolean casting) {
            this.casting = casting;
        }

        private int monitorTicks() {
            return monitorTicks;
        }

        private void monitorTicks(int monitorTicks) {
            this.monitorTicks = monitorTicks;
        }

        private boolean isSameWorld(Player player) {
            return player != null && origin.getWorld() != null && player.getWorld().equals(origin.getWorld());
        }
    }

